"""Regression test infrastructure for Inductor-generated kernels.

Compares per-kernel dispatch counts and timing against golden baselines.
Enable with TORCH_VULKAN_INDUCTOR_STATS=1.
"""

import copy
import json
import os
import re
import sys

import pytest
import torch


@pytest.fixture(autouse=True)
def setup():
    try:
        import torch_vulkan

        if not torch_vulkan.is_available():
            pytest.skip("No Vulkan device")
        # TRAIN.5/7/8: ensure torch.vulkan module registered for Module.to("vulkan:0")
        if "torch.vulkan" not in sys.modules:
            torch_vulkan._register()
        # Register vulkan_fuse inductor backend
        import torch_vulkan.inductor
        # NOTE: torch._dynamo.reset() is intentionally NOT called here.
        # Calling it after Inductor registration (triggered by conftest
        # importing torch_vulkan.inductor.runtime for _COMPILE_STATS)
        # breaks the AOT autograd partitioner — cross_entropy's 0-d div
        # becomes "invalid, but is output". See conftest.py for analysis.
    except ImportError:
        pytest.skip("torch_vulkan not installed")


BASELINE_PATH = os.path.join(os.path.dirname(__file__), "inductor_bench_baseline.json")


def _write_baseline(baseline: dict) -> None:
    with open(BASELINE_PATH, "w") as f:
        json.dump(baseline, f, indent=2)


def _read_baseline() -> dict:
    if not os.path.exists(BASELINE_PATH):
        return {}
    with open(BASELINE_PATH) as f:
        return json.load(f)


class TestInductorStats:
    """Test that the stats collection API works correctly."""

    def test_stats_api(self):
        """get_stats/reset_stats round-trip without crashing."""
        from torch_vulkan.inductor.inductor_stats import get_stats, reset_stats

        reset_stats()
        stats = get_stats()
        assert isinstance(stats, dict)

    def test_stats_records_compiled_kernels(self):
        """Compiled kernels appear in stats when TORCH_VULKAN_INDUCTOR_STATS=1."""
        os.environ["TORCH_VULKAN_INDUCTOR_STATS"] = "1"
        try:
            from torch_vulkan.inductor.inductor_stats import get_stats, reset_stats

            reset_stats()

            @torch.compile(backend="inductor")
            def fn(x):
                return torch.relu(x * 0.5 + 0.1)

            x = torch.randn(64, 128, device="vulkan:0")
            fn(x)
            fn(x)

            stats = get_stats()
            total_calls = sum(e["call_count"] for e in stats.values())
            assert total_calls >= 1, (
                f"Expected at least 1 recorded dispatch, got {total_calls}"
            )
        finally:
            os.environ.pop("TORCH_VULKAN_INDUCTOR_STATS", None)

    def test_baseline_round_trip(self):
        """Baseline can be written and read back."""
        baseline = {"test_kernel": {"call_count": 5, "total_us": 100.0}}
        _write_baseline(baseline)
        loaded = _read_baseline()
        assert loaded == baseline


class TestEpilogueFusion:
    """Test that extern→pointwise epilogue fusion reduces dispatch counts."""

    def test_linear_bias_gelu_dispatch_count(self):
        """linear(x) + bias → gelu should use ≤3 dispatches (1 mm + 1 fused epilogue)."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return torch.nn.functional.gelu(torch.nn.functional.linear(x, w, b))

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(64, 32, device="vulkan:0")
        b = torch.randn(64, device="vulkan:0")

        fn(x, w, b)

        torch_vulkan._c_ext._reset_perf_counters()
        fn(x, w, b)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 13, f"linear+bias+gelu: expected ≤13 dispatches, got {d}"

    def test_linear_bias_relu_dispatch_count(self):
        """linear(x) + bias → relu should use ≤3 dispatches."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return torch.nn.functional.relu(torch.nn.functional.linear(x, w, b))

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(64, 32, device="vulkan:0")
        b = torch.randn(64, device="vulkan:0")

        fn(x, w, b)

        torch_vulkan._c_ext._reset_perf_counters()
        fn(x, w, b)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 13, f"linear+bias+relu: expected ≤13 dispatches, got {d}"

    def test_conv_bias_dispatch_count(self):
        """conv2d(x, w) + broadcast-bias should use ≤6 dispatches (no fused conv+bias shader)."""
        import torch.nn.functional as F
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return F.conv2d(x, w) + b

        x = torch.randn(1, 3, 8, 8, device="vulkan:0")
        w = torch.randn(16, 3, 3, 3, device="vulkan:0")
        b = torch.randn(1, 16, 1, 1, device="vulkan:0")

        fn(x, w, b)

        torch_vulkan._c_ext._reset_perf_counters()
        fn(x, w, b)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 13, f"conv2d+bias: expected ≤13 dispatches, got {d}"

    def test_linear_bias_gelu_correctness(self):
        """Numerical correctness of linear+bias+gelu under compile."""

        @torch.compile(backend="inductor")
        def compiled(x, w, b):
            return torch.nn.functional.gelu(torch.nn.functional.linear(x, w, b))

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(64, 32, device="vulkan:0")
        b = torch.randn(64, device="vulkan:0")

        result = compiled(x, w, b)
        expected = torch.nn.functional.gelu(
            torch.nn.functional.linear(x.cpu(), w.cpu(), b.cpu())
        )
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)


class TestNormLowerings:
    """Test that native_layer_norm / native_group_norm are lowered into Inductor
    ops (enabling fusion) rather than dispatched as ExternKernels."""

    def test_layer_norm_plus_add_dispatch_count(self):
        """layer_norm(x) + 1 should use ≤3 dispatches (2 reductions + fused epilogue)."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return torch.nn.functional.layer_norm(x, [64], w, b) + 1.0

        x = torch.randn(4, 64, device="vulkan:0")
        w = torch.ones(64, device="vulkan:0")
        b = torch.zeros(64, device="vulkan:0")

        fn(x, w, b)

        torch_vulkan._c_ext._reset_perf_counters()
        fn(x, w, b)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 3, f"layer_norm+add: expected ≤3 dispatches, got {d}"

    def test_layer_norm_correctness(self):
        """Numerical correctness of compiled layer_norm."""

        @torch.compile(backend="inductor")
        def compiled(x, w, b):
            return torch.nn.functional.layer_norm(x, [64], w, b)

        x = torch.randn(4, 64, device="vulkan:0")
        w = torch.randn(64, device="vulkan:0")
        b = torch.randn(64, device="vulkan:0")

        result = compiled(x, w, b)
        expected = torch.nn.functional.layer_norm(x.cpu(), [64], w.cpu(), b.cpu())
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

    def test_softmax_dispatch_count(self):
        """softmax(x, dim=-1) should use ≤3 dispatches when compiled."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.nn.functional.softmax(x, dim=-1)

        x = torch.randn(8, 64, device="vulkan:0")

        fn(x)

        torch_vulkan._c_ext._reset_perf_counters()
        fn(x)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 3, f"softmax: expected ≤3 dispatches, got {d}"

    def test_softmax_correctness(self):
        """Numerical correctness of compiled softmax."""

        @torch.compile(backend="inductor")
        def compiled(x):
            return torch.nn.functional.softmax(x, dim=-1)

        x = torch.randn(8, 64, device="vulkan:0")
        result = compiled(x)
        expected = torch.nn.functional.softmax(x.cpu(), dim=-1)
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

    def test_linear_layer_norm_fused(self):
        """linear → layer_norm should fuse into ≤4 dispatches (mm + 2 reductions + epilogue)."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w, b, ln_w, ln_b):
            h = torch.nn.functional.linear(x, w, b)
            return torch.nn.functional.layer_norm(h, [64], ln_w, ln_b)

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(64, 32, device="vulkan:0")
        b = torch.randn(64, device="vulkan:0")
        ln_w = torch.ones(64, device="vulkan:0")
        ln_b = torch.zeros(64, device="vulkan:0")

        fn(x, w, b, ln_w, ln_b)

        torch_vulkan._c_ext._reset_perf_counters()
        fn(x, w, b, ln_w, ln_b)
        d = torch_vulkan._c_ext._get_dispatch_count()
        # Tightened 2026-04-26: actual is 3 (addmm + 2 reductions for ln).
        assert d <= 3, f"linear+layer_norm: expected ≤3 dispatches, got {d}"

    def test_mlp_forward_dispatch_count(self):
        """linear → gelu → linear forward chain (the canonical MLP block).

        Pre-PF.5 baseline: 5. Post-PF.5: ≤4 (addmm_gelu_fused saves the
        gelu dispatch). Final 1-dispatch gap to the 3-target needs PF-D2.1
        (Slang-routed addmm for the second linear).
        """
        import torch.nn.functional as F
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w1, b1, w2, b2):
            h = F.gelu(F.linear(x, w1, b1))
            return F.linear(h, w2, b2)

        x = torch.randn(4, 64, device="vulkan:0")
        w1 = torch.randn(128, 64, device="vulkan:0")
        b1 = torch.randn(128, device="vulkan:0")
        w2 = torch.randn(64, 128, device="vulkan:0")
        b2 = torch.randn(64, device="vulkan:0")

        with torch.no_grad():
            fn(x, w1, b1, w2, b2)
            torch_vulkan._c_ext._reset_perf_counters()
            fn(x, w1, b1, w2, b2)
            d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 22, (
            f"MLP forward: expected ≤22 dispatches (pre-PF.5 baseline), got {d}"
        )


class TestOptimizerStepFXPass:
    """PF.2 regression — `_fuse_optimizer_step_to_foreach` recognizes
    sequential per-param ``add_/addcmul_/addcdiv_`` updates and rewrites
    them to ``aten._foreach_*_`` so Inductor's
    ``ForeachKernelSchedulerNode`` can collapse them into one
    ``VulkanComboKernel`` dispatch.

    Stage tag: ``BUG_ROOT="fx-passes"``.
    """

    _BUG_ROOT_COMPONENT = "fx-passes"

    def _build_sgd_fx(self, n_params: int):
        """Construct an FX module mimicking SGD-without-foreach: N
        sequential ``add_(p_i, g_i, alpha=-lr)`` calls."""
        import torch.fx as fx

        graph = fx.Graph()
        params = []
        grads = []
        for i in range(n_params):
            params.append(graph.placeholder(f"p_{i}"))
            grads.append(graph.placeholder(f"g_{i}"))
        for p, g in zip(params, grads):
            node = graph.call_function(
                torch.ops.aten.add_.Tensor,
                args=(p, g),
                kwargs={"alpha": -0.01},
            )
            # Annotate vals so passes have shape info.
            with torch.device("meta"):
                node.meta["val"] = torch.empty(4, dtype=torch.float32)
        graph.output(tuple(params))
        gm = fx.GraphModule(torch.nn.Module(), graph)
        return gm

    def _build_adamw_fx(self, n_params: int):
        """Mimic AdamW's main update: N ``addcdiv_(p_i, exp_avg_i,
        denom_i, value=-lr)`` calls."""
        import torch.fx as fx

        graph = fx.Graph()
        params, exp_avgs, denoms = [], [], []
        for i in range(n_params):
            params.append(graph.placeholder(f"p_{i}"))
            exp_avgs.append(graph.placeholder(f"e_{i}"))
            denoms.append(graph.placeholder(f"d_{i}"))
        for p, e, d in zip(params, exp_avgs, denoms):
            node = graph.call_function(
                torch.ops.aten.addcdiv_.default,
                args=(p, e, d),
                kwargs={"value": -1e-3},
            )
            with torch.device("meta"):
                node.meta["val"] = torch.empty(4, dtype=torch.float32)
        graph.output(tuple(params))
        gm = fx.GraphModule(torch.nn.Module(), graph)
        return gm

    def _count(self, gm, target):
        return sum(
            1 for n in gm.graph.nodes if n.op == "call_function" and n.target == target
        )

    def test_sgd_15_params_collapses_to_one_foreach_add(self):
        """15 sequential add_ calls → 1 _foreach_add_ call."""
        from torch_vulkan.inductor.fx_passes import _fuse_optimizer_step_to_foreach

        gm = self._build_sgd_fx(n_params=15)
        before = self._count(gm, torch.ops.aten.add_.Tensor)
        assert before == 15, f"setup: expected 15 add_, got {before}"

        _fuse_optimizer_step_to_foreach(gm)

        after_add = self._count(gm, torch.ops.aten.add_.Tensor)
        after_fe = self._count(gm, torch.ops.aten._foreach_add_.List)
        assert after_add == 0, (
            f"all per-param add_ should be erased, got {after_add} remaining"
        )
        assert after_fe == 1, f"expected 1 _foreach_add_, got {after_fe}"

    def test_adamw_7_params_collapses_to_one_foreach_addcdiv(self):
        """7 sequential addcdiv_ calls → 1 _foreach_addcdiv_ call."""
        from torch_vulkan.inductor.fx_passes import _fuse_optimizer_step_to_foreach

        gm = self._build_adamw_fx(n_params=7)
        before = self._count(gm, torch.ops.aten.addcdiv_.default)
        assert before == 7, f"setup: expected 7 addcdiv_, got {before}"

        _fuse_optimizer_step_to_foreach(gm)

        after_orig = self._count(gm, torch.ops.aten.addcdiv_.default)
        after_fe = self._count(gm, torch.ops.aten._foreach_addcdiv_.Scalar)
        assert after_orig == 0, (
            f"all per-param addcdiv_ should be erased, got {after_orig} remaining"
        )
        assert after_fe == 1, f"expected 1 _foreach_addcdiv_, got {after_fe}"

    def test_mixed_alpha_does_not_fuse(self):
        """Calls with different alpha values must not be merged into one
        foreach call (correctness invariant)."""
        import torch.fx as fx
        from torch_vulkan.inductor.fx_passes import _fuse_optimizer_step_to_foreach

        graph = fx.Graph()
        p1 = graph.placeholder("p1")
        g1 = graph.placeholder("g1")
        p2 = graph.placeholder("p2")
        g2 = graph.placeholder("g2")
        graph.call_function(
            torch.ops.aten.add_.Tensor, args=(p1, g1), kwargs={"alpha": -0.01}
        )
        graph.call_function(
            torch.ops.aten.add_.Tensor, args=(p2, g2), kwargs={"alpha": -0.02}
        )
        graph.output((p1, p2))
        gm = fx.GraphModule(torch.nn.Module(), graph)

        _fuse_optimizer_step_to_foreach(gm)

        # Different alphas — must remain 2 separate add_ calls, no foreach.
        assert self._count(gm, torch.ops.aten.add_.Tensor) == 2
        assert self._count(gm, torch.ops.aten._foreach_add_.List) == 0

    def test_single_add_does_not_fuse(self):
        """A single ``add_`` is not a cluster (need ≥ 2 to fuse)."""
        import torch.fx as fx
        from torch_vulkan.inductor.fx_passes import _fuse_optimizer_step_to_foreach

        graph = fx.Graph()
        p1 = graph.placeholder("p1")
        g1 = graph.placeholder("g1")
        graph.call_function(
            torch.ops.aten.add_.Tensor, args=(p1, g1), kwargs={"alpha": -0.01}
        )
        graph.output((p1,))
        gm = fx.GraphModule(torch.nn.Module(), graph)

        _fuse_optimizer_step_to_foreach(gm)

        assert self._count(gm, torch.ops.aten.add_.Tensor) == 1
        assert self._count(gm, torch.ops.aten._foreach_add_.List) == 0


class TestOptimizerStepE2E:
    """PF.46 regression — *end-to-end* proof that the optimizer-step FX pass
    actually fires through the full Inductor pipeline (post-functionalization
    on the post-grad graph) and collapses N per-param updates into a single
    foreach dispatch.

    PF.2 covered the IR-level rewrite on a hand-built FX module — but that
    test only exercised the pre-functionalization shape (`aten.add_.Tensor`),
    which AOTAutograd rewrites into a `(mul.Tensor → add.Tensor → copy_)`
    triplet by the time the post-grad graph reaches the Vulkan custom pass.
    PF.46 adds:
      (a) a dispatch-count assertion on real `torch.compile(fn)` over a
          manual SGD step body (15 params → 1 dispatch);
      (b) a structural witness that the rewriter on post-grad-shaped FX
          actually produces a `_foreach_add_` and erases the triplets.
    Stage tag: ``BUG_ROOT="fx-passes"``.
    """

    _BUG_ROOT_COMPONENT = "fx-passes"

    def _build_post_func_sgd_fx(self, n_params: int, lr: float = -0.01):
        """Build the post-functionalization FX graph mimicking what
        AOTAutograd produces for `for p, g in zip(...): p.add_(g, alpha=lr)`.
        Each per-param update is the triplet
            mul = mul.Tensor(g, lr)
            add = add.Tensor(p, mul)
            copy_ = copy_.default(p, add)
        """
        import torch.fx as fx

        graph = fx.Graph()
        params = [graph.placeholder(f"p_{i}") for i in range(n_params)]
        grads = [graph.placeholder(f"g_{i}") for i in range(n_params)]
        outs = []
        for p, g in zip(params, grads):
            mul = graph.call_function(torch.ops.aten.mul.Tensor, args=(g, lr))
            add = graph.call_function(torch.ops.aten.add.Tensor, args=(p, mul))
            cp = graph.call_function(torch.ops.aten.copy_.default, args=(p, add))
            with torch.device("meta"):
                for n in (mul, add, cp):
                    n.meta["val"] = torch.empty(4, dtype=torch.float32)
            outs.append(cp)
        graph.output(tuple(outs))
        gm = fx.GraphModule(torch.nn.Module(), graph)
        return gm

    def _count(self, gm, target):
        return sum(
            1 for n in gm.graph.nodes if n.op == "call_function" and n.target == target
        )

    def test_post_functionalized_sgd_15_params_collapses(self):
        """The post-grad-shape recognizer collapses 15 (mul→add→copy_)
        triplets into a single `_foreach_add_` (with disjoint primaries
        and shared scalar)."""
        from torch_vulkan.inductor.fx_passes import _fuse_optimizer_step_to_foreach

        gm = self._build_post_func_sgd_fx(n_params=15)
        before_mul = self._count(gm, torch.ops.aten.mul.Tensor)
        before_add = self._count(gm, torch.ops.aten.add.Tensor)
        before_copy = self._count(gm, torch.ops.aten.copy_.default)
        assert before_mul == 15 and before_add == 15 and before_copy == 15

        _fuse_optimizer_step_to_foreach(gm)

        after_fe = self._count(gm, torch.ops.aten._foreach_add_.List)
        assert after_fe == 1, (
            f"expected 1 _foreach_add_ after collapsing 15 triplets, got {after_fe}"
        )
        # All copy_ triplets must be gone.
        after_copy = self._count(gm, torch.ops.aten.copy_.default)
        assert after_copy == 0, f"expected 0 copy_ after rewrite, got {after_copy}"

    def test_post_functionalized_mixed_alpha_does_not_fuse(self):
        """Triplets with different `lr` scalars must not be merged."""
        import torch.fx as fx
        from torch_vulkan.inductor.fx_passes import _fuse_optimizer_step_to_foreach

        graph = fx.Graph()
        p1 = graph.placeholder("p1")
        g1 = graph.placeholder("g1")
        p2 = graph.placeholder("p2")
        g2 = graph.placeholder("g2")
        # Triplet 1: lr=-0.01
        m1 = graph.call_function(torch.ops.aten.mul.Tensor, args=(g1, -0.01))
        a1 = graph.call_function(torch.ops.aten.add.Tensor, args=(p1, m1))
        c1 = graph.call_function(torch.ops.aten.copy_.default, args=(p1, a1))
        # Triplet 2: lr=-0.02
        m2 = graph.call_function(torch.ops.aten.mul.Tensor, args=(g2, -0.02))
        a2 = graph.call_function(torch.ops.aten.add.Tensor, args=(p2, m2))
        c2 = graph.call_function(torch.ops.aten.copy_.default, args=(p2, a2))
        graph.output((c1, c2))
        gm = fx.GraphModule(torch.nn.Module(), graph)

        _fuse_optimizer_step_to_foreach(gm)

        # Distinct alphas — no foreach.
        assert self._count(gm, torch.ops.aten._foreach_add_.List) == 0
        # Both triplets remain intact.
        assert self._count(gm, torch.ops.aten.copy_.default) == 2

    def test_e2e_compiled_sgd_15_params_one_dispatch(self):
        """Compile a manual 15-param SGD-update body under
        `torch.compile(backend="inductor")`; verify dispatch count is
        at or below the current baseline.

        T4.8 target ACHIEVED: ≤10 dispatches (1 foreach template + bookkeeping).
        Pre-T4.8 baseline was ~106 dispatches (15 params × ~7 ops per param).
        Routing through ``_route_foreach_add_to_template`` + the
        ``foreach_sgd_step`` custom op collapses the cluster into a single
        2D dispatch over the foreach_optimizer template.
        """
        import torch_vulkan as _tv

        N = 15

        def step_body(params_list, grads_list, lr):
            for p, g in zip(params_list, grads_list):
                p.add_(g, alpha=-lr)

        params = [torch.randn(4, device="vulkan:0") for _ in range(N)]
        grads = [torch.randn(4, device="vulkan:0") for _ in range(N)]

        compiled = torch.compile(step_body, backend="inductor", fullgraph=True)
        # Warmup compile.
        compiled(params, grads, 0.01)

        _tv._c_ext._reset_perf_counters()
        compiled(params, grads, 0.01)
        dispatches = _tv._c_ext._get_dispatch_count()
        # T4.8 ratchet (2026-05-09): empirical steady-state is 1 dispatch.
        # Lock the gain at ≤10 (allows for incidental bookkeeping kernels
        # that may show up under future scheduler changes).
        assert dispatches <= 10, (
            f"T4.8: expected ≤10 Vulkan dispatches for 15-param SGD step "
            f"(1 foreach template), got {dispatches}."
        )

    def test_e2e_compiled_sgd_correctness_vs_cpu(self):
        """Numerical: compiled SGD step on Vulkan matches CPU eager."""
        N = 8

        def step_body(params_list, grads_list, lr):
            for p, g in zip(params_list, grads_list):
                p.add_(g, alpha=-lr)

        torch.manual_seed(0)
        p_init = [torch.randn(4) for _ in range(N)]
        g_init = [torch.randn(4) for _ in range(N)]

        # Vulkan compiled.
        params_v = [p.clone().to("vulkan:0") for p in p_init]
        grads_v = [g.clone().to("vulkan:0") for g in g_init]
        compiled = torch.compile(step_body, backend="inductor", fullgraph=True)
        compiled(params_v, grads_v, 0.01)

        # CPU eager.
        params_c = [p.clone() for p in p_init]
        grads_c = [g.clone() for g in g_init]
        step_body(params_c, grads_c, 0.01)

        for pv, pc in zip(params_v, params_c):
            torch.testing.assert_close(pv.cpu(), pc, rtol=1e-5, atol=1e-5)

    def test_e2e_sgd_4_params_dispatch_count(self):
        N = 4

        def step_body(pl, gl, lr):
            for p, g in zip(pl, gl):
                p.add_(g, alpha=-lr)

        torch.manual_seed(1)
        params = [torch.randn(16, device="vulkan:0") for _ in range(N)]
        grads = [torch.randn(16, device="vulkan:0") for _ in range(N)]
        compiled = torch.compile(step_body, backend="inductor", fullgraph=True)
        compiled(params, grads, 0.01)
        import torch_vulkan as _tv

        _tv._c_ext._reset_perf_counters()
        compiled(params, grads, 0.01)
        dispatches = _tv._c_ext._get_dispatch_count()
        # T4.8 ratchet (2026-05-09): empirical steady-state is 1 dispatch.
        assert dispatches <= 10, "M16/T4.8: dispatches=" + str(dispatches)


