class TestExtensionDecorators:
    """P5.5: register_lowering / register_template helpers reduce the
    'add a new fused op' boilerplate from five files to one."""

    def test_register_lowering_skips_non_vulkan(self):
        import torch

        # Sentinel op — register_lowering must call upstream's register_lowering
        # but the wrapper must short-circuit when the input is not vulkan.
        # We exercise the wrapper directly without registering with Inductor
        # (avoid leaking into the global lowering table).
        from torch_vulkan.inductor.extensions import _is_vulkan

        class CPUNode:
            def get_device(self):
                return torch.device("cpu")

        assert _is_vulkan(CPUNode()) is False

        class VulkanNode:
            def get_device(self):
                return torch.device("vulkan", 0)

        assert _is_vulkan(VulkanNode()) is True

    def test_register_template_returns_dispatcher(self):
        from torch_vulkan.inductor.extensions import register_template

        src = """
[shader("compute")]
[numthreads(64, 1, 1)]
void computeMain(uint3 tid : SV_DispatchThreadID) { }
"""
        dispatch = register_template(
            "ext_noop", src, n_buffers=0, n_pc=0, pc_size_bytes=0, n_outputs=0
        )
        assert dispatch.cache_key == "ext_noop"
        assert dispatch.n_buffers == 0
        assert callable(dispatch)

    def test_register_template_arg_count_validated(self):
        from torch_vulkan.inductor.extensions import register_template

        src = '[shader("compute")][numthreads(1,1,1)]void computeMain(){}'
        dispatch = register_template("ext_argchk", src, n_buffers=2, n_pc=1)
        import pytest

        with pytest.raises(TypeError, match="expected 2\\+1 args"):
            dispatch(1, 2)  # only 2 args, needs 3


_NAN_REDUCTION_BLOCKER = (
    "P5.6 — Vulkan reductions now propagate NaN via wave-level pre-scan "
    "(WaveActiveAny + isnan). Tests should PASS. Kept as reference for "
    "future regression detection."
)


class TestReductionNaNPropagation:
    """P5.6: torch.amax/amin/max/min must propagate NaNs (matching CPU eager
    semantics) — OpenCL ``fmax``/``fmin`` would suppress them. Reductions
    over a tensor containing NaN must return NaN, not the largest finite
    element. Locks the contract so a future codegen optimization that
    accidentally swaps in NaN-suppressing intrinsics regresses loudly."""

    def _make_input_with_nan(self):
        import torch

        x = torch.randn(64, device="vulkan:0")
        x[7] = float("nan")
        return x

    def test_amax_propagates_nan(self):
        import math

        x = self._make_input_with_nan()
        y = torch.amax(x).item()
        assert math.isnan(y), f"expected NaN, got {y}"

    def test_amin_propagates_nan(self):
        import math

        x = self._make_input_with_nan()
        y = torch.amin(x).item()
        assert math.isnan(y), f"expected NaN, got {y}"

    def test_amax_compiled_propagates_nan(self):
        import math

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.amax(x)

        x = self._make_input_with_nan()
        y = fn(x).item()
        assert math.isnan(y), f"compiled amax dropped NaN, got {y}"

    def test_sum_propagates_nan(self):
        import math

        x = self._make_input_with_nan()
        y = torch.sum(x).item()
        assert math.isnan(y), f"sum() dropped NaN, got {y}"


