def _vulkan_eager_fft_works() -> bool:
    """Probe whether ``aten::_fft_r2c`` is registered for PrivateUse1.

    ``csrc/ops/fft_ops.cpp`` defines the kernels but they are not
    wired into ``Registration.cpp`` today — eager FFT raises
    "Operation not yet implemented for the Vulkan backend". When the
    Group A follow-up lands, this probe will start returning True and
    the gradient-parity tests below will activate automatically.
    """
    try:
        import torch_vulkan  # noqa: F401

        x = torch.randn(8, device="vulkan:0")
        torch.fft.rfft(x)
        return True
    except Exception:
        return False


class TestFftLowerings:
    """OP.4: Inductor fallback lowerings for ``aten._fft_*``.

    Strategy: route to the eager C++ kernels via ``make_fallback``
    rather than write a Slang FFT (anti-goal #1). Inductor upstream
    already registers a fallback for ``_fft_r2c``; this module adds
    the missing ``_fft_c2c`` and ``_fft_c2r`` so high-level wrappers
    (``torch.fft.fft``, ``torch.fft.ifft``, ``torch.fft.irfft``) do
    not graph-break under ``torch.compile``.

    The compile-only test verifies the lowering registration prevents
    a graph break. Numerical-parity tests are gated behind eager FFT
    being functional (``csrc/ops/fft_ops.cpp`` is not registered into
    ``Registration.cpp`` as of 2026-05-08 — Group A follow-up).
    """

    def test_fft_rfft_no_graph_break_op_4(self):
        """Compile ``torch.fft.rfft`` end-to-end. With OP.4 the
        ``aten._fft_r2c`` fallback is registered (upstream + ours
        idempotent), so Dynamo + Inductor produce a single graph
        rather than graph-breaking. We trigger compilation by
        capturing the graph via ``torch._dynamo.export``.
        """
        import torch._dynamo

        def fn(x):
            return torch.fft.rfft(x)

        x = torch.randn(64)
        exported = torch._dynamo.export(fn)(x)
        graph_str = str(exported.graph_module.graph)
        # The captured FX graph must contain the rfft call. If
        # Dynamo had graph-broken the export would have errored or
        # split into multiple subgraphs; with a clean lowering the
        # call survives as a single node.
        assert "fft_rfft" in graph_str or "_fft_r2c" in graph_str, (
            f"expected fft_rfft / _fft_r2c node in exported graph, got: {graph_str!r}"
        )

    def test_fft_lowering_registered_op_4(self):
        """Lock that the three FFT primitives have a fallback or
        proper lowering installed by ``_register_fft_lowerings``.
        Without this, ``_fft_c2c`` / ``_fft_c2r`` graph-break under
        ``torch.compile`` because upstream Inductor only covers
        ``_fft_r2c``.
        """
        from torch._inductor.lowering import fallbacks, lowerings

        aten = torch.ops.aten
        for op in (
            aten._fft_r2c.default,
            aten._fft_c2c.default,
            aten._fft_c2r.default,
        ):
            assert op in lowerings or op in fallbacks, (
                f"FFT op {op} missing Inductor lowering — OP.4 registration regressed"
            )

    @pytest.mark.skipif(
        not _vulkan_eager_fft_works(),
        reason="Vulkan eager FFT not registered (csrc/ops/fft_ops.cpp "
        "not wired into Registration.cpp); OP.4 follow-up Group A item",
    )
    def test_fft_rfft_compile_op_4(self):
        """End-to-end compile + run ``torch.fft.rfft``: numerical
        parity vs CPU eager. Activates once the eager FFT path is
        registered.
        """

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.fft.rfft(x)

        x = torch.randn(64)
        x_vk = x.to("vulkan:0")
        y = fn(x_vk)
        expected = torch.fft.rfft(x)
        torch.testing.assert_close(y.cpu(), expected, rtol=1e-3, atol=1e-3)

    @pytest.mark.skipif(
        not _vulkan_eager_fft_works(),
        reason="Vulkan eager FFT not registered (csrc/ops/fft_ops.cpp "
        "not wired into Registration.cpp); OP.4 follow-up Group A item",
    )
    def test_fft_irfft_compile_op_4(self):
        """End-to-end compile + run ``torch.fft.irfft``: round-trip
        through rfft + irfft must recover the input. Exercises both
        the ``_fft_r2c`` (already upstream) and ``_fft_c2r`` (added
        in OP.4) fallbacks in the same graph.
        """

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.fft.irfft(torch.fft.rfft(x), n=64)

        x = torch.randn(64)
        x_vk = x.to("vulkan:0")
        y = fn(x_vk)
        torch.testing.assert_close(y.cpu(), x, rtol=1e-3, atol=1e-3)


class TestFftStockhamCP2:
    """CP.2 / OP.10: FFT eager dispatch + Stockham Slang template.

    Two-tier verification:
    - Tier 1 (eager): ``torch.fft.fft(x).cpu()`` succeeds on Vulkan tensor
      for c2c, r2c, and c2r paths (exercises the PrivateUse1 registration
      in ``Registration.cpp``).
    - Tier 2 (compiled): FFT under ``torch.compile`` matches CPU numerics
      (exercises the Stockham template via ``install_external_fft()``).
    """

    @pytest.mark.skipif(
        not _vulkan_eager_fft_works(),
        reason="Vulkan eager FFT not registered (rebuild needed)",
    )
    def test_cp2_fft_c2c_eager_succeeds(self):
        """``torch.fft.fft(x).cpu()`` succeeds on Vulkan tensor.

        Exercises the complex-to-complex FFT eager path registered
        at PrivateUse1 in Registration.cpp.
        """
        import torch_vulkan  # noqa: F401

        x = torch.randn(4, 64, dtype=torch.cfloat, device="vulkan:0")
        y = torch.fft.fft(x)
        # Must succeed and produce a valid complex tensor
        assert y.device.type == "vulkan"
        assert y.shape == x.shape
        assert y.dtype == torch.cfloat
        # Round-trip to CPU must not crash
        y_cpu = y.cpu()
        expected = torch.fft.fft(x.cpu())
        torch.testing.assert_close(y_cpu, expected, rtol=1e-3, atol=1e-3)

    @pytest.mark.skipif(
        not _vulkan_eager_fft_works(),
        reason="Vulkan eager FFT not registered (rebuild needed)",
    )
    def test_cp2_fft_r2c_eager_succeeds(self):
        """Real-to-complex FFT (``torch.fft.rfft``) succeeds on Vulkan."""
        import torch_vulkan  # noqa: F401

        x = torch.randn(4, 64, device="vulkan:0")
        y = torch.fft.rfft(x)
        assert y.device.type == "vulkan"
        assert y.dtype == torch.cfloat
        y_cpu = y.cpu()
        expected = torch.fft.rfft(x.cpu())
        torch.testing.assert_close(y_cpu, expected, rtol=1e-3, atol=1e-3)

    @pytest.mark.skipif(
        not _vulkan_eager_fft_works(),
        reason="Vulkan eager FFT not registered (rebuild needed)",
    )
    def test_cp2_fft_c2r_eager_succeeds(self):
        """Complex-to-real FFT (``torch.fft.irfft``) succeeds on Vulkan."""
        import torch_vulkan  # noqa: F401

        x = torch.randn(4, 64, device="vulkan:0")
        x_vk = x.to("vulkan:0")
        xf = torch.fft.rfft(x_vk)
        y = torch.fft.irfft(xf, n=64)
        assert y.device.type == "vulkan"
        assert y.dtype == torch.float32
        y_cpu = y.cpu()
        torch.testing.assert_close(y_cpu, x, rtol=1e-3, atol=1e-3)

    @pytest.mark.skipif(
        not _vulkan_eager_fft_works(),
        reason="Vulkan eager FFT not registered (rebuild needed)",
    )
    def test_cp2_fft_compiled_matches_cpu(self):
        """FFT under ``torch.compile`` matches CPU eager.

        Exercises the Stockham template path via
        ``install_external_fft()`` which is called during backend
        initialization. For small power-of-2 N the template is an
        option; the eager fallback is also available.
        """
        import torch_vulkan  # noqa: F401

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.fft.fft(x)

        x = torch.randn(4, 256, dtype=torch.cfloat)
        x_vk = x.to("vulkan:0")
        y = fn(x_vk)
        expected = torch.fft.fft(x)
        torch.testing.assert_close(y.cpu(), expected, rtol=1e-3, atol=1e-3)


class TestPacked16Verification:
    """P2.3: f16 elementwise kernels should compile + run correctly. The
    packed16 codegen path is gated on dtype eligibility — tests here lock
    correctness so a future packed16 codegen regression is caught."""

    def test_f16_pointwise_correctness(self):
        x = torch.randn(64, 128, device="vulkan:0", dtype=torch.float16)

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.relu(x * 0.5 + 0.1)

        y = fn(x)
        torch.testing.assert_close(
            y.cpu().float(),
            torch.relu(x.cpu().float() * 0.5 + 0.1),
            rtol=1e-2,
            atol=1e-2,
        )

    def test_f16_chain_dispatch_count(self):
        import torch_vulkan

        torch_vulkan._c_ext._reset_perf_counters()

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.tanh(x * 1.5 + 0.3 - 0.5)

        x = torch.randn(256, 256, device="vulkan:0", dtype=torch.float16)
        fn(x)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(x)
        torch_vulkan._c_ext._synchronize(0)
        n = torch_vulkan._c_ext._get_dispatch_count()
        assert n <= 1, f"expected 1 dispatch (fused pointwise), got {n}"


class TestCrossEntropyBaseline:
    """P1.5: F.cross_entropy(logits, target) under torch.compile. Locks
    correctness vs CPU; dispatch-count target depends on the future
    fast-path lowering routing through nll_loss_mean_fused."""

    def test_cross_entropy_correctness(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(x, t):
            return F.cross_entropy(x, t, reduction="mean")

        x = torch.randn(8, 16, device="vulkan:0")
        t = torch.randint(0, 16, (8,), device="vulkan:0")
        y = fn(x, t)
        ref = F.cross_entropy(x.cpu(), t.cpu(), reduction="mean")
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-4)

    def test_cross_entropy_eager_correctness(self):
        """Eager-path cross_entropy on Vulkan must work — this is the
        baseline the compiled path needs to match."""
        import torch.nn.functional as F

        x = torch.randn(8, 16, device="vulkan:0")
        t = torch.randint(0, 16, (8,), device="vulkan:0")
        y = F.cross_entropy(x, t, reduction="mean")
        ref = F.cross_entropy(x.cpu(), t.cpu(), reduction="mean")
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-4)


class TestExprPrinterIntCast:
    """P1.5 / P6.3: VulkanExprPrinter wraps `tmp\\d+` symbols with
    `((int)(...))` only inside subscript context (entered via `subscript()`).
    Outside subscript context the cast would destroy precision on real float
    CSE locals — the `tmp\\d+` namespace is shared between int-index CSE
    values from `indirect_indexing` and float CSE values from arithmetic.
    """

    def test_tmp_symbol_outside_subscript_no_cast(self):
        """Default (non-subscript) context: `tmp4` stays `tmp4` so we don't
        truncate float CSE values that happen to share the namespace."""
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        printer = VulkanExprPrinter()
        out = printer.doprint(sympy.Symbol("tmp4"))
        assert out == "tmp4"

    def test_tmp_symbol_inside_subscript_gets_int_cast(self):
        """In subscript context: `tmp4` → `((int)(tmp4))` so int64 index
        values stored in float CSE locals subscript correctly."""
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        printer = VulkanExprPrinter()
        with printer.subscript():
            out = printer.doprint(sympy.Symbol("tmp4"))
        assert out == "((int)(tmp4))"

    def test_non_tmp_symbol_no_cast(self):
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        printer = VulkanExprPrinter()
        # No cast inside or outside subscript context for non-tmp names.
        assert printer.doprint(sympy.Symbol("xindex")) == "xindex"
        with printer.subscript():
            assert printer.doprint(sympy.Symbol("xindex")) == "xindex"

    def test_tmp_in_index_expr(self):
        """Compound index expression `tmp4 + 16*x0` inside subscript context
        renders both halves correctly: tmp gets the cast, x0 doesn't."""
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        printer = VulkanExprPrinter()
        x0 = sympy.Symbol("x0")
        tmp4 = sympy.Symbol("tmp4")
        with printer.subscript():
            out = printer.doprint(tmp4 + 16 * x0)
        assert "((int)(tmp4))" in out
        assert "x0" in out

    def test_subscript_context_nests_correctly(self):
        """Re-entering subscript() (e.g. recursive index_to_str on a list of
        sub-expressions) must not lose the cast on exit of the inner scope."""
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        printer = VulkanExprPrinter()
        with printer.subscript():
            with printer.subscript():
                inner = printer.doprint(sympy.Symbol("tmp1"))
            outer = printer.doprint(sympy.Symbol("tmp2"))
        assert inner == "((int)(tmp1))"
        assert outer == "((int)(tmp2))"
        # After exiting both, no cast.
        assert printer.doprint(sympy.Symbol("tmp3")) == "tmp3"


class TestScaledBmmFusion:
    """P1.1 / FX pass: bmm + scalar mul → scaled_bmm extern. Locks the
    fused dispatch path: 1 dispatch instead of 2 (transpose + bmm + mul)."""

    def test_scaled_bmm_dispatch_count(self):
        import torch_vulkan

        torch_vulkan._c_ext._reset_perf_counters()
        scale = 0.125

        @torch.compile(backend="inductor")
        def fn(q, k):
            return scale * torch.bmm(q, k.transpose(-2, -1))

        q = torch.randn(2, 8, 16, device="vulkan:0")
        k = torch.randn(2, 8, 16, device="vulkan:0")
        fn(q, k)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(q, k)
        torch_vulkan._c_ext._synchronize(0)
        n = torch_vulkan._c_ext._get_dispatch_count()
        assert n == 1, f"expected 1 dispatch (fused scaled_bmm), got {n}"

    def test_scaled_bmm_correctness(self):
        scale = 0.125

        @torch.compile(backend="inductor")
        def fn(q, k):
            return scale * torch.bmm(q, k.transpose(-2, -1))

        q = torch.randn(2, 8, 16, device="vulkan:0")
        k = torch.randn(2, 8, 16, device="vulkan:0")
        y = fn(q, k)
        ref = scale * torch.bmm(q.cpu(), k.cpu().transpose(-2, -1))
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-4)

    def test_scaled_bmm_op_registered(self):
        """torch.ops.torch_vulkan.scaled_bmm must be a callable OpOverload
        after backend register() — required for Inductor lowering."""
        op = torch.ops.torch_vulkan.scaled_bmm.default
        assert callable(op)


class TestSwigluCorrectness:
    """P1.1: swiglu eager API correctness — `silu(gate) * up`. Locks the
    eager extern that the future SwiGLU FX pass will route to."""

    def test_swiglu_matches_manual(self):
        import torch_vulkan

        gate = torch.randn(4, 32, device="vulkan:0")
        up = torch.randn(4, 32, device="vulkan:0")
