class TestSwigluFusion:
    """P1.1: silu(gate) * up under torch.compile collapses to 1 fused
    dispatch via the SwiGLU FX pass. Locks the fusion contract."""

    def test_swiglu_dispatch_count(self):
        import torch.nn.functional as F
        import torch_vulkan

        torch_vulkan._c_ext._reset_perf_counters()

        @torch.compile(backend="inductor")
        def fn(gate, up):
            return F.silu(gate) * up

        g = torch.randn(4, 32, device="vulkan:0")
        u = torch.randn(4, 32, device="vulkan:0")
        fn(g, u)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(g, u)
        torch_vulkan._c_ext._synchronize(0)
        n = torch_vulkan._c_ext._get_dispatch_count()
        assert n == 1, f"expected 1 dispatch (fused swiglu), got {n}"

    def test_swiglu_fusion_correctness(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(gate, up):
            return F.silu(gate) * up

        g = torch.randn(4, 32, device="vulkan:0")
        u = torch.randn(4, 32, device="vulkan:0")
        y = fn(g, u)
        ref = F.silu(g.cpu()) * u.cpu()
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-4)

    def test_swiglu_op_registered(self):
        op = torch.ops.torch_vulkan.swiglu_fused.default
        assert callable(op)

    def test_swiglu_no_fusion_on_shape_mismatch(self):
        """Different-shape silu/mul operands must not fuse — silu(gate) *
        broadcast_scalar isn't a valid SwiGLU input."""
        import torch.nn.functional as F
        import torch_vulkan

        torch_vulkan._c_ext._reset_perf_counters()

        @torch.compile(backend="inductor")
        def fn(gate, scale_t):
            return F.silu(gate) * scale_t

        g = torch.randn(4, 32, device="vulkan:0")
        # scale_t broadcasts — wrong shape for swiglu fusion.
        s = torch.randn(1, device="vulkan:0")
        # Should compile + execute correctly without invoking swiglu_fused.
        y = fn(g, s)
        ref = F.silu(g.cpu()) * s.cpu()
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-4)


class TestFlashAttentionTemplate:
    """T4.9: flash_attention.py.jinja correctness regression.

    Exercises the Slang flash attention template directly (bypassing the
    autotune choice list, which prefers the C++ eager extern at index 0).
    Catches three concrete defects:
      1. head/q-tile aliasing in `gid.y` decode (was `gid.y / BQ`).
      2. KV head mapping fragile under non-divisible H/KV_H (now
         `(h * KV_H) / H`).
      3. Phase-2 wrote only the `tid`-th D component of O, with a
         per-thread partial-score weight — replaced by a single-pass online
         softmax with full-D score and per-d-slot V accumulation.
    """

    def test_flash_attention_correctness_t4_9(self):
        """T4.9: shapes that simultaneously trip head-aliasing (multiple
        q-tiles per head via N=128 > BQ=32) AND the Phase-2 D-component
        bug (head_dim=64 > 1). Compares against
        torch.nn.functional.scaled_dot_product_attention on CPU."""
        import torch.nn.functional as F

        # Force GQA path (KV_H < H) to also exercise Defect 2's mapping.
        B, H, KV_H, N, D = 2, 4, 2, 128, 64
        S = N

        torch.manual_seed(0)
        q_cpu = torch.randn(B, H, N, D)
        k_cpu = torch.randn(B, KV_H, S, D)
        v_cpu = torch.randn(B, KV_H, S, D)

        # CPU reference uses K/V broadcast across the GQA group.
        groups = H // KV_H
        k_cpu_full = k_cpu.repeat_interleave(groups, dim=1)
        v_cpu_full = v_cpu.repeat_interleave(groups, dim=1)
        ref = F.scaled_dot_product_attention(
            q_cpu, k_cpu_full, v_cpu_full, is_causal=False
        )

        q = q_cpu.to("vulkan:0")
        k = k_cpu.to("vulkan:0")
        v = v_cpu.to("vulkan:0")

        # Drive the Slang template directly. _SlangTileFlashAttention is the
        # picklable callable Inductor uses as a choice; calling it here
        # avoids the autotune fallback to the eager C++ extern.
        from torch_vulkan.inductor.vulkan_template_caller import (
            _SlangTileFlashAttention,
        )

        flash = _SlangTileFlashAttention(head_dim=D, num_stages=1, is_causal=False)
        scale = float(1.0 / (D**0.5))
        out = flash(q, k, v, scale, is_causal=False)
        torch.testing.assert_close(out.cpu(), ref, rtol=1e-3, atol=1e-3)

    def test_flash_attention_param_tile_sizes_t4_10(self):
        """T4.10: ``BK`` and ``BQ`` are caller-supplied template kwargs.
        Verify a non-default tile config (BK=32, BQ=64) produces correct
        results matching the F.scaled_dot_product_attention reference and
        that the cache key plumbing distinguishes it from the default.
        """
        import torch.nn.functional as F
        from torch_vulkan.inductor.vulkan_template_caller import (
            _SlangTileFlashAttention,
        )

        # Multiple q-tiles AND multiple kv-tiles so both tile dims fire.
        # With BQ=64: N=128 -> 2 q-tiles per head.
        # With BK=32: S=128 -> 4 kv-tiles per query.
        B, H, KV_H, N, D = 1, 2, 2, 128, 64
        S = N

        torch.manual_seed(0)
        q_cpu = torch.randn(B, H, N, D)
        k_cpu = torch.randn(B, KV_H, S, D)
        v_cpu = torch.randn(B, KV_H, S, D)

        ref = F.scaled_dot_product_attention(q_cpu, k_cpu, v_cpu, is_causal=False)

        q = q_cpu.to("vulkan:0")
        k = k_cpu.to("vulkan:0")
        v = v_cpu.to("vulkan:0")

        flash_default = _SlangTileFlashAttention(
            head_dim=D, num_stages=1, is_causal=False
        )
        flash_alt = _SlangTileFlashAttention(
            head_dim=D, num_stages=1, is_causal=False, BK=32, BQ=64
        )
        # Distinct cache keys prove the parameterisation reaches the
        # SPIR-V cache (different shaders compile to different binaries).
        _, key_default = flash_default._src_and_key("float")
        _, key_alt = flash_alt._src_and_key("float")
        assert key_default != key_alt, (
            f"BK/BQ must differentiate cache keys, got {key_default!r} == {key_alt!r}"
        )
        assert "BK32_BQ64" in key_alt, key_alt
        assert "BK64_BQ32" in key_default, key_default

        # Pickling round-trips BK/BQ (Inductor's codecache picks choices).
        import pickle

        revived = pickle.loads(pickle.dumps(flash_alt))
        assert revived.BK == 32 and revived.BQ == 64

        # Numerical correctness for the alt tile config.
        scale = float(1.0 / (D**0.5))
        out = flash_alt(q, k, v, scale, is_causal=False)
        torch.testing.assert_close(out.cpu(), ref, rtol=1e-3, atol=1e-3)


class TestFlashAttentionFusion:
    """P1.1: SDPA under torch.compile routes to torch_vulkan.flash_attention
    via the SDPA→flash FX pass when head_dim ∈ {32, 64, 128} and no
    attn_mask/dropout. Locks the dispatch count + correctness."""

    def test_sdpa_dispatch_count(self):
        import torch.nn.functional as F
        import torch_vulkan

        torch_vulkan._c_ext._reset_perf_counters()

        @torch.compile(backend="inductor")
        def fn(q, k, v):
            return F.scaled_dot_product_attention(q, k, v, is_causal=True)

        q = torch.randn(1, 2, 8, 64, device="vulkan:0")
        k = torch.randn(1, 2, 8, 64, device="vulkan:0")
        v = torch.randn(1, 2, 8, 64, device="vulkan:0")
        fn(q, k, v)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(q, k, v)
        torch_vulkan._c_ext._synchronize(0)
        n = torch_vulkan._c_ext._get_dispatch_count()
        # Eager-decomposed SDPA is ≥9 dispatches; with the fusion pass the
        # compiled path lands at ≤5 (1 flash extern + 4 wrapper allocs/
        # transforms). Lock that ceiling so a regression that loses the
        # fusion fires.
        assert n <= 5, f"expected ≤5 dispatches (fused flash), got {n}"

    def test_sdpa_correctness(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(q, k, v):
            return F.scaled_dot_product_attention(q, k, v, is_causal=True)

        q = torch.randn(1, 2, 8, 64, device="vulkan:0")
        k = torch.randn(1, 2, 8, 64, device="vulkan:0")
        v = torch.randn(1, 2, 8, 64, device="vulkan:0")
        y = fn(q, k, v)
        ref = F.scaled_dot_product_attention(q.cpu(), k.cpu(), v.cpu(), is_causal=True)
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-2, atol=1e-2)

    def test_flash_op_registered(self):
        op = torch.ops.torch_vulkan.flash_attention_fused.default
        assert callable(op)

    def test_no_fusion_on_unsupported_head_dim(self):
        """head_dim=48 isn't in {32, 64, 128} — must not fuse, must still compile."""
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(q, k, v):
            return F.scaled_dot_product_attention(q, k, v, is_causal=False)

        q = torch.randn(1, 2, 4, 48, device="vulkan:0")
        k = torch.randn(1, 2, 4, 48, device="vulkan:0")
        v = torch.randn(1, 2, 4, 48, device="vulkan:0")
        # Should compile (no fusion happens) and produce a correct output.
        y = fn(q, k, v)
        ref = F.scaled_dot_product_attention(q.cpu(), k.cpu(), v.cpu(), is_causal=False)
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-2, atol=1e-2)


