class TestConvIm2ColPattern:
    """T4.4 — Verify the conv_im2col pattern fires and produces correct output.

    The pattern rewrites ``torch_vulkan::conv2d_with_optional_bias`` into an
    im2col decomposition (as_strided + view + permute + mm), enabling the
    Inductor scheduler to fuse the decomposition with surrounding pointwise
    and reduction ops. Covers correctness with/without bias and dispatch
    accounting.
    """

    _BUG_ROOT_COMPONENT = "fx-passes"

    def test_conv2d_im2col_correctness_no_bias(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv2d(x, w)

        x = torch.randn(1, 3, 8, 8, device="vulkan:0")
        w = torch.randn(16, 3, 3, 3, device="vulkan:0")
        y = fn(x, w)
        ref = F.conv2d(x.cpu(), w.cpu())
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-3)

    def test_conv2d_im2col_correctness_with_bias(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return F.conv2d(x, w, bias=b)

        x = torch.randn(1, 3, 8, 8, device="vulkan:0")
        w = torch.randn(16, 3, 3, 3, device="vulkan:0")
        b = torch.randn(16, device="vulkan:0")
        y = fn(x, w, b)
        ref = F.conv2d(x.cpu(), w.cpu(), bias=b.cpu())
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-3)

    def test_conv2d_im2col_correctness_with_padding(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv2d(x, w, padding=1)

        x = torch.randn(1, 3, 8, 8, device="vulkan:0")
        w = torch.randn(16, 3, 3, 3, device="vulkan:0")
        y = fn(x, w)
        ref = F.conv2d(x.cpu(), w.cpu(), padding=1)
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-3)

    def test_conv2d_im2col_dispatch_count(self):
        """im2col path decomposes into mm-based ops; dispatch count must
        not reflect a monolithic extern conv dispatch.

        TRAIN.1-F1: Current count is 9 (6 FallbackKernel copies + 1 im2col
        + 1 mm + 1 output permute). Target ≤6 requires either a custom
        aten.mm lowering or a dedicated conv2d template.
        """
        import torch.nn.functional as F
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv2d(x, w)

        x = torch.randn(1, 3, 8, 8, device="vulkan:0")
        w = torch.randn(16, 3, 3, 3, device="vulkan:0")
        fn(x, w)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(x, w)
        torch_vulkan._c_ext._synchronize(0)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 10, f"conv2d im2col: expected ≤10 dispatches, got {d}"


class TestConv1dCompile:
    """M6 Phase 1 / T4.12 — Conv1d compile-path lowering via reshape to Conv2d.

    The lowering registers ``torch_vulkan::conv1d_with_optional_bias`` and
    reshapes the 3-D input/weight tensors to 4-D (adding a dummy spatial
    dim of size 1), then dispatches to the already-working Conv2d path
    (dedicated ``slang_conv2d.slang`` template for groups==1, eager fallback
    otherwise). The result is squeezed back to 3-D.

    This replaces the previous im2col+mm decomposition and automatically
    inherits backward support from the Conv2d backward path (CG.M6).

    Conv3d compile-path is intentionally left as the eager extern fallback
    (``aten.convolution``); ``test_conv3d_falls_back_or_compiles_t_4_12``
    asserts that fallback path still produces correct results.
    """

    _BUG_ROOT_COMPONENT = "lowerings"

    def test_conv1d_compile_correctness_t_4_12(self):
        """Plain Conv1d under torch.compile: shape and grad-free numerics
        match CPU within fp32 tolerance."""
        import torch.nn as nn

        torch._dynamo.reset()
        m = nn.Conv1d(8, 16, kernel_size=3, padding=1).to("vulkan:0")
        x = torch.randn(2, 8, 32, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return m(x)

        with torch.no_grad():
            y = fn(x).cpu()
        ref = m.cpu()(x.cpu())
        torch.testing.assert_close(y, ref, rtol=1e-3, atol=1e-3)

    def test_conv1d_dilated_t_4_12(self):
        """Conv1d with dilation > 1 — exercises the dilation path of
        the as_strided im2col view."""
        import torch.nn as nn

        torch._dynamo.reset()
        m = nn.Conv1d(4, 8, kernel_size=3, padding=2, dilation=2).to("vulkan:0")
        x = torch.randn(2, 4, 32, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return m(x)

        with torch.no_grad():
            y = fn(x).cpu()
        ref = m.cpu()(x.cpu())
        torch.testing.assert_close(y, ref, rtol=1e-3, atol=1e-3)

    def test_conv1d_strided_t_4_12(self):
        """Conv1d with stride > 1 — exercises the stride path of
        the as_strided im2col view."""
        import torch.nn as nn

        torch._dynamo.reset()
        m = nn.Conv1d(4, 8, kernel_size=3, stride=2, padding=1).to("vulkan:0")
        x = torch.randn(2, 4, 32, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return m(x)

        with torch.no_grad():
            y = fn(x).cpu()
        ref = m.cpu()(x.cpu())
        torch.testing.assert_close(y, ref, rtol=1e-3, atol=1e-3)

    # ── M6 Phase 1 ──────────────────────────────────────────────────

    def test_m6_conv1d_backward_matches_cpu(self):
        """M6 Phase 1: Conv1d backward matches CPU via reshape-to-Conv2d.

        The Conv1d lowering reshapes to Conv2d, so backward inherits
        Conv2d's backward path (CG.M6 conv2d bwd template)."""
        import torch.nn as nn

        torch._dynamo.reset()
        m = nn.Conv1d(8, 16, kernel_size=3, padding=1).to("vulkan:0")
        x = torch.randn(2, 8, 32, device="vulkan:0", requires_grad=True)

        # CPU reference
        m_cpu = nn.Conv1d(8, 16, kernel_size=3, padding=1)
        m_cpu.load_state_dict({k: v.cpu() for k, v in m.state_dict().items()})
        x_cpu = x.detach().cpu().clone().requires_grad_(True)
        ref = m_cpu(x_cpu).sum()
        ref.backward()

        @torch.compile(backend="inductor")
        def fn(x):
            return m(x).sum()

        y = fn(x)
        y.backward()

        torch.testing.assert_close(x.grad.cpu(), x_cpu.grad, rtol=1e-3, atol=1e-3)

    def test_m6_conv1d_groups_matches_cpu(self):
        """M6 Phase 1: Grouped Conv1d (groups=2) matches CPU.

        The reshape-to-Conv2d lowering preserves the groups parameter;
        Conv2d eager fallback handles groups>1 correctly."""
        import torch.nn as nn

        torch._dynamo.reset()
        in_ch = 8
        m = nn.Conv1d(in_ch, in_ch, kernel_size=3, padding=1, groups=2).to("vulkan:0")
        x = torch.randn(2, in_ch, 32, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return m(x)

        with torch.no_grad():
            y = fn(x).cpu()
        ref = m.cpu()(x.cpu())
        torch.testing.assert_close(y, ref, rtol=1e-3, atol=1e-3)

    def test_m6_causal_conv1d_matches_cpu(self):
        """M6 Phase 1: Causal Conv1d (Mamba-style) matches CPU.

        Causal conv1d pads on the left only so output[t] only sees
        input[:t+1]. Uses F.conv1d with explicit padding=0 after a
        manual F.pad on the left."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        B, C, T = 2, 16, 32
        kernel_size = 4

        x = torch.randn(B, C, T, device="vulkan:0")
        weight = torch.randn(C, 1, kernel_size, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x, w):
            x_padded = F.pad(x, (kernel_size - 1, 0))
            return F.conv1d(x_padded, w, groups=C)

        with torch.no_grad():
            y = fn(x, weight).cpu()

        # CPU reference
        x_padded_cpu = F.pad(x.cpu(), (kernel_size - 1, 0))
        ref = F.conv1d(x_padded_cpu, weight.cpu(), groups=C)
        torch.testing.assert_close(y, ref, rtol=1e-3, atol=1e-3)

    def test_conv3d_falls_back_or_compiles_t_4_12(self):
        """Conv3d compile-path: today this falls back to the eager
        ``aten.convolution`` extern kernel (no Vulkan-native conv3d
        template). Either route is acceptable as long as the output
        matches CPU."""
        import torch.nn as nn

        torch._dynamo.reset()
        m = nn.Conv3d(2, 4, kernel_size=3, padding=1).to("vulkan:0")
        x = torch.randn(1, 2, 8, 8, 8, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return m(x)

        with torch.no_grad():
            y = fn(x).cpu()
        ref = m.cpu()(x.cpu())
        torch.testing.assert_close(y, ref, rtol=1e-3, atol=1e-3)


class TestConvGeneralityGaps:
    """T4.12 — Conv template coverage and generality tests.

    The Vulkan Inductor backend now supports:

    * **Conv2d (groups=1)**: Dedicated ``slang_conv2d.slang`` template.
    * **Conv2d (groups>1 / depthwise)**: Decomposed to per-group
      im2col+mm via the ``conv_im2col`` FX pattern (M6 Phase 2).
    * **Conv1d (fwd+bwd)**: Reshape-to-Conv2d lowering (M6 Phase 1).
    * **Conv3d**: Reshape-to-Conv2d lowering for KD==1 kernels;
      falls to ``aten.convolution`` extern for KD>1 (T4.12).
    * **Transposed conv (all strides)**: Decomposed to weight flip +
      transpose + regular Conv2d (T4.12). Stride>1 upsamples before conv.

    These tests verify correct behavior (shape-correct, finite output,
    value parity with CPU) for the supported variants and graceful
    fallback for unsupported parameter combinations.
    """

    _BUG_ROOT_COMPONENT = "lowerings"

    def test_depthwise_conv_compiles(self):
        """Depthwise conv (groups=in_channels) matches CPU.

        MobileNet-style depthwise separable convolution uses
        ``groups == in_channels == out_channels``. M6 Phase 2 enables
        this via the ``conv_im2col`` FX pattern decomposing to per-group
        im2col+mm."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        x_cpu = torch.randn(1, 8, 16, 16)
        w_cpu = torch.randn(8, 1, 3, 3)
        x = x_cpu.to("vulkan:0")
        w = w_cpu.to("vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv2d(x, w, groups=8)

        with torch.no_grad():
            out = fn(x, w).cpu()

        ref = F.conv2d(x_cpu, w_cpu, groups=8)
        assert out.shape == ref.shape, f"unexpected shape: {out.shape}"
        torch.testing.assert_close(out, ref, rtol=1e-4, atol=1e-4)

    def test_conv3d_compiles(self):
        """Conv3d with KD=1 compiles and matches CPU.

        The T4.12 Conv3d reshape-to-Conv2d lowering handles KD==1 kernels
        by reshaping [N,C,D,H,W] to [N*D,C,H,W] and applying Conv2d."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        x_cpu = torch.randn(1, 3, 8, 8, 8)
        w_cpu = torch.randn(6, 3, 1, 3, 3)  # KD=1
        x = x_cpu.to("vulkan:0")
        w = w_cpu.to("vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv3d(x, w)

        with torch.no_grad():
            out = fn(x, w).cpu()

        ref = F.conv3d(x_cpu, w_cpu)
        assert out.shape == ref.shape, f"unexpected shape: {out.shape}"
        torch.testing.assert_close(out, ref, rtol=1e-4, atol=1e-4)

    def test_conv3d_kd_gt_1_falls_back(self):
        """Conv3d with KD>1: native slang_conv3d template (MODEL.1).

        The KD>1 path now compiles via the dedicated slang_conv3d.slang
        template instead of falling back to eager extern."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        x_cpu = torch.randn(1, 3, 8, 8, 8)
        w_cpu = torch.randn(6, 3, 3, 3, 3)  # KD=3
        x = x_cpu.to("vulkan:0")
        w = w_cpu.to("vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv3d(x, w)

        with torch.no_grad():
            out = fn(x, w).cpu()

        ref = F.conv3d(x_cpu, w_cpu)
        assert out.shape == ref.shape, f"unexpected shape: {out.shape}"
        torch.testing.assert_close(out, ref, rtol=1e-4, atol=1e-4)

    def test_conv3d_forward_basic(self):
        """MODEL.1: Conv3d forward basic — KD>1 with padding/stride.

        Verifies that native Conv3d compilation produces correct output
        values matching CPU for a simple 3D convolution case."""
        import torch.nn as nn

        torch._dynamo.reset()
        m_cpu = nn.Conv3d(2, 4, kernel_size=3, padding=1)
        m_vk = nn.Conv3d(2, 4, kernel_size=3, padding=1).to("vulkan:0")
        m_vk.load_state_dict(m_cpu.state_dict())

        x_cpu = torch.randn(1, 2, 6, 6, 6)
        x_vk = x_cpu.to("vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return m_vk(x)

        with torch.no_grad():
            out = fn(x_vk).cpu()

        ref = m_cpu(x_cpu)
        assert out.shape == ref.shape, f"shape mismatch: {out.shape} vs {ref.shape}"
        torch.testing.assert_close(out, ref, rtol=1e-3, atol=1e-3)

    def test_conv3d_backward_basic(self):
        """MODEL.1: Conv3d backward gradient check.

        Verifies that the Conv3d backward via slang_conv3d_bwd template
        produces gradients that match CPU autograd."""
        import torch.nn as nn

        torch._dynamo.reset()
        m_cpu = nn.Conv3d(2, 4, kernel_size=3, padding=1)
        m_vk = nn.Conv3d(2, 4, kernel_size=3, padding=1).to("vulkan:0")
        # Copy weights (no deepcopy across devices for nn.Module)
        with torch.no_grad():
            m_vk.weight.copy_(m_cpu.weight)
            if m_vk.bias is not None:
                m_vk.bias.copy_(m_cpu.bias)

        x_cpu = torch.randn(1, 2, 4, 4, 4, requires_grad=True)
        x_vk = x_cpu.detach().clone().to("vulkan:0").requires_grad_(True)

        # Forward + backward on CPU
        y_cpu = m_cpu(x_cpu)
        loss_cpu = y_cpu.sum()
        loss_cpu.backward()

        # Forward + backward on Vulkan (compiled)
        @torch.compile(backend="inductor")
        def fn(x):
            return m_vk(x).sum()

        loss_vk = fn(x_vk)
        loss_vk.backward()

        grad_vk = x_vk.grad.cpu()
        grad_cpu = x_cpu.grad
        torch.testing.assert_close(grad_vk, grad_cpu, rtol=1e-3, atol=1e-3)

        # Check weight gradients
        torch.testing.assert_close(
            m_vk.weight.grad.cpu(), m_cpu.weight.grad, rtol=1e-3, atol=1e-3
        )

    def test_conv3d_dispatch_count(self):
        """MODEL.1: Conv3d forward compiles to ≤ 2 dispatches.

        The native slang_conv3d template should produce 1 dispatch for
        the conv3d compute (+ possibly 1 for bias add if not fused).
        Ratchets toward the target of minimal dispatches for 3D models."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        torch._dynamo.reset()
        x = torch.randn(1, 3, 4, 4, 4, device="vulkan:0")
        w = torch.randn(6, 3, 3, 3, 3, device="vulkan:0")  # KD=3

        @torch.compile(backend="inductor", dynamic=False, fullgraph=True)
        def fn(x, w):
            return F.conv3d(x, w)

        # Warmup compile
        with torch.no_grad():
            fn(x, w)

        _tv._c_ext._reset_perf_counters()
        with torch.no_grad():
            fn(x, w)
        d = _tv._c_ext._get_dispatch_count()
        # Forward conv3d should be 1-2 dispatches (1 for the compute,
        # possibly 1 for contiguous or other overhead)
        assert d <= 3, (
            f"MODEL.1: Conv3d forward should compile to ≤ 3 dispatches "
            f"via the native slang_conv3d template, got {d}"
        )

    def test_transposed_conv_graph_breaks_gracefully(self):
        """Transposed conv2d (stride=1) matches CPU via decomposition.

        The T4.12 decomposition flips the weight spatially, transposes
        in/out channels, then dispatches to the regular Conv2d path.
        Verifies full value parity with CPU (not just shape)."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        x_cpu = torch.randn(1, 3, 8, 8)
        w_cpu = torch.randn(3, 6, 3, 3)
        x = x_cpu.to("vulkan:0")
        w = w_cpu.to("vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv_transpose2d(x, w)

        with torch.no_grad():
            out = fn(x, w).cpu()

        ref = F.conv_transpose2d(x_cpu, w_cpu)
        assert out.shape == ref.shape, f"unexpected shape: {out.shape}"
        torch.testing.assert_close(out, ref, rtol=1e-4, atol=1e-4)

    def test_conv2d_groups_gt_1_falls_back_no_crash(self):
        """Non-depthwise grouped conv (e.g. groups=2 in_channels=6 out=4)
        matches CPU via per-group conv2d decomposition (M6 Phase 2)."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        x_cpu = torch.randn(1, 6, 8, 8)
        w_cpu = torch.randn(4, 3, 3, 3)
        x = x_cpu.to("vulkan:0")
        w = w_cpu.to("vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv2d(x, w, groups=2)

        with torch.no_grad():
            out = fn(x, w).cpu()

        ref = F.conv2d(x_cpu, w_cpu, groups=2)
        assert out.shape == ref.shape, f"unexpected shape: {out.shape}"
        torch.testing.assert_close(out, ref, rtol=1e-4, atol=1e-4)

    # ═══════════════════════════════════════════════════════════════════
    # M6 Phase 2 — Depthwise/grouped conv2d tests
    # ═══════════════════════════════════════════════════════════════════

    def test_m6_depthwise_conv_matches_cpu(self):
        """M6 Phase 2: Depthwise conv2d (groups=C_in=C_out) matches CPU.

        MobileNet-style depthwise conv: each input channel is filtered
        independently by its own 3×3 kernel. Decomposed to per-group
        im2col+mm via the conv_im2col FX pattern."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        for C in [4, 8, 16]:
            for k in [1, 3]:
                x_cpu = torch.randn(2, C, 14, 14)
                w_cpu = torch.randn(C, 1, k, k)
                x = x_cpu.to("vulkan:0")
                w = w_cpu.to("vulkan:0")

                @torch.compile(backend="inductor")
                def fn(x, w):
                    return F.conv2d(x, w, groups=C, padding=k // 2)

                with torch.no_grad():
                    out = fn(x, w).cpu()

                ref = F.conv2d(x_cpu, w_cpu, groups=C, padding=k // 2)
                torch.testing.assert_close(
                    out,
                    ref,
                    rtol=1e-4,
                    atol=1e-4,
                    msg=f"depthwise conv mismatch: C={C}, k={k}",
                )

    def test_m6_grouped_conv_matches_cpu(self):
        """M6 Phase 2: Grouped conv2d (groups=4, C_in=8, C_out=8) matches CPU.

        Grouped convolution splits input/output channels into groups;
        each group dispatches a group-1 ``conv2d_with_optional_bias``
        call through the ``slang_conv2d`` template (no as_strided)."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        x_cpu = torch.randn(2, 8, 16, 16)
        w_cpu = torch.randn(8, 2, 3, 3)  # C_out=8, C_in_per_g=2, groups=4
        x = x_cpu.to("vulkan:0")
        w = w_cpu.to("vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv2d(x, w, groups=4, padding=1)

        with torch.no_grad():
            out = fn(x, w).cpu()

        ref = F.conv2d(x_cpu, w_cpu, groups=4, padding=1)
        torch.testing.assert_close(out, ref, rtol=1e-4, atol=1e-4)

    def test_m6_depthwise_conv_backward_matches_cpu(self):
        """M6 Phase 2: Depthwise conv2d backward matches CPU.

        The backward pass flows through standard autograd on the
        per-group conv2d decomposition (groups=1 per group), routing
        through the CG.M6 conv2d backward template. Verifies that
        grad_input and grad_weight match CPU reference."""
        import torch.nn.functional as F

        torch._dynamo.reset()
        C = 8
        x_cpu = torch.randn(1, C, 16, 16, requires_grad=True)
        w_cpu = torch.randn(C, 1, 3, 3, requires_grad=True)

        def _run(x, w):
            y = F.conv2d(x, w, groups=C, padding=1)
            loss = y.sum()
            loss.backward()
            return x.grad.clone(), w.grad.clone()

        gx_ref, gw_ref = _run(x_cpu, w_cpu)

        x = x_cpu.detach().to("vulkan:0").requires_grad_(True)
        w = w_cpu.detach().to("vulkan:0").requires_grad_(True)

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.conv2d(x, w, groups=C, padding=1).sum()

        y = fn(x, w)
        y.backward()

        torch.testing.assert_close(x.grad.cpu(), gx_ref, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(w.grad.cpu(), gw_ref, rtol=1e-3, atol=1e-3)


class TestMatmulEpiloguePattern:
    """T4.1 — Verify the matmul_epilogue pattern annotates matmul nodes with
    ``vulkan_epilogue`` metadata for IPointwise template dispatch, and that
    the fused matmul+pointwise graph produces correct output.

    The pattern matches ``pointwise(mm/addmm/bmm(args))`` subgraphs where the
    pointwise op is in ``POINTWISE_TABLE``.  Matched pointwise nodes are folded
    into the matmul via ``vulkan_epilogue`` metadata; the scheduler can then
    emit a single fused matmul+epilogue kernel.
    """

    _BUG_ROOT_COMPONENT = "fx-passes"

    def test_epilogue_annotation_on_mm_node(self):
        """Apply matmul_epilogue pattern to gelu(mm(a, w)): the mm node
        must gain ``vulkan_epilogue="OpGELU"`` and ``vulkan_fused=True``
        metadata, and the gelu node must be erased."""
        import torch
        import torch_vulkan.inductor  # noqa: F401 — registers patterns
        from torch_vulkan.inductor.fx_passes.patterns.registry import (
            FX_PATTERN_REGISTRY,
        )

        graph = torch.fx.Graph()
        a = graph.placeholder("a")
        a.meta["val"] = torch.randn(8, 64)
        w = graph.placeholder("w")
        w.meta["val"] = torch.randn(64, 128)
        mm = graph.call_function(torch.ops.aten.mm.default, args=(a, w))
        mm.meta["val"] = torch.randn(8, 128)
        gelu_p = graph.call_function(torch.ops.aten.gelu, args=(mm,))
        gelu_p.meta["val"] = torch.randn(8, 128)
        graph.output(gelu_p)
        gm = torch.fx.GraphModule(torch.nn.Module(), graph)

        FX_PATTERN_REGISTRY.apply_all(gm)

        assert mm.meta.get("vulkan_epilogue") == "OpGELU", (
            f"expected vulkan_epilogue='OpGELU' on mm node, "
            f"got {mm.meta.get('vulkan_epilogue')!r}"
        )
        assert mm.meta.get("vulkan_fused") is True
        # gelu node must be erased (uses replaced with mm)
        assert all(n.target is not torch.ops.aten.gelu for n in gm.graph.nodes), (
            "gelu node should be erased after epilogue fusion"
        )

    def test_epilogue_annotation_with_default_suffix(self):
        """Apply matmul_epilogue pattern with Dynamo-style ``.default``
        suffix targets (e.g. ``aten.relu.default``).  The pattern must strip
        the overload suffix before looking up POINTWISE_TABLE."""
        import torch
        import torch_vulkan.inductor  # noqa: F401 — registers patterns
        from torch_vulkan.inductor.fx_passes.patterns.registry import (
            FX_PATTERN_REGISTRY,
        )

        graph = torch.fx.Graph()
        a = graph.placeholder("a")
        a.meta["val"] = torch.randn(8, 64)
        w = graph.placeholder("w")
        w.meta["val"] = torch.randn(64, 128)
        mm = graph.call_function(torch.ops.aten.mm.default, args=(a, w))
        mm.meta["val"] = torch.randn(8, 128)
        # Dynamo produces aten.relu.default, not aten.relu
        relu_p = graph.call_function(torch.ops.aten.relu.default, args=(mm,))
        relu_p.meta["val"] = torch.randn(8, 128)
        graph.output(relu_p)
        gm = torch.fx.GraphModule(torch.nn.Module(), graph)

        FX_PATTERN_REGISTRY.apply_all(gm)

        assert mm.meta.get("vulkan_epilogue") == "OpReLU", (
            f"expected vulkan_epilogue='OpReLU' on mm node, "
            f"got {mm.meta.get('vulkan_epilogue')!r}"
        )
        assert mm.meta.get("vulkan_fused") is True
        assert all(
            n.target is not torch.ops.aten.relu.default for n in gm.graph.nodes
        ), "relu node should be erased after epilogue fusion"

    def test_epilogue_annotation_skips_non_pointwise(self):
        """A non-pointwise op (e.g. view) following a matmul must NOT be
        matched — the epilogue pattern only fires for POINTWISE_TABLE ops."""
        import torch
        import torch_vulkan.inductor  # noqa: F401 — registers patterns
        from torch_vulkan.inductor.fx_passes.patterns.registry import (
            FX_PATTERN_REGISTRY,
        )

        graph = torch.fx.Graph()
        a = graph.placeholder("a")
        a.meta["val"] = torch.randn(8, 64)
        w = graph.placeholder("w")
        w.meta["val"] = torch.randn(64, 128)
        mm = graph.call_function(torch.ops.aten.mm.default, args=(a, w))
        mm.meta["val"] = torch.randn(8, 128)
        view_p = graph.call_function(torch.ops.aten.view.default, args=(mm, [8, 128]))
        view_p.meta["val"] = torch.randn(8, 128)
        graph.output(view_p)
        gm = torch.fx.GraphModule(torch.nn.Module(), graph)

        FX_PATTERN_REGISTRY.apply_all(gm)

        assert mm.meta.get("vulkan_epilogue") is None, (
            "view is not a pointwise op; mm should NOT be annotated"
        )

    def test_linear_relu_correctness(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return F.relu(F.linear(x, w, b))

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(64, 32, device="vulkan:0")
        b = torch.randn(64, device="vulkan:0")
        y = fn(x, w, b)
        ref = F.relu(F.linear(x.cpu(), w.cpu(), b.cpu()))
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-2, atol=1e-2)

