class TestPostAttentionResidual:
    """P2.5 baseline: `linear(x) + residual` correctness + dispatch
    accounting. Common transformer post-attention pattern. The
    `bias_dropout_residual` fusion is unimplemented — this locks the
    baseline so when the FX pass lands, the dispatch-count target tightens
    visibly."""

    def test_linear_add_residual_correctness(self):
        @torch.compile(backend="inductor")
        def fn(x, w, b, residual):
            return torch.nn.functional.linear(x, w, b) + residual

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(32, 32, device="vulkan:0")
        b = torch.randn(32, device="vulkan:0")
        residual = torch.randn(4, 32, device="vulkan:0")
        y = fn(x, w, b, residual)
        ref = torch.nn.functional.linear(x.cpu(), w.cpu(), b.cpu()) + residual.cpu()
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-2, atol=1e-3)

    def test_linear_add_residual_dispatch_count(self):
        import torch_vulkan

        torch_vulkan._c_ext._reset_perf_counters()

        @torch.compile(backend="inductor")
        def fn(x, w, b, residual):
            return torch.nn.functional.linear(x, w, b) + residual

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(32, 32, device="vulkan:0")
        b = torch.randn(32, device="vulkan:0")
        residual = torch.randn(4, 32, device="vulkan:0")
        fn(x, w, b, residual)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(x, w, b, residual)
        torch_vulkan._c_ext._synchronize(0)
        n = torch_vulkan._c_ext._get_dispatch_count()
        # 3 dispatches today (addmm + extra ops). Target ≤2 once
        # the bias_dropout_residual fusion lands.
        assert n <= 3, f"expected ≤3 dispatches, got {n}"


class TestGeluDropoutBaseline:
    """P2.5 baseline: `gelu(x).dropout(p)` correctness. Dispatch
    expectation depends on p=0 vs p>0; lock the p=0 deterministic case."""

    def test_gelu_dropout_zero_correctness(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(x):
            return F.dropout(F.gelu(x), p=0.0, training=False)

        x = torch.randn(4, 64, device="vulkan:0")
        y = fn(x)
        ref = F.gelu(x.cpu())
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-4)

    def test_gelu_dropout_zero_dispatch_count(self):
        import torch.nn.functional as F
        import torch_vulkan

        torch_vulkan._c_ext._reset_perf_counters()

        @torch.compile(backend="inductor")
        def fn(x):
            return F.dropout(F.gelu(x), p=0.0, training=False)

        x = torch.randn(4, 64, device="vulkan:0")
        fn(x)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(x)
        torch_vulkan._c_ext._synchronize(0)
        n = torch_vulkan._c_ext._get_dispatch_count()
        # p=0 + training=False is identity dropout — should fuse with gelu
        # into 1 dispatch.
        assert n <= 1, f"expected 1 dispatch, got {n}"


class TestEmbeddingLayerNormBaseline:
    """P2.5: `embedding + layer_norm` correctness baseline + dispatch count
    for the future fusion pass that folds the embedding load into the LN
    sum-of-squares pass."""

    def test_embedding_layer_norm_correctness(self):
        @torch.compile(backend="inductor")
        def fn(weight, idx, ln_weight, ln_bias):
            x = torch.nn.functional.embedding(idx, weight)
            return torch.nn.functional.layer_norm(x, [16], ln_weight, ln_bias)

        weight = torch.randn(32, 16, device="vulkan:0")
        idx = torch.tensor([1, 2, 3], device="vulkan:0", dtype=torch.long)
        ln_w = torch.randn(16, device="vulkan:0")
        ln_b = torch.randn(16, device="vulkan:0")
        y = fn(weight, idx, ln_w, ln_b)
        ref = torch.nn.functional.layer_norm(
            torch.nn.functional.embedding(idx.cpu(), weight.cpu()),
            [16],
            ln_w.cpu(),
            ln_b.cpu(),
        )
        torch.testing.assert_close(y.cpu(), ref, rtol=1e-3, atol=1e-4)


