class TestForeachAudit:
    """P10: `_foreach_*` combo-kernel coverage audit. After P1.4 re-enabled
    `BackendFeature.FOREACH` and shipped the combo rewrite, audit which
    ops fuse. `_foreach_add`, `_foreach_mul`, `_foreach_addcmul` all
    collapse to 1 combo dispatch."""

    def _two_lists(self):
        return (
            torch.randn(8, device="vulkan:0"),
            torch.randn(8, device="vulkan:0"),
            torch.randn(8, device="vulkan:0"),
            torch.randn(8, device="vulkan:0"),
        )

    def test_foreach_add_one_dispatch(self):
        import torch_vulkan as _tv

        a, b, c, d = self._two_lists()

        @torch.compile(backend="inductor")
        def fn(a, b, c, d):
            return torch._foreach_add([a, b], [c, d])

        fn(a, b, c, d)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b, c, d)
        d_disp = _tv._c_ext._get_dispatch_count()
        assert d_disp <= 1, f"_foreach_add expected ≤1 dispatch, got {d_disp}"
        torch.testing.assert_close(
            out[0].cpu(), a.cpu() + c.cpu(), rtol=1e-5, atol=1e-5
        )
        torch.testing.assert_close(
            out[1].cpu(), b.cpu() + d.cpu(), rtol=1e-5, atol=1e-5
        )

