class TestSpecialOpsOverrides:
    """P10: `xlogy` / `xlog1py` (and `special_*` aliases) compile via the
    `VulkanOverrides` snippets — fall through to the eager backend when
    Inductor lowers them, and produce numerically correct values vs CPU
    eager. The `0 * log(0)` and `0 * log1p(-1)` corner cases must return
    0, not NaN."""

    def test_xlogy_correctness_and_zero_corner(self):
        @torch.compile(backend="inductor")
        def fn(x, y):
            return torch.xlogy(x, y)

        x = torch.tensor([0.0, 1.0, 2.0, 3.0], device="vulkan:0")
        y = torch.tensor([0.0, 2.0, 0.0, 4.0], device="vulkan:0")
        result = fn(x, y).cpu()
        expected = torch.xlogy(x.cpu(), y.cpu())
        torch.testing.assert_close(result, expected, rtol=1e-5, atol=1e-5)

    def test_xlog1py_correctness_and_zero_corner(self):
        @torch.compile(backend="inductor")
        def fn(x, y):
            return torch.special.xlog1py(x, y)

        x = torch.tensor([0.0, 1.0, 2.0, 3.0], device="vulkan:0")
        y = torch.tensor([-1.0, 0.5, -1.0, 1.0], device="vulkan:0")
        result = fn(x, y).cpu()
        expected = torch.special.xlog1py(x.cpu(), y.cpu())
        torch.testing.assert_close(result, expected, rtol=1e-5, atol=1e-5)


