    def test_kl_div_correctness(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(input, target):
            return F.kl_div(input, target, reduction="sum", log_target=False)

        # input is log-probability, target is probability per the API contract.
        target = torch.softmax(torch.randn(8, 16, device="vulkan:0"), dim=-1)
        input = torch.log_softmax(torch.randn(8, 16, device="vulkan:0"), dim=-1)
