class TestLayerNormBackwardLowering:
    """P0.1 — `aten.native_layer_norm_backward` decomposed into pointwise +
    reductions so Inductor fuses the inner-axis reductions
    (`sum(grad_x_hat)`, `sum(grad_x_hat * x_hat)`) into one kernel and the
    outer-axis grad_w/grad_b reductions into a second.

    Direct invocation under `torch.compile` (not via AOT autograd) so this
    test exercises the lowering today — does not depend on the P0.0
    backward-graph compile blocker.
    """

    def _run(self, shape, normalized_shape, expected_dispatches):
        import torch_vulkan

        x = torch.randn(*shape, device="vulkan:0")
        weight = torch.randn(*normalized_shape, device="vulkan:0")
        bias = torch.randn(*normalized_shape, device="vulkan:0")
        gout = torch.randn(*shape, device="vulkan:0")
        out, mean, rstd = torch.ops.aten.native_layer_norm.default(
            x, normalized_shape, weight, bias, 1e-5
        )
        ns = normalized_shape

        @torch.compile(backend="inductor", dynamic=False)
        def fn(grad_out, inp, mean, rstd, w, b):
            return torch.ops.aten.native_layer_norm_backward.default(
                grad_out, inp, ns, mean, rstd, w, b, [True, True, True]
            )

        # warm + measure
        fn(gout, x, mean, rstd, weight, bias)
        torch_vulkan._c_ext._reset_perf_counters()
        gi, gw, gb = fn(gout, x, mean, rstd, weight, bias)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= expected_dispatches, (
            f"layer_norm_backward shape={shape} ns={ns}: "
            f"expected ≤{expected_dispatches} dispatches, got {d}"
        )

        gi_cpu, gw_cpu, gb_cpu = torch.ops.aten.native_layer_norm_backward.default(
            gout.cpu(),
            x.cpu(),
            ns,
            mean.cpu(),
            rstd.cpu(),
            weight.cpu(),
            bias.cpu(),
            [True, True, True],
        )
        torch.testing.assert_close(gi.cpu(), gi_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gw.cpu(), gw_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gb.cpu(), gb_cpu, rtol=1e-3, atol=1e-3)

    def test_2d_input_dispatch_count(self):
        self._run((16, 64), [64], expected_dispatches=3)

    def test_3d_input_dispatch_count(self):
        self._run((4, 8, 32), [32], expected_dispatches=3)

    def test_multidim_normalized_shape(self):
        self._run((2, 4, 16), [4, 16], expected_dispatches=3)


class TestGroupNormBackwardLowering:
    """P0.1 — `aten.native_group_norm_backward` lowering.

    Upstream decomp produces ~37 dispatches on Vulkan (per-group divisions
    fall through to extern `aten.div.Tensor` + `torch.ones` materialization
    pattern). Our lowering folds the `1/(HxW * cpg)` factor into
    `mul.Scalar` and skips the `ones` constant in the no-gamma path,
    collapsing to ≤5 dispatches.

    Direct invocation under `torch.compile`; does not depend on P0.0
    backward-graph compile.
    """

    def _run(self, N, C, H, W, ngroups, expected_dispatches):
        import torch_vulkan

        x = torch.randn(N, C, H, W, device="vulkan:0")
        weight = torch.randn(C, device="vulkan:0")
        bias = torch.randn(C, device="vulkan:0")
        gout = torch.randn(N, C, H, W, device="vulkan:0")
        out, mean, rstd = torch.ops.aten.native_group_norm.default(
            x, weight, bias, N, C, H * W, ngroups, 1e-5
        )
        # Eager Vulkan returns mean/rstd as flat (M,); reshape to (N, group)
        # so the backward op's shape check passes.
        mean = mean.reshape(N, ngroups)
        rstd = rstd.reshape(N, ngroups)

        @torch.compile(backend="inductor", dynamic=False)
        def fn(grad_out, inp, mean, rstd, w):
            return torch.ops.aten.native_group_norm_backward.default(
                grad_out,
                inp,
                mean,
                rstd,
                w,
                N,
                C,
                H * W,
                ngroups,
                [True, True, True],
            )

        fn(gout, x, mean, rstd, weight)
        torch_vulkan._c_ext._reset_perf_counters()
        gi, gw, gb = fn(gout, x, mean, rstd, weight)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= expected_dispatches, (
            f"group_norm_backward N={N} C={C} HxW={H * W} groups={ngroups}: "
            f"expected ≤{expected_dispatches} dispatches, got {d}"
        )

        gi_cpu, gw_cpu, gb_cpu = torch.ops.aten.native_group_norm_backward.default(
            gout.cpu(),
            x.cpu(),
            mean.cpu(),
            rstd.cpu(),
            weight.cpu(),
            N,
            C,
            H * W,
            ngroups,
            [True, True, True],
        )
        torch.testing.assert_close(gi.cpu(), gi_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gw.cpu(), gw_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gb.cpu(), gb_cpu, rtol=1e-3, atol=1e-3)

    def test_small_dispatch_count(self):
        self._run(2, 8, 4, 4, ngroups=2, expected_dispatches=5)

    def test_resnet_block_shape(self):
        self._run(4, 16, 8, 8, ngroups=4, expected_dispatches=5)


class TestGroupNormModuleBackward:
    """GroupNorm backward via ``nn.GroupNorm`` module under ``torch.compile``.

    Verifies that the full forward+backward path through the user-facing
    ``nn.GroupNorm`` module produces gradients matching CPU (autograd).
    """

    def test_group_norm_backward_matches_cpu(self):
        """GroupNorm backward gradients match CPU via nn.GroupNorm module."""
        N, C, H, W = 2, 8, 16, 16
        num_groups = 4

        gn_cpu = torch.nn.GroupNorm(num_groups, C)
        gn_vk = copy.deepcopy(gn_cpu).vulkan()

        x_cpu = torch.randn(N, C, H, W, requires_grad=True)
        x_vk = x_cpu.detach().clone().to("vulkan:0").requires_grad_(True)

        @torch.compile(backend="inductor")
        def fn(x):
            return gn_vk(x)

        out_cpu = gn_cpu(x_cpu)
        out_vk = fn(x_vk)

        loss_cpu = out_cpu.sum()
        loss_vk = out_vk.sum()
        loss_cpu.backward()
        loss_vk.backward()

        torch.testing.assert_close(
            out_vk.cpu(),
            out_cpu.detach(),
            rtol=1e-4,
            atol=1e-4,
            msg="GroupNorm forward mismatch",
        )
        torch.testing.assert_close(
            x_vk.grad.cpu(),
            x_cpu.grad,
            rtol=1e-4,
            atol=1e-3,
            msg="GroupNorm input grad mismatch",
        )
        torch.testing.assert_close(
            gn_vk.weight.grad.cpu(),
            gn_cpu.weight.grad,
            rtol=1e-4,
            atol=1e-3,
            msg="GroupNorm weight grad mismatch",
        )
        torch.testing.assert_close(
            gn_vk.bias.grad.cpu(),
            gn_cpu.bias.grad,
            rtol=1e-4,
            atol=1e-3,
            msg="GroupNorm bias grad mismatch",
        )


class TestP12ShapeAndLinalgCoverage:
    """P12 — Extended primop coverage round 2.

    Measurement-driven coverage lock — these aten ops compile cleanly through
    Inductor's stock decomposition + Vulkan codegen and don't need a
    Vulkan-specific lowering. Each test asserts ≤N dispatches + correctness vs
    CPU eager so a future regression that pushes them back to extern fires.
    """

    def test_linalg_cross_one_dispatch(self):
        """`torch.linalg.cross` on 3-vectors compiles to 1 dispatch via stock
        pointwise codegen (the cross product is 6 scalar mul/sub ops on
        broadcast slices)."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return torch.linalg.cross(a, b, dim=-1) + 1.0

        a = torch.randn(3, device="vulkan:0")
        b = torch.randn(3, device="vulkan:0")
        fn(a, b)
        fn(a, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"linalg.cross+1 expected ≤1 dispatch, got {d}"
        expected = torch.linalg.cross(a.cpu(), b.cpu(), dim=-1) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_kron_correctness(self):
        """`torch.kron` (Kronecker product) compiles via stock broadcast +
        reshape + pointwise codegen. Verifies correctness; dispatch count is a
        function of the broadcast pattern (≤4 today, may tighten later)."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return torch.kron(a, b) + 1.0

        a = torch.randn(4, device="vulkan:0")
        b = torch.randn(4, device="vulkan:0")
        fn(a, b)
        fn(a, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 4, f"kron+1 expected ≤4 dispatches, got {d}"
        expected = torch.kron(a.cpu(), b.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_narrow_correctness(self):
        """`Tensor.narrow` is a stride-only view + 1 pointwise epilogue."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return x.narrow(0, 1, 3) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 2, f"narrow+1 expected ≤2 dispatches, got {d}"
        expected = x.cpu().narrow(0, 1, 3) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_swapdims_correctness(self):
        """`torch.swapdims` is a stride-only transpose + pointwise epilogue."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.swapdims(x, 0, 1) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 2, f"swapdims+1 expected ≤2 dispatches, got {d}"
        expected = torch.swapdims(x.cpu(), 0, 1) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_atleast_1d_one_dispatch(self):
        """`torch.atleast_1d` on a 1-D tensor is identity + the +1.0 epilogue."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.atleast_1d(x) + 1.0

        x = torch.randn(8, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"atleast_1d+1 expected ≤1 dispatch, got {d}"
        torch.testing.assert_close(
            out.cpu(), torch.atleast_1d(x.cpu()) + 1.0, rtol=1e-5, atol=1e-5
        )

    def test_block_diag_one_dispatch(self):
        """`torch.block_diag(a, b) + 1.0` compiles to 1 dispatch — Inductor
        emits a single output kernel that conditionally copies from each input
        block based on the index."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return torch.block_diag(a, b) + 1.0

        a = torch.randn(2, 3, device="vulkan:0")
        b = torch.randn(2, 2, device="vulkan:0")
        fn(a, b)
        fn(a, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"block_diag+1 expected ≤1 dispatch, got {d}"
        torch.testing.assert_close(
            out.cpu(),
            torch.block_diag(a.cpu(), b.cpu()) + 1.0,
            rtol=1e-5,
            atol=1e-5,
        )

    def test_chunk_one_dispatch(self):
        """`torch.chunk(x, 2)` produces stride+offset views; reducing them
        back together is 1 fused pointwise dispatch."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            c0, c1 = torch.chunk(x, 2)
            return c0 + c1

        x = torch.randn(8, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"chunk+sum expected ≤1 dispatch, got {d}"
        c0, c1 = torch.chunk(x.cpu(), 2)
        torch.testing.assert_close(out.cpu(), c0 + c1, rtol=1e-5, atol=1e-5)

    def test_diff_correctness(self):
        """`torch.diff(x) + 1.0` compiles via stock view+sub+pointwise on
        Vulkan. Currently 4 dispatches — could tighten with a dedicated
        lowering, but correctness is locked."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.diff(x) + 1.0

        x = torch.randn(8, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 4, f"diff+1 expected ≤4 dispatches, got {d}"
        torch.testing.assert_close(
            out.cpu(),
            torch.diff(x.cpu()) + 1.0,
            rtol=1e-5,
            atol=1e-5,
        )


class TestP12HyperbolicAndSpecialPointwise:
    """P12 — hyperbolic + special-pointwise coverage. Locks 1-dispatch contract
    on chains of `tanh/atanh/sinh/cosh/asinh/acosh/expm1/log1p/frexp/where`."""

    def test_tanh_atanh_chain_one_dispatch(self):
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.tanh(x) + torch.atanh(torch.tanh(x) * 0.5)

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"tanh/atanh chain expected ≤1 dispatch, got {d}"
        expected = torch.tanh(x.cpu()) + torch.atanh(torch.tanh(x.cpu()) * 0.5)
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_sinh_cosh_asinh_acosh_chain_one_dispatch(self):
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return (
                torch.sinh(x)
                + torch.cosh(x)
                + torch.asinh(x)
                + torch.acosh(torch.abs(x) + 1.0)
            )

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"sinh/cosh/asinh/acosh chain expected ≤1 dispatch, got {d}"
        expected = (
            torch.sinh(x.cpu())
            + torch.cosh(x.cpu())
            + torch.asinh(x.cpu())
            + torch.acosh(torch.abs(x.cpu()) + 1.0)
        )
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_frexp_one_dispatch(self):
        """`torch.frexp` returns (mantissa, exponent); the exp+frexp chain
        compiles to 1 dispatch via stock multi-output pointwise codegen."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            m, e = torch.frexp(x)
            return m + e.float()

        x = torch.randn(8, 16, device="vulkan:0").abs() + 0.1
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"frexp+add expected ≤1 dispatch, got {d}"
        m, e = torch.frexp(x.cpu())
        torch.testing.assert_close(out.cpu(), m + e.float(), rtol=0, atol=0)

    def test_nested_where_one_dispatch(self):
        """Nested `where(cond1, where(cond2, a, b), c)` collapses to 1 dispatch
        via stock branchless codegen."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, y):
            return torch.where(x > 0, torch.where(y > 0, x * y, x), -x)

        x = torch.randn(8, 16, device="vulkan:0")
        y = torch.randn(8, 16, device="vulkan:0")
        fn(x, y)
        fn(x, y)
        _tv._c_ext._reset_perf_counters()
        out = fn(x, y)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"nested-where expected ≤1 dispatch, got {d}"
        expected = torch.where(
            x.cpu() > 0, torch.where(y.cpu() > 0, x.cpu() * y.cpu(), x.cpu()), -x.cpu()
        )
        torch.testing.assert_close(out.cpu(), expected, rtol=0, atol=0)

    def test_expm1_log1p_chain_one_dispatch(self):
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.expm1(x) + torch.log1p(torch.abs(x))

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"expm1/log1p chain expected ≤1 dispatch, got {d}"
        expected = torch.expm1(x.cpu()) + torch.log1p(torch.abs(x.cpu()))
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_topk_sum_correctness(self):
        """`topk(x, k).values.sum()`: N.2 — BackendFeature.SORT enabled with
        bitonic-sort shader for `k ≤ 1024`. Locks correctness."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.topk(x, k=4, dim=-1)[0].sum()

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 10, f"topk-sum expected ≤10 dispatches, got {d}"
        torch.testing.assert_close(
            out.cpu(),
            torch.topk(x.cpu(), k=4, dim=-1)[0].sum(),
            rtol=1e-3,
            atol=1e-3,
        )


class TestP12ActivationAndNormChains:
    """P12 — activation / normalization / softmax fused-chain coverage. These
    high-value patterns (commonly found in transformer / CNN models) all
    collapse to a small constant dispatch count via stock pointwise +
    reduction codegen on Vulkan. Locks the contract so any future codegen
    change that breaks the fusion fires here."""

    def test_nine_activation_chain_one_dispatch(self):
        """`gelu+silu+mish+hardswish+hardsigmoid+leaky_relu+elu+relu6+softplus`
        all fuse into a single VulkanKernel dispatch."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return (
                F.gelu(x)
                + F.silu(x)
                + F.mish(x)
                + F.hardswish(x)
                + F.hardsigmoid(x)
                + F.leaky_relu(x)
                + F.elu(x)
                + F.relu6(x)
                + F.softplus(x)
            )

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"9-activation chain expected ≤1 dispatch, got {d}"
        expected = (
            F.gelu(x.cpu())
            + F.silu(x.cpu())
            + F.mish(x.cpu())
            + F.hardswish(x.cpu())
            + F.hardsigmoid(x.cpu())
            + F.leaky_relu(x.cpu())
            + F.elu(x.cpu())
            + F.relu6(x.cpu())
            + F.softplus(x.cpu())
        )
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_softmax_plus_logsoftmax_exp_one_dispatch(self):
        """`softmax(x) + log_softmax(x).exp()` collapses to 1 dispatch — both
        paths share the row-reduction (amax + sumexp) and the divide / subtract
        epilogues fuse."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return F.softmax(x, dim=-1) + F.log_softmax(x, dim=-1).exp()

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"softmax+log_softmax.exp expected ≤1 dispatch, got {d}"
        expected = F.softmax(x.cpu(), dim=-1) + F.log_softmax(x.cpu(), dim=-1).exp()
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_rsqrt_var_rmsnorm_shape_one_dispatch(self):
        """`rsqrt(var(x) + eps) * x` is the RMSNorm core; collapses to 1
        dispatch via stock pointwise + reduction codegen."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.rsqrt(x.var(dim=-1, keepdim=True) + 1e-5) * x

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"rsqrt(var)*x expected ≤1 dispatch, got {d}"
        expected = torch.rsqrt(x.cpu().var(dim=-1, keepdim=True) + 1e-5) * x.cpu()
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_f_layer_norm_two_dispatches(self):
        """`F.layer_norm(x, (D,), w, b) + 1.0` compiles to 2 dispatches via
        the existing `native_layer_norm` Inductor lowering (mean+var reduce,
        affine + epilogue). Locks the contract; tightening to 1 dispatch
        would require fusing the affine into the reduction kernel."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return F.layer_norm(x, (16,), w, b) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        w = torch.randn(16, device="vulkan:0")
        b = torch.randn(16, device="vulkan:0")
        fn(x, w, b)
        fn(x, w, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(x, w, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 2, f"F.layer_norm+1 expected ≤2 dispatches, got {d}"
        expected = F.layer_norm(x.cpu(), (16,), w.cpu(), b.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)


class TestP12ReductionAndIndexingChains:
    """P12 — reduction + indexing fused-chain coverage."""

    def test_var_std_chain_one_dispatch(self):
        import torch_vulkan as _tv

