    def test_two_layer_mlp_gelu_correctness(self):
        """`linear(gelu(linear(x))) ` — PF.5 takes 5→4 dispatches via
        addmm_gelu_fused; PF-D2.1 will close the remaining gap to 3."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, w1, b1, w2, b2):
            return F.linear(F.gelu(F.linear(x, w1, b1)), w2, b2)

        x = torch.randn(8, 16, device="vulkan:0")
