class TestP12ConvVariantsAndAdvanced:
    """P12 — depthwise/1×1 conv, scatter_add, where+reduce, bias-less linear."""

    def test_depthwise_conv2d(self):
        """Depthwise conv (`groups == in_ch`): 5 dispatches today; will tighten
        once the §P5.1 depthwise template lands."""
        import torch.nn.functional as F
