    def test_scatter_add_with_epilogue(self):
        """`base.scatter_add(1, idx, src) * 2.0` — 3 dispatches via
        atomic-add codegen + pointwise epilogue."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(base, idx, src):
            return base.scatter_add(1, idx, src) * 2.0

        src = torch.randn(8, 4, device="vulkan:0")
        base = torch.zeros(8, 16, device="vulkan:0")
        idx = torch.randint(0, 16, (8, 4), device="vulkan:0", dtype=torch.int64)
        fn(base, idx, src)
        fn(base, idx, src)
        _tv._c_ext._reset_perf_counters()
        out = fn(base, idx, src)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 3, f"scatter_add+mul expected ≤3 dispatches, got {d}"
        expected = base.cpu().scatter_add(1, idx.cpu(), src.cpu()) * 2.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    @pytest.mark.skip(
        reason=(
            "PF.30.h: Inductor's tuned_mm autotune harness is Triton-only "
            "(autotune_process.benchmark_in_sub_process), so it raises "
            "'Torch not compiled with CUDA enabled' on this Vulkan/CPU build "
            "via the GPUDeviceBenchmarkMixin's CUDA-default fallback. "
            "Tracked as PF-D2 autotune (needs Vulkan-aware autotune harness)."
        )
    )
    def test_two_layer_linear_no_bias(self):
        """`linear(relu(linear(x))) ` no bias — 5 dispatches via 2 mm extern
        + 1 fused relu epilogue + alloc/marshal."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, w1, w2):
            return F.linear(F.relu(F.linear(x, w1)), w2)

        x = torch.randn(8, 16, device="vulkan:0")
        w1 = torch.randn(32, 16, device="vulkan:0")
        w2 = torch.randn(4, 32, device="vulkan:0")
        fn(x, w1, w2)
        fn(x, w1, w2)
        _tv._c_ext._reset_perf_counters()
        out = fn(x, w1, w2)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 5, f"2-layer no-bias MLP expected ≤5 dispatches, got {d}"
        expected = F.linear(F.relu(F.linear(x.cpu(), w1.cpu())), w2.cpu())
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-4, atol=1e-4)

    def test_where_with_reduction_one_dispatch(self):
        """`where(x > t, zeros, x).sum(dim=-1)` — 1 dispatch (where + reduce)."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.where(x > 0.5, torch.zeros_like(x), x).sum(dim=-1)

        a = torch.randn(8, 16, device="vulkan:0")
        fn(a)
        fn(a)
        _tv._c_ext._reset_perf_counters()
        out = fn(a)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"where+reduce expected ≤1 dispatch, got {d}"
        expected = torch.where(a.cpu() > 0.5, torch.zeros_like(a.cpu()), a.cpu()).sum(
            dim=-1
        )
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)


