class TestP12PointwiseRoundTwo:
    """P12 — extended pointwise primop coverage round 2.

    Measurement-driven coverage lock — `nan_to_num`, `logit`, `logaddexp`,
    `logaddexp2`, `sgn`, `real` (real-input passthrough), `heaviside`,
    `float_power` all compile via Inductor's stock decomposition + Vulkan
    pointwise codegen with no Vulkan-specific lowering needed. Each test
    asserts ≤N dispatches + correctness vs CPU eager so a future regression
    that pushes any of them back to extern fires.
    """

    def test_nan_to_num_one_dispatch(self):
        """`torch.nan_to_num(x, 0.0) + 1` — 1 dispatch via stock isnan/isinf
        + where-replace + epilogue codegen."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.nan_to_num(x, 0.0) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"nan_to_num+1 expected ≤1 dispatch, got {d}"
        expected = torch.nan_to_num(x.cpu(), 0.0) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_logit_one_dispatch(self):
        """`torch.logit(x.sigmoid(), eps=1e-6) + 1` — 1 dispatch via stock
        clamp + log + log1p decomposition."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.logit(x.sigmoid(), eps=1e-6) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"logit+1 expected ≤1 dispatch, got {d}"
        expected = torch.logit(x.cpu().sigmoid(), eps=1e-6) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-4, atol=1e-4)

    def test_logaddexp_one_dispatch(self):
        """`torch.logaddexp(x, y) + 1` — numerically-stable log(exp(x)+exp(y))
        decomposes to `max(x,y) + log1p(exp(-|x-y|))` and pointwise-fuses to
        1 dispatch."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, y):
            return torch.logaddexp(x, y) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        y = torch.randn(8, 16, device="vulkan:0")
        fn(x, y)
        fn(x, y)
        _tv._c_ext._reset_perf_counters()
        out = fn(x, y)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"logaddexp+1 expected ≤1 dispatch, got {d}"
        expected = torch.logaddexp(x.cpu(), y.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_logaddexp2_one_dispatch(self):
        """`torch.logaddexp2(x, y) + 1` — base-2 sibling of logaddexp; same
        stable decomposition pattern, 1 dispatch."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, y):
            return torch.logaddexp2(x, y) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        y = torch.randn(8, 16, device="vulkan:0")
        fn(x, y)
        fn(x, y)
        _tv._c_ext._reset_perf_counters()
        out = fn(x, y)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"logaddexp2+1 expected ≤1 dispatch, got {d}"
        expected = torch.logaddexp2(x.cpu(), y.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_sgn_one_dispatch(self):
        """`torch.sgn(x) + 1` — for real tensors, sgn == sign; 1 dispatch."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.sgn(x) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"sgn+1 expected ≤1 dispatch, got {d}"
        expected = torch.sgn(x.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_real_passthrough_one_dispatch(self):
        """`torch.real(x) + 1` — `real` on a real tensor is identity; the
        epilogue lowers to a single pointwise dispatch."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.real(x) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"real+1 expected ≤1 dispatch, got {d}"
        expected = torch.real(x.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_heaviside_correctness(self):
        """`torch.heaviside(x, 0.5) + 1` — currently 5 dispatches via stock
        decomp (compare + select + epilogue chain). Correctness lock; the
        dispatch count tightens once heaviside picks up a fused override."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.heaviside(x, torch.tensor(0.5, device=x.device)) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 5, f"heaviside+1 expected ≤5 dispatches, got {d}"
        expected = torch.heaviside(x.cpu(), torch.tensor(0.5)) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_float_power_correctness(self):
        """`torch.float_power(|x|, |y|) + 1` — currently 4 dispatches via
        stock decomposition (cast → pow → cast). Correctness lock."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, y):
            return torch.float_power(x.abs(), y.abs()) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        y = torch.randn(8, 16, device="vulkan:0")
        fn(x, y)
        fn(x, y)
        _tv._c_ext._reset_perf_counters()
        out = fn(x, y)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 4, f"float_power+1 expected ≤4 dispatches, got {d}"
        expected = torch.float_power(x.cpu().abs(), y.cpu().abs()) + 1.0
        torch.testing.assert_close(out.cpu().double(), expected, rtol=1e-4, atol=1e-4)


