class TestP14DropoutDuringEvalElim:
    """P14 — dropout-during-eval elimination. When `training=False`, Inductor's
    stock decomposition of `aten.dropout` / `aten.native_dropout` already
    folds the op to identity at graph-rewrite time, so no Vulkan-specific FX
    pass is needed. Lock the contract: the entire chain
    `dropout(p=0.5) → relu → dropout(p=0.3) → +1` collapses to 1 dispatch when
    training=False (the relu+1 fuses; both dropouts become identity).
    """

    def test_dropout_eval_zero_dropout_dispatches(self):
        """`F.dropout(x, p=0.5, training=False) + 1.0` → 1 dispatch.
        Verifies identity (output == x + 1.0)."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return F.dropout(x, p=0.5, training=False) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"dropout(eval)+1 expected ≤1 dispatch, got {d}"
        torch.testing.assert_close(out.cpu(), x.cpu() + 1.0, rtol=0, atol=0)

    def test_stack_correctness(self):
        """`torch.stack([a, b, c]) + 1.0` compiles via stock cat+view+pointwise
        codegen (cat shipped under L1 fix, see Recent Changes)."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b, c):
            return torch.stack([a, b, c]) + 1.0

        a = torch.randn(8, device="vulkan:0")
        b = torch.randn(8, device="vulkan:0")
        c = torch.randn(8, device="vulkan:0")
        fn(a, b, c)
        fn(a, b, c)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b, c)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 2, f"stack+1 expected ≤2 dispatches, got {d}"
        torch.testing.assert_close(
            out.cpu(),
            torch.stack([a.cpu(), b.cpu(), c.cpu()]) + 1.0,
            rtol=1e-5,
            atol=1e-5,
        )

    def test_hstack_vstack_correctness(self):
        """`vstack` + `hstack.mean()` chain: 1 dispatch since vstack is a view
        when shapes align and the mean reduces with hstack into the epilogue."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return torch.vstack([a, b]) + torch.hstack([a, b]).mean()

        a = torch.randn(4, 8, device="vulkan:0")
        b = torch.randn(4, 8, device="vulkan:0")
        fn(a, b)
        fn(a, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 2, f"vstack+hstack-mean expected ≤2 dispatches, got {d}"
        expected = (
            torch.vstack([a.cpu(), b.cpu()]) + torch.hstack([a.cpu(), b.cpu()]).mean()
        )
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

    def test_dropout_eval_chain_one_dispatch(self):
        """`dropout(p=0.5,training=False) → relu → dropout(p=0.3,training=False) → +1`
        collapses to 1 fused VulkanKernel dispatch."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            x = F.dropout(x, p=0.5, training=False)
            x = F.relu(x)
            x = F.dropout(x, p=0.3, training=False)
            return x + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"dropout(eval) chain expected ≤1 dispatch, got {d}"
        expected = F.relu(x.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)


class TestP12PointwiseRoundNine:
    """P12 — pointwise compound-fuse coverage round 9.

    Eight new patterns each compile to 1 fused dispatch under
    `torch.compile(backend='inductor')` with values matching CPU eager.
    Locks composite-math (hypot/expm1+log1p), three-arg ops (lerp / where),
    two-arg trig (atan2), modular (fmod), special (xlogy / logaddexp), and
    bitwise-integer pointwise. Each was a measured win discovered in the
    2026-04-27 measurement pass; the regression locks the contract so a
    future codegen change that breaks any of them fails CI.
    """

    def test_hypot_chain_one_dispatch(self):
        """`(a*a + b*b).sqrt() + 1` — hypot via expand."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return (a * a + b * b).sqrt() + 1.0

        a = torch.randn(8, 16, device="vulkan:0")
        b = torch.randn(8, 16, device="vulkan:0")
        fn(a, b)
        fn(a, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"hypot chain expected ≤1 dispatch, got {d}"
        expected = (a.cpu() * a.cpu() + b.cpu() * b.cpu()).sqrt() + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_atan2_one_dispatch(self):
        """`atan2(y, x) + 1` — two-arg trig."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(y, x):
            return torch.atan2(y, x) + 1.0

        y = torch.randn(8, 16, device="vulkan:0")
        x = torch.randn(8, 16, device="vulkan:0").abs() + 0.1
        fn(y, x)
        fn(y, x)
        _tv._c_ext._reset_perf_counters()
        out = fn(y, x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"atan2+1 expected ≤1 dispatch, got {d}"
        expected = torch.atan2(y.cpu(), x.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_lerp_one_dispatch(self):
        """`lerp(a, b, w) + 1` — three-arg interpolation."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b, w):
            return torch.lerp(a, b, w) + 1.0

        a = torch.randn(8, 16, device="vulkan:0")
        b = torch.randn(8, 16, device="vulkan:0")
        w = torch.rand(8, 16, device="vulkan:0")
        fn(a, b, w)
        fn(a, b, w)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b, w)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"lerp+1 expected ≤1 dispatch, got {d}"
        expected = torch.lerp(a.cpu(), b.cpu(), w.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_frac_one_dispatch(self):
        """`frac(x) + 1` — fractional part."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a):
            return torch.frac(a) + 1.0

        x = torch.randn(8, 16, device="vulkan:0") * 5.0
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"frac+1 expected ≤1 dispatch, got {d}"
        expected = torch.frac(x.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_expm1_log1p_chain_one_dispatch(self):
        """`expm1(x) + log1p(|x|) + 1` — composite e^x-1 / log(1+x)."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a):
            return torch.expm1(a) + torch.log1p(a.abs()) + 1.0

        x = torch.randn(8, 16, device="vulkan:0") * 0.5
        fn(x)
        fn(x)
        _tv._c_ext._reset_perf_counters()
        out = fn(x)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"expm1+log1p+1 expected ≤1 dispatch, got {d}"
        expected = torch.expm1(x.cpu()) + torch.log1p(x.cpu().abs()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_logaddexp_one_dispatch(self):
        """`logaddexp(a, b) + 1` — log-sum-exp building block."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return torch.logaddexp(a, b) + 1.0

        a = torch.randn(8, 16, device="vulkan:0")
        b = torch.randn(8, 16, device="vulkan:0")
        fn(a, b)
        fn(a, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"logaddexp+1 expected ≤1 dispatch, got {d}"
        expected = torch.logaddexp(a.cpu(), b.cpu()) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_xlogy_one_dispatch(self):
        """`xlogy(|x|, |y|+0.1) + 1` — entropy-style special op."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return torch.xlogy(a.abs(), b.abs() + 0.1) + 1.0

        x = torch.randn(8, 16, device="vulkan:0")
        y = torch.randn(8, 16, device="vulkan:0")
        fn(x, y)
        fn(x, y)
        _tv._c_ext._reset_perf_counters()
        out = fn(x, y)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"xlogy+1 expected ≤1 dispatch, got {d}"
        expected = torch.xlogy(x.cpu().abs(), y.cpu().abs() + 0.1) + 1.0
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_bitwise_int_chain_one_dispatch(self):
        """`(a & b) | (a ^ b)` — pure-int bitwise composite."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(a, b):
            return (a & b) | (a ^ b)

        a = torch.randint(-100, 100, (8, 16), device="vulkan:0", dtype=torch.int32)
        b = torch.randint(1, 100, (8, 16), device="vulkan:0", dtype=torch.int32)
        fn(a, b)
        fn(a, b)
        _tv._c_ext._reset_perf_counters()
        out = fn(a, b)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"bitwise int chain expected ≤1 dispatch, got {d}"
        expected = (a.cpu() & b.cpu()) | (a.cpu() ^ b.cpu())
        torch.testing.assert_close(out.cpu(), expected, rtol=0, atol=0)


class TestHelpersModuleCompilesAndLinks:
    """P0.1 — `shaders/lib/helpers.slang` compiles and links into a kernel.

    Imports the Slang module from a trivial pointwise shader, compiles it
    end-to-end via `slangc -I <lib>`, dispatches via the JIT runtime, and
    verifies the kernel produces correct output. Locks the contract that
    later phases (P0.5 ParameterBlock migration, P0.8 import-vs-string
    codegen) build on.
    """

    def test_welford_combine_via_module_import(self):
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        src = """
        import helpers;

        [[vk::binding(0, 0)]] StructuredBuffer<float> in_a;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_b;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_mean;
        [[vk::binding(3, 0)]] RWStructuredBuffer<float> out_var;

        [shader("compute")]
        [numthreads(1, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            Welford a; a.mean = in_a[0]; a.m2 = 0.0f; a.n = 1.0f;
            Welford b; b.mean = in_b[0]; b.m2 = 0.0f; b.n = 1.0f;
            Welford c = welford_combine(a, b);
            float2 mv = welford_finalize(c);
            out_mean[0] = mv.x;
            out_var[0] = mv.y;
        }
        """

        a = torch.tensor([3.0], device="vulkan:0")
        b = torch.tensor([7.0], device="vulkan:0")
        out_mean = torch.zeros(1, device="vulkan:0")
        out_var = torch.zeros(1, device="vulkan:0")

        compile_and_dispatch(
            src,
            tensors=[a, b, out_mean, out_var],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            entry="computeMain",
            cache_key="test_helpers_welford_v1",
            num_outputs=2,
        )

        torch.testing.assert_close(
            out_mean.cpu(),
            torch.tensor([5.0]),
            rtol=1e-5,
            atol=1e-5,
        )
        torch.testing.assert_close(
            out_var.cpu(),
            torch.tensor([4.0]),
            rtol=1e-5,
            atol=1e-5,
        )

    def test_packed16_roundtrip_via_module_import(self):
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        src = """
        import helpers;

        [[vk::binding(0, 0)]] StructuredBuffer<float> in_lo;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_hi;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_lo;
        [[vk::binding(3, 0)]] RWStructuredBuffer<float> out_hi;

        [shader("compute")]
        [numthreads(1, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            uint w = pack_f16x2(in_lo[0], in_hi[0]);
            float2 lh = unpack_f16x2(w);
            out_lo[0] = lh.x;
            out_hi[0] = lh.y;
        }
        """

        lo = torch.tensor([1.5], device="vulkan:0")
        hi = torch.tensor([-2.25], device="vulkan:0")
        out_lo = torch.zeros(1, device="vulkan:0")
        out_hi = torch.zeros(1, device="vulkan:0")

        compile_and_dispatch(
            src,
            tensors=[lo, hi, out_lo, out_hi],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            entry="computeMain",
            cache_key="test_helpers_packed16_v1",
            num_outputs=2,
        )

        torch.testing.assert_close(
            out_lo.cpu(),
            torch.tensor([1.5]),
            rtol=1e-3,
            atol=1e-3,
        )
        torch.testing.assert_close(
            out_hi.cpu(),
            torch.tensor([-2.25]),
            rtol=1e-3,
            atol=1e-3,
        )


class TestTensorLayoutModule:
    """P0.2 — `shaders/lib/tensor_layout.slang` provides stride math /
    broadcast helpers consumable from a real kernel.

    Synthetic strided-load kernel imports the module and gathers a 2D
    transposed view through `strided_offset<2>(...)`. Verified against the
    same gather computed via PyTorch CPU.
    """

    def test_strided_offset_2d_transposed_load(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        src = """
        import tensor_layout;

        [[vk::binding(0, 0)]] StructuredBuffer<float> in_strided;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_contig;

        [[vk::push_constant]] cbuffer Push {
            uint shape0;
            uint shape1;
            uint stride0;
            uint stride1;
            uint total;
        };

        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x >= total) return;
            uint shape[2] = {shape0, shape1};
            uint stride[2] = {stride0, stride1};
            uint src_off = strided_offset<2>(tid.x, shape, stride);
            out_contig[tid.x] = in_strided[src_off];
        }
        """

        H, W = 4, 6
        cpu_src = torch.arange(H * W, dtype=torch.float32).reshape(H, W)
        # transposed view: out[i, j] = src[j, i]; treat output as shape (W, H).
        in_t = cpu_src.contiguous().to("vulkan:0")
        out_t = torch.zeros(W * H, dtype=torch.float32, device="vulkan:0")

        # Output traversal logical shape (W, H); src strides in row-major are (W, 1).
        push = struct.pack("IIIII", W, H, 1, W, W * H)

        compile_and_dispatch(
            src,
            tensors=[in_t, out_t],
            wg_x=(W * H + 63) // 64,
            wg_y=1,
            wg_z=1,
            push_constants=push,
            entry="computeMain",
            cache_key="test_tensor_layout_strided_v1",
            num_outputs=1,
        )

        expected = cpu_src.t().contiguous().reshape(-1)
        torch.testing.assert_close(out_t.cpu(), expected, rtol=0, atol=0)

    def test_broadcast_offset_2d(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        src = """
        import tensor_layout;

        [[vk::binding(0, 0)]] StructuredBuffer<float> in_src;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_contig;

        [[vk::push_constant]] cbuffer Push {
            uint out0;
            uint out1;
            uint src0;
            uint src1;
            uint sstride0;
            uint sstride1;
            uint total;
        };

        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x >= total) return;
            uint out_shape[2] = {out0, out1};
            uint src_shape[2] = {src0, src1};
            uint src_stride[2] = {sstride0, sstride1};
            uint off = broadcast_offset<2>(tid.x, out_shape, src_shape, src_stride);
            out_contig[tid.x] = in_src[off];
        }
        """

        # Source shape (1, 5) broadcast to (4, 5).
        cpu_src = torch.tensor([10.0, 20.0, 30.0, 40.0, 50.0]).reshape(1, 5)
        in_t = cpu_src.contiguous().to("vulkan:0")
        out_t = torch.zeros(4 * 5, dtype=torch.float32, device="vulkan:0")
        # src strides in row-major (1,5) layout: (5, 1) — but dim 0 is broadcast,
        # so its stride contributes 0 inside the helper.
        push = struct.pack("IIIIIII", 4, 5, 1, 5, 5, 1, 4 * 5)

        compile_and_dispatch(
            src,
            tensors=[in_t, out_t],
            wg_x=(4 * 5 + 63) // 64,
            wg_y=1,
            wg_z=1,
            push_constants=push,
            entry="computeMain",
            cache_key="test_tensor_layout_broadcast_v1",
            num_outputs=1,
        )

        expected = cpu_src.expand(4, 5).contiguous().reshape(-1)
        torch.testing.assert_close(out_t.cpu(), expected, rtol=0, atol=0)


class TestModulePrecompilation:
    """P0.3 — `precompile_shader_libs()` emits `.slang-module` artifacts and
    reuses them when source content is unchanged.

    First call compiles every `shaders/lib/*.slang` to its serialized IR
    counterpart. Second call (no source change) hits the cache: the
    artifact mtime is unchanged AND the function reports 0 compiles + N
    cached. Touching the source bumps the hash and triggers exactly one
    recompile on the next invocation. Locks the contract that compiled
    kernels link against the cached module artifact rather than re-parsing
    the source on every cold compile.
    """

    def test_module_precompile_caches_on_unchanged_source(self, tmp_path, monkeypatch):
        from torch_vulkan.inductor import runtime as rt

        monkeypatch.setattr(rt, "_SHADER_LIB_MODULE_CACHE_DIR", str(tmp_path))
        result1 = rt.precompile_shader_libs(force=True)
        assert "helpers" in result1["compiled"]
        assert "tensor_layout" in result1["compiled"]
        assert result1["cached"] == []

        helpers_mod = tmp_path / "helpers.slang-module"
        layout_mod = tmp_path / "tensor_layout.slang-module"
        assert helpers_mod.exists() and layout_mod.exists()
        m1 = helpers_mod.stat().st_mtime_ns
        m2 = layout_mod.stat().st_mtime_ns

        result2 = rt.precompile_shader_libs()
        assert set(result2["cached"]) >= {"helpers", "tensor_layout"}
        assert result2["compiled"] == []
        assert helpers_mod.stat().st_mtime_ns == m1
        assert layout_mod.stat().st_mtime_ns == m2

    def test_module_precompile_recompiles_on_source_change(self, tmp_path, monkeypatch):
        import shutil

        # Stage a private copy of the lib dir so we can mutate without
        # touching the real shaders/lib.
        priv_lib = tmp_path / "lib"
        priv_lib.mkdir()
        from torch_vulkan.inductor import runtime as rt

        for src in os.listdir(rt._SHADERS_LIB_DIR):
            if src.endswith(".slang"):
                shutil.copy(os.path.join(rt._SHADERS_LIB_DIR, src), priv_lib / src)

        cache_dir = tmp_path / "cache"
        cache_dir.mkdir()
        monkeypatch.setattr(rt, "_SHADERS_LIB_DIR", str(priv_lib))
        monkeypatch.setattr(rt, "_SHADER_LIB_MODULE_CACHE_DIR", str(cache_dir))

        rt.precompile_shader_libs(force=True)
        helpers_mod = cache_dir / "helpers.slang-module"
        m_initial = helpers_mod.stat().st_mtime_ns

        # Mutate helpers.slang content — append a comment changes the hash.
        helpers_src = priv_lib / "helpers.slang"
        with open(helpers_src, "a") as f:
            f.write("\n// pragma: cache buster\n")

        result = rt.precompile_shader_libs()
        assert "helpers" in result["compiled"], result
        assert "tensor_layout" in result["cached"], result
        assert helpers_mod.stat().st_mtime_ns > m_initial

    def test_compile_kernel_links_against_precompiled_module(self):
        """Compile a kernel that imports `helpers` after precompilation —
        must succeed and produce correct output even if the source dir
        contains no `.slang` files (only the precompiled module)."""
        # First call ensures the module cache is populated.
        from torch_vulkan.inductor import runtime as rt
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        rt._reset_shader_lib_modules_ready()
        rt._ensure_shader_lib_modules()

        src = """
        import helpers;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_a;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_b;
        [shader("compute")]
        [numthreads(1, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            Welford w; w.mean = in_a[0]; w.m2 = 0.0f; w.n = 1.0f;
            out_b[0] = welford_finalize(w).x;
        }
        """
        a = torch.tensor([13.5], device="vulkan:0")
        out = torch.zeros(1, device="vulkan:0")
        compile_and_dispatch(
            src,
            tensors=[a, out],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            entry="computeMain",
            cache_key="test_module_link_v1",
            num_outputs=1,
        )
        torch.testing.assert_close(
            out.cpu(), torch.tensor([13.5]), rtol=1e-5, atol=1e-5
        )


class TestReflectionDrivenBinding:
    """P0.4 — slangc reflection JSON is emitted, cached, and parsed.

    Round-trips a non-trivial-layout shader through the reflection
    pipeline: compile → reflection JSON cached on disk → Python derives
    descriptor binding indices and push-constant size from compiler
    truth, no hand-counting. The contract is "Python doesn't guess";
    later C++ work (descriptor-set-layout creation from reflection)
    can rely on the same JSON.
    """

    def test_reflection_extracts_bindings_and_push_constants(self):
        from torch_vulkan.inductor.runtime import compile_slang_to_spirv_with_reflection

        src = """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_a;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_b;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_c;
        [[vk::push_constant]] cbuffer Push {
            uint n;
            float scale;
            uint flag;
        };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) {
                float v = in_a[tid.x] + in_b[tid.x] * scale;
                out_c[tid.x] = (flag != 0u) ? v : -v;
            }
        }
        """

        spv, layout = compile_slang_to_spirv_with_reflection(
            src,
            entry="computeMain",
            cache_key="test_reflection_v1",
        )
        assert len(spv) > 0
        # Bindings: (set, index, name) — sorted by (set, index).
        names = [b[2] for b in layout["bindings"]]
        idxs = [b[1] for b in layout["bindings"]]
        assert names == ["in_a", "in_b", "out_c"], layout
        assert idxs == [0, 1, 2], layout
        # Push constants are 3 × 4 bytes = 12.
        assert layout["push_constant_size"] == 12, layout

    def test_reflection_cache_hits_on_recompile(self):
        from torch_vulkan.inductor import runtime as rt
        from torch_vulkan.inductor.runtime import compile_slang_to_spirv_with_reflection

        src = """
        [[vk::binding(0, 0)]] RWStructuredBuffer<float> out_a;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(1, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) out_a[tid.x] = float(tid.x);
        }
        """
        compile_slang_to_spirv_with_reflection(
            src,
            cache_key="test_refl_cache_v1",
        )
        # Second call must reuse the cached reflection (in-memory or disk)
        # without going back to slangc — the in-memory hit is verified by
        # asserting the cache map carries the key.
        rt._cache_by_key.pop("test_refl_cache_v1", None)
        _, layout = compile_slang_to_spirv_with_reflection(
            src,
            cache_key="test_refl_cache_v1",
        )
        assert layout["bindings"][0][2] == "out_a"
        assert layout["push_constant_size"] == 4


class TestParameterBlockPointwise:
    """P0.5 — `ParameterBlock<KernelArgs>` adoption proof.

    Migrates a unary pointwise kernel from N hand-written
    `[[vk::binding(N, 0)]]` lines to a single `ParameterBlock<KernelArgs>`
    declaration. Verifies (a) bit-exact output vs the equivalent
    explicit-binding shader and (b) reflection JSON shows the same
    sequential descriptor-set-0 binding layout, so existing
    C++ Pipeline.cpp dispatches the new shader without any layout
    changes. Locks the contract that the codegen rewrite (P3.x) can
    incrementally swap shaders to ParameterBlock without breaking the
    runtime.
    """

    @staticmethod
    def _baseline_src() -> str:
        return """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) out_y[tid.x] = in_x[tid.x] * 2.0f;
        }
        """

    @staticmethod
    def _parameter_block_src() -> str:
        return """
        struct KernelArgs {
            StructuredBuffer<float> in_x;
            RWStructuredBuffer<float> out_y;
        };
        ParameterBlock<KernelArgs> kargs;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) kargs.out_y[tid.x] = kargs.in_x[tid.x] * 2.0f;
        }
        """

    def test_parameter_block_dispatches_bitexact_to_baseline(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        x = torch.arange(256, dtype=torch.float32, device="vulkan:0")
        y_baseline = torch.zeros(256, device="vulkan:0")
        y_pb = torch.zeros(256, device="vulkan:0")
        push = struct.pack("I", 256)

        compile_and_dispatch(
            self._baseline_src(),
            tensors=[x, y_baseline],
            wg_x=4,
            wg_y=1,
            wg_z=1,
            push_constants=push,
            entry="computeMain",
            cache_key="p05_baseline_v1",
            num_outputs=1,
        )
        compile_and_dispatch(
            self._parameter_block_src(),
            tensors=[x, y_pb],
            wg_x=4,
            wg_y=1,
            wg_z=1,
            push_constants=push,
            entry="computeMain",
            cache_key="p05_paramblock_v1",
            num_outputs=1,
        )

        torch.testing.assert_close(y_pb.cpu(), y_baseline.cpu(), rtol=0, atol=0)
        torch.testing.assert_close(
            y_pb.cpu(),
            (x.cpu() * 2.0),
            rtol=0,
            atol=0,
        )

    def test_parameter_block_reflection_matches_baseline_layout(self):
        from torch_vulkan.inductor.runtime import compile_slang_to_spirv_with_reflection

        _, layout_baseline = compile_slang_to_spirv_with_reflection(
            self._baseline_src(),
            cache_key="p05_baseline_refl_v1",
        )
        _, layout_pb = compile_slang_to_spirv_with_reflection(
            self._parameter_block_src(),
            cache_key="p05_paramblock_refl_v1",
        )
        # Baseline: two sequential descriptor bindings + 4-byte push.
        assert [b[1] for b in layout_baseline["bindings"]] == [0, 1]
        assert layout_baseline["push_constant_size"] == 4
        # ParameterBlock: same push-constant size; the resource bindings
        # inside the block are not listed at the top level (they appear
        # inside `parameters[].type.elementType.fields`), so the top-level
        # binding list is empty — the C++ Pipeline.cpp still gets the
        # same descriptor-set-0 sequential storage-buffer layout because
        # slangc lays out the parameter block's resources at slots 0..N-1
        # in set 0 (verified separately by the bit-exact dispatch above).
        assert layout_pb["push_constant_size"] == 4


class TestSpecializationConstantTilePipeline:
    """P0.6 — `[[vk::constant_id(N)]] const uint TILE_*` declarations
    survive into SPIR-V as proper `OpSpecConstant` + `SpecId N` pairs.

    Locks the contract that the same SPV blob can spawn N distinct
    pipelines (one per tile geometry) by passing different
    `VkSpecializationInfo` at pipeline-creation time — the future C++
    wiring can rely on the spec-constant catalog already being there.
    The SPIR-V cache holds 1 entry for this kernel; the runtime would
    cache pipelines by `(cache_key, spec_tuple)` once C++ support
    lands. Verified by parsing the SPV bytes ourselves.
    """

    def test_spec_constants_emitted_with_correct_ids_and_defaults(self):
        from torch_vulkan.inductor.runtime import (
            compile_slang_to_spirv,
            parse_spec_constants,
        )

        src = """
        [[vk::constant_id(0)]] const uint TILE_M = 16;
        [[vk::constant_id(1)]] const uint TILE_N = 32;
        [[vk::constant_id(2)]] const uint TILE_K = 8;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n)
                out_y[tid.x] = in_x[tid.x] * float(TILE_M * TILE_N + TILE_K);
        }
        """

        spv = compile_slang_to_spirv(src, cache_key="p06_spec_v1")
        spec = parse_spec_constants(spv)
        # Three spec IDs with defaults (16, 32, 8).
        assert spec == [(0, 16), (1, 32), (2, 8)], spec

    def test_single_spv_for_kernel_regardless_of_tile_choice(self):
        """SPIR-V cache must hold *one* entry per source — not per tile
        geometry. Verifies repeat compiles share the same SPV blob (the
        spec values would override at pipeline-creation time, not source
        render time)."""
        from torch_vulkan.inductor.runtime import compile_slang_to_spirv

        src = """
        [[vk::constant_id(0)]] const uint TILE = 32;
        [[vk::binding(0, 0)]] RWStructuredBuffer<float> out_x;
        [shader("compute")]
        [numthreads(1, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            out_x[0] = float(TILE);
        }
        """
        spv1 = compile_slang_to_spirv(src, cache_key="p06_one_spv_v1")
        spv2 = compile_slang_to_spirv(src, cache_key="p06_one_spv_v1")
        assert spv1 is spv2, "expected in-memory cache hit, not a fresh compile"


class TestCapabilityGatedReduction:
    """P0.7 — Capability-gated wave-vs-groupshared reduction.

    Two independent reduction paths live in `helpers.slang`:
        - `wave_sum<T>(v)`         — `WaveActiveSum`, requires subgroup
        - `wg_sum_smem(v, tid, n)` — log2-step tree in groupshared, no
                                     subgroup intrinsics
    Both are dispatched on the agent's RDNA1 device (which supports
    subgroups) and must produce numerically identical results. On
    SwiftShader (no subgroups), only the smem path runs — verified by
    the smem path's continued green status independent of GPU
    capabilities. Locks the contract that the codegen rewrite (P3.x)
    can pick the wave path on capable devices and fall back to smem
    elsewhere with no behavioral diff.
    """

    def test_wave_and_smem_paths_produce_identical_sum(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        N = 64
        x = torch.arange(N, dtype=torch.float32, device="vulkan:0")
        out_wave = torch.zeros(1, device="vulkan:0")
        out_smem = torch.zeros(1, device="vulkan:0")
        push = struct.pack("I", N)

        wave_src = """
        import helpers;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID, uint3 lid : SV_GroupThreadID) {
            float v = (tid.x < n) ? in_x[tid.x] : 0.0f;
            float s = wave_sum<float>(v);
            if (lid.x == 0) out_y[0] = s;
        }
        """

        smem_src = """
        import helpers;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID, uint3 lid : SV_GroupThreadID) {
            float v = (tid.x < n) ? in_x[tid.x] : 0.0f;
            float s = wg_sum_smem(v, lid.x, n);
            if (lid.x == 0) out_y[0] = s;
        }
        """

        compile_and_dispatch(
            wave_src,
            tensors=[x, out_wave],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            push_constants=push,
            entry="computeMain",
            cache_key="p07_wave_v1",
            num_outputs=1,
        )
        compile_and_dispatch(
            smem_src,
            tensors=[x, out_smem],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            push_constants=push,
            entry="computeMain",
            cache_key="p07_smem_v1",
            num_outputs=1,
        )

        expected = float(N * (N - 1) // 2)
        torch.testing.assert_close(
            out_wave.cpu(),
            torch.tensor([expected]),
            rtol=0,
            atol=0,
        )
        torch.testing.assert_close(
            out_smem.cpu(),
            torch.tensor([expected]),
            rtol=0,
            atol=0,
        )
        torch.testing.assert_close(out_wave.cpu(), out_smem.cpu(), rtol=0, atol=0)


class TestCodegenEmitsImport:
    """P0.8 — `emit_helpers` ships `import helpers;` for the module subset.

    When a kernel's helper headers are all in `HELPERS_MODULE_HEADERS`,
    `emit_helpers` writes a single `import helpers;` line instead of
    inlining ~300 lines of helper bodies. Locks the contract that
    Inductor-emitted Slang shrinks toward `import` over string-glued
    bodies, slashing per-kernel parse cost + SPV size. Kernels needing
    helpers not yet ported (e.g. wgreduce_*, igamma, zeta) keep the
    inline path until subsequent migration items move them.
    """

    def test_module_subset_emits_single_import(self):
        from torch._inductor.codegen.common import IndentedBuffer
        from torch_vulkan.inductor.slang_helpers import (
            _reset_emit_helpers_cache,
            emit_helpers,
        )

        _reset_emit_helpers_cache()
        buf = IndentedBuffer()
        emit_helpers(
            buf, headers={"erf", "log1p"}, max_threadgroup_size=256, simd_group_size=64
        )
        out = buf.getvalue()
        # Exactly one import line, zero inline bodies.
        assert out.strip().count("\n") == 0, out
        assert "import helpers;" in out
        assert "c10_vulkan_erf(" not in out
        assert "c10_vulkan_log1p(" not in out

    def test_mixed_headers_falls_back_to_inline_bodies(self):
        from torch._inductor.codegen.common import IndentedBuffer
        from torch_vulkan.inductor.slang_helpers import (
            _reset_emit_helpers_cache,
            emit_helpers,
        )

        _reset_emit_helpers_cache()
        buf = IndentedBuffer()
        # `erf` is in module; `wgreduce_sum` is not — must fall back to
        # inlining everything (regression risk is what would happen if we
        # emitted the import AND skipped the un-ported helpers).
        emit_helpers(
            buf,
            headers={"erf", "wgreduce_sum"},
            max_threadgroup_size=256,
            simd_group_size=64,
        )
        out = buf.getvalue()
        assert "import helpers;" not in out
        assert "c10_vulkan_erf(" in out
        assert "c10_vulkan_wg_reduce_sum(" in out

    def test_imported_helpers_still_compile_and_dispatch(self):
        """End-to-end: a kernel using only module-resident helpers
        compiles via `import helpers;` and dispatches with correct
        output. Locks that the new path produces the same bits as the
        old inline path."""
        from torch._inductor.codegen.common import IndentedBuffer
        from torch_vulkan.inductor.runtime import compile_and_dispatch
        from torch_vulkan.inductor.slang_helpers import (
            _reset_emit_helpers_cache,
            emit_helpers,
        )

        _reset_emit_helpers_cache()
        helpers_buf = IndentedBuffer()
        emit_helpers(
            helpers_buf, headers={"erf"}, max_threadgroup_size=64, simd_group_size=64
        )
        helpers_block = helpers_buf.getvalue()
        assert "import helpers;" in helpers_block, helpers_block

        src = (
            helpers_block
            + """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) out_y[tid.x] = in_x[tid.x].erf();
        }
        """
        )

        x = torch.linspace(-2.0, 2.0, 256, device="vulkan:0")
        y = torch.zeros(256, device="vulkan:0")
        import struct

        compile_and_dispatch(
            src,
            tensors=[x, y],
            wg_x=4,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("I", 256),
            entry="computeMain",
            cache_key="p08_import_erf_v1",
            num_outputs=1,
        )
        torch.testing.assert_close(y.cpu(), torch.erf(x.cpu()), rtol=1e-4, atol=1e-4)

    def test_digamma_lgamma_in_module_path(self):
        """P5.7 — `digamma` and `lgamma` joined the module-path subset.
        Locks that headers={'digamma'} and headers={'lgamma'} both emit
        `import helpers;` (no inline body) and the imported function
        round-trips correctly via real Vulkan dispatch."""
        from torch._inductor.codegen.common import IndentedBuffer
        from torch_vulkan.inductor.runtime import (
            compile_and_dispatch,
            precompile_shader_libs,
        )
        from torch_vulkan.inductor.slang_helpers import (
            HELPERS_MODULE_HEADERS,
            _reset_emit_helpers_cache,
            emit_helpers,
        )

        assert "digamma" in HELPERS_MODULE_HEADERS
        assert "lgamma" in HELPERS_MODULE_HEADERS

        # Force module rebuild so the new helpers.slang symbols are
        # picked up regardless of disk cache state from prior runs.
        precompile_shader_libs(force=True)

        for header, py_fn in (("digamma", torch.digamma), ("lgamma", torch.lgamma)):
            _reset_emit_helpers_cache()
            buf = IndentedBuffer()
            emit_helpers(
                buf, headers={header}, max_threadgroup_size=64, simd_group_size=64
            )
            block = buf.getvalue()
            assert "import helpers;" in block, block
            assert f"c10_vulkan_{header}(" not in block, block

            src = (
                block
                + f"""
            [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
            [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
            [[vk::push_constant]] cbuffer Push {{ uint n; }};
            [shader("compute")]
            [numthreads(64, 1, 1)]
            void computeMain(uint3 tid : SV_DispatchThreadID) {{
                if (tid.x < n) out_y[tid.x] = c10_vulkan_{header}(in_x[tid.x]);
            }}
            """
            )

            x = torch.linspace(0.5, 8.0, 256, device="vulkan:0")
            y = torch.zeros(256, device="vulkan:0")
            import struct

            compile_and_dispatch(
                src,
                tensors=[x, y],
                wg_x=4,
                wg_y=1,
                wg_z=1,
                push_constants=struct.pack("I", 256),
                entry="computeMain",
                cache_key=f"p57_import_{header}_v1",
                num_outputs=1,
            )
            torch.testing.assert_close(y.cpu(), py_fn(x.cpu()), rtol=2e-3, atol=2e-3)


class TestPointwiseGenericFamily:
    """P1.1 — `pointwise.slang` exposes `IPointwise<T>` /
    `IPointwiseBinary<T>` interfaces with concrete struct ops.

    Locks the contract that every activation + binary op runs through a
    single template instantiation (`pointwise_unary_apply<Op>` /
    `pointwise_binary_apply<Op>`) and produces output bit-equivalent
    (within fp32 tolerance) to torch eager. Exercises the full set of
    ops the eager backend hand-rolled: ReLU, Sigmoid, Tanh, GELU, SiLU,
    ELU, HardSwish, HardSigmoid, Mish, Softplus, Relu6, Abs, Neg, Exp,
    Log, Sqrt, Rsqrt, Reciprocal (unary) + Add, Sub, Mul, Div, Min, Max,
    Pow (binary).
    """

    @staticmethod
    def _unary_kernel(op_name: str) -> str:
        return f"""
        import pointwise;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push {{ uint n; }};
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {{
            pointwise_unary_apply<{op_name}>(in_x, out_y, tid.x, n);
        }}
        """

    @staticmethod
    def _binary_kernel(op_name: str) -> str:
        return f"""
        import pointwise;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_a;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_b;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push {{ uint n; }};
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {{
            pointwise_binary_apply<{op_name}>(in_a, in_b, out_y, tid.x, n);
        }}
        """

    def _dispatch_unary(self, op_name: str, x: torch.Tensor) -> torch.Tensor:
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        x_v = x.to("vulkan:0")
        out = torch.zeros_like(x_v)
        compile_and_dispatch(
            self._unary_kernel(op_name),
            tensors=[x_v, out],
            wg_x=(x.numel() + 63) // 64,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("I", x.numel()),
            entry="computeMain",
            cache_key=f"p11_unary_{op_name}_v1",
            num_outputs=1,
        )
        return out.cpu()

    def _dispatch_binary(
        self, op_name: str, a: torch.Tensor, b: torch.Tensor
    ) -> torch.Tensor:
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        a_v = a.to("vulkan:0")
        b_v = b.to("vulkan:0")
        out = torch.zeros_like(a_v)
        compile_and_dispatch(
            self._binary_kernel(op_name),
            tensors=[a_v, b_v, out],
            wg_x=(a.numel() + 63) // 64,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("I", a.numel()),
            entry="computeMain",
            cache_key=f"p11_binary_{op_name}_v1",
            num_outputs=1,
        )
        return out.cpu()

    def test_unary_ops_match_torch_eager(self):
        import torch.nn.functional as F

        x = torch.linspace(-3.0, 3.0, 256)
        cases = [
            ("OpReLU", F.relu),
            ("OpSigmoid", torch.sigmoid),
            ("OpTanh", torch.tanh),
            ("OpGELU", lambda t: F.gelu(t, approximate="none")),
            ("OpSiLU", F.silu),
            ("OpELU", F.elu),
            ("OpHardSwish", F.hardswish),
            ("OpHardSigmoid", F.hardsigmoid),
            ("OpMish", F.mish),
            ("OpSoftplus", F.softplus),
            ("OpRelu6", F.relu6),
            ("OpAbs", torch.abs),
            ("OpNeg", torch.neg),
            ("OpExp", torch.exp),
        ]
        for op_name, ref_fn in cases:
            got = self._dispatch_unary(op_name, x)
            ref = ref_fn(x)
            torch.testing.assert_close(
                got,
                ref,
                rtol=1e-4,
                atol=1e-4,
                msg=lambda m, n=op_name: f"{n}: {m}",
            )

    def test_unary_log_sqrt_rsqrt_reciprocal_on_positive(self):
        x = torch.linspace(0.1, 4.0, 256)
        for op_name, ref_fn in [
            ("OpLog", torch.log),
            ("OpSqrt", torch.sqrt),
            ("OpRsqrt", torch.rsqrt),
            ("OpReciprocal", torch.reciprocal),
        ]:
            got = self._dispatch_unary(op_name, x)
            ref = ref_fn(x)
            torch.testing.assert_close(
                got,
                ref,
                rtol=1e-4,
                atol=1e-4,
                msg=lambda m, n=op_name: f"{n}: {m}",
            )

    def test_binary_ops_match_torch_eager(self):
        a = torch.linspace(-2.0, 2.0, 256)
        b = torch.linspace(0.1, 4.0, 256)
        cases = [
            ("OpAdd", torch.add, a, b),
            ("OpSub", torch.sub, a, b),
            ("OpMul", torch.mul, a, b),
            ("OpDiv", torch.div, a, b),
            ("OpMin", torch.min, a, b),
            ("OpMax", torch.max, a, b),
            # Pow: HLSL `pow(x, y)` is undefined for x < 0; constrain inputs.
            ("OpPow", torch.pow, b, torch.linspace(0.5, 2.5, 256)),
        ]
        for op_name, ref_fn, ai, bi in cases:
            got = self._dispatch_binary(op_name, ai, bi)
            ref = ref_fn(ai, bi)
            torch.testing.assert_close(
                got,
                ref,
                rtol=1e-4,
                atol=1e-4,
                msg=lambda m, n=op_name: f"{n}: {m}",
            )


class TestReductionGenericFamily:
    """P1.2 — `reduction.slang` exposes `IReduction` interface.

    Single `wg_reduce<R>` template handles sum/prod/max/min/any/all/xor;
    dedicated `wg_argmax`/`wg_argmin` for index-tracking reductions.
    Bit-equivalent to torch eager within fp32 tolerance.
    """

    @staticmethod
    def _reduce_kernel(op_name: str) -> str:
        return f"""
        import reduction;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push {{ uint n; }};
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID, uint3 lid : SV_GroupThreadID) {{
            float v = (tid.x < n) ? in_x[tid.x] : {op_name}::identity();
            float s = wg_reduce<{op_name}>(v, lid.x, n);
            if (lid.x == 0) out_y[0] = s;
        }}
        """

    def _dispatch_reduce(self, op_name: str, x: torch.Tensor) -> torch.Tensor:
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        x_v = x.to("vulkan:0")
        out = torch.zeros(1, device="vulkan:0")
        compile_and_dispatch(
            self._reduce_kernel(op_name),
            tensors=[x_v, out],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("I", x.numel()),
            entry="computeMain",
            cache_key=f"p12_reduce_{op_name}_v1",
            num_outputs=1,
        )
        return out.cpu()

    def test_sum_prod_max_min_match_torch(self):
        x = torch.linspace(
            0.5, 2.0, 64
        )  # bounded range; prod(64 vals) explodes otherwise
        cases = [
            ("OpSum", torch.sum),
            ("OpMaxReduce", torch.max),
            ("OpMinReduce", torch.min),
        ]
        for op_name, ref_fn in cases:
            got = self._dispatch_reduce(op_name, x)
            ref = ref_fn(x).reshape(1)
            torch.testing.assert_close(
                got,
                ref,
                rtol=1e-4,
                atol=1e-3,
                msg=lambda m, n=op_name: f"{n}: {m}",
            )

    def test_prod_small_inputs(self):
        x = torch.linspace(0.9, 1.1, 64)  # prod stays in fp32 range
        got = self._dispatch_reduce("OpProd", x)
        ref = torch.prod(x).reshape(1)
        torch.testing.assert_close(got, ref, rtol=1e-4, atol=1e-4)

    def test_any_all_match_torch(self):
        x_any = torch.tensor([0.0] * 60 + [1.0] * 4)
        got = self._dispatch_reduce("OpAny", x_any)
        assert got.item() == 1.0

        x_no = torch.zeros(64)
        got = self._dispatch_reduce("OpAny", x_no)
        assert got.item() == 0.0

        x_all = torch.ones(64)
        got = self._dispatch_reduce("OpAll", x_all)
        assert got.item() == 1.0

        x_one_zero = torch.cat([torch.ones(63), torch.zeros(1)])
        got = self._dispatch_reduce("OpAll", x_one_zero)
        assert got.item() == 0.0

    def test_argmax_argmin_match_torch(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        # All unique values so the reduction order doesn't matter for ties.
        torch.manual_seed(7)
        x = torch.randn(64) * 5.0

        for which in ("wg_argmax", "wg_argmin"):
            src = f"""
            import reduction;
            [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
            [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_v;
            [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_i;
            [[vk::push_constant]] cbuffer Push {{ uint n; }};
            [shader("compute")]
            [numthreads(64, 1, 1)]
            void computeMain(uint3 tid : SV_DispatchThreadID, uint3 lid : SV_GroupThreadID) {{
                ArgPair p;
                p.val = (tid.x < n) ? in_x[tid.x]
                                    : {"OpMaxReduce" if which == "wg_argmax" else "OpMinReduce"}::identity();
                p.idx = float(tid.x);
                ArgPair r = {which}(p, lid.x, n);
                if (lid.x == 0) {{
                    out_v[0] = r.val;
                    out_i[0] = r.idx;
                }}
            }}
            """
            x_v = x.to("vulkan:0")
            out_v = torch.zeros(1, device="vulkan:0")
            out_i = torch.zeros(1, device="vulkan:0")
            compile_and_dispatch(
                src,
                tensors=[x_v, out_v, out_i],
                wg_x=1,
                wg_y=1,
                wg_z=1,
                push_constants=struct.pack("I", x.numel()),
                entry="computeMain",
                cache_key=f"p12_{which}_v1",
                num_outputs=2,
            )
            ref_idx = (
                torch.argmax(x) if which == "wg_argmax" else torch.argmin(x)
            ).item()
            ref_val = x[ref_idx].item()
            assert out_v.cpu().item() == ref_val, (which, out_v, ref_val)
            assert int(out_i.cpu().item()) == ref_idx, (which, out_i, ref_idx)


class TestMMGenericSpecConst:
    """P1.3 — `mm.slang` exposes a generic tiled matmul template
    parameterized by `[[vk::constant_id(N)]]` tile sizes and an
    `IEpilogue` interface.

    Foundational implementation: single-output-per-thread, no
    register tiling or double-buffering yet (the full Jinja
    feature parity — register tile, multi-stage, alpha/beta —
    lands in a follow-up). Locks the contract that future
    `VkSpecializationInfo` work can spawn N pipelines from this
    one SPV blob (P0.6 + P1.3 followup).
    """

    @staticmethod
    def _kernel(epi: str) -> str:
        return f"""
        import mm;
        [[vk::binding(0, 0)]] StructuredBuffer<float> A;
        [[vk::binding(1, 0)]] StructuredBuffer<float> B;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> C;
        [[vk::push_constant]] cbuffer Push {{ uint M; uint N; uint K; }};
        [shader("compute")]
        [numthreads(16, 16, 1)]
        void computeMain(uint3 gid : SV_GroupID, uint3 lid : SV_GroupThreadID) {{
            mm_tiled<{epi}>(A, B, C, M, N, K, gid, lid);
        }}
        """

    def _run_mm(
        self, epi: str, M: int, N: int, K: int
    ) -> tuple[torch.Tensor, torch.Tensor]:
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(0)
        A = torch.randn(M, K) * 0.1
        B = torch.randn(K, N) * 0.1

        A_v = A.contiguous().reshape(-1).to("vulkan:0")
        B_v = B.contiguous().reshape(-1).to("vulkan:0")
        C_v = torch.zeros(M * N, device="vulkan:0")

        wg_x = (N + 15) // 16
        wg_y = (M + 15) // 16
        compile_and_dispatch(
            self._kernel(epi),
            tensors=[A_v, B_v, C_v],
            wg_x=wg_x,
            wg_y=wg_y,
            wg_z=1,
            push_constants=struct.pack("III", M, N, K),
            entry="computeMain",
            cache_key=f"p13_mm_{epi}_{M}x{N}x{K}_v1",
            num_outputs=1,
        )

        return C_v.cpu().reshape(M, N), A @ B

    def test_identity_epilogue_matches_torch(self):
        got, ref = self._run_mm("EpilogueIdentity", 32, 48, 64)
        torch.testing.assert_close(got, ref, rtol=1e-4, atol=1e-4)

    def test_relu_epilogue_matches_torch(self):
        got, ref = self._run_mm("EpilogueReLU", 32, 48, 64)
        torch.testing.assert_close(got, torch.relu(ref), rtol=1e-4, atol=1e-4)

    def test_clamp_epilogue_matches_torch(self):
        got, ref = self._run_mm("EpilogueClampPositive", 32, 48, 64)
        torch.testing.assert_close(got, ref.clamp(0.0, 6.0), rtol=1e-4, atol=1e-4)

    def test_single_spv_for_three_epilogues(self):
        """Each epilogue selection produces a different shader source
        (and thus different SPV cache key), but each `(epi)` source has
        one cached SPV regardless of M/N/K — push constants drive the
        shape, not the source. Locks the contract for the spec-constant
        pipeline future."""
        from torch_vulkan.inductor.runtime import compile_slang_to_spirv

        spvs = {
            epi: compile_slang_to_spirv(
                self._kernel(epi), cache_key=f"p13_mm_one_spv_{epi}_v1"
            )
            for epi in ("EpilogueIdentity", "EpilogueReLU", "EpilogueClampPositive")
        }
        assert len(set(id(s) for s in spvs.values())) == 3


class TestConvGenericFamily:
    """P1.4 — `conv.slang` exposes a 2D direct-convolution template
    parameterized by `[[vk::constant_id(N)]]` for kernel/stride/pad/
    dilation, plus an `IConvBias` interface (None / FromBuffer).

    Foundational implementation: direct conv2d single-output-per-thread
    over the (Cout, OH, OW) grid for batch=1; 1×1, 3×3, depthwise, and
    Winograd routes are filed for the algorithm-selection follow-up.
    Bit-equivalent to torch.nn.functional.conv2d for fp32 within
    ~1e-4 tolerance.
    """

    @staticmethod
    def _kernel(bias: str) -> str:
        return f"""
        import conv;
        [[vk::binding(0, 0)]] StructuredBuffer<float> X;
        [[vk::binding(1, 0)]] StructuredBuffer<float> W;
        [[vk::binding(2, 0)]] StructuredBuffer<float> bias;
        [[vk::binding(3, 0)]] RWStructuredBuffer<float> Y;
        [[vk::push_constant]] cbuffer Push {{
            uint N; uint Cin; uint H; uint Wd; uint Cout; uint OH; uint OW;
        }};
        [shader("compute")]
        [numthreads(8, 8, 1)]
        void computeMain(uint3 gid : SV_DispatchThreadID) {{
            ConvShape s; s.N=N; s.Cin=Cin; s.H=H; s.W=Wd;
            s.Cout=Cout; s.OH=OH; s.OW=OW;
            conv2d_direct<{bias}>(X, W, bias, Y, s, 0, gid.z, gid.y, gid.x);
        }}
        """

    def test_conv2d_direct_3x3_no_bias(self):
        import struct

        import torch.nn.functional as F
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(11)
        Cin, Cout, H, Wd = 3, 4, 8, 8
        KH, KW = 3, 3
        OH, OW = H - KH + 1, Wd - KW + 1
        X = torch.randn(1, Cin, H, Wd)
        Wt = torch.randn(Cout, Cin, KH, KW)
        ref = F.conv2d(X, Wt)
        bias_dummy = torch.zeros(Cout)

        X_v = X.contiguous().reshape(-1).to("vulkan:0")
        W_v = Wt.contiguous().reshape(-1).to("vulkan:0")
        b_v = bias_dummy.to("vulkan:0")
        Y_v = torch.zeros(Cout * OH * OW, device="vulkan:0")

        compile_and_dispatch(
            self._kernel("BiasNone"),
            tensors=[X_v, W_v, b_v, Y_v],
            wg_x=(OW + 7) // 8,
            wg_y=(OH + 7) // 8,
            wg_z=Cout,
            push_constants=struct.pack("IIIIIII", 1, Cin, H, Wd, Cout, OH, OW),
            entry="computeMain",
            cache_key="p14_conv_nobias_3x3_v1",
            num_outputs=1,
        )
        torch.testing.assert_close(
            Y_v.cpu().reshape(1, Cout, OH, OW),
            ref,
            rtol=1e-4,
            atol=1e-4,
        )

    def test_conv2d_direct_with_bias(self):
        import struct

        import torch.nn.functional as F
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(13)
        Cin, Cout, H, Wd = 2, 3, 6, 6
        KH, KW = 3, 3
        OH, OW = H - KH + 1, Wd - KW + 1
        X = torch.randn(1, Cin, H, Wd)
        Wt = torch.randn(Cout, Cin, KH, KW)
        bias_t = torch.randn(Cout)
        ref = F.conv2d(X, Wt, bias_t)

        X_v = X.contiguous().reshape(-1).to("vulkan:0")
        W_v = Wt.contiguous().reshape(-1).to("vulkan:0")
        b_v = bias_t.to("vulkan:0")
        Y_v = torch.zeros(Cout * OH * OW, device="vulkan:0")

        compile_and_dispatch(
            self._kernel("BiasFromBuffer"),
            tensors=[X_v, W_v, b_v, Y_v],
            wg_x=(OW + 7) // 8,
            wg_y=(OH + 7) // 8,
            wg_z=Cout,
            push_constants=struct.pack("IIIIIII", 1, Cin, H, Wd, Cout, OH, OW),
            entry="computeMain",
            cache_key="p14_conv_bias_3x3_v1",
            num_outputs=1,
        )
        torch.testing.assert_close(
            Y_v.cpu().reshape(1, Cout, OH, OW),
            ref,
            rtol=1e-4,
            atol=1e-4,
        )


class TestNormGenericFamily:
    """P1.5 — `norm.slang` shares a Welford-driven core across
    layer_norm / rms_norm via an `INormAffine` interface (None /
    WeightOnly / WeightBias).

    Foundational implementation: per-row template targeting D ≤ 64
    (single-workgroup reduction), drives the same `wg_welford`
    helper that group/instance/batch will eventually share. Bit-
    equivalent to torch eager within fp32 tolerance. Multi-block
    rows + group/instance/batch variants filed for follow-up.
    """

    def test_layer_norm_d64_matches_torch(self):
        import struct

        import torch.nn.functional as F
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(2)
        D = 64
        rows = 8
        X = torch.randn(rows, D)
        weight = torch.randn(D)
        bias = torch.randn(D)
        eps = 1e-5
        ref = F.layer_norm(X, (D,), weight, bias, eps=eps)

        X_v = X.contiguous().reshape(-1).to("vulkan:0")
        W_v = weight.to("vulkan:0")
        B_v = bias.to("vulkan:0")
        Y_v = torch.zeros(rows * D, device="vulkan:0")

        src = """
        import norm;
        [[vk::binding(0, 0)]] StructuredBuffer<float> X;
        [[vk::binding(1, 0)]] StructuredBuffer<float> W;
        [[vk::binding(2, 0)]] StructuredBuffer<float> B;
        [[vk::binding(3, 0)]] RWStructuredBuffer<float> Y;
        [[vk::push_constant]] cbuffer Push { uint D; float eps; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 gid : SV_GroupID, uint3 lid : SV_GroupThreadID) {
            layer_norm_row<AffineWeightBias>(X, W, B, Y, gid.x, D, eps, lid.x, 64, 64u);
        }
        """
        compile_and_dispatch(
            src,
            tensors=[X_v, W_v, B_v, Y_v],
            wg_x=rows,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("If", D, eps),
            entry="computeMain",
            cache_key="p15_layer_norm_d64_v1",
            num_outputs=1,
        )
        torch.testing.assert_close(
            Y_v.cpu().reshape(rows, D),
            ref,
            rtol=1e-3,
            atol=1e-3,
        )

    def test_rms_norm_d64_matches_torch(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(3)
        D = 64
        rows = 4
        X = torch.randn(rows, D)
        weight = torch.randn(D)
        bias_dummy = torch.zeros(D)
        eps = 1e-6

        ref = X * torch.rsqrt(X.pow(2).mean(dim=-1, keepdim=True) + eps) * weight

        X_v = X.contiguous().reshape(-1).to("vulkan:0")
        W_v = weight.to("vulkan:0")
        B_v = bias_dummy.to("vulkan:0")
        Y_v = torch.zeros(rows * D, device="vulkan:0")

        src = """
        import norm;
        [[vk::binding(0, 0)]] StructuredBuffer<float> X;
        [[vk::binding(1, 0)]] StructuredBuffer<float> W;
        [[vk::binding(2, 0)]] StructuredBuffer<float> B;
        [[vk::binding(3, 0)]] RWStructuredBuffer<float> Y;
        [[vk::push_constant]] cbuffer Push { uint D; float eps; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 gid : SV_GroupID, uint3 lid : SV_GroupThreadID) {
            rms_norm_row<AffineWeightOnly>(X, W, B, Y, gid.x, D, eps, lid.x, 64, 64u);
        }
        """
        compile_and_dispatch(
            src,
            tensors=[X_v, W_v, B_v, Y_v],
            wg_x=rows,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("If", D, eps),
            entry="computeMain",
            cache_key="p15_rms_norm_d64_v1",
            num_outputs=1,
        )
        torch.testing.assert_close(
            Y_v.cpu().reshape(rows, D),
            ref,
            rtol=1e-3,
            atol=1e-3,
        )


class TestCodegenDispatchTableNotStrings:
    """P1.6 — `generic_dispatch_table.POINTWISE_TABLE` replaces the
    per-op string-emit logic in overrides.py.

    Foundation tier: data-table + emit helpers exist and are exercised
    by codegen-emitting a tiny `gelu(x*0.5+1.0)` fused snippet via the
    table — assertion: the emitted Slang routes through
    `pointwise_unary_apply<OpGELU>` style calls and contains no inline
    `0.5 * x * (1 + erf(x * 0.7071...))` math snippet. Full overrides.py
    migration filed as P1.6-followup-overrides-migration.
    """

    def test_table_covers_all_pointwise_struct_ops(self):
        from torch_vulkan.inductor.generic_dispatch_table import POINTWISE_TABLE

        # Every op in pointwise.slang is registered in the table.
        struct_names = {entry.op_struct for entry in POINTWISE_TABLE.values()}
        expected = {
            "OpReLU",
            "OpSigmoid",
            "OpTanh",
            "OpGELU",
            "OpSiLU",
            "OpELU",
            "OpHardSwish",
            "OpHardSigmoid",
            "OpMish",
            "OpSoftplus",
            "OpRelu6",
            "OpAbs",
            "OpNeg",
            "OpExp",
            "OpLog",
            "OpSqrt",
            "OpRsqrt",
            "OpReciprocal",
            "OpAdd",
            "OpSub",
            "OpMul",
            "OpDiv",
            "OpMin",
            "OpMax",
            "OpPow",
        }
        missing = expected - struct_names
        assert not missing, f"missing entries: {missing}"

    def test_emit_call_dispatches_to_struct_apply(self):
        from torch_vulkan.inductor.generic_dispatch_table import (
            emit_pointwise_via_table,
        )

        assert emit_pointwise_via_table("aten.gelu", "x") == "OpGELU::apply(x)"
        assert emit_pointwise_via_table("aten.add", "a", "b") == "OpAdd::apply(a, b)"
        assert (
            emit_pointwise_via_table("aten.relu", "(x*0.5f+1.0f)")
            == "OpReLU::apply((x*0.5f+1.0f))"
        )

    def test_collect_imports_includes_helpers_for_gelu(self):
        from torch_vulkan.inductor.generic_dispatch_table import collect_imports

        # gelu pulls helpers (for c10_vulkan_erf); plain mul stays bare.
        assert "helpers" in collect_imports(["aten.gelu"])
        assert collect_imports(["aten.mul"]) == ("pointwise",)
        # mish + softplus also need helpers.
        assert "helpers" in collect_imports(["aten.mish", "aten.softplus"])

    def test_codegen_via_table_dispatches_bitexact_to_torch(self):
        """Snapshot the emitted Slang for `gelu(x*0.5+1.0)` via the table
        and verify it (a) contains zero inline gelu math and (b) produces
        torch-equivalent output when actually dispatched."""
        import struct

        import torch.nn.functional as F
        from torch_vulkan.inductor.generic_dispatch_table import (
            collect_imports,
            emit_pointwise_via_table,
        )
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        imports = collect_imports(["aten.gelu"])
        body = emit_pointwise_via_table("aten.gelu", "(in_x[tid.x] * 0.5f + 1.0f)")

        src = (
            "\n".join(f"import {m};" for m in imports)
            + f"""
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push {{ uint n; }};
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {{
            if (tid.x < n) out_y[tid.x] = {body};
        }}
        """
        )

        # The emitted source contains the table-routed call, NOT inline
        # `0.5 * x * (1 + erf(...))` math.
        assert "OpGELU::apply(" in src
        assert "0.7071067811865475" not in src
        assert "c10_vulkan_erf" not in src

        x = torch.linspace(-2.0, 2.0, 256, device="vulkan:0")
        out = torch.zeros(256, device="vulkan:0")
        compile_and_dispatch(
            src,
            tensors=[x, out],
            wg_x=4,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("I", 256),
            entry="computeMain",
            cache_key="p16_table_gelu_v1",
            num_outputs=1,
        )
        ref = F.gelu(x.cpu() * 0.5 + 1.0, approximate="none")
        torch.testing.assert_close(out.cpu(), ref, rtol=1e-4, atol=1e-4)


class TestActivationsAutodiffBackward:
    """P2.1 — `[Differentiable]` activation forwards in `pointwise.slang`
    let backward shaders be generated automatically via `bwd_diff(fwd)`.

    Verifies the autodiff-generated gradient matches CPU eager
    autograd for ReLU, Sigmoid, Tanh, SiLU, ELU, HardSwish,
    HardSigmoid, Softplus, Mish. (GELU's autodiff path uses the
    `tanh` approximation since `c10_vulkan_erf` isn't yet
    `[Differentiable]`; the exact-erf forward is still callable
    through `OpGELU::apply`.)
    """

    @staticmethod
    def _bwd_kernel(fn_name: str) -> str:
        return f"""
        import pointwise;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_dout;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_din;
        [[vk::push_constant]] cbuffer Push {{ uint n; }};
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {{
            if (tid.x >= n) return;
            DifferentialPair<float> x_pair = diffPair(in_x[tid.x], 0.0f);
            bwd_diff({fn_name})(x_pair, in_dout[tid.x]);
            out_din[tid.x] = x_pair.d;
        }}
        """

    def _grad_via_autodiff(
        self, fn_name: str, x: torch.Tensor, dout: torch.Tensor
    ) -> torch.Tensor:
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        x_v = x.to("vulkan:0")
        dout_v = dout.to("vulkan:0")
        din_v = torch.zeros_like(x_v)
        compile_and_dispatch(
            self._bwd_kernel(fn_name),
            tensors=[x_v, dout_v, din_v],
            wg_x=(x.numel() + 63) // 64,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("I", x.numel()),
            entry="computeMain",
            cache_key=f"p21_bwd_{fn_name}_v1",
            num_outputs=1,
        )
        return din_v.cpu()

    def _torch_grad(self, fwd_fn, x: torch.Tensor, dout: torch.Tensor) -> torch.Tensor:
        x_g = x.detach().clone().requires_grad_(True)
        y = fwd_fn(x_g)
        y.backward(dout)
        return x_g.grad.detach()

    @pytest.mark.timeout(300)
    def test_relu_silu_elu_softplus_hardswish_hardsigmoid_match_torch(self):
        import torch.nn.functional as F

        torch.manual_seed(5)
        x = torch.randn(256) * 2.0
        dout = torch.randn(256)
        cases = [
            ("relu_fwd", F.relu),
            ("silu_fwd", F.silu),
            ("elu_fwd", F.elu),
            ("softplus_fwd", F.softplus),
            # mish_fwd tested separately in test_mish_bwd_diff_slang_autodiff_matches_torch.
            ("hardswish_fwd", F.hardswish),
            ("hardsigmoid_fwd", F.hardsigmoid),
        ]
        for fn_name, fwd in cases:
            got = self._grad_via_autodiff(fn_name, x, dout)
            ref = self._torch_grad(fwd, x, dout)
            torch.testing.assert_close(
                got,
                ref,
                rtol=2e-3,
                atol=2e-3,
                msg=lambda m, n=fn_name: f"{n}: {m}",
            )

    @pytest.mark.timeout(300)
    def test_mish_bwd_diff_slang_autodiff_matches_torch(self):
        """mish_fwd bwd_diff via raw Slang import matches CPU reference."""
        import torch.nn.functional as F

        torch.manual_seed(5)
        x = torch.randn(256) * 2.0
        dout = torch.randn(256)
        got = self._grad_via_autodiff("mish_fwd", x, dout)
        ref = self._torch_grad(F.mish, x, dout)
        torch.testing.assert_close(got, ref, rtol=2e-3, atol=2e-3)

    def test_sigmoid_tanh_match_torch(self):
        torch.manual_seed(7)
        x = torch.randn(256) * 1.5
        dout = torch.randn(256)
        for fn_name, fwd in [("sigmoid_fwd", torch.sigmoid), ("tanh_fwd", torch.tanh)]:
            got = self._grad_via_autodiff(fn_name, x, dout)
            ref = self._torch_grad(fwd, x, dout)
            torch.testing.assert_close(
                got,
                ref,
                rtol=1e-4,
                atol=1e-4,
                msg=lambda m, n=fn_name: f"{n}: {m}",
            )

    def test_gelu_tanh_approx_matches_torch_tanh_approx(self):
        import torch.nn.functional as F

        torch.manual_seed(11)
        x = torch.randn(256)
        dout = torch.randn(256)
        got = self._grad_via_autodiff("gelu_fwd", x, dout)
        ref = self._torch_grad(lambda t: F.gelu(t, approximate="tanh"), x, dout)
        torch.testing.assert_close(got, ref, rtol=2e-3, atol=2e-3)


class TestLossAutodiffBackward:
    """P2.2 — `[Differentiable]` per-element loss forwards in
    `losses.slang` give us autodiff backwards via `bwd_diff(loss_fwd)`.

    Element-wise (no reduction): `bwd_diff` of `loss_elem(pred, target)`
    against `dout` yields `dpred = dout * d/dpred loss_elem`. Reduction
    (mean/sum) for the user-facing loss happens outside the kernel; the
    kernel only computes the per-element gradient. Bit-equivalent to
    torch CPU autograd for mse, l1, smooth_l1, huber, bce_with_logits.
    """

    @staticmethod
    def _bwd_kernel(fn_name: str, extra_arg: str = "") -> str:
        if extra_arg:
            return f"""
            import losses;
            [[vk::binding(0, 0)]] StructuredBuffer<float> in_p;
            [[vk::binding(1, 0)]] StructuredBuffer<float> in_t;
            [[vk::binding(2, 0)]] StructuredBuffer<float> in_dout;
            [[vk::binding(3, 0)]] RWStructuredBuffer<float> out_dp;
            [[vk::push_constant]] cbuffer Push {{ uint n; float k; }};
            [shader("compute")]
            [numthreads(64, 1, 1)]
            void computeMain(uint3 tid : SV_DispatchThreadID) {{
                if (tid.x >= n) return;
                DifferentialPair<float> p = diffPair(in_p[tid.x], 0.0f);
                DifferentialPair<float> t = diffPair(in_t[tid.x], 0.0f);
                bwd_diff({fn_name})(p, t, k, in_dout[tid.x]);
                out_dp[tid.x] = p.d;
            }}
            """
        return f"""
        import losses;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_p;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_t;
        [[vk::binding(2, 0)]] StructuredBuffer<float> in_dout;
        [[vk::binding(3, 0)]] RWStructuredBuffer<float> out_dp;
        [[vk::push_constant]] cbuffer Push {{ uint n; }};
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {{
            if (tid.x >= n) return;
            DifferentialPair<float> p = diffPair(in_p[tid.x], 0.0f);
            DifferentialPair<float> t = diffPair(in_t[tid.x], 0.0f);
            bwd_diff({fn_name})(p, t, in_dout[tid.x]);
            out_dp[tid.x] = p.d;
        }}
        """

    def _grad(
        self,
        fn_name: str,
        p: torch.Tensor,
        t: torch.Tensor,
        dout: torch.Tensor,
        k: float | None = None,
    ) -> torch.Tensor:
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        p_v, t_v, d_v = p.to("vulkan:0"), t.to("vulkan:0"), dout.to("vulkan:0")
        out = torch.zeros_like(p_v)
        if k is None:
            push = struct.pack("I", p.numel())
            extra = ""
        else:
            push = struct.pack("If", p.numel(), k)
            extra = "k"
        compile_and_dispatch(
            self._bwd_kernel(fn_name, extra_arg=extra),
            tensors=[p_v, t_v, d_v, out],
            wg_x=(p.numel() + 63) // 64,
            wg_y=1,
            wg_z=1,
            push_constants=push,
            entry="computeMain",
            cache_key=f"p22_{fn_name}_{'k' if k is not None else 'nok'}_v1",
            num_outputs=1,
        )
        return out.cpu()

    def _torch_elem_grad(self, elem_fn, p, t, dout):
        p_g = p.detach().clone().requires_grad_(True)
        y = elem_fn(p_g, t)
        y.backward(dout)
        return p_g.grad.detach()

    def test_mse_l1_match_torch(self):
        torch.manual_seed(13)
        p = torch.randn(256)
        t = torch.randn(256)
        dout = torch.ones(256)
        for fn_name, elem in [
            ("mse_elem", lambda p, t: (p - t) ** 2),
            ("l1_elem", lambda p, t: (p - t).abs()),
        ]:
            got = self._grad(fn_name, p, t, dout)
            ref = self._torch_elem_grad(elem, p, t, dout)
            torch.testing.assert_close(
                got,
                ref,
                rtol=1e-4,
                atol=1e-4,
                msg=lambda m, n=fn_name: f"{n}: {m}",
            )

    def test_smooth_l1_huber_match_torch(self):
        torch.manual_seed(17)
        p = torch.randn(256) * 2.0
        t = torch.randn(256) * 2.0
        dout = torch.ones(256)
        beta = 1.0

        def smooth_l1_elem(p, t):
            d = p - t
            ad = d.abs()
            return torch.where(ad < beta, 0.5 * d * d / beta, ad - 0.5 * beta)

        def huber_elem(p, t):
            d = p - t
            ad = d.abs()
            return torch.where(ad < beta, 0.5 * d * d, beta * (ad - 0.5 * beta))

        got = self._grad("smooth_l1_elem", p, t, dout, k=beta)
        ref = self._torch_elem_grad(smooth_l1_elem, p, t, dout)
        torch.testing.assert_close(got, ref, rtol=1e-4, atol=1e-4)

        got = self._grad("huber_elem", p, t, dout, k=beta)
        ref = self._torch_elem_grad(huber_elem, p, t, dout)
        torch.testing.assert_close(got, ref, rtol=1e-4, atol=1e-4)

    def test_bce_with_logits_matches_torch(self):
        torch.manual_seed(19)
        p = torch.randn(256) * 1.5
        t = torch.empty(256).bernoulli_(0.5)
        dout = torch.ones(256)

        # bce_with_logits per-element forward: max(l,0) - l*t + log(1+exp(-|l|))
        def bce_elem(l, t):
            return torch.clamp(l, min=0) - l * t + torch.log1p(torch.exp(-l.abs()))

        got = self._grad("bce_with_logits_elem", p, t, dout)
        ref = self._torch_elem_grad(bce_elem, p, t, dout)
        torch.testing.assert_close(got, ref, rtol=1e-4, atol=1e-4)


class TestNormAutodiffBackward:
    """P2.3 — `[Differentiable]` per-element norm forwards in
    `norm.slang` give us autodiff backward for the element-wise
    affine portion (without re-deriving Welford stats).

    Locked: `bwd_diff(ln_affine_elem)` produces dL/dx that matches
    pre-computed CPU-eager gradients when stats (mean, rstd) are
    held fixed via `no_diff`. The full autodiff over Welford
    (which gives the dx-vs-stats coupling that PyTorch's exact
    backward exploits) is a follow-up since it needs the smem
    reduction marked `[Differentiable]` too.
    """

    def test_layer_norm_affine_elem_backward_matches_torch(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(23)
        D = 64
        x = torch.randn(D)
        w = torch.randn(D)
        b = torch.randn(D)
        # Pre-computed stats; held fixed (no_diff) for the element kernel.
        mean = x.mean().item()
        var = x.var(unbiased=False).item()
        rstd = 1.0 / (var + 1e-5) ** 0.5
        dout = torch.randn(D)

        x_v = x.to("vulkan:0")
        w_v = w.to("vulkan:0")
        b_v = b.to("vulkan:0")
        dout_v = dout.to("vulkan:0")
        out_dx = torch.zeros_like(x_v)

        src = """
        import norm;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_w;
        [[vk::binding(2, 0)]] StructuredBuffer<float> in_b;
        [[vk::binding(3, 0)]] StructuredBuffer<float> in_dout;
        [[vk::binding(4, 0)]] RWStructuredBuffer<float> out_dx;
        [[vk::push_constant]] cbuffer Push { uint n; float mean; float rstd; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x >= n) return;
            DifferentialPair<float> x = diffPair(in_x[tid.x], 0.0f);
            DifferentialPair<float> w = diffPair(in_w[tid.x], 0.0f);
            DifferentialPair<float> b = diffPair(in_b[tid.x], 0.0f);
            bwd_diff(ln_affine_elem)(x, mean, rstd, w, b, in_dout[tid.x]);
            out_dx[tid.x] = x.d;
        }
        """

        compile_and_dispatch(
            src,
            tensors=[x_v, w_v, b_v, dout_v, out_dx],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("Iff", D, mean, rstd),
            entry="computeMain",
            cache_key="p23_ln_affine_v1",
            num_outputs=1,
        )

        # Pure-element backward: dL/dx = dout * rstd * w (mean/rstd held fixed).
        ref = dout * rstd * w
        torch.testing.assert_close(out_dx.cpu(), ref, rtol=1e-4, atol=1e-4)

    def test_rms_norm_affine_elem_backward_matches_torch(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(29)
        D = 64
        x = torch.randn(D)
        w = torch.randn(D)
        rstd = 1.0 / ((x.pow(2).mean() + 1e-6).sqrt().item())
        dout = torch.randn(D)

        x_v = x.to("vulkan:0")
        w_v = w.to("vulkan:0")
        dout_v = dout.to("vulkan:0")
        out_dx = torch.zeros_like(x_v)

        src = """
        import norm;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_w;
        [[vk::binding(2, 0)]] StructuredBuffer<float> in_dout;
        [[vk::binding(3, 0)]] RWStructuredBuffer<float> out_dx;
        [[vk::push_constant]] cbuffer Push { uint n; float rstd; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x >= n) return;
            DifferentialPair<float> x = diffPair(in_x[tid.x], 0.0f);
            DifferentialPair<float> w = diffPair(in_w[tid.x], 0.0f);
            bwd_diff(rms_affine_elem)(x, rstd, w, in_dout[tid.x]);
            out_dx[tid.x] = x.d;
        }
        """

        compile_and_dispatch(
            src,
            tensors=[x_v, w_v, dout_v, out_dx],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("If", D, rstd),
            entry="computeMain",
            cache_key="p23_rms_affine_v1",
            num_outputs=1,
        )
        ref = dout * rstd * w
        torch.testing.assert_close(out_dx.cpu(), ref, rtol=1e-4, atol=1e-4)


class TestCGM4NormBackwardComposable:
    """CG.M4 — Norm backward via ``[Differentiable]`` composable chains.

    Tests that ``bwd_diff(layer_norm_chain)`` (with fully differentiable
    mean/rstd — NOT ``no_diff``) produces correct per-element gradients
    for x, weight, bias, AND the stats contributions (d_mean, d_rstd).

    The per-element chain gradient is verified against PyTorch's exact
    analytical norm backward formula.  The welford-combine backward is
    tested via ``bwd_diff(welford_combine)``, which invokes the
    ``[BackwardDerivative(welford_combine_bwd)]`` annotation.
    """

    def test_cgm4_layer_norm_elem_chain_is_differentiable(self):
        """Verify that ``bwd_diff(layer_norm_chain)`` compiles and
        dispatches, producing gradients for all 5 params (x, mean, rstd,
        weight, bias) — not just x."""
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(42)
        D = 64
        x = torch.randn(D, device="vulkan:0")
        mean_v = torch.tensor([0.3], device="vulkan:0")
        rstd_v = torch.tensor([0.8], device="vulkan:0")
        w = torch.randn(D, device="vulkan:0")
        b = torch.randn(D, device="vulkan:0")
        dout = torch.randn(D, device="vulkan:0")

        out_dx = torch.empty_like(x)
        out_dmean = torch.empty_like(mean_v)
        out_drstd = torch.empty_like(rstd_v)
        out_dw = torch.empty_like(w)
        out_db = torch.empty_like(b)

        src = """
        import norm;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_mean;
        [[vk::binding(2, 0)]] StructuredBuffer<float> in_rstd;
        [[vk::binding(3, 0)]] StructuredBuffer<float> in_w;
        [[vk::binding(4, 0)]] StructuredBuffer<float> in_b;
        [[vk::binding(5, 0)]] StructuredBuffer<float> in_dout;
        [[vk::binding(6, 0)]] RWStructuredBuffer<float> out_dx;
        [[vk::binding(7, 0)]] RWStructuredBuffer<float> out_dw;
        [[vk::binding(8, 0)]] RWStructuredBuffer<float> out_db;
        [[vk::binding(9, 0)]] RWStructuredBuffer<float> out_dmean;
        [[vk::binding(10, 0)]] RWStructuredBuffer<float> out_drstd;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x >= n) return;
            float xi = in_x[tid.x];
            float mn = in_mean[0];
            float rs = in_rstd[0];
            float wi = in_w[tid.x];
            float bi = in_b[tid.x];
            float dout_i = in_dout[tid.x];
            DifferentialPair<float> dx = diffPair(xi, 0.0f);
            DifferentialPair<float> dmean = diffPair(mn, 0.0f);
            DifferentialPair<float> drstd = diffPair(rs, 0.0f);
            DifferentialPair<float> dw = diffPair(wi, 0.0f);
            DifferentialPair<float> db = diffPair(bi, 0.0f);
            bwd_diff(layer_norm_chain)(dx, dmean, drstd, dw, db, dout_i);
            out_dx[tid.x] = dx.d;
            out_dw[tid.x] = dw.d;
            out_db[tid.x] = db.d;
            InterlockedAdd(out_dmean[0], asuint(dmean.d));
            InterlockedAdd(out_drstd[0], asuint(drstd.d));
        }
        """

        out_dmean.zero_()
        out_drstd.zero_()

        compile_and_dispatch(
            src,
            tensors=[
                x,
                mean_v,
                rstd_v,
                w,
                b,
                dout,
                out_dx,
                out_dw,
                out_db,
                out_dmean,
                out_drstd,
            ],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("<I", D),
            entry="computeMain",
            cache_key="cgm4_ln_chain_diff",
            num_outputs=5,
        )

        x_c = x.cpu()
        w_c = w.cpu()
        dout_c = dout.cpu()
        mean_f = mean_v.cpu().item()
        rstd_f = rstd_v.cpu().item()

        ref_dx = dout_c * rstd_f * w_c
        ref_dmean = (-rstd_f * (dout_c * w_c).sum()).item()
        ref_drstd = ((dout_c * w_c) * (x_c - mean_f)).sum().item()
        ref_dw = dout_c * (x_c - mean_f) * rstd_f
        ref_db = dout_c.clone()

        torch.testing.assert_close(out_dx.cpu(), ref_dx, rtol=1e-4, atol=1e-4)
        torch.testing.assert_close(out_dw.cpu(), ref_dw, rtol=1e-4, atol=1e-4)
        torch.testing.assert_close(out_db.cpu(), ref_db, rtol=1e-4, atol=1e-4)
        import math

        assert math.isclose(
            out_dmean.cpu().item(), ref_dmean, rel_tol=1e-4, abs_tol=1e-4
        )
        assert math.isclose(
            out_drstd.cpu().item(), ref_drstd, rel_tol=1e-4, abs_tol=1e-4
        )

    def test_cgm4_layer_norm_backward_matches_cpu(self):
        """Compiled native_layer_norm_backward matches CPU for a 2D input."""

        torch.manual_seed(99)
        shape = (16, 64)
        ns = [64]
        x = torch.randn(*shape, device="vulkan:0")
        weight = torch.randn(*ns, device="vulkan:0")
        bias = torch.randn(*ns, device="vulkan:0")
        gout = torch.randn(*shape, device="vulkan:0")

        out, mean, rstd = torch.ops.aten.native_layer_norm.default(
            x, ns, weight, bias, 1e-5
        )

        @torch.compile(backend="inductor", dynamic=False)
        def fn(grad_out, inp, mean, rstd, w, b):
            return torch.ops.aten.native_layer_norm_backward.default(
                grad_out, inp, ns, mean, rstd, w, b, [True, True, True]
            )

        gi, gw, gb = fn(gout, x, mean, rstd, weight, bias)

        gi_cpu, gw_cpu, gb_cpu = torch.ops.aten.native_layer_norm_backward.default(
            gout.cpu(),
            x.cpu(),
            ns,
            mean.cpu(),
            rstd.cpu(),
            weight.cpu(),
            bias.cpu(),
            [True, True, True],
        )
        torch.testing.assert_close(gi.cpu(), gi_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gw.cpu(), gw_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gb.cpu(), gb_cpu, rtol=1e-3, atol=1e-3)

    def test_cgm4_group_norm_backward_matches_cpu(self):
        """Compiled native_group_norm_backward matches CPU."""
        N, C, H, W = 2, 8, 4, 4
        ngroups = 2
        x = torch.randn(N, C, H, W, device="vulkan:0")
        weight = torch.randn(C, device="vulkan:0")
        bias = torch.randn(C, device="vulkan:0")
        gout = torch.randn(N, C, H, W, device="vulkan:0")

        out, mean, rstd = torch.ops.aten.native_group_norm.default(
            x, weight, bias, N, C, H * W, ngroups, 1e-5
        )
        mean = mean.reshape(N, ngroups)
        rstd = rstd.reshape(N, ngroups)

        @torch.compile(backend="inductor", dynamic=False)
        def fn(grad_out, inp, mean, rstd, w):
            return torch.ops.aten.native_group_norm_backward.default(
                grad_out, inp, mean, rstd, w, N, C, H * W, ngroups, [True, True, True]
            )

        gi, gw, gb = fn(gout, x, mean, rstd, weight)

        gi_cpu, gw_cpu, gb_cpu = torch.ops.aten.native_group_norm_backward.default(
            gout.cpu(),
            x.cpu(),
            mean.cpu(),
            rstd.cpu(),
            weight.cpu(),
            N,
            C,
            H * W,
            ngroups,
            [True, True, True],
        )
        torch.testing.assert_close(gi.cpu(), gi_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gw.cpu(), gw_cpu, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(gb.cpu(), gb_cpu, rtol=1e-3, atol=1e-3)

    @pytest.mark.slow
    @pytest.mark.timeout(300)
    def test_cgm4_batch_norm_backward_matches_cpu(self):
        """Compiled native_batch_norm_backward (eval mode) matches CPU."""
        N, C, H, W = 8, 16, 4, 4
        x = torch.randn(N, C, H, W, device="vulkan:0")
        weight = torch.randn(C, device="vulkan:0")
        bias = torch.randn(C, device="vulkan:0")
        rm = torch.randn(C, device="vulkan:0")
        rv = torch.randn(C, device="vulkan:0").abs() + 0.1
        gout = torch.randn(N, C, H, W, device="vulkan:0")
        save_mean = torch.zeros(C, device="vulkan:0")
        save_invstd = torch.zeros(C, device="vulkan:0")

        @torch.compile(backend="inductor", dynamic=False)
        def fn(grad_out, inp, w, rm, rv, sm, sinv):
            return torch.ops.aten.native_batch_norm_backward.default(
                grad_out,
                inp,
                w,
                rm,
                rv,
                sm,
                sinv,
                False,
                1e-5,
                [True, True, True],
            )

        gi, gw, gb = fn(gout, x, weight, rm, rv, save_mean, save_invstd)

        gi_cpu, gw_cpu, gb_cpu = torch.ops.aten.native_batch_norm_backward.default(
            gout.cpu(),
            x.cpu(),
            weight.cpu(),
            rm.cpu(),
            rv.cpu(),
            save_mean.cpu(),
            save_invstd.cpu(),
            False,
            1e-5,
            [True, True, True],
        )
        torch.testing.assert_close(gi.cpu(), gi_cpu, rtol=2e-3, atol=2e-3)
        torch.testing.assert_close(gw.cpu(), gw_cpu, rtol=2e-3, atol=2e-3)
        torch.testing.assert_close(gb.cpu(), gb_cpu, rtol=2e-3, atol=2e-3)

    def test_cgm4_welford_combine_bwd_compiles(self):
        """Verify that ``bwd_diff(welford_combine)`` compiles — the
        ``[BackwardDerivative(welford_combine_bwd)]`` annotation is
        recognized by slangc and produces loadable SPIR-V."""
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(77)

        a_mean = torch.tensor([2.0], device="vulkan:0")
        a_m2 = torch.tensor([0.5], device="vulkan:0")
        a_n = torch.tensor([3.0], device="vulkan:0")
        b_mean = torch.tensor([5.0], device="vulkan:0")
        b_m2 = torch.tensor([1.0], device="vulkan:0")
        b_n = torch.tensor([2.0], device="vulkan:0")
        d_mean = torch.tensor([0.7], device="vulkan:0")
        d_m2 = torch.tensor([0.3], device="vulkan:0")
        d_n = torch.tensor([0.1], device="vulkan:0")

        out_da_mean = torch.zeros(1, device="vulkan:0")
        out_da_m2 = torch.zeros(1, device="vulkan:0")
        out_da_n = torch.zeros(1, device="vulkan:0")
        out_db_mean = torch.zeros(1, device="vulkan:0")
        out_db_m2 = torch.zeros(1, device="vulkan:0")
        out_db_n = torch.zeros(1, device="vulkan:0")

        src = """
        import reduction;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_a_mean;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_a_m2;
        [[vk::binding(2, 0)]] StructuredBuffer<float> in_a_n;
        [[vk::binding(3, 0)]] StructuredBuffer<float> in_b_mean;
        [[vk::binding(4, 0)]] StructuredBuffer<float> in_b_m2;
        [[vk::binding(5, 0)]] StructuredBuffer<float> in_b_n;
        [[vk::binding(6, 0)]] StructuredBuffer<float> in_d_mean;
        [[vk::binding(7, 0)]] StructuredBuffer<float> in_d_m2;
        [[vk::binding(8, 0)]] StructuredBuffer<float> in_d_n;
        [[vk::binding(9, 0)]] RWStructuredBuffer<float> out_da_mean;
        [[vk::binding(10, 0)]] RWStructuredBuffer<float> out_da_m2;
        [[vk::binding(11, 0)]] RWStructuredBuffer<float> out_da_n;
        [[vk::binding(12, 0)]] RWStructuredBuffer<float> out_db_mean;
        [[vk::binding(13, 0)]] RWStructuredBuffer<float> out_db_m2;
        [[vk::binding(14, 0)]] RWStructuredBuffer<float> out_db_n;
        [shader("compute")]
        [numthreads(1, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            WelfordResult<float> a_primal;
            a_primal.mean = in_a_mean[0];
            a_primal.m2 = in_a_m2[0];
            a_primal.n = in_a_n[0];
            WelfordResult<float> b_primal;
            b_primal.mean = in_b_mean[0];
            b_primal.m2 = in_b_m2[0];
            b_primal.n = in_b_n[0];
            DifferentialPair<WelfordResult<float>> a = diffPair(
                a_primal,
                WelfordResult<float>(0.0f, 0.0f, 0.0f)
            );
            DifferentialPair<WelfordResult<float>> b = diffPair(
                b_primal,
                WelfordResult<float>(0.0f, 0.0f, 0.0f)
            );
            WelfordResult<float> d_out;
            d_out.mean = in_d_mean[0];
            d_out.m2 = in_d_m2[0];
            d_out.n = in_d_n[0];
            bwd_diff(welford_combine)(a, b, d_out);
            out_da_mean[0] = a.d.mean;
            out_da_m2[0] = a.d.m2;
            out_da_n[0] = a.d.n;
            out_db_mean[0] = b.d.mean;
            out_db_m2[0] = b.d.m2;
            out_db_n[0] = b.d.n;
        }
        """

        compile_and_dispatch(
            src,
            tensors=[
                a_mean,
                a_m2,
                a_n,
                b_mean,
                b_m2,
                b_n,
                d_mean,
                d_m2,
                d_n,
                out_da_mean,
                out_da_m2,
                out_da_n,
                out_db_mean,
                out_db_m2,
                out_db_n,
            ],
            wg_x=1,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("<I", 0),
            entry="computeMain",
            cache_key="cgm4_welford_bwd",
            num_outputs=6,
        )

        assert out_da_mean.cpu().isfinite().all()
        assert out_db_mean.cpu().isfinite().all()


class TestHotPathBackwardDerivativeOf:
    """P2.4 — `[BackwardDerivative(custom_bwd)]` annotation lets a
    hand-written backward keep its eager-style fused fast formula.

    Sigmoid is the smoke-test override: forward is the same
    `1/(1+exp(-x))` autograd would emit, but backward is forced to
    `sigmoid_fast_bwd` which reuses `y` instead of recomputing
    `exp(-x)`. Verified by (a) backward gradient still matches torch,
    (b) the override is specialized at link time — SPV blobs for
    sigmoid (custom override) and ReLU (auto-generated) are distinct.
    """

    def test_sigmoid_custom_backward_matches_torch(self):
        import struct

        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(31)
        x = torch.randn(256) * 1.5
        dout = torch.randn(256)
        x_v = x.to("vulkan:0")
        d_v = dout.to("vulkan:0")
        out = torch.zeros_like(x_v)

        src = """
        import pointwise;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_dout;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_dx;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x >= n) return;
            DifferentialPair<float> x = diffPair(in_x[tid.x], 0.0f);
            bwd_diff(sigmoid_fwd)(x, in_dout[tid.x]);
            out_dx[tid.x] = x.d;
        }
        """
        compile_and_dispatch(
            src,
            tensors=[x_v, d_v, out],
            wg_x=4,
            wg_y=1,
            wg_z=1,
            push_constants=struct.pack("I", 256),
            entry="computeMain",
            cache_key="p24_sigmoid_custom_bwd_v1",
            num_outputs=1,
        )
        # Reference: y = sigmoid(x); dx = dout * y * (1 - y)
        y = torch.sigmoid(x)
        ref = dout * y * (1.0 - y)
        torch.testing.assert_close(out.cpu(), ref, rtol=1e-4, atol=1e-4)

    def test_sigmoid_and_relu_backward_spv_blobs_differ(self):
        """Sigmoid (custom backward override) and ReLU (auto-generated
        backward) both compile through the same `bwd_diff` mechanism but
        produce different SPV blobs — proves the override is wired."""
        from torch_vulkan.inductor.runtime import compile_slang_to_spirv

        def kernel_for(fn: str) -> str:
            return f"""
            import pointwise;
            [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
            [[vk::binding(1, 0)]] StructuredBuffer<float> in_d;
            [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_dx;
            [[vk::push_constant]] cbuffer Push {{ uint n; }};
            [shader("compute")]
            [numthreads(64, 1, 1)]
            void computeMain(uint3 tid : SV_DispatchThreadID) {{
                if (tid.x >= n) return;
                DifferentialPair<float> x = diffPair(in_x[tid.x], 0.0f);
                bwd_diff({fn})(x, in_d[tid.x]);
                out_dx[tid.x] = x.d;
            }}
            """

        spv_sig = compile_slang_to_spirv(
            kernel_for("sigmoid_fwd"),
            cache_key="p24_compare_sig_v1",
        )
        spv_relu = compile_slang_to_spirv(
            kernel_for("relu_fwd"),
            cache_key="p24_compare_relu_v1",
        )
        assert spv_sig != spv_relu


class TestNoOrphanBackwardShaders:
    """P2.5 — backward-shader audit gate.

    The eager backend ships ~99 hand-written backward shaders under
    `shaders/<category>/`; those are tracked as `eager-only` and retire
    incrementally as Inductor families take over. The new contract is
    that ANY hand-written backward shader landing under `shaders/lib/`
    must be wired via `[BackwardDerivative(name)]` on its forward.
    Without this gate the autodiff path would silently grow back into
    string-glued bodies.
    """

    def test_audit_returns_classified_entries(self):
        from torch_vulkan.inductor.backward_audit import audit_backward_shaders

        entries = audit_backward_shaders()
        assert all(
            e.category in {"lib-registered", "eager-only", "orphan"} for e in entries
        )

    def test_no_orphan_backward_shaders_in_lib(self):
        from torch_vulkan.inductor.backward_audit import (
            assert_no_orphan_backward_shaders,
        )

        # Raises AssertionError on any orphan; passes silently otherwise.
        assert_no_orphan_backward_shaders()

    def test_summary_reports_eager_only_baseline(self):
        from torch_vulkan.inductor.backward_audit import summarize

        s = summarize()
        # Lock the eager backward inventory floor — anything added below
        # this number means a backward got retired (good); the assertion
        # here ensures the audit *is* finding the eager files at all.
        assert s["eager_only"] >= 60, s


class TestTR19BackwardConsolidation:
    """TR.19 — backward lowerings consolidated into ``bwd_lowerings.py``.

    Anti-goal #3: zero ``@register_lowering(aten.*_backward)`` decorators
    in ``lowerings/``.  All backward dispatch routes through a single source
    of truth (``bwd_lowerings.py`` → ``bwd_diff_dispatch.py`` or algebraic
    decompositions).
    """

    def test_no_aten_backward_in_lowerings_dir(self):
        """Exit gate: grep returns zero hits in lowerings/."""
        import os
        import subprocess

        lowerings_dir = os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "lowerings",
        )
        result = subprocess.run(
            ["grep", "-rl", r"register_lowering(aten\..*_backward", lowerings_dir],
            capture_output=True,
            text=True,
        )
        files = [f for f in result.stdout.strip().split("\n") if f]
        assert len(files) == 0, (
            f"TR.19 violation: found @register_lowering(aten.*_backward) in "
            f"lowerings/: {files}"
        )

    def test_bwd_lowerings_module_exists_and_has_register(self):
        """``bwd_lowerings.py`` exists and exports ``register()``."""
        from torch_vulkan.inductor.bwd_lowerings import register

        assert callable(register), "bwd_lowerings.register must be callable"

    def test_silu_backward_routes_through_bwd_diff(self):
        """silu_backward is registered via bwd_diff dispatch, not hand decomp."""
        import torch
        from torch._inductor import lowering as L

        aten = torch.ops.aten
        # The lowering must be registered.
        assert aten.silu_backward in L.lowerings, (
            "aten.silu_backward must be in Inductor lowerings"
        )
        # Verify the lowering is a FallbackKernel producer (bwd_diff path).
        # We can't easily introspect the lowering function, but we can check
        # that the custom op exists.
        assert hasattr(torch.ops.torch_vulkan, "silu_backward_bwd_diff"), (
            "torch_vulkan::silu_backward_bwd_diff custom op must be registered"
        )

    def test_mse_loss_backward_routes_through_bwd_diff(self):
        """mse_loss_backward is table-driven via bwd_diff dispatch."""
        import torch

        assert hasattr(torch.ops.torch_vulkan, "mse_loss_backward_bwd_diff"), (
            "torch_vulkan::mse_loss_backward_bwd_diff custom op must be registered"
        )
        from torch_vulkan.inductor.bwd_diff_table import BWD_DIFF_TABLE

        assert "aten.mse_loss_backward" in BWD_DIFF_TABLE, (
            "aten.mse_loss_backward must be in BWD_DIFF_TABLE"
        )

    def test_gelu_backward_still_handles_both_approximate_modes(self):
        """gelu_backward is algebraic (not bwd_diff) to handle both approx modes."""
        import torch
        from torch._inductor import lowering as L

        aten = torch.ops.aten
        assert aten.gelu_backward in L.lowerings, (
            "aten.gelu_backward must be in Inductor lowerings"
        )
        # Verify it's NOT routed through bwd_diff (no custom op).
        assert not hasattr(torch.ops.torch_vulkan, "gelu_backward_bwd_diff") or (
            getattr(torch.ops.torch_vulkan, "gelu_backward_bwd_diff", None) is None
        ), "gelu_backward must NOT use bwd_diff — it needs both approximate modes"

    def test_all_unary_bwd_diff_ops_have_custom_ops(self):
        """Every op in _UNARY_BWD_DIFF_LOWERING_OPS has a registered custom op."""
        import torch
        from torch_vulkan.inductor.bwd_lowerings import _UNARY_BWD_DIFF_LOWERING_OPS

        for aten_op in sorted(_UNARY_BWD_DIFF_LOWERING_OPS):
            short = aten_op.split(".")[-1]
            ns_name = f"{short}_bwd_diff"
            assert hasattr(torch.ops.torch_vulkan, ns_name), (
                f"Custom op torch_vulkan::{ns_name} must be registered for {aten_op}"
            )

    def test_all_binary_bwd_diff_ops_have_custom_ops(self):
        """Every op in _BINARY_BWD_DIFF_LOWERING_OPS has a registered custom op."""
        import torch
        from torch_vulkan.inductor.bwd_lowerings import _BINARY_BWD_DIFF_LOWERING_OPS

        for aten_op in sorted(_BINARY_BWD_DIFF_LOWERING_OPS):
            short = aten_op.split(".")[-1]
            ns_name = f"{short}_bwd_diff"
            assert hasattr(torch.ops.torch_vulkan, ns_name), (
                f"Custom op torch_vulkan::{ns_name} must be registered for {aten_op}"
            )

    @staticmethod
    def _count_lowering_files():
        import os

        lowerings_dir = os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "lowerings",
        )
        return lowerings_dir


class TestCodegenSmellRatchet:
    """P3.1/P3.2/P3.3 — codegen-shrink ratchets.

    Phase 3's exit criterion (`kernel.py` ≤ 800 lines, no per-dtype
    branches, no wave/smem branching, no manual binding arithmetic) is
    too big for one diff. Instead, lock current counts of each smell as
    a ceiling and ratchet down per commit. The follow-up PRs that
    actually delete the branches lower these constants accordingly.
    """

    def test_locked_ceilings_match_measured_state(self):
        from torch_vulkan.inductor.codegen_audit import (
            LOCKED_CEILINGS,
            codegen_smell_counts,
        )

        actual = codegen_smell_counts()
        # Sanity: the audit *finds* every category and the snapshot
        # matches what we locked.
        for k, ceiling in LOCKED_CEILINGS.items():
            assert k in actual
            # Ceiling matches the measured value at lock time. Future
            # commits MAY lower the ceiling — they MUST NOT raise it.
            assert actual[k] <= ceiling, (
                f"{k} grew past locked ceiling: {actual[k]} > {ceiling}"
            )

    def test_ratchet_assertion_passes_under_lock(self):
        from torch_vulkan.inductor.codegen_audit import assert_under_locked_ceilings

        assert_under_locked_ceilings()


class TestExternMMUsesGenericSlang:
    """P3.4 — `mm_loader.generic_mm_kernel_source()` is the seam by
    which the ExternKernelChoice path will load `mm.slang` instead
    of rendering the legacy Jinja template.

    Foundation tier: the loader exists, returns a buildable kernel,
    and dispatches torch-equivalent output. Caller migration in
    `vulkan_template_caller.py` is filed under
    `P3.4-followup-jinja-retire`.
    """

    def test_generic_mm_loader_dispatches_bitexact(self):
        import struct

        from torch_vulkan.inductor.mm_loader import generic_mm_kernel_source
        from torch_vulkan.inductor.runtime import compile_and_dispatch

        torch.manual_seed(41)
        M, N, K = 32, 48, 64
        A = torch.randn(M, K) * 0.1
        B = torch.randn(K, N) * 0.1
        ref = A @ B
        A_v = A.contiguous().reshape(-1).to("vulkan:0")
        B_v = B.contiguous().reshape(-1).to("vulkan:0")
        C_v = torch.zeros(M * N, device="vulkan:0")

        compile_and_dispatch(
            generic_mm_kernel_source("EpilogueIdentity"),
            tensors=[A_v, B_v, C_v],
            wg_x=(N + 15) // 16,
            wg_y=(M + 15) // 16,
            wg_z=1,
            push_constants=struct.pack("III", M, N, K),
            entry="computeMain",
            cache_key="p34_extern_mm_v1",
            num_outputs=1,
        )
        torch.testing.assert_close(
            C_v.cpu().reshape(M, N),
            ref,
            rtol=1e-4,
            atol=1e-4,
        )

    def test_loader_source_imports_mm_module(self):
        from torch_vulkan.inductor.mm_loader import generic_mm_kernel_source

        src = generic_mm_kernel_source("EpilogueReLU")
        assert "import mm;" in src
        assert "EpilogueReLU" in src
        # No Jinja artifacts (loose check).
        assert "{%" not in src and "{{" not in src


class TestComboKernelViaModuleImport:
    """P3.5 — combo-kernel string-concat ratchet.

    The legacy `vulkan_combo_kernel.py` emits multiple subkernels by
    concatenating Python source strings. Replacing it with a Slang
    module that imports per-subkernel logic and dispatches by spec
    constant is the goal. Until that lands, this ratchet locks the
    current combo-string-concat count and prevents new growth.
    """

    def test_combo_string_concat_under_locked_ceiling(self):
        from torch_vulkan.inductor.codegen_audit import (
            LOCKED_CEILINGS,
            codegen_smell_counts,
        )

        actual = codegen_smell_counts()["combo_string_concat"]
        assert actual <= LOCKED_CEILINGS["combo_string_concat"]


class TestAutotuneCacheDiscipline:
    """P5.6 — repeat compiles of the same kernel hit the cache.

    `cache_hit_rate()` returns hits / (hits + cold_compiles); after
    warmup, dispatch the same kernel twice and assert the second
    invocation hits the in-memory cache. Locks the contract that
    cache keys are stable enough not to fragment per-shape (which
    would force a slangc cold compile every step).
    """

    def test_repeat_compile_hits_cache(self):
        from torch_vulkan.inductor.runtime import (
            cache_hit_rate,
            compile_slang_to_spirv,
            reset_compile_stats,
        )

        src = """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) out_y[tid.x] = in_x[tid.x] + 1.0f;
        }
        """
        # Warmup pass populates the cache.
        compile_slang_to_spirv(src, cache_key="p56_disc_v1")
        reset_compile_stats()
        for _ in range(8):
            compile_slang_to_spirv(src, cache_key="p56_disc_v1")
        # All 8 must be cache hits — none cold.
        assert cache_hit_rate() == 1.0, cache_hit_rate()


class TestInductorOpCoverageAudit:
    """P7.4 — `scripts/audit_inductor_op_coverage.py` summarizes which
    aten ops have lowering / meta / override coverage in the Inductor
    backend.

    Locks the contract that the audit script runs and reports a
    self-consistent summary; future extensions (cross-checking
    against the Inductor decomposition table to find gaps) extend
    this baseline.
    """

    def test_audit_reports_self_consistent_summary(self):
        # Run the audit script as a subprocess and parse its summary
        # output (cleanest way to verify the CLI surface stays usable).
        import subprocess
        import sys

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_inductor_op_coverage.py",
        )
        r = subprocess.run(
            [sys.executable, script],
            capture_output=True,
            text=True,
            check=True,
        )
        out = r.stdout
        assert "Inductor op-coverage audit" in out
        assert "total_ops" in out
        assert "lowered" in out
        # Pull total_ops out of the summary line.
        for line in out.splitlines():
            if line.strip().startswith("total_ops"):
                total = int(line.split("=")[1].strip())
                assert total >= 50, f"unexpectedly low op count: {total}"
                break
        else:
            raise AssertionError("audit output missing total_ops line")


class TestInductorWrapperEmitImports:
    """P7.4 extension — wrapper-emit import audit (PF.54-era class).

    The Inductor wrapper-codegen header (`wrapper.py:write_header`)
    splices Python `from <module> import <name>` lines into every
    compiled-graph wrapper. If a re-export from the package surface is
    silently stripped (the bug class that broke MLP/CNN compile until
    `_empty_strided_vulkan` was re-added), the failure shows up only
    at `torch.compile` runtime when the wrapper module first imports.

    This test catches the failure at static-analysis time. Runs the
    audit's `emit_import_summary()` and asserts every emitted import
    resolves. A non-zero `broken` count names the offending file:line
    and the symbol that's missing.

    `_BUG_ROOT_COMPONENT="package-surface"` (per §"Bug-Rooting Protocol":
    fix is a re-export in the relevant package's `__init__.py`).
    """

    def _import_audit(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        import audit_inductor_op_coverage as a

        return a

    def test_every_emitted_import_resolves(self):
        a = self._import_audit()
        s = a.emit_import_summary()
        assert s["broken"] == 0, (
            f"P7.4 wrapper-emit audit found {s['broken']} broken "
            f"import(s) in wrapper-codegen header(s) — every compiled "
            f"graph would fail at wrapper-import time:\n  - "
            + "\n  - ".join(
                f"{r['file']}:{r['line']} "
                f"`from {r['module']} import {r['name']}` — {r['error']}"
                for r in s["broken_rows"]
            )
        )

    def test_audit_finds_at_least_one_emitted_import(self):
        # Sanity: if the regex falls behind the wrapper's emission
        # syntax (e.g. someone refactors `header.splice` to use
        # f-strings), the audit silently reports `total_imports=0`
        # and the broken-count check above degenerates. Assert we're
        # actually scanning *something*.
        a = self._import_audit()
        s = a.emit_import_summary()
        assert s["total_imports"] >= 1, (
            "P7.4 wrapper-emit audit scanned 0 imports — regex "
            "likely fell behind wrapper.py's emission syntax. Update "
            "`_EMIT_IMPORT_RE` in audit_inductor_op_coverage.py."
        )

    def test_cli_section_runs(self):
        # CLI path: the audit script's `main()` prints a "Wrapper-emit
        # import audit" section. Locks the surface so a future refactor
        # of the script keeps the section visible to humans inspecting
        # the audit output.
        import os
        import subprocess
        import sys

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_inductor_op_coverage.py",
        )
        r = subprocess.run(
            [sys.executable, script],
            capture_output=True,
            text=True,
            check=True,
        )
        out = r.stdout
        assert "Wrapper-emit import audit" in out, (
            "audit CLI dropped the wrapper-emit section"
        )


class TestSlangcSmokeAudit:
    """P7.4.b — slangc-smoke audit catches the PF.5-era class.

    The wrapper-emit import audit (`TestInductorWrapperEmitImports`)
    catches the *Python-import* class of teammate-introduced
    breakage. The slangc-smoke audit catches the *shader-compile*
    class: a teammate change that breaks slangc compile of a
    canonical kernel pattern (e.g. helpers.slang loses a `public`
    export, or an mm-template mutation tickles a slangc bug) makes
    every inductor-emitted kernel of that shape fail at compile
    time inside `torch.compile`.

    Three canonical snippets cover today's emit shapes:
      - bare pointwise relu (no `import`, no helpers)
      - pointwise gelu using `import helpers;` + `c10_vulkan_erf`
      - mm-epilogue with push-constant struct + bias + erf
        (mirrors PF.5's `addmm_gelu_fused` codegen)

    The audit invokes slangc via the runtime entry point
    (`compile_slang_to_spirv`) so the same module-cache resolution
    Inductor uses at runtime is exercised — a stale
    `helpers.slang-module` cache surfaces here just as it would in
    a compiled-graph run.

    Skips when slangc is unavailable (CI without the binary).
    `_BUG_ROOT_COMPONENT="slang-shader-pipeline"`.
    """

    def _import_audit(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        import audit_inductor_op_coverage as a

        return a

    def test_every_canonical_snippet_compiles(self):
        a = self._import_audit()
        s = a.slangc_smoke_summary()
        if s["unavailable"] >= s["total"] and s["total"] > 0:
            import pytest

            pytest.skip("slangc unavailable — smoke audit needs slangc")
        assert s["broken"] == 0, (
            f"P7.4.b slangc smoke audit found {s['broken']} canonical "
            f"snippet(s) that no longer compile — every "
            f"inductor-emitted kernel of a similar shape will fail at "
            f"`torch.compile` runtime:\n  - "
            + "\n  - ".join(f"{r['name']}: {r['error']}" for r in s["broken_rows"])
        )

    def test_audit_covers_at_least_one_helpers_module_path(self):
        # Sanity: at least one canonical snippet must exercise
        # `import helpers;` so a regression that breaks the
        # module-resolution path is caught (the exact PF.5 symptom).
        a = self._import_audit()
        snippets = a._SLANGC_SMOKE_SNIPPETS
        assert any("import helpers" in src for src in snippets.values()), (
            "slangc smoke audit must include at least one snippet "
            "exercising `import helpers;` to catch helpers-module "
            "regressions (PF.5 class). Add an entry to "
            "`_SLANGC_SMOKE_SNIPPETS` in audit_inductor_op_coverage.py."
        )

    @pytest.mark.timeout(600)
    @pytest.mark.slow_compile(seconds=700)
    def test_cli_smoke_section_runs(self):
        import os
        import subprocess
        import sys

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_inductor_op_coverage.py",
        )
        r = subprocess.run(
            [sys.executable, script],
            capture_output=True,
            text=True,
            check=True,
            timeout=590,
        )
        out = r.stdout
        assert "Slangc smoke audit" in out, "audit CLI dropped the slangc smoke section"


class TestSlangcConftestAutoResolver:
    """PF.57 — `backends/vulkan_slang/conftest.py` auto-resolves SLANGC at
    pytest_configure time.

    Without auto-resolution the audit-family classes (TestSlangcSmokeAudit,
    TestPoolReleaseTupleOutput) silently degrade to RED whenever a fresh
    shell forgets to `export SLANGC=...` even though a built slangc is
    sitting on disk. The conftest searches well-known build dirs (newest
    version first) and exports SLANGC before runtime.py imports.

    `_BUG_ROOT_COMPONENT="test-harness"`.
    """

    def test_slangc_set_after_session_start(self):
        # Conftest ran before this test → SLANGC must be set whenever any
        # built slangc is on disk.
        import glob
        import os

        repo_root = os.path.normpath(
            os.path.join(os.path.dirname(__file__), "..", "..", "..")
        )
        backend_root = os.path.normpath(os.path.join(os.path.dirname(__file__), ".."))
        any_built = bool(
            glob.glob(
                os.path.join(repo_root, "third_party/slang/build/slang-*/bin/slangc")
            )
            or glob.glob(
                os.path.join(backend_root, "third_party/slang/build/slang-*/bin/slangc")
            )
        )
        if not any_built and not os.access("/tmp/bin/slangc", os.X_OK):
            import shutil

            if not shutil.which("slangc"):
                import pytest

                pytest.skip("no built or PATH-resident slangc — conftest behavior n/a")
        assert os.environ.get("SLANGC"), (
            "PF.57 conftest auto-resolver should have set SLANGC when a "
            "built slangc exists on disk (or on PATH)"
        )
        assert os.path.exists(os.environ["SLANGC"]), (
            f"PF.57 SLANGC={os.environ['SLANGC']!r} does not point at a real file"
        )

    def test_explicit_slangc_not_overridden(self, monkeypatch):
        # Locks the "respect explicit env" contract. Re-invoke the conftest
        # resolver under monkeypatched SLANGC and assert it does not clobber.
        import importlib
        import os
        import sys

        monkeypatch.setenv("SLANGC", "/explicit/path/that/may/not/exist")
        # The conftest module is loaded as ``conftest`` by pytest; reload it
        # so pytest_configure re-runs against the patched env.
        if "conftest" in sys.modules:
            mod = sys.modules["conftest"]
            importlib.reload(mod)
            if hasattr(mod, "pytest_configure"):
                # Pass a stub config object that just absorbs attribute writes.
                class _Stub:
                    pass

                mod.pytest_configure(_Stub())
        assert os.environ["SLANGC"] == "/explicit/path/that/may/not/exist"


class TestCustomOpEagerPatchConsistency:
    """PF.58 — every `_ensure_<opname>_op_registered` in fx_passes that
    has an eager-side counterpart must have a matching `F.<opname> =
    _patched_<opname>` (or equivalent) in `python/torch_vulkan/__init__.py`.

    The half-done-ship pattern this defends against (twice observed in
    one loop): a roadmap item ships the FX-pass / Inductor-lowering half
    of a two-site contract but defers the eager-side `__init__.py`
    monkey-patch. Regression suite stays GREEN on the custom_op contract
    while live `torch.compile` of the op continues to fail because eager
    dispatch never reaches the registered shim. PF.30.d's claim about
    `_patched_max_pool2d` was wrong for an entire loop until PF.3.b.1
    landed it.

    The audit's allowlist documents which `_ensure_*` functions need an
    eager patch (rewriting an existing `F.*` op like conv2d / sdpa /
    max_pool2d) versus the fused FX-only custom_ops (swiglu, addmm_gelu,
    qkv_cat, scaled_bmm, flash_attention) which are graph-rewrite targets
    only and have no `F.*` counterpart in eager. Adding a new
    `_ensure_*` function with an eager analog forces a conscious choice
    in the audit's requirement-map, surfacing the contract.

    `_BUG_ROOT_COMPONENT="measurement"`.
    """

    def _import_audit(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        import audit_custom_op_eager_patches as a

        return a

    def test_every_registered_custom_op_has_eager_patch(self):
        a = self._import_audit()
        s = a.eager_patch_summary()
        assert s["broken"] == 0, (
            f"PF.58 custom-op eager-patch audit found {s['broken']} "
            f"`_ensure_<opname>_op_registered` site(s) whose required "
            f"eager `F.<opname> = _patched_<opname>` is missing from "
            f"`python/torch_vulkan/__init__.py`:\n  - "
            + "\n  - ".join(
                f"{r['ensure_fn']} → expected `F.{r['expected_fn']} = "
                f"_patched_{r['expected_fn']}` — {r['error']}"
                for r in s["broken_rows"]
            )
        )

    def test_audit_allowlist_covers_every_ensure_site(self):
        # Sanity: if a new `_ensure_<X>_op_registered` lands in
        # fx_passes.py and is neither in the requirement-map nor in the
        # known-fused allowlist, the audit must fail (not silently pass)
        # so the author makes a conscious choice. Locks the audit's own
        # discoverability — if `_ENSURE_RE` falls behind, this trips.
        a = self._import_audit()
        s = a.eager_patch_summary()
        assert s["unclassified"] == 0, (
            f"PF.58 audit found {s['unclassified']} `_ensure_*` site(s) "
            f"in fx_passes.py that are not in the requirement-map and "
            f"not in the fused-only allowlist. Add each one to the "
            f"matching set in `audit_custom_op_eager_patches.py`:\n  - "
            + "\n  - ".join(s["unclassified_rows"])
        )

    def test_cli_section_runs(self):
        import os
        import subprocess
        import sys

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_custom_op_eager_patches.py",
        )
        r = subprocess.run(
            [sys.executable, script],
            capture_output=True,
            text=True,
            check=True,
        )
        assert "Custom-op eager-patch audit" in r.stdout, (
            "audit CLI dropped its section header"
        )


class TestStageTagTaxonomy:
    """PF.59 — `_BUG_ROOT_COMPONENT` stage-tag taxonomy: every value used
    in the codebase must be a recognized canonical stage (from §"Inductor
    Pipeline Integration Map"), a registered sub-stage, or a registered
    meta-stage. New tag values fail the suite loud.

    Three drift instances captured in one loop: PF.3.b
    (`wrapper-codegen → fake-impl → dynamo`), PF.27.a (`wrapper-codegen`
    catch-all), P5.11.a-split (numeric "stage 11" / "stage 13" had to be
    converted to kebab names on accept). The audit's RECOGNIZED_STAGES
    registry serves as the inline reference at PROPOSAL drafting time;
    this test class locks that the registry stays consistent with the
    pipeline-map document and that no filed tag drifts from it silently.

    `_BUG_ROOT_COMPONENT="measurement"`.
    """

    def _import_audit(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        import audit_stage_tags as a

        return a

    def test_recognized_stages_list_matches_pipeline_map(self):
        # Lock 1: parse §"Inductor Pipeline Integration Map" rows + the
        # deliberately-extended sub-stage / meta-stage allowlist; assert
        # the resulting set equals the registry exposed by the audit
        # script. If a new pipeline-stage row lands without registry
        # update (or vice versa), this test fails loud.
        a = self._import_audit()
        s = a.taxonomy_summary()
        assert s["pipeline_map_canonical"] == s["registered_canonical"], (
            "PF.59: §'Inductor Pipeline Integration Map' canonical stages "
            "diverge from RECOGNIZED_STAGES['canonical']:\n"
            f"  in-map but unregistered: "
            f"{sorted(s['pipeline_map_canonical'] - s['registered_canonical'])}\n"
            f"  registered but missing from map: "
            f"{sorted(s['registered_canonical'] - s['pipeline_map_canonical'])}"
        )

    def test_every_filed_bug_root_component_is_recognized(self):
        # Lock 2: every `_BUG_ROOT_COMPONENT="..."` literal in the repo
        # (roadmap doc + python + csrc + tests) must be in
        # RECOGNIZED_STAGES (canonical / sub-stages / meta-stages).
        # Initial run will RED on today's drift values; fix is to
        # consciously register each one (move to canonical, register as
        # sub-stage, register as meta-stage, or rename).
        a = self._import_audit()
        s = a.taxonomy_summary()
        assert s["unrecognized"] == 0, (
            f"PF.59: found {s['unrecognized']} `_BUG_ROOT_COMPONENT` "
            f"value(s) not in RECOGNIZED_STAGES — register each one "
            f"consciously in `audit_stage_tags.py`:\n  - "
            + "\n  - ".join(sorted(s["unrecognized_values"]))
        )

    def test_routing_gap_audit_script_is_present(self):
        # Lock 3 (refined per roadmap-manager accept): the routing-gap
        # delivery-verification CLI exists, parses without error, and the
        # RECOGNIZED_STAGES registry is populated. The actual delivery
        # check is an investigation tool used during incidents — its
        # output is signal, not failure. This lock asserts the tool's
        # presence, not its outcome.
        a = self._import_audit()
        assert hasattr(a, "RECOGNIZED_STAGES"), (
            "PF.59: audit script must expose RECOGNIZED_STAGES dict"
        )
        assert isinstance(a.RECOGNIZED_STAGES, dict), (
            "PF.59: RECOGNIZED_STAGES must be a dict "
            "(canonical / sub_stages / meta_stages keys)"
        )
        total = sum(len(v) for v in a.RECOGNIZED_STAGES.values())
        assert total > 0, (
            "PF.59: RECOGNIZED_STAGES is empty — registry must be "
            "populated from the canonical 20 + accepted sub/meta-stages"
        )
        assert hasattr(a, "routing_gap_check"), (
            "PF.59: audit script must expose `routing_gap_check()` "
            "function for the investigation CLI"
        )


class TestRecognizedStagesIsSingleSourceOfTruth:
    """PF.59 ratchet — the dual-registry contract.

    PF.12's `audit_bug_root_components.py` and PF.59's
    `audit_stage_tags.py` both expose a `RECOGNIZED_STAGES` symbol.
    Pre-PF.59-ratchet, PF.12 carried a duplicated inline `frozenset`
    of 20 short-form canonicals that drifted from PF.59's 33-entry
    3-bucket registry — `aoti-runtime` (registered as a sub-stage in
    PF.59) failed PF.12 audit because PF.12 didn't know about
    sub-stages. Lock the contract: PF.12's registry must equal the
    union of PF.59's three buckets.

    `_BUG_ROOT_COMPONENT="measurement"`.
    """

    def _import_audits(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        # Re-import to defeat module caching when this test runs across
        # the pre/post-ratchet bisect.
        import importlib

        import audit_bug_root_components
        import audit_stage_tags

        importlib.reload(audit_stage_tags)
        importlib.reload(audit_bug_root_components)
        return audit_bug_root_components, audit_stage_tags

    def test_audit_bug_root_components_imports_from_audit_stage_tags(self):
        bug_root, stage_tags = self._import_audits()
        expected = frozenset(stage_tags.all_recognized())
        actual = bug_root.RECOGNIZED_STAGES
        assert actual == expected, (
            "PF.59 ratchet: `audit_bug_root_components.RECOGNIZED_STAGES` "
            "must equal the union of `audit_stage_tags.RECOGNIZED_STAGES` "
            "buckets. Inline-duplicated registries drift (see PF.12-RED on "
            "`aoti-runtime` pre-ratchet). Fix: in "
            "`scripts/audit_bug_root_components.py`, replace the inline "
            "`frozenset({...})` literal with "
            "`from audit_stage_tags import all_recognized; "
            "RECOGNIZED_STAGES = frozenset(all_recognized())`.\n"
            f"  in PF.59 but missing from PF.12: "
            f"{sorted(expected - actual)}\n"
            f"  in PF.12 but missing from PF.59: "
            f"{sorted(actual - expected)}"
        )


class TestOpCoverageAudit:
    """P7.4 enrichment — undeclared-op gate (post-PF.54/PF.55-era).

    FX-traces every model in `benchmarks/inductor_train.py` (CPU,
    `make_fx` real-tensor mode), collects the set of aten ops each
    model touches, and cross-references against four coverage
    dimensions:
      1. Lowering (`lowerings.py`)
      2. FakeTensor impl (`meta_patches.py`)
      3. Inductor pointwise override (`overrides.py:VulkanOverrides`)
      4. `torch_vulkan::*` custom-op shim (`fx_passes.py`)
      plus a small upstream-decomposed allow-list (view/reshape
      family that Inductor decomposes before reaching the backend).

    An aten op used by ≥1 model with NO coverage is a future
    PF.54/PF.55-class blocker. The test gates against new ones
    landing silently. Today's floor: 0 (was 1 — `aten.bmm.default`
    was used by transformer_block with no audit-visible coverage;
    PF.56 added `_register_bmm_lowering()` in `lowerings.py` that
    triggers `install_external_bmm()` and surfaces `aten.bmm` to the
    coverage scan. The actual tuned-bmm lowering registration lives in
    `vulkan_template_caller.py` so the autotune ExternKernelChoice
    surface stays in one place). Ratchet `_MAX_UNDECLARED` downward
    as coverage lands.

    Build-break-immune: FX-tracing happens on CPU, no slangc, no
    `torch.compile` of the trained model.

    `_BUG_ROOT_COMPONENT="op-coverage"`.
    """

    _MAX_UNDECLARED: int = 0

    def _import_audit(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        import audit_inductor_op_coverage as a

        return a

    def test_no_undeclared_ops(self):
        a = self._import_audit()
        s = a.undeclared_op_summary()
        if s["total_undeclared"] > self._MAX_UNDECLARED:
            lines = [
                f"P7.4: {s['total_undeclared']} aten op(s) used by "
                f"benchmark models have no Vulkan coverage "
                f"(ceiling {self._MAX_UNDECLARED}). Each is a future "
                f"PF.54/PF.55-class blocker — add a lowering, "
                f"fake_impl, override, or `torch_vulkan::*` shim:"
            ]
            for r in s["rows"]:
                models = ", ".join(r["models_using_it"])
                lines.append(
                    f"  - {r['op']} (models: {models}; "
                    f"suggested owner: {r['suggested_owner']})"
                )
            raise AssertionError("\n".join(lines))

    def test_audit_traces_at_least_one_model(self):
        a = self._import_audit()
        usage = a.model_op_usage()
        assert len(usage) >= 1, (
            "P7.4: model_op_usage() returned no models — make_fx or "
            "the bench registry is broken. Audit has lost regression "
            "power."
        )

    def test_cli_undeclared_section_runs(self):
        import os
        import subprocess
        import sys

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_inductor_op_coverage.py",
        )
        r = subprocess.run(
            [sys.executable, script],
            capture_output=True,
            text=True,
            check=True,
        )
        out = r.stdout
        assert "Undeclared aten ops" in out, (
            "audit CLI dropped the undeclared-ops section"
        )

    def test_markdown_report_renders(self):
        import importlib.util
        import sys
        from unittest.mock import patch

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_inductor_op_coverage.py",
        )
        spec = importlib.util.spec_from_file_location(
            "_audit_inductor_op_coverage", script
        )
        mod = importlib.util.module_from_spec(spec)
        sys.modules[spec.name] = mod
        try:
            spec.loader.exec_module(mod)
            # Skip slow model-tracing (FX make_fx on all benchmark models);
            # the structure of the report is what we're testing, not the data.
            with patch.object(mod, "_model_op_usage_uncached", return_value={}):
                out = mod.markdown_report()
        finally:
            sys.modules.pop(spec.name, None)
        for header in (
            "# Inductor op-coverage audit",
            "## Coverage summary",
            "## Wrapper-emit imports",
            "## Undeclared aten ops used by benchmark models",
        ):
            assert header in out, f"markdown report missing section: {header!r}"


class TestPF5FollowupTargets:
    """PF.5 follow-up — measurement-side regression gate that ratchets
    when inductor-expert's `mm+bias+gelu` epilogue fusion lands.

    PF.5 collapses the MLP forward chain `linear → gelu → linear → gelu
    → linear` from 8 dispatches (eager) / 5 dispatches (today, no
    epilogue) toward **3** by routing two of the three linears through
    `torch.ops.torch_vulkan.addmm_gelu_fused`. The dispatch reduction
    is the visible signal; the *useful* signal — the one the user
    actually cares about — is **GPU utilization gain**: each fused
    dispatch packs more arithmetic per host overhead, so
    `kernel_us / wall_us` should rise.

    This test asserts the post-PF.5 targets:
      (a) `dispatches_per_step <= 3` (PF.5's contract — 8 → 3)
      (b) `wall_per_step_us <= 250` (today's TRUST-on floor 302 →
          target 250 once PF.5 trims one full dispatch + Python
          wrapper line)
      (c) `kernel_us / wall_us >= 0.15` (post-PF.5 utilization floor;
          today ~0.04, expected ~0.15 once fused-op kernel time
          dominates over Python wrapper overhead)

    **Skip-mode while PF.5 is in flight**: until the in-flight
    `addmm_gelu_fused` template's slangc breakage clears (see
    inductor-expert's tracking item), the compile path raises;
    the test catches that and skips with `slangc compile broken —
    waiting for PF.5 fix`. When the fix lands, the test
    auto-activates and either passes (PF.5 hit its targets) or
    fails (PF.5 reduced dispatch count without lifting util — that's
    a real regression worth investigating).

    Cross-references P5.9's wall-time ceiling (which uses today's
    much looser floor of 800 µs/step) — when this test ratchets,
    raise `_MAX_WALL_US_PER_STEP` in `TestMLPForwardGPUUtilization`
    accordingly.

    `_BUG_ROOT_COMPONENT="codegen-epilogue-fusion"`.
    """

    _MAX_DISPATCHES_PER_STEP: int = 3
    _MAX_WALL_US_PER_STEP: float = 250.0
    _MIN_UTIL: float = 0.15
    _STEPS: int = 10

    @pytest.mark.xfail(
        strict=True,
        reason="PF.5 in-flight — fused `addmm_gelu_fused` codegen "
        "ships partially today (4 dispatches/step). Test "
        "auto-flips to passed when the third linear's path "
        "also fuses (target 3 dispatches/step + util ≥ 15%). "
        "When this xfail flips, remove the decorator and "
        "tighten `_MAX_*` constants.",
    )
    def test_post_pf5_dispatch_wall_util(self):
        import os
        import time

        os.environ.setdefault("TORCH_VULKAN_INDUCTOR_STATS", "1")
        os.environ.setdefault("TORCH_VULKAN_TRUST_INDUCTOR", "1")
        from torch_vulkan.inductor.inductor_stats import get_stats, reset_stats

        torch._dynamo.reset()
        import torch_vulkan as _tv

        m = (
            torch.nn.Sequential(
                torch.nn.Linear(256, 512),
                torch.nn.GELU(),
                torch.nn.Linear(512, 256),
                torch.nn.GELU(),
                torch.nn.Linear(256, 64),
            )
            .to("vulkan:0")
            .eval()
        )
        for p in m.parameters():
            p.requires_grad_(False)
        x = torch.randn(32, 256, device="vulkan:0")
        comp = torch.compile(m, backend="inductor")

        # Skip cleanly while PF.5's fused template has broken slangc.
        # When the upstream fix lands, this catch path stops firing
        # and the assertions below activate.
        try:
            with torch.no_grad():
                for _ in range(3):
                    comp(x)
                torch.empty(1, device="vulkan:0").cpu()
        except Exception as e:
            import pytest

            pytest.skip(
                f"PF.5 follow-up: MLP compile path is broken — "
                f"waiting for in-flight fix to land. {type(e).__name__}: "
                f"{str(e)[:200]}"
            )

        with torch.no_grad():
            reset_stats()
            _tv._c_ext._reset_perf_counters()
            t0 = time.perf_counter()
            try:
                for _ in range(self._STEPS):
                    comp(x)
                torch.empty(1, device="vulkan:0").cpu()
            except Exception as e:
                import pytest

                pytest.skip(
                    f"PF.5 follow-up: steady-state run raised — "
                    f"{type(e).__name__}: {str(e)[:200]}"
                )
            wall_us = (time.perf_counter() - t0) * 1e6

        wall_per_step = wall_us / self._STEPS
        total_dispatches = _tv._c_ext._get_dispatch_count()
        dispatches_per_step = total_dispatches / self._STEPS

        stats = get_stats()
        kernel_us = sum(e["total_us"] for e in stats.values())
        util = (kernel_us / wall_us) if (wall_us and kernel_us) else 0.0

        # (a) dispatch-count target — PF.5's primary contract.
        assert dispatches_per_step <= self._MAX_DISPATCHES_PER_STEP, (
            f"PF.5 follow-up: dispatches/step = "
            f"{dispatches_per_step:.1f} > target "
            f"{self._MAX_DISPATCHES_PER_STEP}. PF.5's "
            f"`addmm_gelu_fused` epilogue should collapse the chain "
            f"to 3 dispatches; the codegen + FX-pass shipped but "
            f"didn't reduce the count. (total={total_dispatches}, "
            f"steps={self._STEPS})."
        )
        # (b) wall-time ceiling — fewer dispatches + same kernel time
        # → less Python wrapper overhead → lower wall.
        assert wall_per_step <= self._MAX_WALL_US_PER_STEP, (
            f"PF.5 follow-up: wall_per_step_us = "
            f"{wall_per_step:.1f} > ceiling "
            f"{self._MAX_WALL_US_PER_STEP}. Dispatch count "
            f"{dispatches_per_step:.1f} hit the target but wall "
            f"didn't drop accordingly — likely Python wrapper "
            f"overhead per remaining dispatch is the new bottleneck "
            f"(see P5.11 sub-items)."
        )
        # (c) GPU utilization floor — only when stats actually report
        # kernel time (post-PF.5 it MAY be empty since the fused
        # custom op routes through eager dispatch.cpp, not
        # _KERNEL_STATS — in that case we only assert (a) and (b)).
        if kernel_us > 0:
            assert util >= self._MIN_UTIL, (
                f"PF.5 follow-up: util = {util:.3f} < floor "
                f"{self._MIN_UTIL}. Dispatch count fell to "
                f"{dispatches_per_step:.1f} but the saved kernel time "
                f"didn't materialize as utilization gain — likely a "
                f"new Python overhead path or a slower fused kernel. "
                f"(kernel_us={kernel_us:.1f}, wall_us={wall_us:.1f})"
            )


class TestVGPROccupancyGate:
    """P5.5 — VGPR / occupancy regression gate.

    Walks the canonical generic-family entry points (one per Slang
    library: pointwise, reduction, mm, norm, losses), compiles each to
    SPIR-V via slangc, and locks four proxies for register/occupancy
    pressure: workgroup_size, groupshared_vars, function_local_vars,
    instruction_count. A Slang upgrade or kernel-source change that
    bloats codegen fails this test.

    The proxies are vendor-neutral (parsed from SPIR-V) so the gate
    runs in any environment with slangc; it skips silently when slangc
    is unavailable. See `python/torch_vulkan/inductor/occupancy_audit.py`
    for the locked baseline and parsing logic.
    """

    def test_metrics_match_locked_baseline(self):
        from torch_vulkan.inductor.occupancy_audit import (
            LOCKED_OCCUPANCY,
            measure_registered,
        )

        measured = measure_registered()
        if not measured:
            import pytest

            pytest.skip("slangc unavailable — occupancy audit needs slangc")
        # Every registered entry has a locked baseline.
        assert set(measured.keys()) == set(LOCKED_OCCUPANCY.keys()), (
            f"registered={set(measured.keys())} locked={set(LOCKED_OCCUPANCY.keys())}"
        )

    def test_no_metric_grew_above_ceiling(self):
        from torch_vulkan.inductor.occupancy_audit import (
            assert_under_locked_ceilings,
            measure_registered,
        )

        if not measure_registered():
            import pytest

            pytest.skip("slangc unavailable — occupancy audit needs slangc")
        assert_under_locked_ceilings()

    def test_spirv_parser_rejects_non_spirv(self):
        import pytest
        from torch_vulkan.inductor.occupancy_audit import parse_spirv_metrics

        with pytest.raises(ValueError):
            parse_spirv_metrics(b"not a spirv binary at all xxxx")
        with pytest.raises(ValueError):
            parse_spirv_metrics(b"\x00\x00\x00\x00" * 6)


class TestPerformanceTargetDispatchCounts:
    """P5.1 — Each row in §"Performance Targets" gets a regression test.

    Locks the *current* measured forward dispatch count as a no-regression
    ceiling so future commits can't accidentally bloat the count. As
    optimizations land, each ceiling ratchets *down* toward its target
    (the second number in the assertion message). Eventually flips from
    ``<= ceiling`` to ``== target`` once the floor is verified (per the
    spec "Tightening from <= target to == target").

    Models that don't compile today (transformer_block hits the view
    fast-path blocker; resnet18 needs torchvision; miniqwen3 4L isn't
    in the benchmark registry yet) are explicit `pytest.skip` stubs so
    the contract is visible — when P4.1 unblocks the graph, removing
    the skip is a one-line follow-up.
    """

    def _measure_fwd(self, model_name: str) -> int:
        import os
        import sys

        bench_dir = os.path.normpath(
            os.path.join(os.path.dirname(__file__), "..", "benchmarks")
        )
        if bench_dir not in sys.path:
            sys.path.insert(0, bench_dir)
        import inductor_train as it
        import torch_vulkan

        # Isolate from prior recompile state — earlier tests in the suite
        # may have triggered Dynamo's automatic dynamic shapes for the same
        # model class, which collides with the C++ vulkan_view kernel's
        # SymInt unpacking (see PF.30.f).
        torch._dynamo.reset()

        builder = it._MODELS[model_name]
        model, make_inputs = builder()
        model = model.to("vulkan:0").eval()
        inputs = tuple(t.to("vulkan:0") for t in make_inputs())
        comp = torch.compile(model, backend="inductor")
        with torch.no_grad():
            comp(*inputs)  # warmup
            torch_vulkan._c_ext._reset_perf_counters()
            comp(*inputs)
            return torch_vulkan._c_ext._get_dispatch_count()

    def test_mlp_forward_under_ceiling(self):
        # 2026-04-28 measured: 8 dispatches. Performance target: 3.
        d = self._measure_fwd("mlp")
        assert d <= 8, f"MLP fwd: {d} > 8 (target=3, current=8)"

    def test_mnist_cnn_forward_under_ceiling(self):
        # 2026-04-28 measured: 13 dispatches. No specific Performance
        # Targets entry — locked as a no-regression on the canonical
        # mnist_cnn benchmark workload until a target row is added.
        d = self._measure_fwd("mnist_cnn")
        assert d <= 13, f"mnist_cnn fwd: {d} > 13 (target=ratchet-down)"

    def test_resnet18_forward_under_ceiling(self):
        import pytest

        try:
            import torchvision  # noqa: F401
        except ImportError:
            pytest.skip("torchvision not installed — resnet18 unavailable")
        # Performance target: 18. Current ceiling: 81 (eager equivalent
        # on the Vulkan eager backend, per Performance Targets table).
        # Once compiled forward succeeds end-to-end, lock the actual
        # measured value here.
        d = self._measure_fwd("resnet18")
        assert d <= 81, f"resnet18 fwd: {d} > 81 (target=18, eager=81)"

    def test_transformer_block_forward_under_ceiling(self):
        import pytest

        # Compiled forward currently fails at `aten.reshape.default` due
        # to the FakeTensor view fast-path that P4.1 tracks (stride
        # mismatch on broadcasted views). When that lands, remove this
        # skip and lock the measured count.
        pytest.skip(
            "transformer_block forward blocked on view fast-path "
            "(P4.1 upstream FakeTensor fix)"
        )

    def test_miniqwen3_4l_forward_under_ceiling(self):
        import pytest

        # Not in the inductor_train.py model registry yet. Performance
        # target row: 24 fwd / 50 bwd. Awaits backward-compile unblock
        # (P4.1) before adding to the registry.
        pytest.skip("miniqwen3_4l not in benchmark registry yet — awaits P4.1")


class TestBufferPoolReuseRate:
    """P5.4 — Buffer-pool hit rate ≥ 90% in the realistic acquire/release
    pattern wrapper code emits.

    Inductor's static-buffer reuse means a single repeated compiled
    graph has zero per-step *acquires* in steady state — the pool's
    value is across graph boundaries (varying input shapes, separate
    forward/backward graphs, multiple compiled functions sharing
    similar buffer shapes). This test exercises the pool directly with
    that pattern to lock its hit-rate contract, plus a smoke test
    confirming the wrapper integrates with the pool (enabled by default).
    """

    def test_pool_hit_rate_above_90pct_on_repeated_shape_traffic(self):
        from torch_vulkan.inductor import buffer_pool as bp

        bp._reset_disabled_cache()
        bp.reset_pool()

        # Realistic mix: 4 distinct (size, stride, dtype) shapes,
        # each released and re-acquired 25 times. First acquire of
        # each shape misses; subsequent 24 hit. Hit rate = 96%.
        shapes = [
            ((4, 64), (64, 1), torch.float32),
            ((4, 128), (128, 1), torch.float32),
            ((4, 256), (256, 1), torch.float32),
            ((4, 64), (64, 1), torch.float16),
        ]
        for size, stride, dt in shapes:
            t0 = torch.empty_strided(size, stride, dtype=dt, device="vulkan:0")
            bp.vulkan_pool_release(t0)
            for _ in range(25):
                pooled = bp.vulkan_pool_acquire(size, stride, dt)
                if pooled is None:
                    pooled = torch.empty_strided(
                        size, stride, dtype=dt, device="vulkan:0"
                    )
                bp.vulkan_pool_release(pooled)
        s = bp.pool_stats()
        rate = s["hits"] / max(1, s["acquires"])
        assert rate >= 0.9, f"buffer-pool hit rate {rate:.3f} < 0.9; stats={s}"

    def test_eviction_rate_under_realistic_pattern_under_ceiling(self):
        from torch_vulkan.inductor import buffer_pool as bp

        bp._reset_disabled_cache()
        bp.reset_pool()

        shapes = [
            ((4, 64), (64, 1), torch.float32),
            ((4, 128), (128, 1), torch.float32),
            ((4, 256), (256, 1), torch.float32),
            ((4, 64), (64, 1), torch.float16),
        ]
        for size, stride, dt in shapes:
            t0 = torch.empty_strided(size, stride, dtype=dt, device="vulkan:0")
            bp.vulkan_pool_release(t0)
            for _ in range(25):
                pooled = bp.vulkan_pool_acquire(size, stride, dt)
                if pooled is None:
                    pooled = torch.empty_strided(
                        size, stride, dtype=dt, device="vulkan:0"
                    )
                bp.vulkan_pool_release(pooled)
        s = bp.pool_stats()
        # In this pattern every release immediately follows an acquire,
        # so the bucket holds at most 1 item — well under per-key cap.
        # Eviction fires here only on a regression (cap shrink, key
        # collisions, etc.).
        assert s["evictions"] == 0, (
            f"unexpected evictions={s['evictions']} under steady "
            f"acquire/release; stats={s}. See P7.7."
        )

    def test_wrapper_pool_integration_when_enabled(self):
        """When the pool is enabled (default), the compiled wrapper releases
        its end-of-life buffers to the pool. Asserts releases > 0 after
        a single compiled step — that's the live wrapper integration
        contract; the *steady-state* acquires-vs-releases ratio depends
        on Inductor's static-buffer-reuse (often zero acquires per step).
        """
        import os
        import sys

        from torch_vulkan.inductor import buffer_pool as bp

        bp._reset_disabled_cache()
        bp.reset_pool()

        bench_dir = os.path.normpath(
            os.path.join(os.path.dirname(__file__), "..", "benchmarks")
        )
        if bench_dir not in sys.path:
            sys.path.insert(0, bench_dir)
        import inductor_train as it

        builder = it._MODELS["mlp"]
        model, make_inputs = builder()
        model = model.to("vulkan:0").eval()
        inputs = tuple(t.to("vulkan:0") for t in make_inputs())
        comp = torch.compile(model, backend="inductor")
        with torch.no_grad():
            comp(*inputs)
            comp(*inputs)
        s = bp.pool_stats()
        assert s["releases"] > 0, (
            f"wrapper failed to release any buffers to the pool: {s}"
        )

    def test_wrapper_teardown_eviction_rate_under_ceiling(self):
        """P7.7.1 — Pool cap policy for compile-teardown bursts.

        At the end of each compiled-graph step the wrapper releases N
        end-of-life buffers in a row. With `_GLOBAL_CAP=64` and
        Inductor freeing > 64 buffers, the tail evicts. Today's MLP
        forward × 2 steps measures evictions ≤ ~80 across all releases.
        Locked here as a no-regression ceiling so a future graph that
        leaks more buffers (or a smaller cap) is caught in CI. Ratchets
        DOWN as the wrapper learns to release more selectively or as
        Inductor's static-buffer-reuse covers more cases.
        """
        import os
        import sys

        from torch_vulkan.inductor import buffer_pool as bp

        bp._reset_disabled_cache()
        bp.reset_pool()

        bench_dir = os.path.normpath(
            os.path.join(os.path.dirname(__file__), "..", "benchmarks")
        )
        if bench_dir not in sys.path:
            sys.path.insert(0, bench_dir)
        import inductor_train as it

        builder = it._MODELS["mlp"]
        model, make_inputs = builder()
        model = model.to("vulkan:0").eval()
        inputs = tuple(t.to("vulkan:0") for t in make_inputs())
        comp = torch.compile(model, backend="inductor")
        with torch.no_grad():
            for _ in range(3):
                comp(*inputs)
        s = bp.pool_stats()
        # No-regression ceiling — keep evictions bounded; today's
        # MLP × 3 steps measures ≤ 200 across all releases.
        assert s["evictions"] <= 200, (
            f"wrapper teardown eviction count {s['evictions']} > 200; "
            f"stats={s}. See P7.7.1."
        )


class TestColdCompileTimeBudget:
    """P5.3 — Cold-compile time budget.

    Locks the cold-compile time of MLP forward as a no-regression
    ceiling. Spec target: < 1_000_000 us (1 s) once Slang modules +
    spec constants reduce slangc invocations 10–20×. Today's measured
    floor on the agent's RDNA1 box (slang-2026.5.2, modules pre-warmed,
    fresh kernel cache): ~6_000_000 us / 25 cold compiles. Ceiling
    set generously (10_000_000 us) to absorb run-to-run noise; ratchet
    down as cold-compile fan-in shrinks.
    """

    _COLD_COMPILE_CEILING_US = 10_000_000

    def test_mlp_forward_cold_compile_under_ceiling(self):
        import os
        import shutil
        import sys

        import pytest

        if not os.environ.get("SLANGC"):
            pytest.skip("SLANGC env var not set — cold-compile path inactive")

        bench_dir = os.path.normpath(
            os.path.join(os.path.dirname(__file__), "..", "benchmarks")
        )
        if bench_dir not in sys.path:
            sys.path.insert(0, bench_dir)
        import inductor_train as it
        from torch_vulkan.inductor.runtime import (
            _COMPILE_STATS,
            _DISK_CACHE_DIR,
            _cache_by_hash,
            _cache_by_key,
            precompile_shader_libs,
            reset_compile_stats,
        )

        # Pre-warm shader-lib modules so this test doesn't double-count
        # foundation work; that's the spec's "(modules cached)" caveat.
        precompile_shader_libs()
        # Clear in-memory kernel caches and the disk SPIR-V cache so
        # every kernel slangc-compiles fresh.
        _cache_by_hash.clear()
        _cache_by_key.clear()
        shutil.rmtree(_DISK_CACHE_DIR, ignore_errors=True)
        reset_compile_stats()

        builder = it._MODELS["mlp"]
        model, make_inputs = builder()
        model = model.to("vulkan:0").eval()
        inputs = tuple(t.to("vulkan:0") for t in make_inputs())
        comp = torch.compile(model, backend="inductor")
        with torch.no_grad():
            comp(*inputs)

        cold_us = _COMPILE_STATS["cold_compile_us"]
        n_cold = _COMPILE_STATS["cold_compiles"]
        ceiling = self._COLD_COMPILE_CEILING_US
        assert cold_us < ceiling, (
            f"MLP cold-compile time {cold_us:.0f}us "
            f"({n_cold} cold compiles) > ceiling {ceiling}us. "
            f"Spec target is < 1_000_000us; current floor ~6_000_000us. "
            f"See P5.3 in docs/10-inductor-backend.md."
        )


class TestNoWaterfallOutlier:
    """P5.2 — Per-kernel waterfall: no undocumented kernel > 5%.

    Runs each benchmark with `TORCH_VULKAN_INDUCTOR_STATS=1` and walks
    `inductor_stats.summary()`. Any kernel taking > 5% of total time
    must either:
      (a) be in `_DOCUMENTED_OUTLIERS` (known dominant kernel with
          reason — e.g. the only inductor-emitted kernel on a tiny
          workload, or a fundamental compute kernel), or
      (b) have an active P7 (Continuous Discovery) roadmap entry to
          shrink it.

    A new commit that introduces an outlier without documenting it fails
    here. The check is a no-op when the workload has < 5 distinct
    inductor-emitted kernels (5% threshold is meaningless on tiny graphs;
    everything is an outlier by definition).
    """

    # Documented dominant kernels. Each entry is `cache_key_prefix:
    # reason`. As workloads grow, this list moves entries OUT (P7 work
    # shrinks them) rather than IN.
    _DOCUMENTED_OUTLIERS: dict[str, str] = {
        # MLP forward today emits a single fused inductor kernel
        # (3-linear + 2-gelu chain reduces to one combo dispatch
        # outside the addmm extern templates). Until ResNet/Transformer
        # forwards compile end-to-end (P4.1 unblock) and add multiple
        # inductor-emitted kernels, MLP's lone kernel is 100% by
        # definition. Tracked under P5.2-followup.
        "vulkan_kernel_0_": "MLP fused pointwise — single inductor kernel today",
    }

    def _is_documented(self, kernel_key: str) -> bool:
        return any(kernel_key.startswith(p) for p in self._DOCUMENTED_OUTLIERS)

    def _run_and_check(self, model_name: str) -> None:
        import os
        import sys

        os.environ["TORCH_VULKAN_INDUCTOR_STATS"] = "1"
        bench_dir = os.path.normpath(
            os.path.join(os.path.dirname(__file__), "..", "benchmarks")
        )
        if bench_dir not in sys.path:
            sys.path.insert(0, bench_dir)
        import inductor_train as it
        from torch_vulkan.inductor.inductor_stats import reset_stats, summary

        # Isolate from prior recompile state — see _measure_fwd / PF.30.f.
        torch._dynamo.reset()

        builder = it._MODELS[model_name]
        model, make_inputs = builder()
        model = model.to("vulkan:0").eval()
        inputs = tuple(t.to("vulkan:0") for t in make_inputs())
        comp = torch.compile(model, backend="inductor")
        with torch.no_grad():
            comp(*inputs)
            reset_stats()
            for _ in range(20):
                comp(*inputs)
            torch.empty(1, device="vulkan:0").cpu()  # sync

        s = summary(top_n=20)
        if s["n_kernels"] < 5:
            return  # threshold meaningless on tiny graphs
        if s["total_us"] <= 0:
            return  # stats off — nothing to check
        for k, us, _cnt, _avg, _h in s["top"]:
            pct = us / s["total_us"] * 100
            if pct > 5.0 and not self._is_documented(k):
                raise AssertionError(
                    f"{model_name}: kernel {k} = {pct:.1f}% of step "
                    f"(>5%, undocumented). Add a P7 entry to shrink "
                    f"it OR add the cache-key prefix to "
                    f"`TestNoWaterfallOutlier._DOCUMENTED_OUTLIERS` "
                    f"with a reason."
                )

    def test_mlp_forward(self):
        self._run_and_check("mlp")

    def test_mnist_cnn_forward(self):
        self._run_and_check("mnist_cnn")


class TestMnistCnnEmitsKernel:
    """P7.6 / PF.30.a — `mnist_cnn` forward must produce at least one
    inductor-emitted vulkan kernel.

    Pre-PF.30.a: `_patched_conv2d` carried `@torch.compiler.disable`,
    fragmenting the FX graph at every Conv2d call so 0 inductor kernels
    emitted. PF.30.a replaces the decorator with a
    `torch_vulkan::conv2d_with_optional_bias` custom_op shim — Dynamo
    captures it as a single FX node and the surrounding pointwise /
    pool operations now fuse into ≥ 1 inductor kernel.
    """

    def test_n_kernels_ge_one(self):
        import os
        import sys

        os.environ["TORCH_VULKAN_INDUCTOR_STATS"] = "1"
        bench_dir = os.path.normpath(
            os.path.join(os.path.dirname(__file__), "..", "benchmarks")
        )
        if bench_dir not in sys.path:
            sys.path.insert(0, bench_dir)
        import inductor_train as it
        from torch_vulkan.inductor.inductor_stats import reset_stats, summary

        # Isolate from prior recompile state — see PF.30.f.
        torch._dynamo.reset()

