class TestGradientReleaseE2ECompiled:
    """PF.42 e2e floor — gradient-class release fires in compiled training.

    RESOLVED (2026-05-06): After a pool-enabled compiled training step,
    ``release_count_for_class('gradient')`` is ≥ 1, confirming that
    ``_install_zero_grad_release_hook`` fires at runtime.

    Stage tag: ``BUG_ROOT="runtime"``.
    """

    _BUG_ROOT_COMPONENT = "runtime"

    def test_gradient_class_releases_on_compiled_zero_grad(self):
        """Pool-enabled compiled training: ``release_count_for_class(
        'gradient') >= 1`` after 2 steps confirms the hook fired."""
        import torch.nn as nn
        from torch_vulkan.inductor import buffer_pool

        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()
