class TestN1bSearchsortedAndRepeatInterleave:
    """N.1.b: ``aten.searchsorted`` CPU-roundtrip baseline tests.

    These tests exercise the PrivateUse1 override path.  N.1.b-fast
    (TestN1bFastSearchsorted) replaces the CPU roundtrip with a GPU
    parallel-binary-search shader.
    """

    """N.1.b: ``aten.searchsorted`` CPU-roundtrip baseline tests.

    These tests exercise the PrivateUse1 override path.  N.1.b-fast
    (TestN1bFastSearchsorted) replaces the CPU roundtrip with a GPU
    parallel-binary-search shader.
    """
    """N.1.b: ``aten.searchsorted`` CPU-roundtrip baseline tests.

    These tests exercise the PrivateUse1 override path.  N.1.b-fast
    (TestN1bFastSearchsorted) replaces the CPU roundtrip with a GPU
    parallel-binary-search shader.
    """
    """N.1.b: ``aten.searchsorted`` CPU-roundtrip baseline tests.

    These tests exercise the PrivateUse1 override path.  N.1.b-fast
    (TestN1bFastSearchsorted) replaces the CPU roundtrip with a GPU
    parallel-binary-search shader.
    """
    """N.1.b: ``aten.searchsorted`` CPU-roundtrip baseline tests.

    These tests exercise the PrivateUse1 override path.  N.1.b-fast
    (TestN1bFastSearchsorted) replaces the CPU roundtrip with a GPU
    parallel-binary-search shader.
    """
    """N.1.b: ``aten.searchsorted`` CPU-roundtrip baseline tests.

    These tests exercise the PrivateUse1 override path.  N.1.b-fast
    (TestN1bFastSearchsorted) replaces the CPU roundtrip with a GPU
    parallel-binary-search shader.
    """
    """N.1.b: ``aten.searchsorted`` CPU-roundtrip baseline tests.

    These tests exercise the PrivateUse1 override path.  N.1.b-fast
    (TestN1bFastSearchsorted) replaces the CPU roundtrip with a GPU
    parallel-binary-search shader.
    """

    def test_searchsorted_correctness_n_1_b(self):
        @torch.compile(backend="inductor")
        def fn(s, v):
            return torch.searchsorted(s, v)

        s = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(s, v)
        expected = torch.tensor([1, 2, 3, 4], dtype=y.dtype)
        torch.testing.assert_close(y.cpu(), expected)

    def test_searchsorted_right_correctness_n_1_b(self):
        @torch.compile(backend="inductor")
        def fn(s, v):
            return torch.searchsorted(s, v, right=True)

        s = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(s, v)
        expected = torch.tensor([1, 2, 3, 4], dtype=y.dtype)
        torch.testing.assert_close(y.cpu(), expected)

    def test_repeat_interleave_tensor_n_1_b(self):
        @torch.compile(backend="inductor")
        def fn(x, r):
            return x.repeat_interleave(r)

        x = torch.tensor([10.0, 20.0, 30.0], device="vulkan:0")
        r = torch.tensor([1, 2, 3], dtype=torch.int64, device="vulkan:0")
        y = fn(x, r)
        expected = torch.tensor([10.0, 20.0, 20.0, 30.0, 30.0, 30.0])
        torch.testing.assert_close(y.cpu(), expected)


