# OP.8 — aten.bucketize GPU path (wired via searchsorted shader)


class TestBucketizeGPU:
    """GPU-native ``aten.bucketize`` via ``bucket.slang`` searchsorted shader.

    bucketize and searchsorted are semantically identical — both find
    insertion indices of values in a sorted sequence.  We reuse the same
    parallel-binary-search compute shader from ``shaders/lib/bucket.slang``.
    """

    def test_bucketize_gpu_matches_cpu(self):
        """GPU bucketize matches CPU reference for left-side insertion."""

        @torch.compile(backend="inductor")
        def fn(b, v):
            return torch.bucketize(v, b)

        b = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(b, v)
        expected = torch.tensor([1, 2, 3, 4], dtype=y.dtype)
        torch.testing.assert_close(y.cpu(), expected)

    def test_bucketize_gpu_right_matches_cpu(self):
        """GPU bucketize right=True matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(b, v):
            return torch.bucketize(v, b, right=True)

        b = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(b, v)
        expected = torch.tensor([1, 2, 3, 4], dtype=y.dtype)
        torch.testing.assert_close(y.cpu(), expected)

    def test_bucketize_gpu_large(self):
        """GPU bucketize on larger tensors works correctly."""

        @torch.compile(backend="inductor")
        def fn(b, v):
            return torch.bucketize(v, b)

        torch.manual_seed(42)
        b = torch.linspace(0.0, 100.0, 500, device="vulkan:0")
        v = torch.rand(1500, device="vulkan:0") * 100.0
        y = fn(b, v)
        expected = torch.bucketize(v.cpu(), b.cpu())
        torch.testing.assert_close(y.cpu(), expected)

    def test_bucketize_gpu_out_int32(self):
        """GPU bucketize with out_int32=True produces int32 output."""

        @torch.compile(backend="inductor")
        def fn(b, v):
            return torch.bucketize(v, b, out_int32=True)

        b = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(b, v)
        assert y.dtype == torch.int32
        expected = torch.tensor([1, 2, 3, 4], dtype=torch.int32)
        torch.testing.assert_close(y.cpu(), expected)

    def test_bucketize_gpu_scalar(self):
        """GPU bucketize with scalar value works."""
        b = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        y = torch.bucketize(torch.tensor(4.0, device="vulkan:0"), b)
        expected = torch.tensor(2)
        torch.testing.assert_close(y.cpu(), expected)


