class TestOp11Multinomial:
    """OP.11: ``aten.multinomial`` decomposes through cumsum + Philox
    rand + searchsorted (inverse-CDF method).  Only ``replacement=True``
    is supported for now; ``replacement=False`` falls through to the
    upstream path."""

    def test_op11_multinomial_compiles(self):
        """Multinomial with replacement=True compiles without graph-break."""

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(probs, num_samples):
            return torch.multinomial(probs, num_samples, replacement=True)

        probs = torch.tensor([0.1, 0.2, 0.3, 0.4], device="vulkan:0")
        result = fn(probs, 10)
        assert result.shape == (10,)
        assert result.dtype == torch.int64
        assert result.device.type == "vulkan"

    def test_op11_multinomial_valid_samples(self):
        """All samples are within [0, num_categories)."""

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(probs, num_samples):
            return torch.multinomial(probs, num_samples, replacement=True)

        num_categories = 5
        probs = torch.ones(num_categories, device="vulkan:0")
        num_samples = 100
        result = fn(probs, num_samples).cpu()
        assert (result >= 0).all()
        assert (result < num_categories).all()

    def test_op11_multinomial_distribution(self):
        """Over many samples, the empirical distribution roughly matches
        the input probabilities (replacement=True)."""

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(probs, num_samples):
            return torch.multinomial(probs, num_samples, replacement=True)

        torch.manual_seed(42)
        probs = torch.tensor([0.1, 0.2, 0.3, 0.4], device="vulkan:0")
        num_samples = 5000
        result = fn(probs, num_samples).cpu()

        # Count empirical frequencies
        counts = torch.zeros(4, dtype=torch.float32)
        for i in range(4):
            counts[i] = (result == i).sum().float()
        empirical = counts / num_samples

        # Allow 5% absolute tolerance for each category
        expected = probs.cpu()
        torch.testing.assert_close(empirical, expected, atol=0.05, rtol=0.0)

    def test_op11_multinomial_replacement_true_explicit(self):
        """Explicit replacement=True flag compiles and produces valid output."""

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(probs, num_samples):
            return torch.multinomial(probs, num_samples, replacement=True)

        probs = torch.tensor([[0.1, 0.2, 0.7], [0.5, 0.3, 0.2]], device="vulkan:0")
        result = fn(probs, 8)
        expected_shape = (2, 8)
        assert result.shape == expected_shape, (
            f"Expected shape {expected_shape}, got {result.shape}"
        )
        assert result.dtype == torch.int64
        assert result.device.type == "vulkan"

    def test_op11_multinomial_2d_batched(self):
        """Batched (2D) probabilities work: [B, C] → [B, N]."""

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(probs, num_samples):
            return torch.multinomial(probs, num_samples, replacement=True)

        torch.manual_seed(123)
        probs = torch.tensor(
            [[0.1, 0.2, 0.3, 0.4], [0.4, 0.3, 0.2, 0.1]],
            device="vulkan:0",
        )
        num_samples = 50
        result = fn(probs, num_samples).cpu()
        assert result.shape == (2, num_samples)
        # Row 0 should heavily favor category 3
        row0_counts = torch.bincount(result[0], minlength=4)
        assert row0_counts[3] > row0_counts[0], (
            f"Row 0: expected cat 3 most frequent, got {row0_counts}"
        )
        # Row 1 should heavily favor category 0
        row1_counts = torch.bincount(result[1], minlength=4)
        assert row1_counts[0] > row1_counts[3], (
            f"Row 1: expected cat 0 most frequent, got {row1_counts}"
        )

    def test_op11_multinomial_zero_probability(self):
        """Categories with zero probability are never sampled."""

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(probs, num_samples):
            return torch.multinomial(probs, num_samples, replacement=True)

        torch.manual_seed(42)
        num_categories = 4
        probs = torch.tensor([1.0, 0.0, 1.0, 0.0], device="vulkan:0")
        num_samples = 200
        result = fn(probs, num_samples).cpu()
        # Categories 1 and 3 should never appear
        assert (result != 1).all(), "Zero-prob category 1 was sampled!"
        assert (result != 3).all(), "Zero-prob category 3 was sampled!"
        # Categories 0 and 2 should be equally likely
        count_0 = (result == 0).sum().item()
        count_2 = (result == 2).sum().item()
        # With 200 samples, each should get ~100. Allow ±30.
        assert 70 <= count_0 <= 130, f"Expected ~100 samples for cat 0, got {count_0}"
        assert 70 <= count_2 <= 130, f"Expected ~100 samples for cat 2, got {count_2}"


