    def test_cgm1_abs_backward_autodiff(self):
        """CG.M1: abs backward matches CPU autograd."""
        torch._dynamo.reset()
        torch.manual_seed(42)

        x_cpu = torch.randn(4, 8, requires_grad=True)
        y_cpu = torch.abs(x_cpu).sum()
        y_cpu.backward()
        grad_cpu = x_cpu.grad.clone()

        x = x_cpu.detach().to("vulkan:0").requires_grad_(True)

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.abs(x).sum()

        loss = fn(x)
        loss.backward()
        assert x.grad is not None
        torch.testing.assert_close(x.grad.cpu(), grad_cpu, rtol=1e-3, atol=1e-3)

