    def test_d2a_dynamic_batch_bn_compiles(self):
        """BatchNorm over dynamic batch compiles without NotImplementedError."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:
            import torch.nn as nn

            class M(nn.Module):
                def __init__(self):
                    super().__init__()
                    self.bn = nn.BatchNorm2d(16)

                def forward(self, x):
                    return self.bn(x)

            m = M().to("vulkan:0").eval()
            fn = torch.compile(m, backend="inductor", dynamic=True)

            # Warmup — must not raise DynamicShapeNotImplemented
            x = torch.randn(4, 16, 8, 8, device="vulkan:0")
            fn(x)

            for B in [7, 13]:
                x_vk = torch.randn(B, 16, 8, 8, device="vulkan:0")
                fn(x_vk)
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]

