class TestCGM5MatmulBackward:
    """CG.M5 — Matmul backward via [Differentiable] tile_inner_madd.

    Validates that the single-kernel matmul backward template
    (slang_mm_bwd.py.jinja) compiles and produces correct gradients
    matching CPU reference at rtol=1e-3.
    """

    def _render_and_check_syntax(self, tile_m=32, tile_n=32, tile_k=16):
        """Helper: render the template and verify Slang syntax is valid."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        from torch_vulkan.inductor.vulkan_template_caller import _render_mm_bwd_slang

        src = _render_mm_bwd_slang(tile_m, tile_n, tile_k)
        assert src, "_render_mm_bwd_slang returned empty string"
        assert "tile_inner_madd" in src, "Template should contain tile_inner_madd"
        assert "[Differentiable]" in src, (
            "Template should contain [Differentiable] annotation"
        )
        assert "bwd_diff" in src, "Template should contain bwd_diff call"

    def test_cgm5_mm_bwd_syntax(self):
        """The rendered mm backward template passes Slang syntax checks."""
        self._render_and_check_syntax()

    def test_cgm5_bwd_template_registry_entries(self):
        """BWD_TEMPLATE_REGISTRY has CG.M5 entries for mm/bmm/addmm."""
