class TestCGM9BackwardDerivative:
    """CG.M9 — [BackwardDerivative] audit + expansion.

    Slang's autodiff (bwd_diff) produces correct but sometimes-suboptimal
    backward code. [BackwardDerivative(fast_bwd)] tells slangc to use an
    optimized hand-written backward instead of the autodiff-generated one.

    CG.M9 target: ≥27 [BackwardDerivative] annotations across
    lib/{pointwise,losses,norm}.slang, with quality audits on each.
    """

    # ── annotation inventory ──────────────────────────────────────────
    _ANNOTATED_POINTWISE = {
        "relu_fast_bwd",
        "sigmoid_fast_bwd",
        "tanh_fast_bwd",
        "gelu_fast_bwd",
        "silu_fast_bwd",
        "elu_fast_bwd",
        "hardswish_fast_bwd",
        "hardsigmoid_fast_bwd",
        "softplus_fast_bwd",
        "mish_fast_bwd",
        "leaky_relu_fast_bwd",
        # CG.M9 additions:
        "expm1_fast_bwd",
        "log1p_fast_bwd",
        "abs_fast_bwd",
        "neg_fast_bwd",
        "sqrt_fast_bwd",
        "reciprocal_fast_bwd",
        "erf_fast_bwd",
        "erfc_fast_bwd",
        "atan2_fast_bwd",
        "hypot_fast_bwd",
        "max_fast_bwd",
        "min_fast_bwd",
    }

    _ANNOTATED_LOSSES = {
        "mse_elem_bwd",
        "l1_elem_bwd",
        "smooth_l1_elem_bwd",
        "huber_elem_bwd",
        "bce_elem_bwd",
        "bce_with_logits_elem_bwd",
        "kl_div_elem_bwd",
    }

    _ANNOTATED_NORM = {
        "ln_affine_elem_bwd",
        "ln_no_affine_elem_bwd",
        "rms_affine_elem_bwd",
        "rms_no_affine_elem_bwd",
    }

    # [Differentiable] functions that intentionally DON'T need
    # [BackwardDerivative] because their backward is either:
    #   (a) a Slang built-in intrinsic that slangc already knows
    #       (sin, cos, exp, log, etc. are [BackwardDifferentiable]
    #       in Slang's stdlib), or
    #   (b) a CG.M4 chain function meant to be composed via bwd_diff
    #       with reduction backward (layer_norm_chain, etc.).
    _VERIFIED_AUTODIFF_ONLY = {
        # pointwise — Slang built-in intrinsics:
        "sin_fwd",
        "cos_fwd",
        "tan_fwd",
        "asin_fwd",
        "acos_fwd",
        "atan_fwd",
        "sinh_fwd",
        "cosh_fwd",
        "asinh_fwd",
        "acosh_fwd",
        "atanh_fwd",
        "exp_fwd",
        "exp2_fwd",
        "log_fwd",
        "log2_fwd",
        "log10_fwd",
        "rsqrt_fwd",
        # pointwise — binary / special (left to autodiff until CG.M2/M3):
        "pow_fwd",
        "copysign_fwd",
        "erfinv_fwd",
        "lgamma_fwd",
        "digamma_fwd",
        "ndtri_fwd",
        "i0_fwd",
        "i0e_fwd",
        "i1_fwd",
        "i1e_fwd",
        # norm — CG.M4 chain functions (composed via bwd_diff):
        "layer_norm_chain",
        "layer_norm_chain_no_affine",
        "rms_norm_chain",
        "rms_norm_chain_no_affine",
    }

    # ── helpers ────────────────────────────────────────────────────────

    @staticmethod
    def _extract_annotations(filepath):
        """Parse [BackwardDerivative(...)] annotations from a .slang file."""
        import re

        names = set()
        with open(filepath) as f:
            for line in f:
                if line.lstrip().startswith("//"):
                    continue
                m = re.search(r"\[BackwardDerivative\((\w+)\)\]", line)
                if m:
                    names.add(m.group(1))
        return names

    @staticmethod
    def _extract_differentiable(filepath):
        """Parse [Differentiable] public float fname(...) from a .slang file."""
        import re

        names = set()
        with open(filepath) as f:
            content = f.read()
        pattern = (
            r"\[Differentiable\](?:\s*\[\w+\(\w+\)\])*\s*public\s+float\s+(\w+)\s*\("
        )
        for m in re.finditer(pattern, content):
            names.add(m.group(1))
        return names

    # ── count target ──────────────────────────────────────────────────

    def test_cgm9_backward_derivative_count_meets_target(self):
        """≥ 27 [BackwardDerivative] annotations exist across the three lib files."""
        import os

        lib_dir = os.path.join(
            os.path.dirname(__file__),
            "..",
            "shaders",
            "lib",
        )
        total = 0
        for fname in ("pointwise.slang", "losses.slang", "norm.slang"):
            path = os.path.join(lib_dir, fname)
            annotations = self._extract_annotations(path)
            total += len(annotations)

        assert total >= 27, (
            f"CG.M9: expected >=27 [BackwardDerivative] annotations, got {total}"
        )

    # ── mathematical correctness ──────────────────────────────────────

    def test_cgm9_erf_fast_bwd_matches_autodiff(self):
        """erf fast backward formula matches PyTorch autograd.

        d/dx erf(x) = 2/sqrt(pi) * exp(-x^2)
        """
        import math

        x = torch.linspace(-3.0, 3.0, 1001, requires_grad=True)
        y = torch.erf(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = 2.0 / math.sqrt(math.pi) * torch.exp(-(x.detach() ** 2))

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    def test_cgm9_erfc_fast_bwd_matches_autodiff(self):
        """erfc fast backward formula matches PyTorch autograd.

        d/dx erfc(x) = -2/sqrt(pi) * exp(-x^2)
        """
        import math

        x = torch.linspace(-3.0, 3.0, 1001, requires_grad=True)
        y = torch.erfc(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = -2.0 / math.sqrt(math.pi) * torch.exp(-(x.detach() ** 2))

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    def test_cgm9_log1p_fast_bwd_matches_autodiff(self):
        """log1p fast backward formula matches PyTorch autograd.

        d/dx log1p(x) = 1/(1+x)
        """
        x = torch.linspace(-0.5, 3.0, 1001, requires_grad=True)
        y = torch.log1p(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = 1.0 / (1.0 + x.detach())

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    def test_cgm9_expm1_fast_bwd_matches_autodiff(self):
        """expm1 fast backward formula matches PyTorch autograd.

        d/dx expm1(x) = exp(x)
        """
        x = torch.linspace(-3.0, 3.0, 1001, requires_grad=True)
        y = torch.expm1(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = torch.exp(x.detach())

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    def test_cgm9_abs_fast_bwd_matches_autodiff(self):
        """abs fast backward formula matches PyTorch autograd.

        d/dx |x| = sign(x), with subgradient 0 at x=0.
        """
        x = torch.linspace(-3.0, 3.0, 1001, requires_grad=True)
        y = torch.abs(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = torch.sign(x.detach())

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    def test_cgm9_sqrt_fast_bwd_matches_autodiff(self):
        """sqrt fast backward formula matches PyTorch autograd.

        d/dx sqrt(x) = 1/(2*sqrt(x))
        """
        x = torch.linspace(0.01, 3.0, 1001, requires_grad=True)
        y = torch.sqrt(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = 1.0 / (2.0 * torch.sqrt(x.detach()))

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    def test_cgm9_reciprocal_fast_bwd_matches_autodiff(self):
        """reciprocal fast backward formula matches PyTorch autograd.

        d/dx (1/x) = -1/x^2
        """
        x = torch.linspace(0.5, 3.0, 1001, requires_grad=True)
        y = torch.reciprocal(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = -1.0 / (x.detach() ** 2)

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    def test_cgm9_atan2_fast_bwd_matches_autodiff(self):
        """atan2 fast backward formula matches PyTorch autograd.

        d/dy atan2(y,x) = x/(x^2+y^2)
        d/dx atan2(y,x) = -y/(x^2+y^2)
        """
        y = torch.linspace(-3.0, 3.0, 101, requires_grad=True)
        x = torch.linspace(0.5, 3.0, 101, requires_grad=True)
        z = torch.atan2(y, x)
        z.sum().backward()
        autodiff_gy = y.grad.clone()
        autodiff_gx = x.grad.clone()

        denom = x.detach() ** 2 + y.detach() ** 2
        fast_gy = x.detach() / denom
        fast_gx = -y.detach() / denom

        torch.testing.assert_close(fast_gy, autodiff_gy, rtol=1e-6, atol=1e-8)
        torch.testing.assert_close(fast_gx, autodiff_gx, rtol=1e-6, atol=1e-8)

    def test_cgm9_hypot_fast_bwd_matches_autodiff(self):
        """hypot fast backward formula matches PyTorch autograd.

        d/da hypot(a,b) = a / hypot(a,b)
        d/db hypot(a,b) = b / hypot(a,b)
        """
        a = torch.linspace(-3.0, 3.0, 101, requires_grad=True)
        b = torch.linspace(0.5, 3.0, 101, requires_grad=True)
        z = torch.hypot(a, b)
        z.sum().backward()
        autodiff_ga = a.grad.clone()
        autodiff_gb = b.grad.clone()

        h = torch.hypot(a.detach(), b.detach())
        fast_ga = a.detach() / h
        fast_gb = b.detach() / h

        torch.testing.assert_close(fast_ga, autodiff_ga, rtol=1e-6, atol=1e-8)
        torch.testing.assert_close(fast_gb, autodiff_gb, rtol=1e-6, atol=1e-8)

    def test_cgm9_max_fast_bwd_matches_autodiff(self):
        """max fast backward formula matches PyTorch autograd.

        d/da max(a,b) = 1 if a >= b else 0
        d/db max(a,b) = 1 if a < b else 0
        Inputs are constructed without ties so the convention at equality
        is not exercised (both PyTorch and the fast path are consistent
        on strict inequalities).
        """
        a = torch.linspace(0.0, 1.0, 101, requires_grad=True)
        b = torch.linspace(1.5, 2.5, 101, requires_grad=True)
        z = torch.maximum(a, b)
        z.sum().backward()
        autodiff_ga = a.grad.clone()
        autodiff_gb = b.grad.clone()

        a_wins = (a.detach() >= b.detach()).float()
        fast_ga = a_wins
        fast_gb = 1.0 - a_wins

        torch.testing.assert_close(fast_ga, autodiff_ga, rtol=1e-6, atol=1e-8)
        torch.testing.assert_close(fast_gb, autodiff_gb, rtol=1e-6, atol=1e-8)

    def test_cgm9_min_fast_bwd_matches_autodiff(self):
        """min fast backward formula matches PyTorch autograd.

        d/da min(a,b) = 1 if a <= b else 0
        d/db min(a,b) = 1 if a > b else 0
        """
        a = torch.linspace(0.0, 1.0, 101, requires_grad=True)
        b = torch.linspace(1.5, 2.5, 101, requires_grad=True)
        z = torch.minimum(a, b)
        z.sum().backward()
        autodiff_ga = a.grad.clone()
        autodiff_gb = b.grad.clone()

        a_wins = (a.detach() <= b.detach()).float()
        fast_ga = a_wins
        fast_gb = 1.0 - a_wins

        torch.testing.assert_close(fast_ga, autodiff_ga, rtol=1e-6, atol=1e-8)
        torch.testing.assert_close(fast_gb, autodiff_gb, rtol=1e-6, atol=1e-8)

    def test_cgm9_neg_fast_bwd_matches_autodiff(self):
        """neg fast backward formula matches PyTorch autograd.

        d/dx (-x) = -1
        """
        x = torch.linspace(-3.0, 3.0, 1001, requires_grad=True)
        y = torch.neg(x)
        y.sum().backward()
        autodiff_grad = x.grad.clone()

        fast_grad = torch.full_like(x.detach(), -1.0)

        torch.testing.assert_close(
            fast_grad,
            autodiff_grad,
            rtol=1e-6,
            atol=1e-8,
        )

    # ── coverage integrity ────────────────────────────────────────────

    def test_cgm9_all_differentiable_have_either_bwd_derivative_or_verified_autodiff(
        self,
    ):
        """Every [Differentiable] function is accounted for:
        either it has [BackwardDerivative] or it's in _VERIFIED_AUTODIFF_ONLY.
        """
        import os

        lib_dir = os.path.join(
            os.path.dirname(__file__),
            "..",
            "shaders",
            "lib",
        )

        all_differentiable = set()
        all_annotated = set()

        for fname in ("pointwise.slang", "losses.slang", "norm.slang"):
            path = os.path.join(lib_dir, fname)
            all_differentiable |= self._extract_differentiable(path)
            all_annotated |= self._extract_annotations(path)

        # Build the set of forward functions that have bwd annotations.
        covered_by_bwd = set()
        for bwd_name in all_annotated:
            if bwd_name.endswith("_elem_bwd"):
                fwd_name = bwd_name[: -len("_elem_bwd")] + "_elem"
            elif bwd_name.endswith("_fast_bwd"):
                fwd_name = bwd_name[: -len("_fast_bwd")] + "_fwd"
            elif bwd_name.endswith("_bwd"):
                fwd_name = bwd_name[: -len("_bwd")] + "_fwd"
            else:
                fwd_name = bwd_name
            covered_by_bwd.add(fwd_name)

        unaccounted = all_differentiable - covered_by_bwd - self._VERIFIED_AUTODIFF_ONLY

        assert not unaccounted, (
            f"CG.M9: {len(unaccounted)} [Differentiable] function(s) have "
            f"neither [BackwardDerivative] nor VERIFIED_AUTODIFF_ONLY entry:\n"
            + "\n".join(f"  - {n}" for n in sorted(unaccounted))
        )

    # ── structural integrity ──────────────────────────────────────────

    def test_cgm9_annotations_match_defined_backward_functions(self):
        """Every [BackwardDerivative(name)] annotation has a matching
        void name(...) definition in the same file."""
        import os

        lib_dir = os.path.join(
            os.path.dirname(__file__),
            "..",
            "shaders",
            "lib",
        )

        for fname in ("pointwise.slang", "losses.slang", "norm.slang"):
            path = os.path.join(lib_dir, fname)
            annotations = self._extract_annotations(path)
            with open(path) as f:
                content = f.read()
            for name in annotations:
                assert f"void {name}(" in content, (
                    f"CG.M9: [BackwardDerivative({name})] in {fname} "
                    f"has no matching void {name}(...) definition"
                )


class TestNoNativeFloatAtomicEmit:
    """Mesa ACO on RDNA1 cannot lower SPIR-V `OpAtomicFAddEXT` /
    `buffer_atomic_add_f32`. The eager+compile conv backward path crashed
    with `Unsupported opcode: buffer_atomic_add_f32` at shader assembly
    time until `slang_conv_bwd` and `flash_attention_bwd` switched to
    the CAS-based `vk_atomic_add` from `lib/atomics.slang`.

    This regression test scans every Jinja template in
    `python/torch_vulkan/inductor/templates/` and asserts none of them
    emit `InterlockedAdd(<RWStructuredBuffer<float> field>, ...)` directly.
    Future templates that need atomic float accumulation must call
    `vk_atomic_add(uint_buffer, idx, value)`.
    """

    def test_no_interlocked_add_on_float_rwbuffer(self):
        import os
        import re

        template_dir = os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "templates",
        )
        offenders: list[tuple[str, int, str]] = []
        # Match the dangerous 2-arg form `InterlockedAdd(buf[idx], value);`.
        # The legitimate 3-arg form `InterlockedAdd(buf[idx], val, original)`
        # is safe — it's only used on uint counters and ACO supports
        # native uint atomics. The check here is intentionally narrow:
        # 2 args inside the parens (a single comma between depth-zero items
        # before the closing paren).
        interlocked_re = re.compile(
            r"\bInterlockedAdd\s*\(\s*[\w.]+\s*\[[^\]]+\]\s*,\s*[^,;()]+\)\s*;"
        )
        for fname in sorted(os.listdir(template_dir)):
            if not (fname.endswith(".slang") or fname.endswith(".py.jinja")):
                continue
            path = os.path.join(template_dir, fname)
            with open(path) as f:
                for lineno, line in enumerate(f, start=1):
                    if line.lstrip().startswith("//"):
                        continue
                    if interlocked_re.search(line):
                        offenders.append((fname, lineno, line.rstrip()))
        assert not offenders, (
            "Templates contain InterlockedAdd on indexed buffers — RDNA1 "
            "ACO crashes on `buffer_atomic_add_f32`. Use vk_atomic_add from "
            "lib/atomics.slang instead.\n"
            + "\n".join(f"  {f}:{ln}  {src}" for f, ln, src in offenders)
        )


# ═══════════════════════════════════════════════════════════════════════
# CG.M8 — Codegen-level direct emission of bwd_diff()
# ═══════════════════════════════════════════════════════════════════════


class TestCGM8InlineBwdDiff:
    """CG.M8 — Inductor codegen directly emits ``bwd_diff(fwd)`` Slang
    instead of routing through the Python custom-op shim.

    Floor signals:
    - ``aten.silu_backward`` lowering produces a Pointwise IR node
      (not a FallbackKernel with a Python custom op)
    - The generated Slang source contains ``bwd_diff(silu_fwd)``
    - The gradient output matches CPU autograd
    - The fallback path still works when inline is disabled
    """

    @staticmethod
    def _get_slang_source_for_fn(fn, *args, **kwargs):
        """Compile a function and return the generated Slang source(s).

        Returns a set of unique Slang source strings emitted during
        compilation.  Only works when the compile actually runs.
        """
        import torch_vulkan  # noqa: F401
        from torch_vulkan.inductor.runtime import _cache_by_key

        # Snapshot existing cache keys
        before = set(_cache_by_key.keys())

        compiled = torch.compile(backend="inductor", fullgraph=True)(fn)
        compiled(*args, **kwargs)

        after = set(_cache_by_key.keys())
        new_keys = after - before

        sources = set()
        for k in new_keys:
            entry = _cache_by_key.get(k)
            if entry is not None and hasattr(entry, "src"):
                sources.add(entry.src if hasattr(entry, "src") else str(entry))

        return sources

    def test_cgm8_inline_bwd_diff_emitted_for_silu(self):
        """silu backward emits inline ``bwd_diff(silu_fwd)`` in Slang source."""
        import torch.nn.functional as F
        import torch_vulkan  # noqa: F401
        from torch_vulkan.inductor.runtime import _cache_by_key

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x):
            return F.silu(x).sum()

        x = torch.randn(64, device="vulkan:0", requires_grad=True)

        before = set(_cache_by_key.keys())
        fn(x).backward()
        after = set(_cache_by_key.keys())

        new_keys = after - before
        found_bwd_diff = False
        for k in new_keys:
            entry = _cache_by_key.get(k)
            if entry is not None:
                src = str(entry)
                if "bwd_diff" in src and "silu_fwd" in src:
                    found_bwd_diff = True
                    break

        assert found_bwd_diff, (
            "CG.M8: silu backward did not emit bwd_diff(silu_fwd) in any "
            "compiled Slang source. The inline codegen path may not be "
            "wired correctly."
        )

    def test_cgm8_inline_bwd_diff_produces_correct_gradient(self):
        """Inline bwd_diff gradient matches CPU autograd for silu."""
        import torch.nn.functional as F
        import torch_vulkan  # noqa: F401

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x):
            return F.silu(x).sum()

        x_vk = torch.randn(64, device="vulkan:0", requires_grad=True)
        x_cpu = x_vk.clone().detach().cpu().requires_grad_(True)

        fn(x_vk).backward()
        fn(x_cpu).backward()

        torch.testing.assert_close(
            x_vk.grad.cpu(),
            x_cpu.grad,
            rtol=1e-3,
            atol=1e-3,
        )

    def test_cgm8_fallback_to_separate_dispatch_for_complex_ops(self):
        """Complex ops (e.g., norm backward) still get separate dispatch.

        The layer_norm backward is NOT bwd_diff-inlineable because it
        requires reduction + groupshared.  It should still work via the
        existing FallbackKernel / Python custom-op shim.
        """
        import torch_vulkan  # noqa: F401

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x, w, b):
            return torch.nn.functional.layer_norm(x, [64], w, b).sum()

        x = torch.randn(4, 64, device="vulkan:0", requires_grad=True)
        w = torch.randn(64, device="vulkan:0", requires_grad=True)
        b = torch.randn(64, device="vulkan:0", requires_grad=True)

        # This should compile and run without errors, using the fallback path
        fn(x, w, b).backward()

        # If we got here, the fallback path worked
        assert x.grad is not None, "Expected grad to be computed"

    def test_cgm8_can_inline_bwd_diff_returns_true_for_unary_ops(self):
        """can_inline_bwd_diff returns True for all unary activation ops."""
        from torch_vulkan.inductor.kernel.bwd_diff_inline import can_inline_bwd_diff

        unary_ops = [
            "aten.silu_backward",
            "aten.relu_backward",
            "aten.sigmoid_backward",
            "aten.tanh_backward",
            "aten.gelu_backward",
            "aten.elu_backward",
            "aten.hardswish_backward",
            "aten.hardsigmoid_backward",
            "aten.sin_backward",
            "aten.cos_backward",
            "aten.log_backward",
            "aten.exp_backward",
            "aten.sqrt_backward",
        ]
        for op in unary_ops:
            assert can_inline_bwd_diff(op), (
                f"CG.M8: can_inline_bwd_diff({op!r}) returned False "
                f"for an op that should be inlinable"
            )

    def test_cgm8_can_inline_bwd_diff_returns_false_for_excluded_ops(self):
        """can_inline_bwd_diff returns False for excluded/complex ops."""
        from torch_vulkan.inductor.kernel.bwd_diff_inline import can_inline_bwd_diff

        # Norm and reduction ops should not be inlinable
        assert not can_inline_bwd_diff("aten.native_layer_norm_backward"), (
            "layer_norm backward should not be inlinable (needs reduction)"
        )
        # Ops not in BWD_DIFF_TABLE
        assert not can_inline_bwd_diff("aten.nonexistent_backward"), (
            "Non-existent op should not be inlinable"
        )

    def test_cgm8_inline_bwd_diff_respects_env_disable(self):
        """When TORCH_VULKAN_INLINE_BWD_DIFF=0, the Python custom-op shim
        path is used instead of inline bwd_diff."""
        import os

        import torch.nn.functional as F
        import torch_vulkan  # noqa: F401
        from torch_vulkan.inductor.runtime import _cache_by_key

        try:
            os.environ["TORCH_VULKAN_INLINE_BWD_DIFF"] = "0"

            @torch.compile(backend="inductor", fullgraph=True)
            def fn(x):
                return F.silu(x).sum()

            x = torch.randn(64, device="vulkan:0", requires_grad=True)

            before = set(_cache_by_key.keys())
            fn(x).backward()
            after = set(_cache_by_key.keys())

            new_keys = after - before
            # With inline disabled, the old path should be used.
            # The old path emits a bwd_diff kernel (with dispatch_unary_bwd).
            # Either way, the backward should succeed.
            assert x.grad is not None, (
                "CG.M8: backward should succeed even with inline disabled"
            )
        finally:
            os.environ.pop("TORCH_VULKAN_INLINE_BWD_DIFF", None)

    def test_cgm8_relu_backward_uses_inline_bwd_diff(self):
        """relu backward also emits inline bwd_diff(relu_fwd)."""
        import torch.nn.functional as F
        import torch_vulkan  # noqa: F401
        from torch_vulkan.inductor.runtime import _cache_by_key

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x):
            return F.relu(x).sum()

        x = torch.randn(64, device="vulkan:0", requires_grad=True)

        before = set(_cache_by_key.keys())
        fn(x).backward()
        after = set(_cache_by_key.keys())

        new_keys = after - before
        found_bwd_diff = False
        for k in new_keys:
            entry = _cache_by_key.get(k)
            if entry is not None:
                src = str(entry)
                if "bwd_diff" in src and "relu_fwd" in src:
                    found_bwd_diff = True
                    break

        assert found_bwd_diff, (
            "CG.M8: relu backward did not emit bwd_diff(relu_fwd) in "
            "compiled Slang source"
        )


class TestD4DynamicBatchExitGate:
    """D.4: Variable-batch MLP compiles fwd+bwd with correct gradients.

    The exit gate for Track D (Dynamic Shapes): compile an MLP ONCE
    with ``dynamic=True`` and call it with B ∈ {1, 4, 16, 64} —
    forward output matches CPU at ``rtol=1e-3`` and backward gradients
    match CPU at ``rtol=1e-3``.  The same compiled function handles
    every batch size without recompiling the SPIR-V kernel.

    Depends on D.2.a (dynamic reduction codegen), D.2.b (PC-slice fix),
    and D.3 (reflection-based buffer binding).
    """

    @staticmethod
    def _build_mlp(layers=(64, 128, 32)):
        """Build a deterministic MLP for fwd+bwd correctness tests."""
        import torch.nn as nn

        torch.manual_seed(0)
        blocks: list[nn.Module] = []
        for i in range(len(layers) - 1):
            blocks.append(nn.Linear(layers[i], layers[i + 1]))
            if i < len(layers) - 2:
                blocks.append(nn.GELU())
        m_cpu = nn.Sequential(*blocks).eval()
        m_vk = nn.Sequential(*blocks).eval()
        m_vk.load_state_dict(m_cpu.state_dict())
        return m_cpu, m_vk

    def test_d4_mlp_forward_dynamic_batch(self):
        """MLP forward with variable batch sizes B ∈ {1, 4, 16, 64}
        matches CPU when compiled with ``dynamic=True``."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:
            m_cpu, m_vk = self._build_mlp()
            m_vk = m_vk.to("vulkan:0")
            fn = torch.compile(m_vk, backend="inductor", dynamic=True)

            # Warmup with a representative batch size (triggers compilation).
            with torch.no_grad():
                fn(torch.randn(4, 64, device="vulkan:0"))

            for B in [1, 4, 16, 64]:
                x_cpu = torch.randn(B, 64)
                x_vk = x_cpu.to("vulkan:0")
                with torch.no_grad():
                    out_vk = fn(x_vk)
                    out_cpu = m_cpu(x_cpu)
                torch.testing.assert_close(
                    out_vk.cpu(),
                    out_cpu,
                    rtol=1e-3,
                    atol=1e-3,
                    msg=f"D.4 fwd: MLP batch={B} diverged from CPU",
                )
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]

    def test_d4_mlp_backward_dynamic_batch(self):
        """MLP backward with variable batch sizes has correct gradients
        matching CPU ``torch.autograd.grad`` at ``rtol=1e-3``."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:
            m_cpu, m_vk = self._build_mlp()
            m_vk = m_vk.to("vulkan:0")

            @torch.compile(backend="inductor", dynamic=True)
            def fn(x):
                return m_vk(x)

            # Warmup
            fn(torch.randn(4, 64, device="vulkan:0"))

            for B in [1, 4, 16, 64]:
                x_cpu = torch.randn(B, 64, requires_grad=True)
                x_vk = x_cpu.detach().to("vulkan:0").requires_grad_(True)

                # Vulkan forward + backward
                out_vk = fn(x_vk)
                out_vk.sum().backward()
                grad_vk = x_vk.grad

                # CPU forward + backward
                out_cpu = m_cpu(x_cpu)
                out_cpu.sum().backward()
                grad_cpu = x_cpu.grad

                torch.testing.assert_close(
                    out_vk.cpu(),
                    out_cpu,
                    rtol=1e-3,
                    atol=1e-3,
                    msg=f"D.4 bwd fwd: MLP batch={B} output diverged",
                )
                torch.testing.assert_close(
                    grad_vk.cpu(),
                    grad_cpu,
                    rtol=1e-3,
                    atol=1e-2,
                    msg=f"D.4 bwd: MLP batch={B} input grad diverged",
                )
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]

    def test_d4_variable_batch_same_compile(self):
        """Same compiled function handles different batch sizes — the
        key contract: compile once, dispatch many shapes.

        Verifies that a single cold compile serves B ∈ {1, 4, 16, 64}
        and that ``_COMPILE_STATS['cold_compiles']`` ≤ 2 (the single
        symbolic-shape kernel plus potential epilogue).
        """
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        from torch_vulkan.inductor.runtime import _COMPILE_STATS, reset_compile_stats

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:
            m_cpu, m_vk = self._build_mlp()
            m_vk = m_vk.to("vulkan:0")

            @torch.compile(backend="inductor", dynamic=True)
            def fn(x):
                return m_vk(x)

            # Warmup (triggers cold compile).
            with torch.no_grad():
                fn(torch.randn(4, 64, device="vulkan:0"))

            # Reset stats to count only post-warmup compiles.
            reset_compile_stats()

            # Run all batch sizes — must NOT recompile the kernel.
            with torch.no_grad():
                for B in [1, 4, 16, 64]:
                    out_vk = fn(torch.randn(B, 64, device="vulkan:0"))
                    out_cpu = m_cpu(torch.randn(B, 64))
                    torch.testing.assert_close(
                        out_vk.cpu(),
                        out_cpu,
                        rtol=1e-3,
                        atol=1e-3,
                        msg=f"D.4 same-compile: batch={B} diverged",
                    )

            # Zero new cold compiles — the symbolic-shape kernel was
            # already cached during warmup.
            cold = _COMPILE_STATS.get("cold_compiles", 0)
            assert cold == 0, (
                f"D.4: dynamic MLP triggered {cold} cold compiles "
                f"across 4 batch sizes after warmup — expected 0. "
                f"The symbolic-shape kernel should be reused for every size."
            )
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]

    def test_d4_parameter_gradients_match_cpu(self):
        """Parameter gradients (Linear.weight + Linear.bias) match CPU
        across variable batch sizes.

        This is the full D.4 exit-gate contract: an optimizer step on
        the compiled model produces parameter updates that match CPU.
        """
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:
            m_cpu, m_vk = self._build_mlp()
            m_vk = m_vk.to("vulkan:0")

            @torch.compile(backend="inductor", dynamic=True)
            def fn(x):
                return m_vk(x)

            # Warmup
            fn(torch.randn(4, 64, device="vulkan:0"))

            for B in [4, 16, 64]:
                x_cpu = torch.randn(B, 64, requires_grad=False)
                x_vk = x_cpu.to("vulkan:0")

                # Forward + backward on Vulkan
                out_vk = fn(x_vk)
                out_vk.sum().backward()

                # Forward + backward on CPU
                out_cpu = m_cpu(x_cpu)
                out_cpu.sum().backward()

                # Compare every parameter gradient
                cpu_params = dict(m_cpu.named_parameters())
                vk_params = dict(m_vk.named_parameters())
                for pname in cpu_params:
                    gcpu = cpu_params[pname].grad
                    gvk = vk_params[pname].grad
                    assert gvk is not None, (
                        f"D.4: param '{pname}' has no grad on Vulkan (batch={B})"
                    )
                    assert gcpu is not None, (
                        f"D.4: param '{pname}' has no grad on CPU (batch={B})"
                    )
                    torch.testing.assert_close(
                        gvk.cpu(),
                        gcpu,
                        rtol=1e-2,
                        atol=1e-2,
                        msg=f"D.4: param '{pname}' grad batch={B} diverged",
                    )

                # Zero grads for next iteration
                m_vk.zero_grad()
                m_cpu.zero_grad()
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]


class TestD3DynamicBufferBinding:
    """D.3: Dynamic buffer binding — n_buffers and n_pc extracted from
    reflection at runtime for variable-arity kernels."""

    def test_d3_reflection_binding_count_matches_hand_count(self):
        """``get_reflected_binding_count`` returns the correct number of
        storage-buffer bindings for a known shader."""
        from torch_vulkan.inductor.runtime import (
            compile_slang_to_spirv,
            get_reflected_binding_count,
        )

        # A shader with 3 buffer bindings: 2 inputs + 1 output.
        src = """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_a;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_b;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_c;
        [[vk::push_constant]] cbuffer Push {
            uint n;
        };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) {
                out_c[tid.x] = in_a[tid.x] + in_b[tid.x];
            }
        }
        """
        spv = compile_slang_to_spirv(src, cache_key="test_d3_reflection_binding_count")
        n = get_reflected_binding_count(spv)
        assert n == 3, f"D.3: expected 3 bindings from reflection, got {n}"

    def test_d3_make_vulkan_kernel_accepts_none_n_buffers(self):
        """``make_vulkan_kernel`` with ``n_buffers=None`` derives the
        buffer count from reflection and dispatches correctly."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        import numpy as np
        from torch_vulkan.inductor.runtime import make_vulkan_kernel

        src = """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_a;
        [[vk::binding(1, 0)]] StructuredBuffer<float> in_b;
        [[vk::binding(2, 0)]] RWStructuredBuffer<float> out_c;
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < 256u) {
                out_c[tid.x] = in_a[tid.x] + in_b[tid.x];
            }
        }
        """
        # n_buffers=None → derived from reflection (should be 3).
        kernel = make_vulkan_kernel(
            src,
            "test_d3_none_n_buffers",
            n_buffers=None,
            pc_size_bytes=0,
            n_pc=0,
        )

        a = torch.ones(256, device="vulkan:0")
        b = torch.ones(256, device="vulkan:0") * 2
        out = torch.zeros(256, device="vulkan:0")

        kernel(a, b, out, 1, 1, 1)

        expected = np.full(256, 3.0, dtype=np.float32)
        torch.testing.assert_close(
            out.cpu(),
            torch.tensor(expected),
            rtol=1e-3,
            atol=1e-3,
            msg="D.3: reflection-derived n_buffers dispatch produced wrong output",
        )

    def test_d3_dynamic_buffer_binding_works_end_to_end(self):
        """Variable-arity kernel dispatches with correct buffer count
        under ``dynamic=True`` — the full D.3 integration test."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:
            # A simple pointwise chain that generates a dynamic-batch
            # kernel. The compile path exercises make_vulkan_kernel
            # with n_pc > 0 (dynamic numels become push constants).

            @torch.compile(backend="inductor", dynamic=True)
            def fn(x):
                return x * 2.0 + 1.0

            # Warmup
            fn(torch.randn(4, 128, device="vulkan:0"))

            for B in [1, 4, 16, 64]:
                x_cpu = torch.randn(B, 128)
                x_vk = x_cpu.to("vulkan:0")
                out_vk = fn(x_vk)
                out_cpu = x_cpu * 2.0 + 1.0
                torch.testing.assert_close(
                    out_vk.cpu(),
                    out_cpu,
                    rtol=1e-3,
                    atol=1e-3,
                    msg=f"D.3 e2e: dynamic buffer binding batch={B} diverged",
                )
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]


class TestN15DescriptorIndexing:
    """N+1.5.c — descriptor indexing feature gate and >16 binding cap."""

    def test_n15_descriptor_indexing_feature_gate(self):
        """Feature gate reads TORCH_VULKAN_DESCRIPTOR_INDEXING env var."""
        from torch_vulkan.inductor.config import descriptor_indexing_enabled

        # Default: enabled (empty/missing env var → "1" != "0" → True).
        # This test verifies the function works and respects the env var.
        result = descriptor_indexing_enabled()
        assert isinstance(result, bool), (
            "N+1.5.c: descriptor_indexing_enabled() must return bool"
        )

    def test_n15_max_storage_bufs_raised_with_indexing(self):
        """When descriptor indexing is enabled, _get_max_storage_bufs
        returns >16. When disabled via env, it respects the lower cap."""
        import os

        from torch_vulkan.inductor.scheduling import VulkanScheduling

        # Clear the cache so we get a fresh probe.
        VulkanScheduling._cached_max_storage_bufs = None

        try:
            # Default mode (descriptor indexing ON unless explicitly disabled).
            if os.environ.get("TORCH_VULKAN_DESCRIPTOR_INDEXING") == "0":
                # With indexing explicitly disabled, cap should be <= 60.
                cap = VulkanScheduling._get_max_storage_bufs()
                assert cap <= 60, (
                    f"N+1.5.c: expected cap <= 60 with indexing off, got {cap}"
                )
            else:
                # Default or explicitly enabled.
                cap = VulkanScheduling._get_max_storage_bufs()
                # Cap should be at least 12 (minimum) and could be
                # either the pre-indexing cap (~60) or the raised cap
                # (up to 256) depending on whether the device probe
                # succeeds and whether descriptor indexing is active.
                assert cap >= 12, f"N+1.5.c: cap should be >= 12, got {cap}"
                # Verify the cap is an integer.
                assert isinstance(cap, int), (
                    f"N+1.5.c: cap should be int, got {type(cap)}"
                )
        finally:
            VulkanScheduling._cached_max_storage_bufs = None

    def test_n15_max_storage_bufs_override(self):
        """TORCH_VULKAN_MAX_STORAGE_BUFS overrides the device probe."""
        import os

        from torch_vulkan.inductor.scheduling import VulkanScheduling

        VulkanScheduling._cached_max_storage_bufs = None
        try:
            os.environ["TORCH_VULKAN_MAX_STORAGE_BUFS"] = "48"
            cap = VulkanScheduling._get_max_storage_bufs()
            assert cap == 48, f"N+1.5.c: override cap should be 48, got {cap}"
        finally:
            VulkanScheduling._cached_max_storage_bufs = None
            os.environ.pop("TORCH_VULKAN_MAX_STORAGE_BUFS", None)

    def test_n15_combo_kernel_handles_gt16_bindings(self):
        """Combo kernel with 20+ buffers should not crash when descriptor
        indexing is enabled. This is a smoke test for the binding management
        in vulkan_combo_kernel.py — verify that the global binding map
        doesn't impose a hard cap at 16."""
        import torch_vulkan  # noqa: F401
        from torch_vulkan.inductor.config import parameter_block

        # The combo kernel's binding management uses a simple slot counter
        # that increments per unique outer buffer. There is no hard cap
        # in VulkanComboKernel — the only cap is the pre-merge check in
        # can_fuse() which uses _get_max_storage_bufs(). This test
        # verifies that raising the cap doesn't break the combo kernel
        # assembly.
        #
        # We create a chain of 22 pointwise ops on 22 distinct buffers
        # and verify they all compile through the Inductor pipeline.

        if not parameter_block():
            # Without ParameterBlock, the header.py slot counter is used.
            # The combo kernel's own slot counter works identically.
            pass

        # Verify that _get_max_storage_bufs returns a value.
        from torch_vulkan.inductor.scheduling import VulkanScheduling

        cap = VulkanScheduling._get_max_storage_bufs()
        assert cap > 0, f"N+1.5.c: _get_max_storage_bufs returned {cap}"


class TestN18TemplateSlangMirrors:
    """N+1.8: Every .py.jinja template must have a corresponding .slang mirror."""

    # Templates that are expected to have .slang mirrors.
    _EXPECTED_SLANG_MIRRORS = [
        "slang_mm",
        "slang_mm_bwd",
        "slang_conv2d",
        "slang_conv_bwd",
        "flash_attention",
        "flash_attention_bwd",
        "foreach_optimizer",
        "philox_rng",
        "scatter_atomic",
        "rnn_cell",
        "fft_stockham",
    ]

    @staticmethod
    def _template_dir() -> str:
        return os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "templates",
        )

    def test_slang_mirrors_exist(self):
        """N+1.8: Each template has a .slang mirror."""
        template_dir = self._template_dir()
        assert os.path.isdir(template_dir), f"template dir not found: {template_dir}"
        missing = []
        for name in self._EXPECTED_SLANG_MIRRORS:
            slang_path = os.path.join(template_dir, f"{name}.slang")
            if not os.path.isfile(slang_path):
                missing.append(f"{name}.slang")
        assert not missing, (
            f"N+1.8: missing .slang mirrors: {missing}\nTemplate dir: {template_dir}"
        )

    def test_slang_mirrors_not_empty(self):
        """N+1.8: .slang mirrors are non-empty and contain Slang code."""
        template_dir = self._template_dir()
        assert os.path.isdir(template_dir), f"template dir not found: {template_dir}"
        empty_or_small = []
        for name in self._EXPECTED_SLANG_MIRRORS:
            slang_path = os.path.join(template_dir, f"{name}.slang")
            if not os.path.isfile(slang_path):
                continue
            size = os.path.getsize(slang_path)
            if size < 100:
                empty_or_small.append(f"{name}.slang ({size} bytes)")
        assert not empty_or_small, (
            f"N+1.8: .slang mirrors are too small: {empty_or_small}"
        )

    def test_py_jinja_has_slang_counterpart(self):
        """N+1.8: Every .py.jinja file has a corresponding .slang file."""
        template_dir = self._template_dir()
        assert os.path.isdir(template_dir), f"template dir not found: {template_dir}"
        py_jinja_files = sorted(
            f for f in os.listdir(template_dir) if f.endswith(".py.jinja")
        )
        for py_jinja in py_jinja_files:
            base = py_jinja.replace(".py.jinja", "")
            slang_path = os.path.join(template_dir, f"{base}.slang")
            assert os.path.isfile(slang_path), (
                f"N+1.8: .py.jinja file {py_jinja} has no .slang mirror at {slang_path}"
            )

    def test_slang_files_loadable(self):
        """N+1.8: .slang files can be loaded via _load_slang_template."""
        from torch_vulkan.inductor.vulkan_template import _load_slang_template

        for name in self._EXPECTED_SLANG_MIRRORS:
            src = _load_slang_template(name)
            assert src, f"N+1.8: _load_slang_template('{name}') returned empty string"
            assert len(src) > 50, (
                f"N+1.8: _load_slang_template('{name}') returned short "
                f"content ({len(src)} chars)"
            )


class TestN16ParallelCompileConfig:
    """N+1.6: Parallel compilation config is properly wired."""

    def test_max_slangc_workers_alias(self):
        """_MAX_SLANGC_WORKERS is an alias for _ASYNC_MAX_WORKERS."""
        from torch_vulkan.inductor.runtime import (
            _ASYNC_MAX_WORKERS,
            _MAX_SLANGC_WORKERS,
        )

        assert _MAX_SLANGC_WORKERS == _ASYNC_MAX_WORKERS, (
            f"N+1.6: _MAX_SLANGC_WORKERS ({_MAX_SLANGC_WORKERS}) "
            f"!= _ASYNC_MAX_WORKERS ({_ASYNC_MAX_WORKERS})"
        )
        assert isinstance(_MAX_SLANGC_WORKERS, int), (
            f"N+1.6: _MAX_SLANGC_WORKERS should be int, got {type(_MAX_SLANGC_WORKERS)}"
        )
        assert _MAX_SLANGC_WORKERS >= 1, (
            f"N+1.6: _MAX_SLANGC_WORKERS should be >= 1, got {_MAX_SLANGC_WORKERS}"
        )

    def test_async_compile_env_var_gate(self):
        """TORCH_VULKAN_ASYNC_COMPILE controls _ASYNC_COMPILE flag."""
        from torch_vulkan.inductor.runtime import _ASYNC_COMPILE

        # Default is True (async compilation enabled).
        assert _ASYNC_COMPILE is True, (
            f"N+1.6: _ASYNC_COMPILE should default to True, got {_ASYNC_COMPILE}"
        )

    def test_parallel_compile_env_var_gate(self):
        """TORCH_VULKAN_PARALLEL_COMPILE controls _PARALLEL_COMPILE flag."""
        from torch_vulkan.inductor.runtime import _PARALLEL_COMPILE

        assert _PARALLEL_COMPILE is True, (
            f"N+1.6: _PARALLEL_COMPILE should default to True, got {_PARALLEL_COMPILE}"
        )

    def test_batch_parallel_function_exists(self):
        """_compile_slang_batch_parallel is importable and callable."""
        from torch_vulkan.inductor.runtime import _compile_slang_batch_parallel

        assert callable(_compile_slang_batch_parallel), (
            "N+1.6: _compile_slang_batch_parallel should be callable"
        )

    def test_default_max_workers_respects_env(self):
        """TORCH_VULKAN_SLANGC_WORKERS overrides default max workers."""
        import importlib
        import os as _os

        from torch_vulkan.inductor import runtime as rt

        prev = _os.environ.get("TORCH_VULKAN_SLANGC_WORKERS")
        try:
            _os.environ["TORCH_VULKAN_SLANGC_WORKERS"] = "8"
            importlib.reload(rt)
            assert rt._default_max_workers() == 8, (
                f"N+1.6: expected 8 workers, got {rt._default_max_workers()}"
            )
            assert rt._MAX_SLANGC_WORKERS == 8, (
                f"N+1.6: _MAX_SLANGC_WORKERS should be 8, got {rt._MAX_SLANGC_WORKERS}"
            )
        finally:
            if prev is not None:
                _os.environ["TORCH_VULKAN_SLANGC_WORKERS"] = prev
            else:
                _os.environ.pop("TORCH_VULKAN_SLANGC_WORKERS", None)
            importlib.reload(rt)


class TestN111TileSizesPushConstants:
    """N+1.11 — Tile sizes are emitted as :attr:`[[vk::constant_id]]`
    specialization constants (for groupshared arrays / numthreads) and
    push-constant struct members (for loop bounds).  The same SPIR-V
    module serves multiple tile configurations that share the same
    ``(M_PER_THREAD, N_PER_THREAD, TILE_M*TILE_K, TILE_K*TILE_N)``
    shape class.
    """

    def test_n111_tile_sizes_are_spec_constants_and_push_constants(self):
        """Generated source uses [[vk::constant_id]] for groupshared/
        numthreads sizing and pc.tile_m/pc.tile_n/pc.tile_k for loop
        bounds — not Jinja-literal numbers."""
        from torch_vulkan.inductor.vulkan_template_caller import _render_mm_slang

        src = _render_mm_slang(
            32,
            32,
            16,
            dtype_a="float",
            dtype_b="float",
            dtype_c="float",
            dtype_acc="float",
            m_per_thread=1,
            n_per_thread=1,
            use_module=False,
        )
        # Spec constants must be present.
        assert "[[vk::constant_id(20)]]" in src
        assert "[[vk::constant_id(21)]]" in src
        assert "[[vk::constant_id(22)]]" in src
        assert "[[vk::constant_id(23)]]" in src
        assert "[[vk::constant_id(24)]]" in src
        # PC struct must contain tile config fields.
        assert "uint tile_m;" in src
        assert "uint tile_n;" in src
        assert "uint tile_k;" in src
        assert "uint m_per_thread;" in src
        assert "uint n_per_thread;" in src
        # Loop bounds use pc.tile_k, not Jinja literals.
        assert "pc.tile_k" in src
        assert "pc.m_per_thread" in src
        assert "pc.n_per_thread" in src
        # numthreads uses WG_N, WG_M (spec constants), not Jinja.
        assert "numthreads(WG_N, WG_M, 1)" in src
        # No Jinja `{{ tile_m }}` literals remain in rendered source.
        assert "{{ tile_m }}" not in src
        assert "{{ tile_n }}" not in src
        assert "{{ tile_k }}" not in src

    def test_n111_cache_key_includes_n111_tag(self):
        """Cache keys carry the _n111 tag so pre-N+1.11 cached SPIR-V
        is never reused with the new (larger) push-constant layout."""
        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileMM

        caller = _SlangTileMM(32, 32, 16)
        _, ck = caller._src_and_key("float")
        assert "_n111" in ck, f"cache key missing _n111 tag: {ck}"

    def test_n111_mm_correctness_with_push_constant_tiles(self):
        """Correctness: matmul via the new spec-constant + push-constant
        template matches eager CPU result."""
        if not torch.cuda.is_available():
            try:
                import torch_vulkan

                if not torch_vulkan.is_available():
                    pytest.skip("No Vulkan device")
            except ImportError:
                pytest.skip("torch_vulkan not installed")

        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileMM

        a_cpu = torch.randn(128, 64, dtype=torch.float32)
        b_cpu = torch.randn(64, 96, dtype=torch.float32)
        expected = a_cpu @ b_cpu

        try:
            a_vk = a_cpu.to("vulkan")
            b_vk = b_cpu.to("vulkan")
        except Exception:
            pytest.skip("Vulkan device not available")

        caller = _SlangTileMM(32, 32, 16, num_stages=1)
        result = caller(a_vk, b_vk)
        result_cpu = result.cpu()

        torch.testing.assert_close(
            result_cpu,
            expected,
            rtol=1e-4,
            atol=1e-4,
            msg="N+1.11 tile push-constant matmul correctness mismatch",
        )

    def test_n111_register_tile_correctness(self):
        """Register-tiled config also works with push-constant tile sizes."""
        try:
            import torch_vulkan

            if not torch_vulkan.is_available():
                pytest.skip("No Vulkan device")
        except ImportError:
            pytest.skip("torch_vulkan not installed")

        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileMM

        a_cpu = torch.randn(256, 128, dtype=torch.float32)
        b_cpu = torch.randn(128, 192, dtype=torch.float32)
        expected = a_cpu @ b_cpu

        try:
            a_vk = a_cpu.to("vulkan")
            b_vk = b_cpu.to("vulkan")
        except Exception:
            pytest.skip("Vulkan device not available")

        # Register-tiled: 64×64 tile, 4×4 per thread, 256 threads.
        caller = _SlangTileMM(64, 64, 16, num_stages=1, m_per_thread=4, n_per_thread=4)
        result = caller(a_vk, b_vk)
        result_cpu = result.cpu()

        torch.testing.assert_close(
            result_cpu,
            expected,
            rtol=1e-4,
            atol=1e-4,
            msg="N+1.11 register-tile push-constant matmul correctness mismatch",
        )

    def test_n111_spec_constants_in_compiled_spirv(self):
        """The compiled SPIR-V from the rendered template contains
        OpSpecConstant instructions with the expected SpecId values."""
        from torch_vulkan.inductor.runtime import (
            compile_slang_to_spirv,
            parse_spec_constants,
        )
        from torch_vulkan.inductor.vulkan_template_caller import _render_mm_slang

        src = _render_mm_slang(
            32,
            32,
            16,
            dtype_a="float",
            dtype_b="float",
            dtype_c="float",
            dtype_acc="float",
            m_per_thread=1,
            n_per_thread=1,
        )
        spv = compile_slang_to_spirv(src, cache_key="n111_spec_test_v1")
        spec = parse_spec_constants(spv)
        # We expect 5 spec constants: TILE_M(20), TILE_N(21), TILE_K(22),
        # M_PER_THREAD(23), N_PER_THREAD(24)
        spec_ids = {s[0] for s in spec}
        assert spec_ids >= {20, 21, 22, 23, 24}, (
            f"missing spec constant ids: {spec_ids}"
        )
        # Verify defaults match what we rendered.
        spec_map = dict(spec)
        assert spec_map[20] == 32, f"TILE_M default: {spec_map[20]}"
        assert spec_map[21] == 32, f"TILE_N default: {spec_map[21]}"
        assert spec_map[22] == 16, f"TILE_K default: {spec_map[22]}"
        assert spec_map[23] == 1, f"M_PER_THREAD default: {spec_map[23]}"
        assert spec_map[24] == 1, f"N_PER_THREAD default: {spec_map[24]}"

    def test_n111_slang_mirror_syncs_with_jinja(self):
        """The .slang mirror has the same spec constant declarations
        as the .py.jinja source (after unwrapping)."""
        import os as _os

        template_dir = _os.path.join(
            _os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "templates",
        )
        jinja_path = _os.path.join(template_dir, "slang_mm.py.jinja")
        slang_path = _os.path.join(template_dir, "slang_mm.slang")
        assert _os.path.exists(jinja_path), f"missing {jinja_path}"
        assert _os.path.exists(slang_path), f"missing {slang_path}"

        with open(slang_path) as f:
            slang_src = f.read()

        # The .slang mirror must contain the spec constant declarations.
        assert "[[vk::constant_id(20)]] const uint TILE_M" in slang_src
        assert "[[vk::constant_id(21)]] const uint TILE_N" in slang_src
        assert "[[vk::constant_id(22)]] const uint TILE_K" in slang_src
        assert "[[vk::constant_id(23)]] const uint M_PER_THREAD" in slang_src
        assert "[[vk::constant_id(24)]] const uint N_PER_THREAD" in slang_src
        # And the PC struct with tile fields.
        assert "uint tile_m;" in slang_src
        assert "uint tile_n;" in slang_src
        assert "uint tile_k;" in slang_src
        assert "uint m_per_thread;" in slang_src
        assert "uint n_per_thread;" in slang_src


# ═══════════════════════════════════════════════════════════════════════════
# M27 / M28 — Workgroup size and push-constant struct field ordering
# ═══════════════════════════════════════════════════════════════════════════


class TestM27M28Conventions:
    """M27: Workgroup size standardization.
    M28: Push-constant struct field ordering."""

    # ── M27 ────────────────────────────────────────────────────────────

    def test_m27_workgroup_size_convention_documented(self):
        """M27: The workgroup size convention is documented in
        kernel/header.py's module docstring."""
        import importlib

        import torch_vulkan.inductor.kernel.header as _hdr

        importlib.reload(_hdr)
        doc = _hdr.__doc__ or ""
        assert "M27" in doc, (
            "M27 workgroup-size convention must appear in header.py module docstring"
        )
        assert "numthreads" in doc, "Convention must mention numthreads"
        assert "256" in doc, "Convention must document the default 256-thread workgroup"
        assert "1024" in doc, (
            "Convention must call out the 1024 Vulkan minimum guarantee"
        )

    def test_m27_workgroup_size_product_le_1024(self):
        """M27: Every hand-written shader under shaders/ must have a
        numthreads product ≤ 1024 (Vulkan minimum guarantee)."""
        import os as _os
        import re as _re

        shaders_root = _os.path.join(
            _os.path.dirname(__file__),
            "..",
            "shaders",
        )
        _numt_re = _re.compile(r"\[numthreads\((\d+)\s*,\s*(\d+)\s*,\s*(\d+)\)\]")
        violations: list[str] = []
        for dirpath, _dirnames, filenames in _os.walk(shaders_root):
            for fn in filenames:
                if not fn.endswith(".slang"):
                    continue
                fpath = _os.path.join(dirpath, fn)
                with open(fpath) as f:
                    src = f.read()
                for m in _numt_re.finditer(src):
                    x, y, z = int(m.group(1)), int(m.group(2)), int(m.group(3))
                    product = x * y * z
                    if product > 1024:
                        violations.append(
                            f"{_os.path.relpath(fpath, shaders_root)}: "
                            f"[numthreads({x},{y},{z})] product={product}"
                        )
        assert len(violations) == 0, (
            f"Found {len(violations)} shader(s) with numthreads product "
            f"> 1024:\n" + "\n".join(violations)
        )

    def test_m27_validator_warns_on_wave64_misalignment(self):
        """M27: _validate_workgroup_size warns when numthreads product
        is not a multiple of 64 (suboptimal on RDNA1)."""
        from torch_vulkan.inductor.slang_validator import _validate_workgroup_size

        # 100 threads → not a multiple of 64 → warning expected
        src = """
[numthreads(100, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) { }
"""
        errors = _validate_workgroup_size(src)
        assert any("multiple of wave size" in e for e in errors), (
            f"Expected wave64-alignment warning for 100 threads, got: {errors}"
        )

        # 256 threads = 4 × 64 → clean (hard limit passes, wave64 passes)
        src_ok = """
[numthreads(256, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) { }
"""
        errors_ok = _validate_workgroup_size(src_ok)
        assert len(errors_ok) == 0, f"256 threads should be clean, got: {errors_ok}"

        # 16×16 = 256 → clean
        src_2d = """
[numthreads(16, 16, 1)]
void main(uint3 gtid : SV_DispatchThreadID) { }
"""
        errors_2d = _validate_workgroup_size(src_2d)
        assert len(errors_2d) == 0, f"16×16 threads should be clean, got: {errors_2d}"

    # ── M28 ────────────────────────────────────────────────────────────

    def test_m28_pc_struct_ordering_convention_documented(self):
        """M28: The push-constant struct field ordering convention is
        documented in kernel/header.py's module docstring."""
        import importlib

        import torch_vulkan.inductor.kernel.header as _hdr

        importlib.reload(_hdr)
        doc = _hdr.__doc__ or ""
        assert "M28" in doc, (
            "M28 PC struct ordering convention must appear in header.py "
            "module docstring"
        )
        assert "Push-Constant" in doc, (
            "Convention must mention push-constant struct ordering"
        )
        assert "alignment" in doc.lower(), (
            "Convention must discuss alignment requirements"
        )
        assert "uint32_t" in doc or "uint" in doc, (
            "Convention must specify uint field ordering"
        )

    def test_m28_pc_struct_fields_ordered_by_alignment(self):
        """M28: Audit PC structs in templates for alignment ordering.

        Per the convention: uint fields first, then float fields.
        The flash_attention template has a known, documented violation
        (``float scale`` between ``uint`` groups) that is tolerated
        because it groups the semantic parameters together.
        """
        import os as _os
        import re as _re

        template_dir = _os.path.join(
            _os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "templates",
        )
        # Known exceptions — templates with documented violations.
        # flash_attention: float scale between uint fields.
        KNOWN_EXCEPTIONS = {"flash_attention.py.jinja", "flash_attention.slang"}

        violations: list[str] = []

        for fn in sorted(_os.listdir(template_dir)):
            if not (fn.endswith(".py.jinja") or fn.endswith(".slang")):
                continue
            # Skip slang mirrors that are just Jinja comments — they
            # contain no struct PC definition.
            fpath = _os.path.join(template_dir, fn)
            with open(fpath) as f:
                src = f.read()

            # Extract PC struct body
            pc_match = _re.search(r"struct PC\s*\{([^}]*(?:\{[^}]*\}[^}]*)*)\}", src)
            if not pc_match:
                continue
            body = pc_match.group(1)

            # Extract member type-name pairs
            members = _re.findall(
                r"(?:^\s*|\n\s*)"
                r"(\w+(?:\d+)?)\s+"
                r"(\w+)\s*"
                r"(?:\[[^\]]+\])?\s*"
                r"(?:;|(?=\n))",
                body,
            )
            if not members:
                continue

            # Check ordering: non-float types should precede float types.
            saw_float = False
            for type_str, name in members:
                is_float = type_str in ("float", "float2", "float3", "float4")
                if is_float:
                    saw_float = True
                elif saw_float and type_str not in (
                    "float",
                    "float2",
                    "float3",
                    "float4",
                ):
                    if fn not in KNOWN_EXCEPTIONS:
                        violations.append(
                            f"{fn}: non-float field '{type_str} {name}' "
                            f"appears after float field(s)"
                        )

        assert len(violations) == 0, (
            f"Found {len(violations)} PC struct(s) with alignment "
            f"ordering violations:\n" + "\n".join(violations)
        )


