class TestMVal4PreSlangcValidator:
    """M-VAL.4 (v7) — pre-slangc static AST validator.

    The validator runs at ``slangc.py:161`` BEFORE any slangc subprocess,
    catching codegen mistakes in milliseconds rather than subprocess seconds.
    Already integrated as M22.1.i; this test locks the invariant.
    """

    def test_validator_importable_and_callable(self):
        """``validate_slang_source`` is importable and returns a list."""
        from torch_vulkan.inductor.validate import validate_slang_source

        # Valid empty shader should produce no issues.
        empty = '[shader("compute")] [numthreads(64,1,1)] void main() {}'
        issues = validate_slang_source(empty)
        assert isinstance(issues, list), (
            f"validate_slang_source must return list, got {type(issues)}"
        )
        assert len(issues) == 0, (
            f"Valid empty shader should have 0 issues, got {len(issues)}"
        )

    def test_validator_catches_brace_mismatch(self):
        """Unbalanced braces must be caught before slangc."""
        from torch_vulkan.inductor.validate import validate_slang_source

        bad = '[shader("compute")] [numthreads(64,1,1)] void main() { '
        issues = validate_slang_source(bad)
        assert len(issues) > 0, "Unbalanced braces must produce validation issues"
        assert any(i.category == "brace" for i in issues), "Brace mismatch not detected"

    def test_validator_integrated_in_slangc_compile(self):
        """``slangc.py:_compile_slang`` calls the validator before
        spawning slangc subprocess."""
        import inspect

        from torch_vulkan.inductor.runtime import slangc

        src = inspect.getsource(slangc._compile_slang)
        assert "validate_slang_source" in src, (
            "M-VAL.4: _compile_slang must call validate_slang_source "
            "before any slangc subprocess invocation"
        )


class TestMProbe2AutoOff:
    """M-PROBE.2 (v7) — auto_probe_on_import defaults to OFF.

    ``_resolve_auto_level()`` returns ``None`` for default "auto"/unset.
    Users must call ``torch_vulkan.prepare_device()`` explicitly.
    """

    def test_auto_level_defaults_to_none(self):
        """When TORCH_VULKAN_PROFILE_DEVICE is unset or 'auto',
        _resolve_auto_level returns None (skip)."""
        import os

        from torch_vulkan.inductor.hardware_probe import _resolve_auto_level

        # Unset: default to off.
        old = os.environ.pop("TORCH_VULKAN_PROFILE_DEVICE", None)
        try:
            assert _resolve_auto_level("auto") is None, (
                "M-PROBE.2: 'auto' must resolve to None (off)"
            )
            assert _resolve_auto_level("") is None, (
                "M-PROBE.2: unset must resolve to None (off)"
            )
        finally:
            if old is not None:
                os.environ["TORCH_VULKAN_PROFILE_DEVICE"] = old

    def test_quick_still_opt_in(self):
        """Explicit TORCH_VULKAN_PROFILE_DEVICE=quick still works."""
        from torch_vulkan.inductor.hardware_probe import (
            LEVEL_QUICK,
            _resolve_auto_level,
        )

        assert _resolve_auto_level("quick") == LEVEL_QUICK, (
            "M-PROBE.2: 'quick' must still resolve to LEVEL_QUICK"
        )


class TestMCG3ConvGnReluFusedShader:
    """M-CG.3 (v7) — conv_gn_relu fused shader re-armed.

    The slangc 2026.7.1 multi-wave write-coverage miscompile (Group-D)
    was worked around by reducing workgroup size from 256→64 (single
    wave64).  The 3-dispatch aten decomp fallback in the Python caller
    has been removed; the fused shader is the active path.
    """

    def test_fallback_removed_from_caller(self):
        """The 3-dispatch aten decomp fallback must NOT be present
        in ``_slang_tile_conv2d_gn_relu``."""
        import inspect

        from torch_vulkan.inductor.templates.caller.conv import (
            _slang_tile_conv2d_gn_relu,
        )

        src = inspect.getsource(_slang_tile_conv2d_gn_relu)
        # The old fallback used aten.convolution + F.group_norm + F.relu
        assert "aten.convolution.default" not in src, (
            "M-CG.3: aten.convolution fallback must be removed from "
            "_slang_tile_conv2d_gn_relu"
        )
        assert "F.group_norm" not in src, (
            "M-CG.3: F.group_norm fallback must be removed"
        )
        # The fused dispatch must be the active path.
        assert "compile_and_dispatch" in src, (
            "M-CG.3: fused dispatch path must be re-armed"
        )

    def test_shader_uses_single_wave_workgroup(self):
        """conv_gn_relu.slang uses numthreads(64,1,1) — single wave64."""
        import os

        tmpl_dir = os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "templates",
        )
        path = os.path.join(tmpl_dir, "conv_gn_relu.slang")
        src = open(path).read()
        assert "[numthreads(64, 1, 1)]" in src, (
            "M-CG.3: conv_gn_relu.slang must use numthreads(64,1,1) "
            "(single wave64) to avoid slangc multi-wave miscompile"
        )
        # Must NOT have the old 256
        assert "[numthreads(256, 1, 1)]" not in src, (
            "M-CG.3: old numthreads(256,1,1) must be replaced with 64"
        )


