class TestM22WrapperHelpersSplit:
    """M22.1 — wrapper.py split via wrapper_helpers.py.

    wrapper.py was 881 L — over the 800-line anti-goal #7 cap.
    Module-level helpers and monkey-patches extracted to wrapper_helpers.py;
    wrapper.py now contains only VulkanPythonWrapperCodegen.
    """

    def test_wrapper_py_under_800_lines(self):
        import torch_vulkan.inductor.wrapper as mod

        with open(mod.__file__) as f:
            n = sum(1 for _ in f)
        assert n <= 800, (
            f"wrapper.py is {n} lines — exceeds anti-goal #7 cap of 800. "
            "Extract more content to wrapper_helpers.py."
        )

    def test_wrapper_helpers_under_800_lines(self):
        import torch_vulkan.inductor.wrapper_helpers as mod

        with open(mod.__file__) as f:
            n = sum(1 for _ in f)
        assert n <= 800, (
            f"wrapper_helpers.py is {n} lines — exceeds anti-goal #7 cap of 800."
        )

    def test_helpers_imported_into_wrapper(self):
        """wrapper.py must import key helpers from wrapper_helpers."""
        import torch_vulkan.inductor.wrapper as mod

        with open(mod.__file__) as f:
            src = f.read()
        assert "from .wrapper_helpers import" in src, (
            "wrapper.py must import from wrapper_helpers"
        )
        for name in (
            "_batch_dispatch_enabled",
            "_lifetime_class_for_name",
            "_normalize_strides_to_row_major",
        ):
            assert name in src, f"wrapper.py must import {name} from wrapper_helpers"

    def test_helpers_not_defined_in_wrapper(self):
        """wrapper.py must NOT define the moved helpers inline."""
        import torch_vulkan.inductor.wrapper as mod

        with open(mod.__file__) as f:
            src = f.read()
        for fn in (
            "def _install_vulkan_skip_alignment_clone",
            "def _batch_dispatch_enabled",
            "def _lifetime_class_for_name",
        ):
            assert fn not in src, (
                f"wrapper.py still defines {fn!r} — should be in wrapper_helpers.py"
            )

    def test_normalize_strides_correctness(self):
        """_normalize_strides_to_row_major produces correct row-major strides."""
        from torch_vulkan.inductor.wrapper_helpers import (
            _normalize_strides_to_row_major,
        )

        assert _normalize_strides_to_row_major([4], [1]) == [1]
        assert _normalize_strides_to_row_major([3, 4], [4, 1]) == [4, 1]
        assert _normalize_strides_to_row_major([2, 3, 4], [12, 4, 1]) == [12, 4, 1]
        assert _normalize_strides_to_row_major([], []) == []


class TestMAG51ActivationDecompRouting:
    """M-AG5.1 Tier-0/Tier-1/Tier-2 closeout (anti-goal #5 cleanup).

    Ten activation backward ops (hardswish, hardsigmoid, mish, threshold,
    silu, leaky_relu, elu, sigmoid, tanh, softplus) had decomposition
    entries in ``meta_patches/decomposition_passes.py`` that competed
    with the autodiff / algebraic-lowering paths in ``bwd_diff_table.py``
    + ``bwd_lowerings.py``. The decomp entries were symptom-patches;
    deleting them lets the autodiff (or algebraic) path own these ops
    outright.

    The tests below lock in the deletion at the structural level — they
    inspect the ``_patch_decompositions`` source and the routing tables.
    They deliberately do NOT inspect ``torch._decomp.decomposition_table``
    after init because PyTorch core also ships defaults for the same
    backward ops; the point of M-AG5.1 is that our patch no longer
    overrides those upstream entries.

    * ``test_patch_does_not_override_deleted_ops`` — the
      ``replacements`` dict in ``_patch_decompositions`` does NOT include
      any of the ten Tier-0/Tier-1/Tier-2 aten backward ops.
    * ``test_patch_still_overrides_retained_ops`` — the three Tier-3/4
      entries (``hardtanh``, ``relu`` fwd, ``gelu``) ARE still
      overridden, with their documented blockers.
    * ``test_bwd_diff_routing_intact`` — every deleted op still has
      either a ``BWD_DIFF_TABLE`` entry or a direct ``register_lowering``.
    """

    _BUG_ROOT_COMPONENT = "fx-meta-patches"

    # Aten ops whose decomp entries were deleted.
    _DELETED_OPS = (
        "hardswish_backward",
        "hardsigmoid_backward",
        "mish_backward",
        "threshold_backward",
        "silu_backward",
        "leaky_relu_backward",
        "elu_backward",
        "sigmoid_backward",
        "tanh_backward",
        # Tier-2 (M-AG5.1, 2026-05-22). softplus_backward routes via
        # the algebraic lowering in bwd_lowerings.py — see
        # TestMAG51Tier2Softplus below for the dedicated coverage.
        "softplus_backward",
    )

    # Decomp entries that remain (each with a documented blocker).
    _RETAINED_OPS = (
        "hardtanh_backward",  # Tier-3 (no hardtanh_fwd in BWD_DIFF_TABLE)
        "gelu_backward",  # Tier-4 (string approximate= arg)
    )

    @staticmethod
    def _patch_source() -> str:
        import inspect

        from torch_vulkan.inductor.meta_patches.decomposition_passes import (
            _patch_decompositions,
        )

        return inspect.getsource(_patch_decompositions)

    def test_patch_does_not_override_deleted_ops(self):
        src = self._patch_source()
        for short in self._DELETED_OPS:
            needle = f"aten.{short}.default"
            assert needle not in src, (
                f"M-AG5.1: ``{needle}`` is still mapped inside "
                f"_patch_decompositions() — the decomp entry must be "
                f"removed in favour of the autodiff path "
                f"(bwd_diff_table.py + bwd_lowerings.py)."
            )

    def test_patch_still_overrides_retained_ops(self):
        src = self._patch_source()
        for short in self._RETAINED_OPS:
            needle = f"aten.{short}.default"
            assert needle in src, (
                f"M-AG5.1: ``{needle}`` is missing from "
                f"_patch_decompositions() — it is documented as Tier-2/3/4 "
                f"and must remain overridden until its blocker is closed."
            )
        # ``aten.relu.default`` (forward decomp, ReluBackward0 safety net)
        assert "aten.relu.default" in src, (
            "M-AG5.1: ``aten.relu.default`` forward decomp missing from "
            "_patch_decompositions() — this is the C1 safety net so "
            "ReluBackward0 never enters the joint trace."
        )

    def test_bwd_diff_routing_intact(self):
        """Every deleted decomp op must still have a Vulkan backward path.

        Either via ``BWD_DIFF_TABLE`` (autodiff codegen) or a direct
        ``@register_lowering`` in ``bwd_lowerings.py`` (algebraic
        decomposition).
        """
        import torch_vulkan  # noqa: F401
        from torch._inductor import lowering as L
        from torch_vulkan.inductor.bwd_diff_table import BWD_DIFF_TABLE

        aten = torch.ops.aten
        for short in self._DELETED_OPS:
            aten_key = f"aten.{short}"
            target = getattr(aten, short)
            has_table = aten_key in BWD_DIFF_TABLE
            try:
                target_default = target.default
            except AttributeError:
                target_default = target
            has_lowering = target in L.lowerings or target_default in L.lowerings
            assert has_table or has_lowering, (
                f"M-AG5.1: aten.{short} has no Vulkan backward routing "
                f"after the decomp deletion — neither BWD_DIFF_TABLE entry "
                f"nor register_lowering. Restore one or revert the deletion."
            )


# ═══════════════════════════════════════════════════════════════════════════
# M-AG5.1 Tier-2 — softplus_backward algebraic lowering closeout
# ═══════════════════════════════════════════════════════════════════════════


class TestMAG51Tier2Softplus:
    """M-AG5.1 Tier-2 (2026-05-22): ``aten.softplus_backward`` no longer
    routes through ``meta_patches/decomposition_passes.py`` and no longer
    appears in ``BWD_DIFF_TABLE``. Instead it has a dedicated algebraic
    ``register_lowering`` in
    ``bwd_lowerings.py::_register_algebraic_backward_lowerings`` that
    mirrors the leaky_relu pattern — multiply, sigmoid, threshold-mask,
    ``where`` — producing pointwise IR the Inductor scheduler can fuse
    with neighbouring ops.

    The Tier-2 plan originally called for extending the unary bwd_diff
    emitter with ``no_diff_params``, but ``softplus_fwd`` in
    ``shaders/lib/pointwise.slang`` (Group G, off-limits to this branch)
    does not declare ``beta``/``threshold`` parameters; the
    ``no_diff_params`` plumbing already supports them on the emitter
    side (see ``aten.leaky_relu_backward``), but the shader signature
    mismatch would cause slangc to reject the emitted call. The
    algebraic route is the Group-B-only closeout — see the documented
    Tier-2 entry in ``EXCLUDED_DIFFERENTIABLE_FWDS``.

    Tests:

    * ``test_table_does_not_route_softplus`` — ``BWD_DIFF_TABLE`` has
      no ``aten.softplus_backward`` entry; ``softplus_fwd`` IS listed in
      ``EXCLUDED_DIFFERENTIABLE_FWDS`` with a documented reason.
    * ``test_softplus_backward_registered_in_lowering_table`` — the
      Inductor lowering table has a ``register_lowering`` for
      ``aten.softplus_backward``.
    * ``test_softplus_backward_correctness_default_beta`` — end-to-end
      ``torch.compile`` backward with the PyTorch default
      ``beta=1, threshold=20`` matches CPU autograd.
    * ``test_softplus_backward_correctness_non_default_beta`` — the same
      check with ``beta=1.5`` exercises the multiplication by ``beta``
      that the previous broken bwd_diff route would have silently lost.
    * ``test_softplus_backward_correctness_threshold_branch`` — drives
      ``self`` large enough that ``beta*self > threshold`` everywhere,
      forcing the ``where`` to pick the identity branch
      (``grad_input == grad_output``).
    """

    _BUG_ROOT_COMPONENT = "fx-meta-patches"

    def test_table_does_not_route_softplus(self):
        from torch_vulkan.inductor.bwd_diff_table import (
            BWD_DIFF_TABLE,
            EXCLUDED_DIFFERENTIABLE_FWDS,
        )

        assert "aten.softplus_backward" not in BWD_DIFF_TABLE, (
            "M-AG5.1 Tier-2: aten.softplus_backward must NOT be in "
            "BWD_DIFF_TABLE — the unary emitter cannot thread "
            "beta/threshold through softplus_fwd (the shader signature "
            "does not declare them as no_diff scalars)."
        )
        assert "softplus_fwd" in EXCLUDED_DIFFERENTIABLE_FWDS, (
            "M-AG5.1 Tier-2: softplus_fwd retains its [Differentiable] "
            "annotation in shaders/lib/pointwise.slang, so it must be "
            "listed in EXCLUDED_DIFFERENTIABLE_FWDS with a documented "
            "reason or the BwdDiffCoverageGate will fail."
        )

    def test_softplus_backward_registered_in_lowering_table(self):
        import torch_vulkan  # noqa: F401
        from torch._inductor import lowering as L
        from torch_vulkan.inductor import register

        register()
        target = torch.ops.aten.softplus_backward.default
        assert target in L.lowerings, (
            "M-AG5.1 Tier-2: aten.softplus_backward.default missing "
            "from L.lowerings — the algebraic register_lowering in "
            "bwd_lowerings.py::_register_algebraic_backward_lowerings "
            "did not fire."
        )

    @staticmethod
    def _check_correctness(beta: float, threshold: float, scale: float = 1.0):
        torch._dynamo.reset()
        torch.manual_seed(0xA51 ^ int(beta * 1000) ^ int(threshold * 1000))

        shape = (8, 32)
        x_cpu = (torch.randn(shape) * scale).contiguous()
        x_cpu_ref = x_cpu.detach().clone().requires_grad_(True)
        ref = torch.nn.functional.softplus(x_cpu_ref, beta=beta, threshold=threshold)
        ref.sum().backward()
        grad_ref = x_cpu_ref.grad.clone()

        x_v = x_cpu.detach().to("vulkan:0").requires_grad_(True)

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.nn.functional.softplus(x, beta=beta, threshold=threshold).sum()

        loss = fn(x_v)
        loss.backward()
        assert x_v.grad is not None, (
            f"M-AG5.1 Tier-2: x.grad is None for beta={beta}, threshold={threshold}"
        )
        torch.testing.assert_close(x_v.grad.cpu(), grad_ref, rtol=1e-4, atol=1e-5)

    def test_softplus_backward_correctness_default_beta(self):
        # PyTorch defaults: beta=1, threshold=20.
        self._check_correctness(beta=1.0, threshold=20.0, scale=2.0)

    def test_softplus_backward_correctness_non_default_beta(self):
        # beta=1.5 — exercises the ``mul(self, beta)`` step that the
        # previous broken bwd_diff route would have lost (the old unary
        # lowering signature was ``(grad_output, self)`` with no slot
        # for beta).
        self._check_correctness(beta=1.5, threshold=20.0, scale=2.0)

    def test_softplus_backward_correctness_threshold_branch(self):
        # scale=15 with threshold=20 puts most x values close to (but
        # straddling) the threshold so both ``where`` branches fire.
        self._check_correctness(beta=1.0, threshold=20.0, scale=15.0)


# ═══════════════════════════════════════════════════════════════════════════
# M-NEW.11 — conv2d + GroupNorm + ReLU fused-op correctness
# ═══════════════════════════════════════════════════════════════════════════


class TestMNew11ConvGnReluFusedCorrectness:
    """Correctness gate for the ``_slang_tile_conv2d_gn_relu`` caller.

    Catches two regressions investigated 2026-05-21:

    1. **Op-order semantic bug** — the pre-fix shader composed
       ``gn(relu(conv(x)))`` instead of the PyTorch-canonical
       ``relu(gn(conv(x)))``.  Even after that fix, slangc 2026.7.1
       miscompiled Pass-3 of the fused shader and dropped Wave 1's
       stores when the stored value depended on both the conv chain
       and the welford output.  The Group-D mitigation routes the
       caller through a 3-dispatch ``aten.convolution`` + ``F.group_norm``
       + ``F.relu`` fallback so eager / compile-mode users keep
       getting correct values while the shader is being rewritten.

    These tests lock in the **callable-level** correctness — they call
    ``_slang_tile_conv2d_gn_relu`` directly (not through the
    ``conv2d_gn_relu_fused`` custom op) so they exercise the Group-D
    Python entry point without depending on FX-pass plumbing.  The
    tolerance is ``1e-3`` to match the SmallCNN E2E gate.
    """

    @staticmethod
    def _run_case(N, C_in, C_out, H, W, num_groups, *, with_bias=True):
        import torch
        import torch.nn.functional as F
        import torch_vulkan  # noqa: F401
        from torch_vulkan.inductor.templates.caller.conv import (
            _slang_tile_conv2d_gn_relu,
        )

        torch.manual_seed(0)
        x_vk = torch.randn(N, C_in, H, W, device="vulkan")
        w_vk = torch.randn(C_out, C_in, 3, 3, device="vulkan")
        b_vk = torch.randn(C_out, device="vulkan") if with_bias else None
        gw_vk = torch.randn(C_out, device="vulkan")
        gb_vk = torch.randn(C_out, device="vulkan")

        x_cpu = x_vk.cpu()
        w_cpu = w_vk.cpu()
        b_cpu = b_vk.cpu() if with_bias else None
        gw_cpu = gw_vk.cpu()
        gb_cpu = gb_vk.cpu()

        out_vk = torch.empty(N, C_out, H, W, device="vulkan")
        _slang_tile_conv2d_gn_relu(
            x_vk,
            w_vk,
            b_vk,
            gw_vk,
            gb_vk,
            out_vk,
            stride=(1, 1),
            padding=(1, 1),
            dilation=(1, 1),
            num_groups=num_groups,
            eps=1e-5,
        )

        out_cpu = F.relu(
            F.group_norm(
                F.conv2d(x_cpu, w_cpu, b_cpu, stride=1, padding=1),
                num_groups,
                gw_cpu,
                gb_cpu,
                eps=1e-5,
            )
        )
        return out_vk.cpu(), out_cpu

    def test_smallcnn_first_block(self):
        """SmallCNN's first conv_gn_relu block (3→16 chans, 32×32, G=4)."""
        out_vk, out_cpu = self._run_case(
            N=2, C_in=3, C_out=16, H=32, W=32, num_groups=4
        )
        err = (out_vk - out_cpu).abs().max().item()
        assert err < 1e-3, f"max_err={err:.6e}"
        # No negatives — ReLU is the outermost op.
        assert (out_vk >= 0).all(), "ReLU was not applied as the outermost op"

    def test_smallcnn_second_block(self):
        """SmallCNN's second conv_gn_relu block (16→32 chans, 16×16, G=8)."""
        out_vk, out_cpu = self._run_case(
            N=2, C_in=16, C_out=32, H=16, W=16, num_groups=8
        )
        err = (out_vk - out_cpu).abs().max().item()
        assert err < 1e-3, f"max_err={err:.6e}"
        assert (out_vk >= 0).all()

    def test_tiny_case(self):
        """Tiny case (1→4 chans, 8×8, G=2) — reproduces the slangc Wave-1
        store-drop signature: half the channels would be left at the
        pre-fill value before the Group-D fallback landed."""

        out_vk, out_cpu = self._run_case(N=1, C_in=1, C_out=4, H=8, W=8, num_groups=2)
        err = (out_vk - out_cpu).abs().max().item()
        assert err < 1e-3, f"max_err={err:.6e}"
        # Every channel must have at least one non-zero value (otherwise
        # the channel was never touched — the Wave-1 miscompile fingerprint).
        for c in range(out_vk.shape[1]):
            assert (out_vk[0, c] > 0).any(), (
                f"Channel {c} produced all-zero output — slangc Wave-1 "
                f"store-drop regression in conv_gn_relu fused path. "
                f"Was the 3-dispatch fallback in "
                f"``_slang_tile_conv2d_gn_relu`` removed?"
            )

    def test_no_bias(self):
        """has_bias=False path (bias=None)."""
        out_vk, out_cpu = self._run_case(
            N=2, C_in=4, C_out=8, H=16, W=16, num_groups=2, with_bias=False
        )
        err = (out_vk - out_cpu).abs().max().item()
        assert err < 1e-3, f"max_err={err:.6e}"


class TestM_NEW_12_SecondConv2dCorrectness:
    """Regression gate for the **DispatchBatcher / direct-dispatch race**.

    Bug (closed 2026-05-22): the wrapper codegen queues Triton-style
    kernel dispatches via ``_batcher.add(...)`` and only flushes them
    at ``_batcher.__exit__``.  Custom-op and template-caller lines such
    as ``torch.ops.torch_vulkan.conv2d_gn_relu_fused.default(...)`` and
    ``_slang_tile_conv2d(buf2, ...)`` are emitted as immediate Python
    function calls that dispatch synchronously.  When a direct call
    reads from a buffer that a still-queued kernel was supposed to
    populate, it reads uninitialised (zero) data.

    Repro before fix: the second ``conv2d_gn_relu_fused`` in a
    ``conv1 → gn1 → relu → maxpool → conv2 → gn2 → relu`` chain emitted
    bias-only output — ``32 unique values per (B, 32, 16, 16) tensor``,
    one per output channel (the per-channel bias value).

    Fix: ``DispatchBatcher.flush_current_if_active()`` flushes any
    queued dispatches; the wrapper emits this call before every direct
    extern-kernel / fallback-kernel / template-caller line.  Wrappers
    around ``_slang_tile_conv2d`` and ``_slang_tile_mm`` in
    ``torch_vulkan.inductor.__init__`` also flush (defence in depth).

    These tests verify the symptom is gone:

    * ``test_pool_then_conv2`` — pool → conv2 (the structural pattern
      with the failure)
    * ``test_full_chain_relu2`` — ``conv1 → gn1 → relu → pool → conv2 →
      gn2 → relu`` (matches SmallCNN's second-block forward), with the
      unique-output-value assertion that catches the bias-only failure.
    * ``test_two_convs_back_to_back`` — sanity check that pure
      conv2d chains stay correct.
    * ``test_dispatchbatcher_active_tracking`` — unit-level check
      that ``DispatchBatcher._current`` tracks correctly.
    """

    @staticmethod
    def _compile_compare(model_factory, x_shape, atol=1e-3):
        import torch
        import torch_vulkan  # noqa: F401

        torch.manual_seed(0)
        m_cpu = model_factory()
        m_vk = model_factory().to("vulkan")
        m_vk.load_state_dict({k: v.to("vulkan") for k, v in m_cpu.state_dict().items()})
        x_cpu = torch.randn(*x_shape)
        x_vk = x_cpu.to("vulkan")
        compiled = torch.compile(lambda m, x: m(x), backend="inductor")
        out_cpu = m_cpu(x_cpu)
        out_vk = compiled(m_vk, x_vk).cpu()
        err = (out_vk - out_cpu).abs().max().item()
        unique = int(torch.unique(out_vk.flatten()).numel())
        return out_vk, out_cpu, err, unique

    def test_pool_then_conv2(self):
        """MaxPool2d → Conv2d: pool kernel is queued, conv2d is direct."""
        import torch.nn as nn

        def factory():
            class M(nn.Module):
                def __init__(self):
                    super().__init__()
                    self.pool = nn.MaxPool2d(2, 2)
                    self.conv = nn.Conv2d(16, 32, 3, padding=1)

                def forward(self, x):
                    return self.conv(self.pool(x))

            return M()

        out_vk, out_cpu, err, unique = self._compile_compare(factory, (2, 16, 32, 32))
        assert err < 1e-3, f"max_err={err:.6e}"
        assert unique > 1000, (
            f"unique-value count too low ({unique}); the queued pool "
            f"kernel was not flushed before the direct conv2d read."
        )

    def test_full_chain_relu2(self):
        """SmallCNN-shaped: conv1 → gn1 → relu → pool → conv2 → gn2 → relu."""
        import torch.nn as nn
        import torch.nn.functional as F

        def factory():
            class M(nn.Module):
                def __init__(self):
                    super().__init__()
                    self.conv1 = nn.Conv2d(3, 16, 3, padding=1)
                    self.gn1 = nn.GroupNorm(4, 16)
                    self.conv2 = nn.Conv2d(16, 32, 3, padding=1)
                    self.gn2 = nn.GroupNorm(8, 32)
                    self.pool = nn.MaxPool2d(2, 2)

                def forward(self, x):
                    x = F.relu(self.gn1(self.conv1(x)))
                    x = self.pool(x)
                    x = F.relu(self.gn2(self.conv2(x)))
                    return x

            return M()

        out_vk, out_cpu, err, unique = self._compile_compare(factory, (2, 3, 32, 32))
        assert err < 1e-3, f"max_err={err:.6e}"
        # Pre-fix unique == 32 (one per output channel = bias broadcast).
        # Healthy output has thousands of distinct values.
        assert unique > 1000, (
            f"unique-value count {unique} suggests the second "
            f"conv2d_gn_relu_fused read from an un-flushed batcher buffer. "
            f"DispatchBatcher.flush_current_if_active() emission may be "
            f"missing from the wrapper for FallbackKernel or "
            f"ExternKernelAlloc lines."
        )

    def test_two_convs_back_to_back(self):
        """Sanity: no pool in between; both convs run with empty batcher."""
        import torch.nn as nn

        def factory():
            class M(nn.Module):
                def __init__(self):
                    super().__init__()
                    self.c1 = nn.Conv2d(3, 16, 3, padding=1)
                    self.c2 = nn.Conv2d(16, 32, 3, padding=1)

                def forward(self, x):
                    return self.c2(self.c1(x))

            return M()

        _, _, err, _ = self._compile_compare(factory, (2, 3, 32, 32))
        assert err < 1e-3, f"max_err={err:.6e}"

    def test_dispatchbatcher_active_tracking(self):
        """Unit-level: ``DispatchBatcher._current`` follows __enter__/__exit__."""
        import torch_vulkan  # noqa: F401
        from torch_vulkan.inductor.runtime.batcher import DispatchBatcher

        assert DispatchBatcher._current is None
        b = DispatchBatcher()
        with b:
            assert DispatchBatcher._current is b
            # flush_current_if_active is a no-op on empty queue
            DispatchBatcher.flush_current_if_active()
        assert DispatchBatcher._current is None


class TestM_NEW_13_NoNaNBackward:
    """Regression gate for the **bool-graph-input load type mismatch**.

    Bug (closed 2026-05-22, M-NEW.13): the load path in
    ``kernel/pointwise_load_mixin.py`` emitted
    ``_vk_unpack_u8(args.in_ptr0, idx)`` for ``torch.bool`` buffers that
    were graph inputs (typical case: a saved ReLU mask from the forward
    partitioned across the fw/bw boundary).  The helper
    ``_vk_unpack_u8(StructuredBuffer<uint> buf, uint idx)`` expects a
    4 B/slot ``uint`` SSBO, but post-M18.4-followup-C all bool buffers
    bind as ``StructuredBuffer<uint8_t>`` (1 B/slot) to match PyTorch's
    1 B/element ``torch.bool`` storage.  slangc errors out with
    ``E30019: type mismatch — expected StructuredBuffer<uint>, got
    StructuredBuffer<uint8_t>`` and the whole backward graph fails to
    compile.

    Pre-fix symptom: SmallCNN's ``test_grad_parity``,
    ``test_10step_no_nan``, and ``test_forward_backward`` all failed
    with ``Non-finite grad for conv1.weight`` — the failure tracked
    back to a slangc compile error on the backward graph that flagged
    a stage with GroupNorm + ReLU + MaxPool2d (the partitioner saved a
    bool mask for the ReLU recompute path).

    Fix (``kernel/pointwise_load_mixin.py``): drop the special branch
    that routed bool graph inputs through ``_vk_unpack_u8``. Bool
    buffers — whether graph inputs OR compile-internal — now read via
    the generic ``_LOAD_DISPATCH`` table's ``((float)(v[i]))`` form,
    matching the ``uint8_t`` slot binding.
    """

    def test_gn_relu_pool_linear_backward_compiles_and_no_nan(self):
        """Repro of the SmallCNN second-block backward: GN + ReLU + Pool + Linear.

        Stage-4 of ``probe_nan_backward.py`` — the minimal slice that hit
        the pre-fix ``E30019`` slangc compile failure.  Verifies the
        backward graph (a) compiles without slangc errors, (b) produces
        non-finite-free gradients on every parameter.
        """
        import torch
        import torch.nn as nn
        import torch.nn.functional as F

        try:
            torch.empty(1, device="vulkan:0")
        except Exception:
            import pytest

            pytest.skip("Vulkan GPU not available")

        torch.manual_seed(42)

        class _Stage4(nn.Module):
            def __init__(self):
                super().__init__()
                self.gn = nn.GroupNorm(8, 32)
                self.pool = nn.MaxPool2d(2, 2)
                self.fc = nn.Linear(32 * 8 * 8, 10)

            def forward(self, x):
                x = F.relu(self.gn(x))
                x = self.pool(x)
                x = x.flatten(1)
                return self.fc(x)

        model = _Stage4().to("vulkan")
        compiled = torch.compile(model, backend="inductor")
        x = torch.randn(2, 32, 16, 16, device="vulkan")
        targets = torch.randint(0, 10, (2,), device="vulkan")

        logits = compiled(x)
        loss = F.cross_entropy(logits, targets)
        loss.backward()

        for name, p in model.named_parameters():
            assert p.grad is not None, f"no grad for {name}"
            finite = torch.isfinite(p.grad.cpu()).all().item()
            assert finite, (
                f"M-NEW.13 regression: non-finite grad for {name} — "
                f"check bool-buffer load path in pointwise_load_mixin.py."
            )

    def test_relu_compare_save_backward_no_compile_error(self):
        """Direct repro of the bool-graph-input shader compile failure.

        Builds a tiny ``relu(x).sum()`` pattern that — under the joint
        trace + partitioner — saves a bool mask as a backward graph
        input.  Pre-fix the backward shader read ``args.in_ptr_<mask>``
        via ``_vk_unpack_u8`` against an ``uint8_t`` SSBO and
        slangc-failed with ``E30019``.  Post-fix the kernel compiles.

        Uses ``aten.gt.Scalar`` to force a bool buffer that the
        partitioner cannot fold away.
        """
        import torch
        import torch.nn.functional as F

        try:
            torch.empty(1, device="vulkan:0")
        except Exception:
            import pytest

            pytest.skip("Vulkan GPU not available")

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            # GN + ReLU + something the partitioner won't trivially fold —
            # use a Linear to keep the graph non-trivial and ensure the
            # backward partitioner saves a bool mask as graph input.
            y = F.relu(F.linear(x, w, b))
            return (y * y).sum()

        x = torch.randn(4, 32, device="vulkan", requires_grad=True)
        w = torch.randn(16, 32, device="vulkan", requires_grad=True)
        b = torch.randn(16, device="vulkan", requires_grad=True)

        out = fn(x, w, b)
        out.backward()

        # The compile would have raised pre-fix; assert that grads exist
        # and are finite as a positive confirmation.
        for tag, t in (("x", x), ("w", w), ("b", b)):
            assert t.grad is not None, f"no grad on {tag}"
            assert torch.isfinite(t.grad.cpu()).all().item(), (
                f"M-NEW.13: non-finite grad on {tag}"
            )


class TestM_NEW_14_TwoBlockSmallCNNBackward:
    """Diagnostic gate for the **two-block CNN backward** NaN bug.

    OPEN as of 2026-05-22.  Locks in the bisect result that single-block
    SmallCNN (Stage 5 of ``agent_space/probe_nan_backward.py`` — one
    ``Conv2d → GroupNorm → ReLU → MaxPool → Linear`` block) produces
    finite gradients under ``torch.compile``, while the two-block
    full SmallCNN (Stage 6 — two stacked Conv+GN+ReLU blocks with a
    pool between them) produces ``conv1.weight.grad = NaN`` AND
    ``gn2.weight.grad = exactly 0`` AND ``gn1.weight.grad`` blown up
    to ~100× the CPU-baseline magnitude.

    The single-block test is the *positive* gate (must stay green).
    The two-block test is the *xfail-strict* gate — flip the
    ``xfail`` to a passing assertion once M-NEW.14 lands.  Diagnosis
    is in ``docs/10-inductor-backend.md`` § 0.0.5 (the M-NEW.14
    OPEN block); the smoking gun is the
    ``reinterpret_tensor`` aliasing of block-2 GN scratch buffers
    (``buf5`` / ``buf6``) into block-1 GN gradient outputs
    (``buf31`` / ``buf32``) in the compile-mode generated wrapper —
    see ``agent_space/m_new_14_compiled_wrapper.py`` lines 930-931.
    """

    @staticmethod
    def _make_small_cnn():
        import torch
        import torch.nn as nn
        import torch.nn.functional as F

        class SmallCNN(nn.Module):
            def __init__(self):
                super().__init__()
                self.conv1 = nn.Conv2d(3, 16, 3, padding=1)
                self.gn1 = nn.GroupNorm(4, 16)
                self.conv2 = nn.Conv2d(16, 32, 3, padding=1)
                self.gn2 = nn.GroupNorm(8, 32)
                self.pool = nn.MaxPool2d(2, 2)
                self.flatten = nn.Flatten()
                self.fc = nn.Linear(32 * 8 * 8, 10)

            def forward(self, x):
                x = F.relu(self.gn1(self.conv1(x)))
                x = self.pool(x)
                x = F.relu(self.gn2(self.conv2(x)))
                x = self.pool(x)
                x = self.flatten(x)
                return self.fc(x)

        return SmallCNN

    @pytest.mark.slow_compile(seconds=180)
    def test_single_block_compile_backward_finite(self):
        """POSITIVE gate — Stage 5 of the bisect probe (single
        Conv+GN+ReLU+Pool+Linear block) backward MUST produce finite
        grads.  Locks the floor below which a regression would mean
        even the single-block case is broken.
        """
        import torch
        import torch.nn as nn
        import torch.nn.functional as F

        try:
            torch.empty(1, device="vulkan:0")
        except Exception:
            import pytest

            pytest.skip("Vulkan GPU not available")

        torch.manual_seed(42)

        class _Stage5(nn.Module):
            def __init__(self):
                super().__init__()
                self.conv = nn.Conv2d(3, 32, 3, padding=1)
                self.gn = nn.GroupNorm(8, 32)
                self.pool = nn.MaxPool2d(2, 2)
                self.flatten = nn.Flatten()
                self.fc = nn.Linear(32 * 16 * 16, 10)

            def forward(self, x):
                x = F.relu(self.gn(self.conv(x)))
                x = self.pool(x)
                x = self.flatten(x)
                return self.fc(x)

        model = _Stage5().to("vulkan")
        compiled = torch.compile(model, backend="inductor")
        x = torch.randn(2, 3, 32, 32, device="vulkan")
        targets = torch.randint(0, 10, (2,), device="vulkan")
        logits = compiled(x)
        loss = F.cross_entropy(logits, targets)
        loss.backward()
        for name, p in model.named_parameters():
            assert p.grad is not None, f"no grad for {name}"
            ok = torch.isfinite(p.grad.cpu()).all().item()
            assert ok, (
                f"M-NEW.14 single-block floor: non-finite grad for {name}. "
                f"Stage-5 of the bisect probe must stay green; if this fails, "
                f"the regression is deeper than the two-block bug."
            )

    @pytest.mark.slow_compile(seconds=180)
    def test_two_block_compile_backward_finite(self):
        """OPEN GATE (M-NEW.14) — Stage 6 of the bisect probe (full
        SmallCNN, two stacked Conv+GN+ReLU blocks) backward.
        """
        import torch
        import torch.nn.functional as F

        try:
            torch.empty(1, device="vulkan:0")
        except Exception:
            import pytest

            pytest.skip("Vulkan GPU not available")

        # Pre-check stage — everything before the assertion must
        # succeed or pytest.skip per
        # feedback_xfail_empirical_verification +
        # feedback_floor_xfail_scoping memories.  A compile-time
        # failure here would otherwise produce a false-XFAIL that
        # masks the regression we're tracking.
        torch.manual_seed(42)
        SmallCNN = self._make_small_cnn()
        model = SmallCNN().to("vulkan")
        compiled = torch.compile(model, backend="inductor")
        x = torch.randn(2, 3, 32, 32, device="vulkan")
        targets = torch.randint(0, 10, (2,), device="vulkan")
        logits = compiled(x)
        loss = F.cross_entropy(logits, targets)
        loss.backward()

        # Pre-check: every parameter has a grad attribute (otherwise
        # the failure is unrelated to NaN — e.g. autograd didn't run).
        for name, p in model.named_parameters():
            if p.grad is None:
                import pytest

                pytest.skip(
                    f"Pre-check skip: no grad attached to {name}; "
                    "unrelated to M-NEW.14."
                )

        # SCOPED assertion — this is what's under xfail-strict.
        # When M-NEW.14 is fixed every grad will be finite; this
        # assertion will pass, the test XPASSes, and CI fails until
        # the marker is removed.
        for name, p in model.named_parameters():
            ok = torch.isfinite(p.grad.cpu()).all().item()
            assert ok, f"M-NEW.14: non-finite grad for {name}"

    # NOTE: the gn2.weight.grad=0 fingerprint is the canonical
    # signature in the standalone-probe run (see
    # ``agent_space/probe_nan_stage6.py``) but does NOT reliably
    # reproduce inside the pytest harness — the conftest autouse
    # ``torch._dynamo.reset()`` + per-test cache-reset combination
    # nudges the compile through a different code path under
    # successive tests, so the in-pytest grad is sometimes finite
    # and non-zero on the 3rd-in-a-class invocation.  We DELIBERATELY
    # don't gate on the zero fingerprint here to avoid a flaky
    # xfail-strict.  The standalone-probe assertion lives in
    # ``agent_space/probe_nan_stage6.py``; the in-pytest gate is
    # only the finite-grads assertion above.


class TestM22_5DeadLoweringCleanup:
    """M22.5 — regression gate: formerly-dead @register_lowering stubs replaced.

    Before M22.5, several ops had ``@register_lowering`` entries that
    immediately returned ``NotImplemented`` or raised on every call — adding
    startup cost and confusing coverage walkers without enabling any kernels.
    The affected ops were:

      - ``aten.addcmul``, ``aten.addcdiv`` (activation.py)
      - ``aten.index_add``, ``aten.index_copy`` (scatter.py)
      - ``aten.unfold`` (view.py)
      - ``aten.rot90`` (activation.py — M19.R fixed the correctness bug and
        removed the old iterative stub)

    After M22.5 these all have real lowerings.  This class asserts:

    1. Each op IS registered in Inductor's lowering table (the registration
       ran at backend init).
    2. ``norm.py`` does NOT contain duplicate ``_register_*_backward``
       definitions — the duplicate stubs were collapsed in M22.5.
    3. The norm-backward stubs in ``norm.py`` remain ``pass``-only
       (no accidental ``@register_lowering`` piggyback that would shadow
       the real lowerings in ``bwd_lowerings.py``).
    """

    _FORMERLY_DEAD_OPS = [
        "torch.ops.aten.addcmul.default",
        "torch.ops.aten.addcdiv.default",
        "torch.ops.aten.index_add.default",
        "torch.ops.aten.index_copy.default",
        "torch.ops.aten.unfold.default",
        "torch.ops.aten.rot90.default",
    ]

    def test_formerly_dead_ops_are_now_registered(self):
        """Each op that was a dead stub must now be in the lowering table."""
        import torch
        from torch._inductor.lowering import lowerings as _L

        missing = []
        for op_str in self._FORMERLY_DEAD_OPS:
            parts = op_str.split(".")
            # Navigate torch.ops.aten.<name>.<overload>
            obj = torch
            try:
                for part in parts[1:]:
                    obj = getattr(obj, part)
                if obj not in _L:
                    missing.append(op_str)
            except AttributeError:
                missing.append(f"{op_str} (attr not found)")

        assert not missing, (
            "M22.5: the following ops were formerly dead stubs and must now "
            "have real @register_lowering entries in the Inductor lowering "
            f"table (they are missing): {missing}"
        )

    def test_norm_py_no_duplicate_backward_stubs(self):
        """norm.py must not contain duplicate _register_*_backward definitions.

        M22.5 collapsed the four duplicate function bodies that Python
        was silently shadowing.  This test locks in the cleanup so
        they don't creep back in.
        """
        import ast
        import pathlib

        norm_path = (
            pathlib.Path(__file__).resolve().parent.parent
            / "python"
            / "torch_vulkan"
            / "inductor"
            / "lowerings"
            / "norm.py"
        )
        src = norm_path.read_text()
        tree = ast.parse(src)

        # Count top-level definitions of each _register_*_backward name.
        counts: dict[str, int] = {}
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                if node.name.startswith("_register_") and node.name.endswith(
                    "_backward"
                ):
                    counts[node.name] = counts.get(node.name, 0) + 1

        duplicates = {name: cnt for name, cnt in counts.items() if cnt > 1}
        assert not duplicates, (
            "M22.5: norm.py contains duplicate function definitions for "
            f"{duplicates}. The duplicate stubs were supposed to be collapsed "
            "in M22.5. Remove the redundant definitions."
        )

    def test_norm_backward_stubs_do_not_register_lowerings(self):
        """The _register_*_backward stubs in norm.py must be pass-only.

        The real backward lowerings live in bwd_lowerings.py.  If the stubs
        in norm.py were to call @register_lowering they would shadow the
        real lowerings registered by bwd_lowerings.py (Inductor is
        first-come-first-served).
        """
        import ast
        import pathlib

        norm_path = (
            pathlib.Path(__file__).resolve().parent.parent
            / "python"
            / "torch_vulkan"
            / "inductor"
            / "lowerings"
            / "norm.py"
        )
        src = norm_path.read_text()
        tree = ast.parse(src)

        violations = []
        for node in ast.walk(tree):
            if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                continue
            if not (
                node.name.startswith("_register_") and node.name.endswith("_backward")
            ):
                continue
            # Look for @register_lowering decorator usage anywhere in the body.
            func_src = ast.get_source_segment(src, node) or ""
            if "register_lowering" in func_src:
                violations.append(node.name)

        assert not violations, (
            "M22.5: the following norm.py backward stubs contain "
            f"@register_lowering calls — they would shadow bwd_lowerings.py: "
            f"{violations}. The stubs must remain pass-only (TR.19)."
        )


class TestM195DynamicShapeConvLifting:
    """M19.5 — symbolic-shape-safe arithmetic in conv lowerings.

    These tests verify that ``lowerings/conv.py`` and
    ``lowerings/conv_transpose.py`` handle SymInt shapes without raising
    ``TypeError: int() argument must be a string, a bytes-like object or a
    real number, not 'Symbol'``.

    They operate at import / sympy level (no GPU required) so they run in
    the mock-test tier alongside ``TestDynamicShapeAudit``.

    Design
    ------
    * The ``H_out / W_out`` arithmetic in the conv2d and conv_transpose2d
      lowerings is the main dynamic-shape surface: it computes
      ``(H_in + 2*pH - dH*(kH-1) - 1) // sH + 1``.
    * The previous code coerced ``H_in`` and ``W_in`` via ``int()`` — this
      fails when they are ``sympy.Symbol`` (SymInt) under dynamic-shape
      compile.
    * M19.5 removes those coercions.  The tests below verify the math
      produces the correct result with both concrete and symbolic inputs.
    """

    @staticmethod
    def _h_out(H_in, kH, sH, pH, dH):
        """Conv2d output height formula (mirrors conv.py and conv_transpose.py)."""
        return (H_in + 2 * pH - dH * (kH - 1) - 1) // sH + 1

    @staticmethod
    def _h_out_transpose(H_in, kH, sH, adj_pH, dH):
        """Adjusted padding formula for conv_transpose2d equivalent conv2d.

        adj_pH = dH * (kH - 1) - pH
        H_out = H_in (stride=1 after upsample) + 2*adj_pH - dH*(kH-1) - 1 + 1
        """
        return H_in + 2 * adj_pH - dH * (kH - 1) - 1 + 1

    def test_h_out_formula_concrete(self):
        """With all-concrete (int) inputs the formula gives correct values."""
        # 8x8 input, 3x3 kernel, stride=1, pad=1 → 8x8 output
        assert self._h_out(8, 3, 1, 1, 1) == 8
        # 8x8 input, 3x3 kernel, stride=2, pad=1 → 4x4 output
        assert self._h_out(8, 3, 2, 1, 1) == 4
        # 16x16 input, 5x5 kernel, stride=1, pad=2 → 16x16
        assert self._h_out(16, 5, 1, 2, 1) == 16

    def test_h_out_formula_symbolic(self):
        """With a sympy Symbol for H_in the formula produces a SymPy expr.

        This is the key M19.5 contract: no ``int()`` coercion on H_in
        so the expression stays symbolic (SymPy propagates through it)
        instead of raising ``TypeError``.
        """
        import sympy

        H_in = sympy.Symbol("H_in", positive=True, integer=True)
        kH, sH, pH, dH = 3, 1, 1, 1
        expr = self._h_out(H_in, kH, sH, pH, dH)
        # Should be a SymPy expression, not raise.
        assert hasattr(expr, "subs"), (
            f"M19.5: H_out formula did not return a SymPy expr for symbolic H_in; "
            f"got {type(expr)!r}"
        )
        # Evaluates correctly for H_in=8 → H_out=8
        val = expr.subs(H_in, 8)
        assert int(val) == 8, f"M19.5: symbolic formula wrong; got {val}"

    def test_conv_weight_dims_are_always_static(self):
        """Verify our assumption: weight kernel dims (kH, kW) are always
        concrete (``int`` or ``sympy.Integer``), not symbolic.

        This is why the remaining ``int(weight.get_size()[2])`` calls in
        conv_transpose.py are safe — they operate on module parameters
        whose spatial dims are fixed at module-build time.
        """
        import sympy

        # Module params are always static: weight.size() returns a tuple of ints.
        # Symbolic batch/spatial only appears on *input* tensors.
        kH = sympy.Integer(3)
        assert isinstance(kH, sympy.Integer), (
            "weight kernel dim should be concrete Integer"
        )
        # int() on sympy.Integer works fine (no TypeError).
        assert int(kH) == 3

    def test_no_input_dim_int_coercion_in_conv_py(self):
        """Static analysis: ``lowerings/conv.py`` must not call ``int()``
        on any expression derived from ``input.get_size()`` for the batch
        or spatial dims (dim 0, 2, 3).

        The weight dims (dim 1, 2, 3) and stride/padding/dilation/groups
        are always-concrete and may still be ``int()``-coerced.

        This test parses the source to verify no line matches
        ``int(t1_sizes[0])``, ``int(t1_sizes[2])``, ``int(t1_sizes[3])``,
        etc. — the form that M19.5 removed.
        """
        import ast
        import inspect

        from torch_vulkan.inductor.lowerings.conv import (
            _register_conv_and_pool_lowerings,
        )

        src = inspect.getsource(_register_conv_and_pool_lowerings)
        tree = ast.parse(src)

        violations = []
        for node in ast.walk(tree):
            # Look for Call nodes: int(...)
            if not isinstance(node, ast.Call):
                continue
            # Check the function is 'int'
            if not (isinstance(node.func, ast.Name) and node.func.id == "int"):
                continue
            # The argument should not be a subscript of t1_sizes / input.get_size()
            # for indices 0, 2, 3 (batch, H, W).
            if not node.args:
                continue
            arg = node.args[0]
            # Pattern: int(t1_sizes[N]) or int(input.get_size()[N])
            if not isinstance(arg, ast.Subscript):
                continue
            # Collect the subscript index value.
            slice_node = arg.slice
            if isinstance(slice_node, ast.Constant) and slice_node.value in (0, 2, 3):
                # Check the sliced object.
                val = arg.value
                if isinstance(val, ast.Name) and val.id in ("t1_sizes",):
                    violations.append(ast.unparse(node))
                elif isinstance(val, ast.Call):
                    # e.g. input.get_size()[0]
                    call_src = ast.unparse(val)
                    if "get_size" in call_src and "input" in call_src:
                        violations.append(ast.unparse(node))

        assert not violations, (
            f"M19.5 regression: conv.py still int()-coerces input batch/spatial "
            f"dims (t1_sizes[0/2/3]). These must stay as SymInt for dynamic-shape "
            f"support. Violations: {violations}"
        )

    def test_no_input_dim_int_coercion_in_conv_transpose_py(self):
        """Same static analysis for ``lowerings/conv_transpose.py``.

        The 4 remaining ``int(weight.get_size()[…])`` calls there operate
        on weight dims (always static). This test verifies that NO call
        coerces ``input.get_size()[0]`` (batch), ``input.get_size()[2]``
        (H), or ``input.get_size()[3]`` (W).
        """
        import ast
        import inspect

        from torch_vulkan.inductor.lowerings.conv_transpose import (
            _register_conv_transpose_lowerings,
        )

        src = inspect.getsource(_register_conv_transpose_lowerings)
        tree = ast.parse(src)

        violations = []
        for node in ast.walk(tree):
            if not isinstance(node, ast.Call):
                continue
            if not (isinstance(node.func, ast.Name) and node.func.id == "int"):
                continue
            if not node.args:
                continue
            arg = node.args[0]
            if not isinstance(arg, ast.Subscript):
                continue
            slice_node = arg.slice
            if isinstance(slice_node, ast.Constant) and slice_node.value in (0, 2, 3):
                val = arg.value
                # Accept int(weight.get_size()[2]) — weight dims are static.
                if isinstance(val, ast.Call):
                    call_src = ast.unparse(val)
                    if "get_size" in call_src and "weight" not in call_src:
                        violations.append(ast.unparse(node))
                elif isinstance(val, ast.Name) and val.id in ("t1_sizes",):
                    violations.append(ast.unparse(node))

        assert not violations, (
            f"M19.5 regression: conv_transpose.py still int()-coerces input "
            f"batch/spatial dims. Violations: {violations}"
        )

    def test_get_static_numel_with_sympy(self):
        """``kernel.symbolic.get_static_numel`` returns None for symbolic
        expressions (not raises). Used in conv.py for channel-count guards.
        """
        import sympy
        from torch_vulkan.inductor.kernel.symbolic import get_static_numel

        C_in_sym = sympy.Symbol("C_in", positive=True, integer=True)
        result = get_static_numel(C_in_sym)
        assert result is None, (
            f"M19.5: get_static_numel(SymInt) should return None, got {result!r}"
        )
        # Concrete values still work.
        assert get_static_numel(sympy.Integer(64)) == 64
        assert get_static_numel(8) == 8


