class TestM198AutotuneEmptyChoices:
    """M19.8 — Autotune empty-choices warning guard.

    Adds a RuntimeWarning when ``benchmark_wg_sizes`` receives an empty
    ``wg_sizes`` list (all candidates filtered by occupancy/VGPR caps)
    instead of crashing with IndexError. Falls back to WG=256.

    Also guards ``VulkanScheduling.create_kernel_choices`` for the case
    where upstream returns no kernel candidates.

    No GPU required — purely logic tests.
    """

    def test_benchmark_wg_sizes_empty_warns(self):
        """benchmark_wg_sizes with empty wg_sizes must warn and return 256."""
        import warnings

        from torch_vulkan.inductor.autotune import benchmark_wg_sizes

        with warnings.catch_warnings(record=True) as caught:
            warnings.simplefilter("always")
            result = benchmark_wg_sizes(
                call_fn=lambda: None,
                wg_sizes=[],
                kernel_hash="deadbeef",
                device_name="test_device",
            )

        assert result == 256, f"M19.8: expected fallback 256, got {result}"
        assert any("M19.8" in str(w.message) for w in caught), (
            "M19.8: expected RuntimeWarning about empty wg_sizes"
        )

    def test_benchmark_wg_sizes_empty_is_runtime_warning(self):
        """The empty-wg_sizes warning must be a RuntimeWarning."""
        import warnings

        from torch_vulkan.inductor.autotune import benchmark_wg_sizes

        with warnings.catch_warnings(record=True) as caught:
            warnings.simplefilter("always")
            benchmark_wg_sizes(
                call_fn=lambda: None,
                wg_sizes=[],
                kernel_hash="cafe1234",
                device_name="test",
            )
        runtime_warns = [w for w in caught if issubclass(w.category, RuntimeWarning)]
        assert runtime_warns, "M19.8: expected at least one RuntimeWarning"

    def test_benchmark_wg_sizes_nonempty_no_warn(self):
        """Non-empty wg_sizes must NOT trigger the M19.8 warning."""
        import time
        import warnings

        from torch_vulkan.inductor.autotune import benchmark_wg_sizes

        calls = [0]

        def fast_call():
            calls[0] += 1

        with warnings.catch_warnings(record=True) as caught:
            warnings.simplefilter("always")
            result = benchmark_wg_sizes(
                call_fn=fast_call,
                wg_sizes=[256],
                kernel_hash="no_warn_test_" + str(int(time.time())),
                device_name="test_device",
                warmup=1,
                rep_ms=5.0,
            )

        m198_warns = [w for w in caught if "M19.8" in str(w.message)]
        assert not m198_warns, (
            f"M19.8: unexpected warning for non-empty wg_sizes: {m198_warns}"
        )
        assert result == 256


class TestM227SparseTensorStub:
    """M22.7 — TORCH_CHECK guards for sparse=True / scale_grad_by_freq=True.

    The eager C++ ``vulkan_embedding`` (and ``VulkanEmbeddingFunction::forward``)
    previously accepted these flags silently and returned wrong results.
    The fix adds ``TORCH_CHECK(!sparse, ...)`` and
    ``TORCH_CHECK(!scale_grad_by_freq, ...)`` in:
      - ``csrc/ops/indexing_ops.cpp:vulkan_embedding``
      - ``csrc/ops/autograd_ops.cpp:VulkanEmbeddingFunction::forward``

    The Python-side Inductor lowering in
    ``lowerings/embedding.py:_vulkan_embedding_dense_backward`` already
    returns ``NotImplemented`` for both flags (line 38-39 of that file).

    Tests that exercise the C++ path are skipped without a C++ rebuild.
    The Python-side lowering test runs without any rebuild.
    """

    @pytest.mark.skip(reason="requires C++ rebuild to activate TORCH_CHECK guard")
    def test_embedding_sparse_true_raises(self):
        """vulkan_embedding with sparse=True must raise RuntimeError."""
        import torch

        w = torch.randn(10, 4).to("vulkan")
        i = torch.tensor([0, 1, 2]).to("vulkan")
        with pytest.raises(RuntimeError, match="sparse"):
            torch.nn.functional.embedding(w, i, sparse=True)

    @pytest.mark.skip(reason="requires C++ rebuild to activate TORCH_CHECK guard")
    def test_embedding_scale_grad_by_freq_raises(self):
        """vulkan_embedding with scale_grad_by_freq=True must raise RuntimeError."""
        import torch

        w = torch.randn(10, 4).to("vulkan")
        i = torch.tensor([0, 1, 2]).to("vulkan")
        with pytest.raises(RuntimeError, match="scale_grad_by_freq"):
            torch.nn.functional.embedding(w, i, scale_grad_by_freq=True)

    @pytest.mark.skip(reason="requires C++ rebuild to verify end-to-end embedding path")
    def test_embedding_default_params_ok(self):
        """vulkan_embedding with sparse=False, scale_grad_by_freq=False works."""
        import torch

        w = torch.randn(10, 4).to("vulkan")
        i = torch.tensor([0, 1, 2]).to("vulkan")
        out = torch.nn.functional.embedding(
            w, i, sparse=False, scale_grad_by_freq=False
        )
        assert out.shape == (3, 4)

    def test_embedding_python_lowering_returns_not_implemented_for_sparse(self):
        """The Inductor Python lowering returns NotImplemented for scale_grad_by_freq=True.

        This test runs without a C++ rebuild — it directly exercises the
        lowering registration logic in embedding.py.
        """
        import sys
        import types

        # Build a minimal stub so the lowering module can be imported without
        # a live Vulkan device.  We only need the ``_is_vulkan`` check to
        # behave correctly for a non-Vulkan tensor so we can reach the
        # ``scale_grad_by_freq`` guard.
        import torch
        import torch._inductor.ir as _ir
        from torch._inductor.lowering import lowerings as _lowerings

        aten = torch.ops.aten

        # Ensure the lowering is registered (safe to call multiple times).
        import importlib

        # Import via the package path so relative imports inside the module work.
        import torch_vulkan.inductor.lowerings.embedding as _emb_mod

        _emb_mod._register_embedding_dense_backward()

        lowering_fn = _lowerings.get(aten.embedding_dense_backward.default)
        assert lowering_fn is not None, (
            "aten.embedding_dense_backward lowering not registered"
        )

        # Create a small CPU grad_output so _is_vulkan returns False →
        # the lowering returns NotImplemented immediately, before the
        # scale_grad_by_freq guard.  That is fine — the important thing is
        # that the function exists, is registered, and has the guard in its
        # source body (verified by source inspection below).
        import inspect

        src = inspect.getsource(lowering_fn)
        assert "scale_grad_by_freq" in src, (
            "scale_grad_by_freq guard missing from _vulkan_embedding_dense_backward"
        )
        assert "NotImplemented" in src, (
            "NotImplemented return missing from _vulkan_embedding_dense_backward"
        )


class TestM233RenderBindingSetRatchet:
    """M23.3 — Safety net: every Slang template must use Set-0 binding annotations.

    Background: slangc v2026.7.1 defaults bare ``[[vk::binding(N)]]``
    (no set qualifier) to Descriptor Set 1.  Our VkPipelineLayout only
    declares Set 0, so any bare binding causes a VUID-07988 validation
    error and silent corruption on non-RADV drivers (RADV ignores the
    wrong-set annotation; Nvidia/Intel/Apple/MoltenVK reject it).

    Fix (M21.3.01): all templates now use ``[[vk::binding(N, 0)]]`` with
    an explicit set-0 qualifier.  This test is the regression gate — it
    will immediately catch any future template that forgets the ``, 0``.

    No GPU required — purely file-based.
    """

    _TEMPLATES_DIR = (
        __import__("pathlib").Path(__file__).parent.parent
        / "python/torch_vulkan/inductor/templates"
    )
    _HEADER_DIR = (
        __import__("pathlib").Path(__file__).parent.parent
        / "python/torch_vulkan/inductor/kernel"
    )

    @staticmethod
    def _find_bare_bindings(path) -> list[tuple[int, str]]:
        """Return (lineno, line) pairs where a bare [[vk::binding(N)]] without
        set-0 qualifier appears outside a Slang comment."""
        import re

        bare = re.compile(r"\[\[vk::binding\(\d+\)\]\]")
        violations = []
        for i, raw in enumerate(path.read_text().splitlines(), 1):
            stripped = raw.lstrip()
            if stripped.startswith("//") or stripped.startswith("*"):
                continue
            if bare.search(raw):
                violations.append((i, raw.rstrip()))
        return violations

    def test_template_slang_files_use_set0_binding(self):
        """All .slang template files must use [[vk::binding(N, 0)]] form."""
        violations = []
        for p in sorted(self._TEMPLATES_DIR.rglob("*.slang")):
            for lineno, line in self._find_bare_bindings(p):
                violations.append(f"{p.name}:{lineno}: {line!r}")
        assert not violations, (
            "M23.3: bare [[vk::binding(N)]] (no set-0) found in templates:\n"
            + "\n".join(violations)
        )

    def test_template_jinja_files_use_set0_binding(self):
        """All .py.jinja / .slang.jinja template files must use [[vk::binding(N, 0)]]."""
        violations = []
        for p in sorted(self._TEMPLATES_DIR.rglob("*.jinja")):
            for lineno, line in self._find_bare_bindings(p):
                violations.append(f"{p.name}:{lineno}: {line!r}")
        assert not violations, (
            "M23.3: bare [[vk::binding(N)]] (no set-0) found in Jinja templates:\n"
            + "\n".join(violations)
        )

    def test_kernel_header_uses_set0_binding(self):
        """The kernel codegen (header.py) must only emit [[vk::binding(N, 0)]] form."""
        violations = []
        header = self._HEADER_DIR / "header.py"
        import re

        bare = re.compile(r"\[\[vk::binding\(\d+\)\]\]")
        for i, raw in enumerate(header.read_text().splitlines(), 1):
            stripped = raw.lstrip()
            if (
                stripped.startswith("#")
                or stripped.startswith('"""')
                or stripped.startswith("'")
            ):
                continue
            if "vk::binding" in raw and bare.search(raw):
                violations.append(f"header.py:{i}: {raw.rstrip()!r}")
        assert not violations, (
            "M23.3: bare [[vk::binding(N)]] (no set-0) found in kernel/header.py:\n"
            + "\n".join(violations)
        )

    def test_slang_lib_parameterblocks_use_set0_binding(self):
        """All ParameterBlock declarations in shaders/lib/*.slang must carry
        [[vk::binding(0, 0)]] so Slang places them on Set 0.

        Without the explicit annotation slangc defaults ParameterBlock to
        Descriptor Set 1, which our VkPipelineLayout does not declare —
        causing VUID-07988 on conformant drivers (M-NEW.6 / M21.3.01).
        RADV silently ignores the wrong-set annotation; NV/Intel/Apple/
        MoltenVK reject it.
        """
        import re

        lib_dir = __import__("pathlib").Path(__file__).parent.parent / "shaders/lib"
        pb_re = re.compile(r"ParameterBlock\s*<")
        binding_re = re.compile(r"\[\[vk::binding\(\s*0\s*,\s*0\s*\)\]\]")
        violations = []
        for slang_file in sorted(lib_dir.glob("*.slang")):
            lines = slang_file.read_text().splitlines()
            for i, raw in enumerate(lines, 1):
                stripped = raw.lstrip()
                if stripped.startswith("//") or stripped.startswith("*"):
                    continue
                if pb_re.search(raw) and "struct" not in raw and "interface" not in raw:
                    # This is a ParameterBlock variable declaration — must have [[vk::binding(0,0)]]
                    if not binding_re.search(raw):
                        violations.append(f"{slang_file.name}:{i}: {raw.rstrip()!r}")
        assert not violations, (
            "M-NEW.6: ParameterBlock declaration without [[vk::binding(0, 0)]] "
            "in shaders/lib (defaults to Set 1 on conformant drivers):\n"
            + "\n".join(violations)
        )


class TestM234ComboChainRenameResolver:
    """M23.4 — Combo-kernel chain-rename transitive resolver unit tests.

    The Inductor memory planner can chain buffer reuses (buf9 → buf10 → buf11).
    A one-step substitution leaves buf10 in args, which references a deleted
    variable at runtime (UnboundLocalError). ``resolve_alias_chain`` must walk
    the full chain transitively.
    """

    _BUG_ROOT_COMPONENT = "scheduler/fusion"

    def _resolve(self, name, freed, old_to_new):
        from torch_vulkan.inductor.kernel.dispatch_call import resolve_alias_chain

        return resolve_alias_chain(name, freed, old_to_new)

    def test_single_step_resolution(self):
        """buf9 freed, reused as buf10 → resolved to buf10."""
        freed = {"buf9"}
        old_to_new = {"buf9": "buf10"}
        assert self._resolve("buf9", freed, old_to_new) == "buf10"

    def test_three_step_chain(self):
        """buf9 → buf10 → buf11: must collapse all the way to buf11, not stop at buf10."""
        freed = {"buf9", "buf10"}
        old_to_new = {"buf9": "buf10", "buf10": "buf11"}
        result = self._resolve("buf9", freed, old_to_new)
        assert result == "buf11", f"Expected buf11, got {result!r}"

    def test_live_name_unchanged(self):
        """A name not in freed is returned unchanged, even if it appears in old_to_new."""
        freed = {"buf9"}
        old_to_new = {"buf9": "buf10", "buf10": "buf11"}
        assert self._resolve("buf10", freed, old_to_new) == "buf10"

    def test_name_not_in_chain_unchanged(self):
        """A name with no alias is returned unchanged."""
        freed = {"buf9"}
        old_to_new = {"buf9": "buf10"}
        assert self._resolve("buf5", freed, old_to_new) == "buf5"

    def test_cycle_detection_terminates(self):
        """Cycle buf9 → buf10 → buf9 must not loop forever."""
        freed = {"buf9", "buf10"}
        old_to_new = {"buf9": "buf10", "buf10": "buf9"}
        result = self._resolve("buf9", freed, old_to_new)
        assert result in ("buf9", "buf10"), f"Cycle not broken: got {result!r}"

    def test_combo_kernel_and_dispatch_call_use_same_function(self):
        """Both call sites import from the same module-level function."""
        import inspect

        from torch_vulkan.inductor.kernel.dispatch_call import (
            resolve_alias_chain as dc_fn,
        )
        from torch_vulkan.inductor.vulkan_combo_kernel import (
            resolve_alias_chain as vck_fn,
        )

        assert dc_fn is vck_fn, "Both modules must use the same resolve_alias_chain"


class TestM235ForeachOutsideCompileRatchet:
    """M23.5 — foreach ops registered in Registration.cpp dispatch to Vulkan
    when called outside torch.compile (eager mode).

    Each test calls a registered ``_foreach_*`` op on Vulkan tensors and
    verifies:
    1. The result stays on Vulkan (no silent CPU fallback).
    2. The result matches CPU ground truth.

    This is a dispatch-ratchet: any op that silently falls back to CPU will
    produce a CPUTensor result and fail the device assertion.  The set of ops
    mirrors the registrations in ``csrc/backend/Registration.cpp``.
    """

    _BUG_ROOT_COMPONENT = "lowering"
    _DEV = "vulkan:0"
    _RTOL = 1e-4
    _ATOL = 1e-4

    def _make(self, *shapes, dtype=torch.float32):
        return [torch.randn(*s, dtype=dtype).to(self._DEV) for s in shapes]

    def _cpu(self, tensors):
        return [t.cpu() for t in tensors]

    def test_foreach_add_scalar_stays_vulkan(self):
        """_foreach_add_.Scalar keeps tensors on Vulkan."""
        ts = self._make((4, 8), (16,))
        refs = [t.cpu().clone() for t in ts]
        torch._foreach_add_(ts, 2.0)
        for t, ref in zip(ts, refs):
            assert t.device.type == "vulkan", "result moved to CPU"
            torch.testing.assert_close(
                t.cpu(), ref + 2.0, rtol=self._RTOL, atol=self._ATOL
            )

    def test_foreach_add_list_stays_vulkan(self):
        """_foreach_add_.List keeps tensors on Vulkan."""
        ts = self._make((4, 8), (16,))
        others = self._make((4, 8), (16,))
        refs = [t.cpu().clone() for t in ts]
        ref_others = [o.cpu() for o in others]
        torch._foreach_add_(ts, others)
        for t, ref, ro in zip(ts, refs, ref_others):
            assert t.device.type == "vulkan", "result moved to CPU"
            torch.testing.assert_close(
                t.cpu(), ref + ro, rtol=self._RTOL, atol=self._ATOL
            )

    def test_foreach_mul_scalar_stays_vulkan(self):
        """_foreach_mul_.Scalar keeps tensors on Vulkan."""
        ts = self._make((4, 8), (16,))
        refs = [t.cpu().clone() for t in ts]
        torch._foreach_mul_(ts, 0.5)
        for t, ref in zip(ts, refs):
            assert t.device.type == "vulkan", "result moved to CPU"
            torch.testing.assert_close(
                t.cpu(), ref * 0.5, rtol=self._RTOL, atol=self._ATOL
            )

    def test_foreach_div_scalar_stays_vulkan(self):
        """_foreach_div_.Scalar keeps tensors on Vulkan."""
        ts = self._make((4, 8), (16,))
        refs = [t.cpu().clone() for t in ts]
        torch._foreach_div_(ts, 3.0)
        for t, ref in zip(ts, refs):
            assert t.device.type == "vulkan", "result moved to CPU"
            torch.testing.assert_close(
                t.cpu(), ref / 3.0, rtol=self._RTOL, atol=self._ATOL
            )

    def test_foreach_sqrt_stays_vulkan(self):
        """_foreach_sqrt returns Vulkan tensors."""
        ts = self._make((4, 8), (16,))
        # Ensure non-negative for sqrt.
        ts = [t.abs() for t in ts]
        refs = [t.cpu() for t in ts]
        result = torch._foreach_sqrt(ts)
        for r, ref in zip(result, refs):
            assert r.device.type == "vulkan", "result moved to CPU"
            torch.testing.assert_close(r.cpu(), ref.sqrt(), rtol=1e-3, atol=1e-3)

    def test_foreach_neg_stays_vulkan(self):
        """_foreach_neg returns Vulkan tensors."""
        ts = self._make((4, 8), (16,))
        refs = [t.cpu() for t in ts]
        result = torch._foreach_neg(ts)
        for r, ref in zip(result, refs):
            assert r.device.type == "vulkan", "result moved to CPU"
            torch.testing.assert_close(r.cpu(), -ref, rtol=self._RTOL, atol=self._ATOL)


class TestM196ForeachPointwiseLowerings:
    """M19.6 — foreach pointwise ops under torch.compile(backend="inductor").

    Verifies that all 16 target _foreach_* ops produce correct outputs when
    compiled through the Vulkan Inductor backend.  Each test:
      1. Compiles the target function with ``torch.compile(backend="inductor")``.
      2. Runs it on Vulkan tensors.
      3. Compares the result against a CPU reference.

    The upstream Inductor already registers these via ``make_foreach_pointwise``
    / ``register_foreach_pointwise``.  ``lowerings/foreach_pointwise.py``
    validates the registration and suppresses any stray AOT decomps.

    No GPU dispatch-count assertions — these tests are correctness-only.
    Dispatch-count ratchets for foreach ops live in
    ``TestM175DispatchOverhead``.
    """

    _DEV = "vulkan:0"
    _RTOL = 1e-4
    _ATOL = 1e-4

    def _make(self, n, *shape, dtype=torch.float32):
        """Return n Vulkan tensors of the given shape."""
        return [torch.randn(*shape, dtype=dtype, device=self._DEV) for _ in range(n)]

    def _cpu(self, tensors):
        return [t.cpu() for t in tensors]

    # ── Registration / smoke tests (no GPU required) ─────────────────────────

    def test_foreach_pointwise_module_importable(self):
        """foreach_pointwise.py is importable and exposes its entry point."""
        from torch_vulkan.inductor.lowerings.foreach_pointwise import (
            register_foreach_pointwise_lowerings,
        )

        assert callable(register_foreach_pointwise_lowerings)

    def test_foreach_pointwise_all_ops_in_lowerings(self):
        """All 16 M19.6 target ops are in Inductor's lowering table after register()."""
        import torch_vulkan.inductor

        torch_vulkan.inductor.register()

        from torch._inductor.lowering import lowerings

        aten = torch.ops.aten

        required = [
            aten._foreach_add.List,
            aten._foreach_add.Scalar,
            aten._foreach_sub.List,
            aten._foreach_sub.Scalar,
            aten._foreach_mul.List,
            aten._foreach_mul.Scalar,
            aten._foreach_div.List,
            aten._foreach_div.Scalar,
            aten._foreach_neg.default,
            aten._foreach_abs.default,
            aten._foreach_sqrt.default,
            aten._foreach_reciprocal.default,
            aten._foreach_add_.List,
            aten._foreach_add_.Scalar,
            aten._foreach_mul_.Scalar,
        ]
        missing = [str(op) for op in required if op not in lowerings]
        assert not missing, f"M19.6: missing lowerings for: {missing}"

    # ── Compile-mode correctness tests ───────────────────────────────────────

    def test_foreach_add_list_compile(self):
        """_foreach_add.List under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts, others):
            return torch._foreach_add(ts, others)

        ts = self._make(2, 4, 8)
        others = self._make(2, 4, 8)
        ts_cpu = self._cpu(ts)
        others_cpu = self._cpu(others)

        with torch.no_grad():
            result = fn(ts, others)
            ref = torch._foreach_add(ts_cpu, others_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_add.List compile mismatch",
            )

    def test_foreach_add_scalar_compile(self):
        """_foreach_add.Scalar under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts, alpha):
            return torch._foreach_add(ts, alpha)

        ts = self._make(3, 16)
        ts_cpu = self._cpu(ts)

        with torch.no_grad():
            result = fn(ts, 3.0)
            ref = torch._foreach_add(ts_cpu, 3.0)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_add.Scalar compile mismatch",
            )

    def test_foreach_sub_list_compile(self):
        """_foreach_sub.List under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts, others):
            return torch._foreach_sub(ts, others)

        ts = self._make(2, 8, 4)
        others = self._make(2, 8, 4)
        ts_cpu = self._cpu(ts)
        others_cpu = self._cpu(others)

        with torch.no_grad():
            result = fn(ts, others)
            ref = torch._foreach_sub(ts_cpu, others_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_sub.List compile mismatch",
            )

    def test_foreach_mul_list_compile(self):
        """_foreach_mul.List under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts, others):
            return torch._foreach_mul(ts, others)

        ts = self._make(2, 8, 8)
        others = self._make(2, 8, 8)
        ts_cpu = self._cpu(ts)
        others_cpu = self._cpu(others)

        with torch.no_grad():
            result = fn(ts, others)
            ref = torch._foreach_mul(ts_cpu, others_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_mul.List compile mismatch",
            )

    def test_foreach_mul_scalar_compile(self):
        """_foreach_mul.Scalar under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts, scalar):
            return torch._foreach_mul(ts, scalar)

        ts = self._make(3, 4, 4)
        ts_cpu = self._cpu(ts)

        with torch.no_grad():
            result = fn(ts, 2.0)
            ref = torch._foreach_mul(ts_cpu, 2.0)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_mul.Scalar compile mismatch",
            )

    def test_foreach_div_scalar_compile(self):
        """_foreach_div.Scalar under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts, scalar):
            return torch._foreach_div(ts, scalar)

        ts = self._make(2, 8, 8)
        ts_cpu = self._cpu(ts)

        with torch.no_grad():
            result = fn(ts, 4.0)
            ref = torch._foreach_div(ts_cpu, 4.0)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_div.Scalar compile mismatch",
            )

    def test_foreach_neg_compile(self):
        """_foreach_neg.default under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts):
            return torch._foreach_neg(ts)

        ts = self._make(2, 8, 4)
        ts_cpu = self._cpu(ts)

        with torch.no_grad():
            result = fn(ts)
            ref = torch._foreach_neg(ts_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_neg compile mismatch",
            )

    def test_foreach_abs_compile(self):
        """_foreach_abs.default under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts):
            return torch._foreach_abs(ts)

        ts = self._make(2, 4, 8)
        # Use mixed-sign values to exercise abs properly.
        ts = [t * 2 - 1 for t in ts]  # shift to [-1, 1]
        ts_cpu = self._cpu(ts)

        with torch.no_grad():
            result = fn(ts)
            ref = torch._foreach_abs(ts_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_abs compile mismatch",
            )

    def test_foreach_sqrt_compile(self):
        """_foreach_sqrt.default under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts):
            return torch._foreach_sqrt(ts)

        # Use positive values only to avoid NaN from sqrt of negative.
        ts = [t.abs() + 0.01 for t in self._make(2, 8, 4)]
        ts_cpu = self._cpu(ts)

        with torch.no_grad():
            result = fn(ts)
            ref = torch._foreach_sqrt(ts_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=1e-3,
                atol=1e-3,
                msg="M19.6 _foreach_sqrt compile mismatch",
            )

    def test_foreach_reciprocal_compile(self):
        """_foreach_reciprocal.default under torch.compile matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(ts):
            return torch._foreach_reciprocal(ts)

        # Use values bounded away from zero to avoid inf.
        ts = [t.abs() + 1.0 for t in self._make(2, 8, 4)]
        ts_cpu = self._cpu(ts)

        with torch.no_grad():
            result = fn(ts)
            ref = torch._foreach_reciprocal(ts_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=1e-3,
                atol=1e-3,
                msg="M19.6 _foreach_reciprocal compile mismatch",
            )

    def test_foreach_add_inplace_list_compile(self):
        """_foreach_add_.List under torch.compile mutates correctly vs CPU."""

        @torch.compile(backend="inductor")
        def fn(ts, others):
            torch._foreach_add_(ts, others)
            return ts

        ts = self._make(2, 4, 8)
        others = self._make(2, 4, 8)
        ts_cpu = [t.cpu().clone() for t in ts]
        others_cpu = self._cpu(others)

        with torch.no_grad():
            result = fn(ts, others)
            torch._foreach_add_(ts_cpu, others_cpu)

        for r, r_cpu in zip(result, ts_cpu):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_add_.List compile mismatch",
            )

    def test_foreach_mul_inplace_scalar_compile(self):
        """_foreach_mul_.Scalar under torch.compile mutates correctly vs CPU."""

        @torch.compile(backend="inductor")
        def fn(ts, scalar):
            torch._foreach_mul_(ts, scalar)
            return ts

        ts = self._make(2, 4, 8)
        ts_cpu = [t.cpu().clone() for t in ts]

        with torch.no_grad():
            result = fn(ts, 0.5)
            torch._foreach_mul_(ts_cpu, 0.5)

        for r, r_cpu in zip(result, ts_cpu):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 _foreach_mul_.Scalar compile mismatch",
            )

    def test_foreach_mixed_chain_compile(self):
        """Chain of foreach ops (neg→mul→add) under compile matches CPU."""

        @torch.compile(backend="inductor")
        def fn(ts, others):
            neg_ts = torch._foreach_neg(ts)
            scaled = torch._foreach_mul(neg_ts, 2.0)
            return torch._foreach_add(scaled, others)

        ts = self._make(2, 8, 8)
        others = self._make(2, 8, 8)
        ts_cpu = self._cpu(ts)
        others_cpu = self._cpu(others)

        with torch.no_grad():
            result = fn(ts, others)
            neg = torch._foreach_neg(ts_cpu)
            scaled = torch._foreach_mul(neg, 2.0)
            ref = torch._foreach_add(scaled, others_cpu)

        for r, r_cpu in zip(result, ref):
            torch.testing.assert_close(
                r.cpu(),
                r_cpu,
                rtol=self._RTOL,
                atol=self._ATOL,
                msg="M19.6 foreach chain compile mismatch",
            )


class TestM223PatternStats:
    """M22.3 — FX pattern firing-rate instrumentation.

    Verifies that:
      1. Firing a pattern (relu_to_clamp_min) increments the per-name counter.
      2. reset_pattern_stats() zeroes all counters.
      3. dump_pattern_stats() is a no-op when TORCH_VULKAN_PATTERN_STATS=0.
    """

    def _make_aten_relu_graph(self):
        """Return a GraphModule with one aten.relu.default node.

        Constructs the graph via the FX Graph API so the node target is
        exactly ``aten.relu.default`` — the form the pattern matcher expects.
        ``symbolic_trace`` would emit ``torch.relu`` (a different target).
        """
        import torch

        aten = torch.ops.aten
        graph = torch.fx.Graph()
        x = graph.placeholder("x")
        out = graph.call_function(aten.relu.default, (x,))
        graph.output(out)
        return torch.fx.GraphModule({}, graph)

    def test_pattern_stats_counter_increments(self):
        """After apply_all on a graph containing aten.relu.default, the
        relu_to_clamp_min counter must be non-zero (stats gate on)."""
        import torch_vulkan.inductor.config as _cfg
        from torch_vulkan.inductor.fx_passes.patterns.registry import (
            FX_PATTERN_REGISTRY,
        )
        from torch_vulkan.inductor.fx_passes.post_grad import (
            _PatternStats,
            reset_pattern_stats,
        )

        # Temporarily enable stats by patching the module-level flag.
        _orig = _cfg._PATTERN_STATS
        _cfg._PATTERN_STATS = True
        try:
            reset_pattern_stats()
            gm = self._make_aten_relu_graph()
            FX_PATTERN_REGISTRY.apply_all(gm)
            # relu_to_clamp_min should have fired since the graph had aten.relu.
            assert "relu_to_clamp_min" in _PatternStats, (
                "relu_to_clamp_min pattern did not appear in _PatternStats "
                f"after apply_all on an aten.relu graph.  Stats: {dict(_PatternStats)}"
            )
            assert _PatternStats["relu_to_clamp_min"] >= 1, (
                f"Expected ≥1 fires for relu_to_clamp_min, got "
                f"{_PatternStats['relu_to_clamp_min']}"
            )
        finally:
            _cfg._PATTERN_STATS = _orig
            reset_pattern_stats()

    def test_pattern_stats_reset(self):
        """reset_pattern_stats() must zero all counters."""
        import torch_vulkan.inductor.config as _cfg
        from torch_vulkan.inductor.fx_passes.post_grad import (
            _PatternStats,
            record_pattern_fire,
            reset_pattern_stats,
        )

        _orig = _cfg._PATTERN_STATS
        _cfg._PATTERN_STATS = True
        try:
            reset_pattern_stats()
            record_pattern_fire("test_pattern_a")
            record_pattern_fire("test_pattern_b")
            assert len(_PatternStats) == 2, (
                f"Expected 2 entries after two record calls, got {len(_PatternStats)}"
            )
            reset_pattern_stats()
            assert len(_PatternStats) == 0, (
                f"reset_pattern_stats() should clear all entries, "
                f"but {len(_PatternStats)} remain: {dict(_PatternStats)}"
            )
        finally:
            _cfg._PATTERN_STATS = _orig
            reset_pattern_stats()

    def test_pattern_stats_env_gate(self):
        """dump_pattern_stats() must produce no output when
        TORCH_VULKAN_PATTERN_STATS=0 (the default)."""
        import io

        import torch_vulkan.inductor.config as _cfg
        from torch_vulkan.inductor.fx_passes.post_grad import (
            dump_pattern_stats,
            record_pattern_fire,
            reset_pattern_stats,
        )

        # Ensure the gate is off.
        _orig = _cfg._PATTERN_STATS
        _cfg._PATTERN_STATS = False
        try:
            reset_pattern_stats()
            record_pattern_fire("some_pattern")
            # Redirect stderr and verify dump_pattern_stats() writes nothing.
            buf = io.StringIO()
            import sys

            _old_stderr = sys.stderr
            sys.stderr = buf
            try:
                dump_pattern_stats()
            finally:
                sys.stderr = _old_stderr
            output = buf.getvalue()
            assert output == "", (
                f"dump_pattern_stats() should be a no-op when "
                f"TORCH_VULKAN_PATTERN_STATS=0, but wrote: {output!r}"
            )
        finally:
            _cfg._PATTERN_STATS = _orig
            reset_pattern_stats()


class TestM222AllocAliasIRMigration:
    """M22.2 — IR-level alloc-alias pass (replaces regex post-processor).

    Validates:
      1. The new IR-level pass module is importable and its public API is stable.
      2. The old regex pass (``alloc_alias.py``) still works — backward compat.
      3. The IR-level ``apply_vulkan_ir_alias_pass`` function is importable.
      4. A compile-mode test verifies correctness of the new path.
      5. The generated wrapper source does not contain the old regex-pass
         ``# (pool-release elided:`` comment (that comment is a regex-pass
         artifact; the IR pass does not emit it).
    """

    def test_old_regex_pass_importable(self):
        """alias_alloc_free_pairs from alloc_alias.py must still be importable
        (backward compat — external tooling or cached code may use it)."""
        from torch_vulkan.inductor.fx_passes.alloc_alias import alias_alloc_free_pairs

        assert callable(alias_alloc_free_pairs)

    def test_old_regex_pass_noop_on_empty(self):
        """alias_alloc_free_pairs returns the input unchanged when there are
        fewer than 2 allocations in the source."""
        from torch_vulkan.inductor.fx_passes.alloc_alias import alias_alloc_free_pairs

        src = (
            "x = empty_strided_vulkan((4,), (1,), torch.float32,"
            " lifetime_class='transient')\n"
        )
        assert alias_alloc_free_pairs(src) == src

    def test_old_regex_pass_aliases_matching_pair(self):
        """alias_alloc_free_pairs rewrites a free-then-alloc pair with the same
        size/stride/dtype into an alias assignment (backward compat check)."""
        from torch_vulkan.inductor.fx_passes.alloc_alias import alias_alloc_free_pairs

        src = (
            "buf0 = empty_strided_vulkan((16, 1024), (1024, 1), torch.float32,"
            " lifetime_class='transient')\n"
            "vulkan_pool_release(buf0, lifetime_class='transient'); buf0 = None\n"
            "buf1 = empty_strided_vulkan((16, 1024), (1024, 1), torch.float32,"
            " lifetime_class='transient')\n"
            "vulkan_pool_release(buf1, lifetime_class='transient'); buf1 = None\n"
        )
        result = alias_alloc_free_pairs(src)
        assert "buf1 = buf0" in result, (
            "Expected 'buf1 = buf0' in aliased output, got:\n" + result
        )

    def test_ir_pass_importable(self):
        """apply_vulkan_ir_alias_pass must be importable from alloc_alias_ir."""
        from torch_vulkan.inductor.fx_passes.alloc_alias_ir import (
            apply_vulkan_ir_alias_pass,
        )

        assert callable(apply_vulkan_ir_alias_pass)

    def test_ir_custom_line_types_importable(self):
        """VulkanAliasAllocLine and VulkanAliasFreeRedirectLine must be importable."""
        from torch_vulkan.inductor.fx_passes.alloc_alias_ir import (
            VulkanAliasAllocLine,
            VulkanAliasFreeRedirectLine,
        )

        assert VulkanAliasAllocLine is not None
        assert VulkanAliasFreeRedirectLine is not None

    def test_alloc_alias_key_returns_none_for_non_layout(self):
        """_alloc_alias_key returns None for nodes without a Layout output spec."""
        from torch_vulkan.inductor.fx_passes.alloc_alias_ir import _alloc_alias_key

        class _FakeNode:
            def get_output_spec(self):
                return None

        assert _alloc_alias_key(_FakeNode()) is None  # type: ignore[arg-type]

    def test_wrapper_generate_no_regex_artifact(self):
        """The old regex-pass comment '# (pool-release elided:' must NOT appear
        in the compiled wrapper source — confirms the regex pass is bypassed."""
        import torch._dynamo
        from torch._inductor.utils import run_and_get_code

        torch._dynamo.reset()

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x):
            a = torch.relu(x)
            b = torch.relu(a + 1.0)
            c = torch.relu(b + 1.0)
            return c

        x = torch.randn(16, 1024, device="vulkan:0")
        _, code_list = run_and_get_code(fn, x)

        for wrapper_src in code_list:
            assert "# (pool-release elided:" not in wrapper_src, (
                "Old regex-pass artifact found in wrapper source — the regex "
                "pass must not run after the M22.2 IR migration.\n\n"
                "Wrapper snippet:\n" + wrapper_src[:2000]
            )

    def test_compile_mode_correctness(self):
        """After the IR migration, compiled output matches CPU reference."""
        import torch._dynamo

        torch._dynamo.reset()

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x, y):
            buf_a = torch.relu(x)
            _scalar = torch.sum(y)
            buf_b = torch.relu(x + _scalar)
            return buf_a + buf_b

        x = torch.randn(16, 1024, device="vulkan:0")
        y = torch.randn(4, device="vulkan:0")

        result = fn(x, y).cpu()

        x_cpu = x.cpu()
        y_cpu = y.cpu()
        buf_a_cpu = torch.relu(x_cpu)
        _scalar_cpu = torch.sum(y_cpu)
        buf_b_cpu = torch.relu(x_cpu + _scalar_cpu)
        ref = buf_a_cpu + buf_b_cpu

        torch.testing.assert_close(
            result,
            ref,
            rtol=1e-4,
            atol=1e-4,
            msg="M22.2: IR alias pass broke numerical correctness",
        )

    def test_wrapper_py_under_800_lines(self):
        """wrapper.py must stay under the 800-line anti-goal #7 cap."""
        from pathlib import Path

        path = (
            Path(__file__).parent.parent
            / "python"
            / "torch_vulkan"
            / "inductor"
            / "wrapper.py"
        )
        lines = path.read_text().count("\n")
        assert lines < 800, (
            f"M22.2: wrapper.py is {lines} lines (anti-goal #7 cap is 800)"
        )

    def test_alloc_alias_ir_py_under_800_lines(self):
        """alloc_alias_ir.py must stay under the 800-line anti-goal #7 cap."""
        from pathlib import Path

        path = (
            Path(__file__).parent.parent
            / "python"
            / "torch_vulkan"
            / "inductor"
            / "fx_passes"
            / "alloc_alias_ir.py"
        )
        lines = path.read_text().count("\n")
        assert lines < 800, (
            f"M22.2: alloc_alias_ir.py is {lines} lines (anti-goal #7 cap is 800)"
        )


class TestM207LibHelperExtraction:
    """M20.7 — Extract streaming Welford accumulator into a shared lib helper.

    The per-element Welford update (Knuth's online algorithm) was previously
    written inline in ``conv_gn_relu.slang`` and any future kernels that need
    single-pass mean/variance computation.  This class verifies that:

    1. ``shaders/lib/helpers.slang`` declares ``welford_update(inout Welford, float)``.
    2. ``conv_gn_relu.slang`` no longer contains the inline implementation;
       instead it calls the shared helper.
    3. The pattern compiles correctly via slangc (import reduction; → helpers; →
       welford_update accessible).

    Grid-stride loop patterns (``for (uint d = tid; d < S; d += 256)``) are NOT
    extracted because Slang lacks a macro system and the loop bound / stride are
    kernel-specific; the extraction would add no reuse.  This is documented in
    the roadmap as the grid-stride sub-item intentionally deferred.
    """

    def test_helpers_slang_declares_welford_update(self):
        """Static check: ``shaders/lib/helpers.slang`` declares
        ``welford_update(inout Welford, float)`` with the correct signature."""
        path = os.path.join(
            os.path.dirname(__file__),
            "..",
            "shaders",
            "lib",
            "helpers.slang",
        )
        with open(path) as f:
            src = f.read()
        # Strip single-line comments to avoid matching documentation text.
        no_comments = re.sub(r"//[^\n]*", "", src)
        decl_re = re.compile(
            r"public\s+void\s+welford_update\s*\(\s*inout\s+Welford\s+\w+\s*,\s*float\s+\w+\s*\)"
        )
        assert decl_re.search(no_comments), (
            "lib/helpers.slang is missing the M20.7 welford_update() function. "
            "Expected a declaration matching:\n"
            "  public void welford_update(inout Welford w, float x)"
        )

    def test_conv_gn_relu_uses_welford_update_helper(self):
        """Static check: ``conv_gn_relu.slang`` calls ``welford_update``
        and no longer contains the inline (local_mean, local_m2, local_n) triple."""
        path = os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "templates",
            "conv_gn_relu.slang",
        )
        with open(path) as f:
            src = f.read()
        # The refactored shader must call welford_update.
        assert "welford_update" in src, (
            "conv_gn_relu.slang does not call welford_update(). "
            "M20.7 requires using the shared lib helper."
        )
        # The old inline triple should be gone (no 'local_mean' or 'local_m2').
        # We allow 'local_wf' as the replacement accumulator variable name.
        no_comments = re.sub(r"//[^\n]*", "", src)
        assert "local_mean" not in no_comments, (
            "conv_gn_relu.slang still contains 'local_mean'. "
            "M20.7 should have replaced the inline accumulation with welford_update()."
        )
        assert "local_m2" not in no_comments, (
            "conv_gn_relu.slang still contains 'local_m2'. "
            "M20.7 should have replaced the inline accumulation with welford_update()."
        )

    def test_welford_update_compiles_via_reduction_import(self):
        """Compile a probe kernel that imports reduction (which re-exports helpers)
        and calls welford_update + wg_welford; assert slangc exits 0.

        This verifies the full code path that conv_gn_relu.slang uses:
          import reduction;
          Welford local_wf = {0, 0, 0};
          welford_update(local_wf, x);
          WelfordResult<float> wf = {local_wf.mean, local_wf.m2, local_wf.n};
          WelfordResult<float> stats = wg_welford(wf, tid, 256u, VK_SUBGROUP_SIZE);
        """
        import subprocess
        import tempfile

        from torch_vulkan.inductor.runtime.slangc import _get_slangc, _slangc_available

        if not _slangc_available():
            pytest.skip("slangc not available")

        probe_src = """
import reduction;

RWStructuredBuffer<float> output;

[shader("compute")]
[numthreads(256, 1, 1)]
void computeMain(uint3 gid : SV_GroupID, uint3 lid : SV_GroupThreadID) {
    uint S = 256u;
    uint tid = lid.x;

    // M20.7 pattern: streaming Welford accumulator via shared helper
    Welford local_wf;
    local_wf.mean = 0.0f;
    local_wf.m2   = 0.0f;
    local_wf.n    = 0.0f;

    for (uint d = tid; d < S; d += 256u) {
        float x = float(d) * 0.01f;
        welford_update(local_wf, x);
    }

    // Bridge to workgroup-level WelfordResult
    WelfordResult<float> wf;
    wf.mean = local_wf.mean;
    wf.m2   = local_wf.m2;
    wf.n    = local_wf.n;
    WelfordResult<float> stats = wg_welford(wf, tid, 256u, VK_SUBGROUP_SIZE);

    if (tid == 0u) {
        output[gid.x] = stats.mean;
    }
}
"""
        slangc = _get_slangc()
        shader_root = os.path.join(os.path.dirname(__file__), "..", "shaders")
        lib_dir = os.path.join(shader_root, "lib")

        with tempfile.TemporaryDirectory() as td:
            src_path = os.path.join(td, "m207_probe.slang")
            spv_path = os.path.join(td, "m207_probe.spv")
            with open(src_path, "w") as f:
                f.write(probe_src)
            proc = subprocess.run(
                [
                    slangc,
                    src_path,
                    "-target",
                    "spirv",
                    "-entry",
                    "computeMain",
                    "-o",
                    spv_path,
                    "-matrix-layout-row-major",
                    "-ignore-capabilities",
                    "-I",
                    lib_dir,
                ],
                capture_output=True,
                text=True,
                timeout=60,
            )
            assert proc.returncode == 0, (
                f"M20.7 probe kernel failed to compile via slangc: "
                f"rc={proc.returncode}\nstderr:\n{proc.stderr[:2000]}"
            )


class TestM205ReflectionMetadata:
    """M20.5 — Reflection metadata coverage 40 % → 80 %.

    Tests that ``_parse_reflection_metrics`` and ``_analyze_spirv_binary``
    now extract the full set of M20.5 fields:
      - subgroup_size (inferred from threadGroupSize in JSON)
      - num_sgprs, num_loads, num_stores, num_atomics (from SPIR-V analysis)
    and that ``_pick_numthreads_from_reflection`` uses them correctly.
    """

    # ── Static schema checks ─────────────────────────────────────────────

    def test_parse_reflection_metrics_schema_has_new_fields(self):
        """_parse_reflection_metrics returns all 8 M20.5 fields."""
        from torch_vulkan.inductor.runtime.reflection_ext import (
            _parse_reflection_metrics,
        )

        result = _parse_reflection_metrics("{}")
        expected_keys = {
            "vgprs",
            "shared_mem",
            "subgroup_size",
            "loop_depth",
            "num_sgprs",
            "num_loads",
            "num_stores",
            "num_atomics",
        }
        assert set(result.keys()) == expected_keys, (
            f"M20.5: _parse_reflection_metrics schema mismatch. "
            f"Got {set(result.keys())} expected {expected_keys}"
        )

    def test_parse_reflection_metrics_subgroup_size_from_threadgroupsize_64(self):
        """M20.5: subgroup_size inferred as 64 when threadGroupSize X is 256."""
        import json

        from torch_vulkan.inductor.runtime.reflection_ext import (
            _parse_reflection_metrics,
        )

        refl = json.dumps(
            {
                "parameters": [],
                "entryPoints": [
                    {
                        "name": "computeMain",
                        "stage": "compute",
                        "threadGroupSize": [256, 1, 1],
                        "parameters": [],
                        "bindings": [],
                    }
                ],
            }
        )
        result = _parse_reflection_metrics(refl)
        assert result["subgroup_size"] == 64, (
            f"M20.5: threadGroupSize=[256,1,1] should infer subgroup_size=64, "
            f"got {result['subgroup_size']}"
        )

    def test_parse_reflection_metrics_subgroup_size_from_threadgroupsize_32(self):
        """M20.5: subgroup_size inferred as 32 when threadGroupSize X is 32."""
        import json

        from torch_vulkan.inductor.runtime.reflection_ext import (
            _parse_reflection_metrics,
        )

        refl = json.dumps(
            {
                "parameters": [],
                "entryPoints": [
                    {
                        "name": "computeMain",
                        "stage": "compute",
                        "threadGroupSize": [32, 1, 1],
                        "parameters": [],
                        "bindings": [],
                    }
                ],
            }
        )
        result = _parse_reflection_metrics(refl)
        assert result["subgroup_size"] == 32, (
            f"M20.5: threadGroupSize=[32,1,1] should infer subgroup_size=32, "
            f"got {result['subgroup_size']}"
        )

    def test_analyze_spirv_binary_new_fields(self):
        """M20.5: _analyze_spirv_binary returns num_loads/stores/atomics/sgprs."""
        from torch_vulkan.inductor.runtime.reflection_ext import _analyze_spirv_binary

        # Empty / invalid SPV should return None for all new fields.
        result = _analyze_spirv_binary(b"")
        assert "num_loads" in result, "M20.5: num_loads key missing"
        assert "num_stores" in result, "M20.5: num_stores key missing"
        assert "num_atomics" in result, "M20.5: num_atomics key missing"
        assert "num_sgprs" in result, "M20.5: num_sgprs key missing"

    def test_analyze_spirv_binary_minimum_vgpr(self):
        """M20.5: Simple kernels with 0 func vars get vgprs=1 (not None).

        Previously a kernel with no function-scope OpVariables returned
        vgprs=None, forcing the sizing path to fall back to heuristics.
        M20.5 returns at least 1 so the reflection path stays active.
        """
        import subprocess
        import tempfile

        from torch_vulkan.inductor.runtime.reflection_ext import _analyze_spirv_binary
        from torch_vulkan.inductor.runtime.slangc import _get_slangc, _slangc_available

        if not _slangc_available():
            pytest.skip("slangc not available")

        # Simplest possible compute kernel — no function-scope variables.
        probe_src = """
RWStructuredBuffer<float> out_buf;

[shader("compute")]
[numthreads(64, 1, 1)]
void computeMain(uint3 sv_tid: SV_DispatchThreadID)
{
    out_buf[sv_tid.x] = 1.0f;
}
"""
        slangc = _get_slangc()
        with tempfile.TemporaryDirectory() as td:
            src_path = os.path.join(td, "probe.slang")
            spv_path = os.path.join(td, "probe.spv")
            with open(src_path, "w") as f:
                f.write(probe_src)
            proc = subprocess.run(
                [
                    slangc,
                    src_path,
                    "-target",
                    "spirv",
                    "-entry",
                    "computeMain",
                    "-o",
                    spv_path,
                    "-matrix-layout-row-major",
                    "-ignore-capabilities",
                ],
                capture_output=True,
                text=True,
                timeout=60,
            )
            if proc.returncode != 0:
                pytest.skip(f"slangc compile failed: {proc.stderr[:500]}")

            spv = open(spv_path, "rb").read()

        result = _analyze_spirv_binary(spv)
        assert result.get("vgprs") is not None and result["vgprs"] >= 1, (
            f"M20.5: trivial kernel vgprs should be >= 1, got {result.get('vgprs')}"
        )
        assert result.get("num_loads") is not None, (
            "M20.5: num_loads should be extracted from SPIR-V"
        )
        assert result.get("num_stores") is not None, (
            "M20.5: num_stores should be extracted from SPIR-V"
        )

    def test_pick_numthreads_uses_num_sgprs(self):
        """M20.5: High SGPR pressure (>64) drops one WG tier."""
        from torch_vulkan.inductor.runtime.reflection_ext import (
            _pick_numthreads_from_reflection,
        )

        # Base: vgprs=16 → 256 threads.  With num_sgprs=80 → should drop to 128.
        result = _pick_numthreads_from_reflection(
            vgprs=16,
            current_numthreads=(256, 1, 1),
            num_sgprs=80,
        )
        assert result[0] <= 128, (
            f"M20.5: num_sgprs=80 > 64 should drop WG from 256, got {result[0]}"
        )

    def test_pick_numthreads_io_heavy_raises_tier(self):
        """M20.5: High I/O count (>128 loads+stores) raises WG tier."""
        from torch_vulkan.inductor.runtime.reflection_ext import (
            _pick_numthreads_from_reflection,
        )

        # Base: vgprs=80 → 64 threads.  With 150 I/O ops → should raise to 128.
        result = _pick_numthreads_from_reflection(
            vgprs=80,
            current_numthreads=(64, 1, 1),
            num_loads=100,
            num_stores=60,
        )
        assert result[0] >= 128, (
            f"M20.5: high I/O count should raise WG from 64, got {result[0]}"
        )

    def test_pick_numthreads_preserves_2d_workgroups(self):
        """M20.5: 2D/3D workgroups are passed through unchanged."""
        from torch_vulkan.inductor.runtime.reflection_ext import (
            _pick_numthreads_from_reflection,
        )

        result = _pick_numthreads_from_reflection(
            vgprs=200,  # would normally drop to 32
            current_numthreads=(64, 4, 1),
            num_sgprs=128,  # high SGPR pressure
        )
        assert result == (64, 4, 1), (
            f"M20.5: 2D workgroups should be preserved, got {result}"
        )

    def test_reflection_coverage_rate(self):
        """M20.5: Document the current reflection coverage rate.

        Counts how many cached kernel metrics have non-None values for
        each field, confirming M20.5 improvements are persisted to disk.

        The target is ≥ 80 % of kernels having vgprs data,
        ≥ 60 % having num_loads/num_stores data (newly added),
        and ≥ 40 % having subgroup_size data (inferred from threadGroupSize).

        This is a documentation/audit test: it logs the coverage rates
        and fails only if vgprs coverage falls below 80 %.
        """
        import glob

        from torch_vulkan.inductor.runtime.common import _get_disk_cache_dir

        cache_dir = _get_disk_cache_dir()
        files = glob.glob(
            os.path.join(cache_dir, "**", "*.metrics.json"), recursive=True
        )

        if len(files) < 10:
            pytest.skip(
                f"Too few cached metrics ({len(files)}); run more kernels first"
            )

        total = len(files)
        counts = {
            "vgprs": 0,
            "subgroup_size": 0,
            "num_loads": 0,
            "num_stores": 0,
            "num_atomics": 0,
            "num_sgprs": 0,
        }
        for f in files:
            try:
                m = json.load(open(f))
                for k in counts:
                    if m.get(k) is not None:
                        counts[k] += 1
            except Exception:
                pass

        vgpr_pct = 100 * counts["vgprs"] / total
        # vgprs coverage must be ≥ 80 % (M20.5 target)
        assert vgpr_pct >= 80.0, (
            f"M20.5: vgprs coverage {vgpr_pct:.1f}% < 80% target "
            f"({counts['vgprs']}/{total} kernels)"
        )
        # Log all coverage rates for reference (not failing assertions)
        for k, cnt in sorted(counts.items()):
            pct = 100 * cnt / total
            print(f"  M20.5 coverage {k}: {cnt}/{total} = {pct:.1f}%")

    def test_get_cached_subgroup_size_returns_reflection_value(self):
        """M20.5: _get_cached_subgroup_size returns subgroup_size from cached metrics.

        Verifies that the ThreadgroupSizingMixin accessor reads the
        subgroup_size field written by _parse_reflection_metrics /
        _analyze_spirv_binary so it can be used as a fallback for sgs
        when the device-interface query returns 0 / None.
        """
        from unittest.mock import patch

        from torch_vulkan.inductor.kernel.threadgroup_sizing import (
            ThreadgroupSizingMixin,
        )

        class _MockKernel(ThreadgroupSizingMixin):
            simd_group_size = 0  # device query "failed"

            def _compute_config_key(self):
                return "test_subgroup_size_key"

        kernel = _MockKernel()

        # Case 1: No cached metrics → should return None.
        with patch(
            "torch_vulkan.inductor.runtime.get_cached_metrics_for_key",
            return_value=None,
        ):
            assert kernel._get_cached_subgroup_size() is None, (
                "M20.5: _get_cached_subgroup_size should return None when no metrics"
            )

        # Case 2: Metrics with subgroup_size=64 → should return 64.
        with patch(
            "torch_vulkan.inductor.runtime.get_cached_metrics_for_key",
            return_value={"subgroup_size": 64, "vgprs": 32},
        ):
            result = kernel._get_cached_subgroup_size()
            assert result == 64, (
                f"M20.5: _get_cached_subgroup_size with subgroup_size=64 "
                f"should return 64, got {result}"
            )

        # Case 3: Metrics with subgroup_size=32 (wave32) → should return 32.
        with patch(
            "torch_vulkan.inductor.runtime.get_cached_metrics_for_key",
            return_value={"subgroup_size": 32, "vgprs": 16},
        ):
            result = kernel._get_cached_subgroup_size()
            assert result == 32, (
                f"M20.5: _get_cached_subgroup_size with subgroup_size=32 "
                f"should return 32, got {result}"
            )

        # Case 4: Metrics with subgroup_size=None → should return None.
        with patch(
            "torch_vulkan.inductor.runtime.get_cached_metrics_for_key",
            return_value={"subgroup_size": None, "vgprs": 32},
        ):
            assert kernel._get_cached_subgroup_size() is None, (
                "M20.5: _get_cached_subgroup_size should return None when "
                "subgroup_size is None in metrics"
            )

    def test_sgs_fallback_uses_cached_subgroup_size(self):
        """M20.5: pointwise WG picker uses cached subgroup_size when simd_group_size=0.

        When the device-interface query returns simd_group_size=0 (device
        not available) and cached reflection has subgroup_size=32 (wave32),
        the WG picker should use 32 as the minimum/multiple rather than the
        hardcoded 64 default.
        """
        from unittest.mock import MagicMock, patch

        from torch_vulkan.inductor.kernel.threadgroup_sizing import (
            ThreadgroupSizingMixin,
        )

        class _MockPointwiseKernel(ThreadgroupSizingMixin):
            simd_group_size = 0  # simulate failed device query
            _packed16 = False
            inside_reduction = False

            numels = {"x": 1024}

            def _compute_config_key(self):
                return "test_wave32_sgs_key"

            def _get_actual_vgprs(self):
                return None

            def _estimate_vgprs(self):
                return 16  # light pressure

            def _get_cached_io_pressure(self):
                return None

            def _get_cached_loop_depth(self):
                return None

            def _estimate_loop_depth(self):
                return 1

        kernel = _MockPointwiseKernel()

        # Patch: reflection reports wave32 (subgroup_size=32).
        # The WG size should be a multiple of 32 (not 64).
        with (
            patch(
                "torch_vulkan.inductor.runtime.get_cached_metrics_for_key",
                return_value={"subgroup_size": 32, "vgprs": 16},
            ),
            patch(
                "torch_vulkan.inductor.config.no_wg_tune",
                return_value=False,
            ),
            patch(
                "torch_vulkan.inductor.config.reflection_enabled",
                return_value=True,
            ),
            patch(
                "torch._dynamo.device_interface.get_interface_for_device",
                side_effect=Exception("no device"),
            ),
        ):
            sgs = kernel.simd_group_size or kernel._get_cached_subgroup_size() or 64
            assert sgs == 32, (
                f"M20.5: with simd_group_size=0 and cached subgroup_size=32, "
                f"sgs fallback should be 32 (wave32), got {sgs}"
            )


# ── M20.9 helpers ────────────────────────────────────────────────────────────


class _M209MockRangeTree:
    """Minimal range-tree node for testing should_use_cooperative_reduction."""

    def __init__(self, numel: int, is_reduction: bool = False):
        self.numel = numel
        self.is_reduction = is_reduction


class _M209MockKernel:
    """Minimal mock of VulkanKernel for M20.9 unit tests.

    Lets the caller control:
      - range_trees: list of _M209MockRangeTree (determines rnumel / numel_hint)
      - io_pressure: value returned by _get_cached_io_pressure (None = no data)
      - num_sgprs: SGPR count returned by _get_cached_num_sgprs (None = no data)
      - has_welford: whether _has_welford_reduction returns True

    Delegates should_use_cooperative_reduction to the real VulkanKernel
    implementation so the tests exercise production code, not a re-
    implementation.
    """

    def __init__(
        self,
        *,
        range_trees=None,
        io_pressure=None,
        num_sgprs=None,
        has_welford: bool = False,
    ):
        self._range_trees = range_trees or []
        self._io_pressure = io_pressure
        self._num_sgprs = num_sgprs
        self._has_welford = has_welford

    @property
    def range_trees(self):
        return self._range_trees

    def _has_welford_reduction(self) -> bool:
        return self._has_welford

    def _get_cached_io_pressure(self):
        return self._io_pressure

    def _get_cached_num_sgprs(self):
        """M20.9: Return pre-set SGPR count (None = no cached data)."""
        return self._num_sgprs

    def _compute_config_key(self) -> str:
        return "mock_key"

    def should_use_cooperative_reduction(self) -> bool:
        """Delegates to the real VulkanKernel implementation."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        return VulkanKernel.should_use_cooperative_reduction(self)


class TestM209CooperativeReductionReflectionAware:
    """M20.9 — should_use_cooperative_reduction reflection-aware thresholds.

    Tests that SGPR pressure lowers the cooperative-reduction rnumel threshold
    (register-heavy kernels avoid extra sync pressure) and that I/O pressure
    raises it (memory-bound kernels hide sync latency).

    All tests use _M209MockKernel which directly controls _get_cached_num_sgprs
    and _get_cached_io_pressure return values, exercising the production
    VulkanKernel.should_use_cooperative_reduction code path without needing
    a live GPU or full kernel compile.
    """

    # ── Static threshold reference (numel_hint > 16 path) ───────────
    # Base: rn <= 4096 → cooperative; rn = 5000 → non-cooperative.
    # With SGPR penalty (×0.5): threshold = 2048 → rn=3000 no longer cooperative.
    # With I/O boost (×2.0): threshold = 8192 → rn=5000 becomes cooperative.

    def _make_range_trees(self, rnumel, numel_hint: int = 32):
        """Helper: one reduction axis (rnumel) + one pointwise axis (numel_hint)."""
        return [
            _M209MockRangeTree(rnumel, is_reduction=True),
            _M209MockRangeTree(numel_hint, is_reduction=False),
        ]

    def test_high_sgpr_pressure_lowers_threshold(self):
        """M20.9: num_sgprs > 64 halves the cooperative-reduction threshold.

        Choose rnumel = 3000, numel_hint = 32 (> 16 path, base threshold = 4096).
        Without SGPR pressure: 3000 <= 4096 → cooperative.
        With SGPR pressure (>64): threshold = 2048 → 3000 > 2048 → non-cooperative.
        """
        # Baseline: no reflection data → static threshold = 4096.
        k_base = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=3000, numel_hint=32),
            io_pressure=None,
            num_sgprs=None,
        )
        assert k_base.should_use_cooperative_reduction() is True, (
            "M20.9: baseline (no reflection) with rnumel=3000 should be cooperative "
            "(3000 <= 4096 static threshold)"
        )

        # With SGPR pressure > 64: threshold drops to 2048 → 3000 > 2048 → False.
        k_sgpr = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=3000, numel_hint=32),
            io_pressure=None,
            num_sgprs=80,  # > 64 → 0.5× penalty
        )
        assert k_sgpr.should_use_cooperative_reduction() is False, (
            "M20.9: num_sgprs=80 (>64) should lower threshold to 2048; "
            "rnumel=3000 > 2048 → expected non-cooperative"
        )

    def test_high_io_pressure_raises_threshold(self):
        """M20.9: num_loads + num_stores > 128 doubles the cooperative threshold.

        Choose rnumel = 5000, numel_hint = 32 (base threshold = 4096).
        Without I/O boost: 5000 > 4096 → non-cooperative.
        With I/O boost (>128): threshold = 8192 → 5000 <= 8192 → cooperative.
        """
        # Baseline: rnumel=5000 > 4096 → non-cooperative.
        k_base = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=5000, numel_hint=32),
            io_pressure=None,
            num_sgprs=None,
        )
        assert k_base.should_use_cooperative_reduction() is False, (
            "M20.9: baseline with rnumel=5000 should be non-cooperative (5000 > 4096)"
        )

        # With high I/O pressure (> 128): threshold doubles to 8192.
        k_io = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=5000, numel_hint=32),
            io_pressure=150,  # 150 > 128 → 2× boost
            num_sgprs=None,
        )
        assert k_io.should_use_cooperative_reduction() is True, (
            "M20.9: io_pressure=150 (>128) should raise threshold to 8192; "
            "rnumel=5000 <= 8192 → expected cooperative"
        )

    def test_no_reflection_data_uses_static_thresholds(self):
        """M20.9: When reflection data is unavailable, static thresholds apply.

        Both _get_cached_io_pressure and _get_cached_num_sgprs return None.
        Verify that numel_hint > 16 path uses the unmodified 4096 threshold.
        """
        # Just at the static threshold → cooperative.
        k_at = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=4096, numel_hint=32),
            io_pressure=None,
            num_sgprs=None,
        )
        assert k_at.should_use_cooperative_reduction() is True, (
            "M20.9: no reflection data, rnumel=4096 <= 4096 (static) → cooperative"
        )

        # Just above the static threshold → non-cooperative.
        k_above = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=4097, numel_hint=32),
            io_pressure=None,
            num_sgprs=None,
        )
        assert k_above.should_use_cooperative_reduction() is False, (
            "M20.9: no reflection data, rnumel=4097 > 4096 (static) → non-cooperative"
        )

    def test_dynamic_rnumel_always_cooperative(self):
        """M20.9: Dynamic rnumel short-circuits to True regardless of reflection.

        Even with high SGPR pressure (would lower threshold), a kernel with
        a dynamic reduction size must always use cooperative reduction so
        that the runtime dispatch path remains valid.
        """
        import sympy

        # Use a symbolic (dynamic) numel for the reduction axis.
        _s = sympy.Symbol("N", positive=True)
        range_trees = [
            _M209MockRangeTree(_s, is_reduction=True),
            _M209MockRangeTree(32, is_reduction=False),
        ]
        k = _M209MockKernel(
            range_trees=range_trees,
            num_sgprs=256,  # high SGPR pressure — should be irrelevant
            io_pressure=None,
        )
        assert k.should_use_cooperative_reduction() is True, (
            "M20.9: dynamic rnumel must always return cooperative=True, "
            "even under high SGPR pressure"
        )

    def test_combined_sgpr_and_io_pressure_apply_both_scales(self):
        """M20.9: When both SGPR and I/O pressure are high, both scales apply.

        SGPR penalty ×0.5 and I/O boost ×2.0 cancel out → net scale = 1.0
        (original threshold unchanged).
        """
        # With net scale = 1.0, threshold stays at 4096.
        k_at = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=4096, numel_hint=32),
            io_pressure=150,  # > 128 → ×2.0 boost
            num_sgprs=80,  # > 64 → ×0.5 penalty; net = 1.0
        )
        assert k_at.should_use_cooperative_reduction() is True, (
            "M20.9: combined SGPR×0.5 + I/O×2.0 = net×1.0; "
            "rnumel=4096 <= 4096 → cooperative"
        )

        k_above = _M209MockKernel(
            range_trees=self._make_range_trees(rnumel=4097, numel_hint=32),
            io_pressure=150,
            num_sgprs=80,
        )
        assert k_above.should_use_cooperative_reduction() is False, (
            "M20.9: combined SGPR×0.5 + I/O×2.0 = net×1.0; "
            "rnumel=4097 > 4096 → non-cooperative"
        )


class TestM208ScatterIScatterGenerics:
    """M20.8 — Anti-goal #6 sweep for scatter_atomic template.

    Verifies that the scatter_atomic template uses the Slang ``IScatter``
    generic interface (declared in ``shaders/lib/atomics.slang``) for all
    atomic operations instead of the old Jinja ``{% if operation == ... %}``
    chain inside the shader body.

    These are static-analysis tests (grep / Jinja render) — no GPU required.
    """

    def _atomics_src(self) -> str:
        path = os.path.join(
            os.path.dirname(__file__),
            "..",
            "shaders",
            "lib",
            "atomics.slang",
        )
        with open(os.path.normpath(path)) as f:
            return f.read()

    def _jinja_src(self) -> str:
        path = os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "templates",
            "scatter_atomic.py.jinja",
        )
        with open(os.path.normpath(path)) as f:
            return f.read()

    def _render(self, operation: str) -> str:
        from jinja2 import Environment

        env = Environment()
        tmpl = env.from_string(self._jinja_src())
        return tmpl.render(operation=operation, dtype="float", index_dtype="int")

    def test_scatter_atomic_slang_uses_iscatter_interface(self):
        """IScatter interface is declared in shaders/lib/atomics.slang."""
        src = self._atomics_src()
        assert "public interface IScatter" in src, (
            "M20.8: `public interface IScatter` must be declared in "
            "shaders/lib/atomics.slang (anti-goal #6 — generics, not strings)."
        )
        # combine method must be part of the interface
        assert (
            "static void combine(RWStructuredBuffer<uint> out, uint idx, float val)"
            in src
        ), (
            "M20.8: IScatter interface must declare "
            "`static void combine(RWStructuredBuffer<uint> out, uint idx, float val)`."
        )

    def test_scatter_structs_implement_iscatter(self):
        """All five concrete IScatter structs exist in atomics.slang."""
        src = self._atomics_src()
        expected_structs = [
            "ScatterAdd",
            "ScatterMax",
            "ScatterMin",
            "ScatterProd",
            "ScatterMean",
        ]
        for struct in expected_structs:
            assert f"public struct {struct} : IScatter" in src, (
                f"M20.8: `public struct {struct} : IScatter` not found in "
                "shaders/lib/atomics.slang."
            )

    def test_scatter_slang_no_operation_if_elif_for_atomics(self):
        """scatter_atomic.py.jinja must not have per-op if/elif for atomic ops.

        The old anti-goal #6 violation was branching on the operation name
        inside the shader body (e.g. ``{% if operation == 'scatter_add' %}``).
        After M20.8, atomic operations are dispatched via ``IScatter`` generics
        — the Jinja template may still use ``operation`` to set Jinja variables
        (scatter_struct, is_atomic, etc.), but must not branch on it inside the
        rendered Slang shader body for the atomic dispatch itself.
        """
        src = self._jinja_src()
        # These patterns are the old per-op branches in the shader body.
        # They must no longer appear.
        forbidden = [
            '{% elif operation == "scatter_add" %}',
            "{% elif operation == 'scatter_add' %}",
            '{% elif operation == "index_put_accumulate" %}',
            "{% elif operation == 'index_put_accumulate' %}",
            '{% elif operation == "scatter_reduce_amax" %}',
            "{% elif operation == 'scatter_reduce_amax' %}",
            '{% elif operation == "scatter_reduce_amin" %}',
            "{% elif operation == 'scatter_reduce_amin' %}",
            '{% elif operation == "scatter_reduce_prod" %}',
            "{% elif operation == 'scatter_reduce_prod' %}",
            '{% elif operation == "scatter_reduce_mean" %}',
            "{% elif operation == 'scatter_reduce_mean' %}",
        ]
        for pattern in forbidden:
            assert pattern not in src, (
                f"M20.8: found forbidden per-op Jinja branch `{pattern}` in "
                "scatter_atomic.py.jinja — anti-goal #6 violation. "
                "Atomic operations must use IScatter::combine generics."
            )

    def test_scatter_add_renders_scatteradd_struct(self):
        """scatter_add renders ScatterAdd::combine, not c10_vulkan_atomic_add."""
        rendered = self._render("scatter_add")
        assert "ScatterAdd::combine(args.out" in rendered, (
            "M20.8: scatter_add must render `ScatterAdd::combine(args.out, ...)` "
            "in the shader body."
        )
        # Old direct call must be gone from the rendered body
        assert "c10_vulkan_atomic_add" not in rendered, (
            "M20.8: scatter_add must not emit raw `c10_vulkan_atomic_add` — "
            "use IScatter::combine instead."
        )

    def test_scatter_reduce_ops_render_correct_structs(self):
        """Each scatter_reduce variant renders the correct IScatter struct."""
        op_to_struct = {
            "index_put_accumulate": "ScatterAdd",
            "scatter_reduce_amax": "ScatterMax",
            "scatter_reduce_amin": "ScatterMin",
            "scatter_reduce_prod": "ScatterProd",
            "scatter_reduce_mean": "ScatterMean",
        }
        for op, struct in op_to_struct.items():
            rendered = self._render(op)
            assert f"{struct}::combine(args.out" in rendered, (
                f"M20.8: operation `{op}` must render `{struct}::combine(args.out, ...)`. "
                "Got:\n" + rendered
            )

    def test_scatter_reduce_mean_still_has_count_increment(self):
        """scatter_reduce_mean still emits InterlockedAdd for the count buffer."""
        rendered = self._render("scatter_reduce_mean")
        assert "InterlockedAdd(args.count[uint(idx)], 1u" in rendered, (
            "M20.8: scatter_reduce_mean must still emit "
            "`InterlockedAdd(args.count[...], 1u, ...)` for the count buffer. "
            "This is a structural gate (is_mean), not an atomic-op gate."
        )

    def test_non_atomic_ops_unchanged(self):
        """Non-atomic ops (gather, scatter, index_put) are structurally unchanged."""
        # gather: reads from src[idx] into out[i]
        rendered_gather = self._render("gather")
        assert "args.out[i] = args.src[uint(idx)]" in rendered_gather, (
            "M20.8: gather path must still write `args.out[i] = args.src[uint(idx)]`."
        )
        # scatter: non-atomic write to out[idx]
        rendered_scatter = self._render("scatter")
        assert "args.out[uint(idx)] = asuint(args.src[i])" in rendered_scatter, (
            "M20.8: scatter path must still write `args.out[uint(idx)] = asuint(args.src[i])`."
        )
        # index_put: non-atomic write to out[idx]
        rendered_ip = self._render("index_put")
        assert "args.out[uint(idx)] = asuint(args.src[i])" in rendered_ip, (
            "M20.8: index_put path must still write `args.out[uint(idx)] = asuint(args.src[i])`."
        )


class TestTestCov4SpecialMathBwd:
    """TEST.COV.4 — gradient-parity tests for the 8 special-math ops that
    have ``[BackwardDerivative]`` annotations in ``shaders/lib/pointwise.slang``
    and are routed through ``bwd_diff_table.py`` on the backward pass.

    Each test:
    1. Runs the forward op on a CPU tensor with ``requires_grad=True`` and
       calls ``.backward()`` to get the reference gradient.
    2. Compiles the same lambda via ``torch.compile(..., backend="inductor")``
       and runs it on a Vulkan tensor, then calls ``.backward()``.
    3. Asserts gradient parity within ``atol=rtol=2e-3``.

    Ops covered (8):
      erfinv  → ``aten.erfinv_backward``   → ``bwd_diff(erfinv_fwd)``
      lgamma  → ``aten.lgamma_backward``   → ``bwd_diff(lgamma_fwd)``
      digamma → ``aten.digamma_backward``  → ``bwd_diff(digamma_fwd)``
      ndtri   → ``aten.ndtri_backward``    → ``bwd_diff(ndtri_fwd)``
      i0      → ``aten.i0_backward``       → ``bwd_diff(i0_fwd)``
      i0e     → ``aten.i0e_backward``      → ``bwd_diff(i0e_fwd)``
      i1      → ``aten.i1_backward``       → ``bwd_diff(i1_fwd)``
      i1e     → ``aten.i1e_backward``      → ``bwd_diff(i1e_fwd)``

    Domain notes:
    - ``erfinv`` input must stay strictly inside (-1, 1); edges diverge.
    - ``ndtri`` (inverse of the normal CDF) input must stay inside (0, 1).
    - ``i1`` / ``i1e`` avoid x=0 where the Bessel function has a removable
      singularity that makes the numerical gradient noisy.

    Closed: TEST.COV.4 — ``TestTestCov4SpecialMathBwd`` (8 tests).
    Added 2026-05-23.
    """

    @pytest.fixture(autouse=True)
    def _require_vulkan(self):
        try:
            import torch_vulkan

            if not torch_vulkan.is_available():
                pytest.skip("No Vulkan device")
        except ImportError:
            pytest.skip("torch_vulkan not installed")

    def _check_grad(self, fn, x_cpu, atol=2e-3, rtol=2e-3):
        """Compile *fn* on Vulkan and assert gradient parity vs CPU.

        Args:
            fn: A ``Tensor → Tensor`` lambda.  Must be differentiable.
            x_cpu: A 1-D CPU float32 ``Tensor`` (no ``requires_grad``).
            atol / rtol: Passed to ``torch.testing.assert_close``.
        """
        # CPU reference
        x_ref = x_cpu.detach().clone().requires_grad_(True)
        y_ref = fn(x_ref)
        y_ref.backward()
        grad_ref = x_ref.grad.clone()

        # Vulkan compiled
        x_vk = x_cpu.detach().to("vulkan:0").requires_grad_(True)
        compiled = torch.compile(fn, backend="inductor")
        y_vk = compiled(x_vk)
        y_vk.backward()
        grad_vk = x_vk.grad.cpu()

        torch.testing.assert_close(
            grad_vk,
            grad_ref,
            atol=atol,
            rtol=rtol,
        )

    @pytest.mark.timeout(300)
    def test_erfinv_backward_grad_parity(self):
        """``torch.erfinv`` backward — domain (-0.9, 0.9) avoids edge divergence."""
        x = torch.linspace(-0.9, 0.9, 32)
        self._check_grad(lambda t: torch.erfinv(t).sum(), x)

    @pytest.mark.timeout(300)
    def test_lgamma_backward_grad_parity(self):
        """``torch.lgamma`` backward — positive domain only."""
        x = torch.linspace(0.5, 5.0, 32)
        self._check_grad(lambda t: torch.lgamma(t).sum(), x)

    @pytest.mark.timeout(300)
    def test_digamma_backward_grad_parity(self):
        """``torch.digamma`` backward — positive domain only."""
        x = torch.linspace(0.5, 5.0, 32)
        self._check_grad(lambda t: torch.digamma(t).sum(), x)

    @pytest.mark.timeout(300)
    def test_ndtri_backward_grad_parity(self):
        """``torch.special.ndtri`` backward — domain (0.1, 0.9) inside (0, 1)."""
        x = torch.linspace(0.1, 0.9, 32)
        self._check_grad(lambda t: torch.special.ndtri(t).sum(), x)

    @pytest.mark.timeout(300)
    def test_i0_backward_grad_parity(self):
        """``torch.i0`` backward — modified Bessel function of the first kind, order 0."""
        x = torch.linspace(-3.0, 3.0, 32)
        self._check_grad(lambda t: torch.i0(t).sum(), x)

    @pytest.mark.timeout(300)
    def test_i0e_backward_grad_parity(self):
        """``torch.special.i0e`` backward — exponentially scaled i0."""
        x = torch.linspace(-3.0, 3.0, 32)
        self._check_grad(lambda t: torch.special.i0e(t).sum(), x)

    @pytest.mark.timeout(300)
    def test_i1_backward_grad_parity(self):
        """``torch.special.i1`` backward — modified Bessel function, order 1; avoid x=0."""
        x = torch.linspace(0.5, 5.0, 32)
        self._check_grad(lambda t: torch.special.i1(t).sum(), x)

    @pytest.mark.timeout(300)
    def test_i1e_backward_grad_parity(self):
        """``torch.special.i1e`` backward — exponentially scaled i1; avoid x=0."""
        x = torch.linspace(0.5, 5.0, 32)
        self._check_grad(lambda t: torch.special.i1e(t).sum(), x)


# ═══════════════════════════════════════════════════════════════════════
# TEST.COV.2 — dtype matrix sweep: fp16 / bf16 × top-10 lowerings
# ═══════════════════════════════════════════════════════════════════════


class TestTestCov2DtypeMatrix:
    """TEST.COV.2 — dtype × op matrix sweep for fp16 and bf16.

    Verifies that fp16/bf16 variants of the top-20 lowerings produce
    CPU-matching output when compiled through the Vulkan Inductor backend.
    Uses atol=5e-3 (fp16 precision floor; bf16 is ±10× coarser but
    operations are simple enough to stay within 1% of CPU).

    18 ops × 2 dtypes = 36 parametrized test cases (top-20 coverage):
      relu, tanh, sigmoid, add, mul, sub, sum, mean, softmax,
      layer_norm, linear/mm, div, exp, log, amax, pow, group_norm, bmm.
    Added 2026-05-23 for TEST.COV.2; expanded 2026-05-25.
    """

    @pytest.fixture(autouse=True)
    def setup(self):
        try:
            import torch_vulkan

            if not torch_vulkan.is_available():
                pytest.skip("No Vulkan device")
        except ImportError:
            pytest.skip("torch_vulkan not installed")

    def _check(self, fn, *cpu_args, dtype=torch.float16, atol=5e-3, rtol=5e-3):
        """Compile *fn* on Vulkan at *dtype* and verify parity with CPU.

        *cpu_args* are float32 tensors; they are cast to *dtype* both for
        Vulkan and for the CPU reference so the comparison is dtype-fair.
        Output is up-cast to float32 before ``assert_close`` to avoid
        fp16 comparison surprises.
        """
        import os

        os.environ.setdefault("TORCH_VULKAN_MM_TILES", "64x64x16")
        args_vk = tuple(
            a.to(dtype).to("vulkan:0") if isinstance(a, torch.Tensor) else a
            for a in cpu_args
        )
        args_cpu = tuple(
            a.to(dtype) if isinstance(a, torch.Tensor) else a for a in cpu_args
        )
        compiled = torch.compile(fn, backend="inductor")
        got = compiled(*args_vk).cpu().float()
        expected = fn(*args_cpu).float()
        torch.testing.assert_close(got, expected, atol=atol, rtol=rtol)

    # ── pointwise ops ────────────────────────────────────────────────

    @pytest.mark.timeout(300)
    @pytest.mark.parametrize("dtype", [torch.float16, torch.bfloat16])
    def test_relu_fp16_bf16(self, dtype):
        """TEST.COV.2: relu at fp16/bf16 matches CPU."""
        torch.manual_seed(0)
        x = torch.randn(128)
        self._check(torch.relu, x, dtype=dtype)

