class TestDECOMP2_ConvBwdBiasGradient:
    """DECOMP.2 — Verify upstream Inductor convolution_backward decomp does
    NOT fire for Vulkan device.

    The upstream decomp at torch/_inductor/decomposition.py:306-336 splits
    convolution_backward into bias_grad=sum(grad) + recursive
    convolution_backward(output_mask=(T,T,F)), but ONLY when
    is_gpu(grad.device.type) is True. Since "vulkan" is not in
    torch._inductor.utils.GPU_TYPES (which contains cuda/mps/xpu/mtia),
    the decomp guard returns NotImplemented — the op survives intact to
    the Vulkan lowering which handles it as a single dispatch.

    This test locks that invariant so a future upstream GPU_TYPES change
    or Vulcan-typo fix doesn't silently break the architecture.
    """

    @pytest.mark.timeout(300)
    def test_vulkan_gpu_types_guard(self):
        """Verify the convolution_backward decomp behavior for Vulkan.

        If vulkan IS in GPU_TYPES (patched PyTorch), the upstream decomp
        fires — convolution_backward must then be in ops_to_suppress.
        If vulkan is NOT in GPU_TYPES, the decomp returns NotImplemented
        and no suppression is needed.
        """
        from torch._inductor.utils import GPU_TYPES

        if "vulkan" in GPU_TYPES:
            # Decomp will fire — must be suppressed in ops_to_suppress.
            import torch
            from torch._inductor.decomposition import decompositions

            aten = torch.ops.aten
            assert aten.convolution_backward.default not in decompositions, (
                "DECOMP.2: vulkan is in GPU_TYPES, so the upstream "
                "convolution_backward decomposition fires. "
                "It must be suppressed or overridden."
            )
        # Either way, our lowering handles it.

    @pytest.mark.timeout(300)
    def test_convolution_backward_in_ops_to_suppress(self):
        """aten.convolution_backward IS in ops_to_suppress (DECOMP.2,
        2026-05-29). AOT Autograd must not decompose it into mm+sum+fold
        before our registered custom lowering fires."""
        import torch
        import torch_vulkan  # triggers _suppress_upstream_decomps
        from torch._inductor.decomposition import decompositions

        aten = torch.ops.aten
        # After _suppress_upstream_decomps() runs, these should be REMOVED
        # from the Inductor decompositions dict.
        assert aten.convolution_backward.default not in decompositions, (
            "DECOMP.2: aten.convolution_backward.default must NOT be in "
            "decompositions after _suppress_upstream_decomps. The op must "
            "be in ops_to_suppress so our Vulkan lowering fires."
        )
        # Also check the AOT decomp table.
        from torch._decomp import decomposition_table as _aot_decomps
        assert aten.convolution_backward.default not in _aot_decomps, (
            "DECOMP.2: aten.convolution_backward.default must NOT be in "
            "the AOT decomp table (torch._decomp.decomposition_table) "
            "after _suppress_upstream_decomps."
        )

    @pytest.mark.timeout(300)
    def test_convolution_backward_lowering_registered(self):
        """The Vulkan backend has a registered lowering for
        aten.convolution_backward.default (single-dispatch Slang kernel)."""
        import torch
        from torch._inductor.lowering import lowerings as _inductor_lowerings

        aten = torch.ops.aten
        key = aten.convolution_backward.default
        assert key in _inductor_lowerings, (
            "DECOMP.2: aten.convolution_backward.default must have a "
            "registered lowering in torch._inductor.lowering.lowerings — "
            "check bwd_lowerings.py:_register_conv_backward()"
        )


